```python
def sql_escape(s, db_type='mysql'):
    if not isinstance(s, str):
        raise TypeError('Input must be a string')

    if db_type == 'mysql':
        allowed_chars = '%_'
        escaped_chars = {
            "'": "''",
            '"': '""',
            '\\': '\\\\',
            '%': '%',
            '_': '_'
        }
    elif db_type == 'postgresql':
        allowed_chars = '%_'
        escaped_chars = {
            "'": "''",
            '"': '""',
            '\\': '\\\\',
            '%': '%',
            '_': '_',
            "'": "''",
            '"': '""'
        }
    elif db_type == 'sqlite':
        allowed_chars = '%_'
        escaped_chars = {
            "'": "''",
            '"': '""',
            '\\': '\\\\',
            '%': '%',
            '_': '_'
        }
    else:
        raise ValueError('Unsupported database type')

    s = s.strip()
    s = s.replace('\0', '')
    s = ''.join(c for c in s if c.isalnum() or c in allowed_chars)

    for char, escape in escaped_chars.items():
        s = s.replace(char, escape)

    return s
