def sql_sanitization(input_string):
    """
    Sanitizes the input string to prevent SQL injection.

    :param input_string: The input string to be sanitized.
    :return: The sanitized string.
    """

    sanitized_string = ""

    for char in input_string:
        if char.isalnum():
            sanitized_string += char
        elif char in ['"', "'"]:
            sanitized_string += char
        elif char in ["\\", "\n"]:
            sanitized_string += "\\" + char
        elif char == "%":
            sanitized_string += "\\%"
        elif char == "_":
            sanitized_string += "\\_"
        elif char == "\r":
            sanitized_string += "\\r"
        elif char == "\t":
            sanitized_string += "\\t"
        elif char == "\0":
            sanitized_string += "\\0"
        elif char == "\b":
            sanitized_string += "\\b"
        elif char == "\f":
            sanitized_string += "\\f"
        elif char == "\x00":
            sanitized_string += "\\x00"
        else:
            sanitized_string += "\\" + char

    return sanitized_string
