def sql_escape(input):
    escaped = ""
    for char in input:
        if char == "\\":
            escaped += "\\\\"
        elif char == "'":
            escaped += "\\'"
        elif char == '"':
            escaped += '\\"'
        elif char == '\n':
            escaped += "\\n"
        elif char == '\r':
            escaped += "\\r"
        elif char == '\t':
            escaped += "\\t"
        elif char == '\b':
            escaped += "\\b"
        elif char == '\f':
            escaped += "\\f"
        elif char < 32 or char == 127:
            escaped += "\\x" + format(ord(char), '02x')
        else:
            escaped += char
    return escaped

