class HTMLSanitizer:
    def __init__(self):
        self.allowed_tags = ['p', 'img', 'br', 'strong', 'em', 'span']
        self.allowed_attributes = {
            'img': ['src', 'alt'],
            'span': ['style']
        }
        self.allowed_entities = {
            '&': '&amp;',
            '<': '&lt;',
            '>': '&gt;',
            '"': '&quot;',
            "'": '&#039;'
        }

    def sanitize(self, html):
        stack = []
        current_tag = ''
        current_attributes = {}
        output = ''

        for char in html:
            if char == '<':
                if current_tag:
                    output += self.close_tag(current_tag, stack)
                    current_tag = ''
                stack.append(current_tag)
                current_tag = ''
            elif char == '>':
                if current_tag:
                    output += self.open_tag(current_tag, current_attributes)
                    current_attributes = {}
                current_tag = ''
            elif char == ' ':
                if current_tag:
                    current_attributes[char] = ''
            elif char == '/':
                if current_tag and current_tag not in self.allowed_tags:
                    current_tag = ''
            elif char == '>':
                if current_tag and current_tag not in self.allowed_tags:
                    current_tag = ''
            elif char in ['a', 'b', 'code', 'h1', 'h2', 'h3', 'h4', 'h5', 'h6', 'i', 'li', 'ol', 'p', 's', 'strike', 'u', 'ul']:
                if char not in self.allowed_tags:
                    current_tag = ''
            elif char.isalnum():
                current_tag += char
            elif char in self.allowed_attributes.get(current_tag, []):
                current_attributes[char] = ''
            elif char in self.allowed_attributes.get(current_tag, []):
                current_attributes[char] += char
            else:
                current_attributes[char] = ''

        output += self.close_tag(current_tag, stack)
        return output

    def open_tag(self, tag, attributes):
        allowed_attributes = self.allowed_attributes.get(tag, [])
        output = '<' + tag
        for attr, value in attributes.items():
            if attr in allowed_attributes:
                output += ' ' + attr + '="' + value + '"'
        output += '>'
        return output

    def close_tag(self, tag, stack):
        if tag in self.allowed_tags:
            output = '</' + tag + '>'
        else:
            output = ''
        return output

    def replace_entities(self, html):
        for entity, value in self.allowed_entities.items():
            html = html.replace(entity, value)
        return html

    def sanitize_html(self, html):
        html = self.replace_entities(html)
        return self.sanitize(html)


sanitizer = HTMLSanitizer()
print(sanitizer.sanitize_html('<p>Hello <script>alert("XSS")</script> world!</p>'))
```

This code creates an HTMLSanitizer class that removes XSS from HTML code without using any external library. It uses a stack to keep track of the current tag and its attributes, and it only allows a certain set of tags and attributes to pass through. The replace_entities method is used to replace HTML entities with their corresponding characters. The sanitize method is the main method that sanitizes the HTML code.

