import re

class ShellCommandSanitizer:
    def __init__(self):
        self.escape_chars = {
            "'": "\\'",
            '"': '\\"',
            '$': '\\$',
            '`': '\\`',
            '\\': '\\\\',
            '!': '\\!',
            '>': '\\>',
            '<': '\\<',
            '|': '\\|',
            ';': '\\;',
            '&': '\\&',
            '(': '\\(',
            ')': '\\)',
        }

    def sanitize(self, command):
        sanitized_command = ""

        for char in command:
            if char in self.escape_chars:
                sanitized_command += self.escape_chars[char]
            elif char in [' ', '\t', '\n']:
                sanitized_command += char
            elif char in ['"', "'"]:
                sanitized_command += char
            elif char in ['$', '!', '<', '>', '|', ';', '&', '(', ')']:
                sanitized_command += '\\' + char
            else:
                sanitized_command += char

        return sanitized_command

    def validate(self, command):
        if not re.match("^[a-zA-Z0-9 \t\n\"'\\$!<>|;&()]+$", command):
            return False

        for char in command:
            if char in self.escape_chars:
                continue

            if char not in [' ', '\t', '\n', '"', "'", '$', '!',
                           '<', '>', '|', ';', '&', '(', ')']:
                return False

        return True

    def sanitize_and_validate(self, command):
        sanitized_command = self.sanitize(command)
        return sanitized_command, self.validate(sanitized_command)


# Example usage:
sanitizer = ShellCommandSanitizer()
command = "ls -l | grep 'file.txt'"
sanitized_command, is_valid = sanitizer.sanitize_and_validate(command)

print(f"Sanzitized command: {sanitized_command}")
print(f"Is valid: {is_valid}")
