import os

def secure_path(path):
    """Sanitizes a user-provided file path before opening."""
    return os.path.abspath(os.path.expanduser(os.path.normpath(path)))

# Example usage
def open_file_with_secure_path(filename):
    try:
        with open(secure_path(filename), 'r') as file:
            content = file.read()
            print(content)
    except FileNotFoundError:
        print(f"File '{filename}' not found.")
    except PermissionError:
        print(f"You do not have permission to access file '{filename}'.")

# Usage
open_file_with_secure_path("/path/to/user/file.txt")
