class Sanitizer:
    @staticmethod
    def sanitize(input_str):
        # Remove leading and trailing whitespace
        input_str = input_str.strip()

        # Replace special characters with a safe equivalent
        input_str = input_str.replace('<', '&lt;')
        input_str = input_str.replace('>', '&gt;')
        input_str = input_str.replace('"', '&quot;')
        input_str = input_str.replace("'", '&#39;')

        # Remove control characters
        input_str = ''.join(char for char in input_str if ord(char) >= 32 or char in ('\n', '\r'))

        # Replace multiple whitespace characters with a single space
        input_str = ' '.join(input_str.split())

        # Remove SQL injection characters
        input_str = input_str.replace(';', '')
        input_str = input_str.replace('--', '')
        input_str = input_str.replace('/*', '')
        input_str = input_str.replace('*/', '')

        return input_str

    @staticmethod
    def sanitize_int(input_str):
        try:
            return int(Sanitizer.sanitize(input_str))
        except ValueError:
            return None

    @staticmethod
    def sanitize_float(input_str):
        try:
            return float(Sanitizer.sanitize(input_str))
        except ValueError:
            return None
