import re
import json

def sanitize_input(data):
    """
    Sanitizes user-provided data by removing special characters and trimming whitespace.
    """
    if isinstance(data, str):
        # Remove special characters and digits
        data = re.sub('[^a-zA-Z\s]', '', data)
        # Trim whitespace
        data = data.strip()
    elif isinstance(data, list):
        # Recursively sanitize list elements
        data = [sanitize_input(item) for item in data]
    elif isinstance(data, dict):
        # Recursively sanitize dictionary values
        data = {key: sanitize_input(value) for key, value in data.items()}
    elif isinstance(data, int):
        data = str(data)
    elif isinstance(data, float):
        data = str(data)
    elif isinstance(data, bool):
        data = str(data).lower()
    return data

def process_data(data):
    """
    Processes sanitized user-provided data.
    """
    return json.dumps(data)

def main():
    user_input = input("Enter data: ")
    sanitized_data = sanitize_input(user_input)
    processed_data = process_data(sanitized_data)
    print(f"Processed data: {processed_data}")

if __name__ == "__main__":
