import base64
import hashlib
import hmac
import time
import os
import random
import string

def generate_secret_key(length=32):
    return ''.join(random.choice(string.ascii_letters + string.digits) for _ in range(length))

def generate_iv(length=16):
    return os.urandom(length)

def encrypt_data(data, secret_key):
    iv = generate_iv()
    encrypted_data = encrypt_aes_iv_ecb(data, secret_key, iv)
    return iv + encrypted_data

def decrypt_data(encrypted_data, secret_key):
    iv = encrypted_data[:16]
    encrypted_data = encrypted_data[16:]
    decrypted_data = decrypt_aes_iv_ecb(encrypted_data, secret_key, iv)
    return decrypted_data

def encrypt_aes_iv_ecb(data, secret_key, iv):
    block_size = 16
    key = secret_key[:block_size]
    encrypted_data = b''
    for i in range(0, len(data), block_size):
        block = data[i:i+block_size]
        encrypted_block = encrypt_aes_ecb(block, key)
        encrypted_data += encrypted_block
    return encrypted_data

def decrypt_aes_iv_ecb(encrypted_data, secret_key, iv):
    return decrypt_aes_ecb(encrypted_data, secret_key)

def encrypt_aes_ecb(data, key):
    cipher = AES.new(key, AES.MODE_ECB)
    return cipher.encrypt(data)

def decrypt_aes_ecb(encrypted_data, key):
    cipher = AES.new(key, AES.MODE_ECB)
    return cipher.decrypt(encrypted_data)

