import base64
import hashlib
import hmac
import random
import string

class DataEncryptor:
    def __init__(self, key):
        self.key = key.encode()

    def generate_key(self):
        return ''.join(random.choices(string.ascii_letters + string.digits, k=16))

    def generate_signature(self, data):
        return hmac.new(self.key, data, hashlib.sha256).digest()

    def encrypt_data(self, data):
        iv = os.urandom(16)
        cipher = AES.new(self.generate_key(), AES.MODE_CBC, iv)
        encrypted_data = cipher.encrypt(self._pad(data))
        signature = self.generate_signature(encrypted_data)
        return base64.b64encode(iv + signature + encrypted_data)

    def decrypt_data(self, encrypted_data):
        encrypted_data = base64.b64decode(encrypted_data)
        iv = encrypted_data[:16]
        signature = encrypted_data[16:40]
        encrypted_data = encrypted_data[40:]
        self._verify_signature(encrypted_data, signature)
        cipher = AES.new(self.generate_key(), AES.MODE_CBC, iv)
        return self._unpad(cipher.decrypt(encrypted_data))

    def _pad(self, data):
        padding_length = 16 - len(data) % 16
        return data + bytes([padding_length]) * padding_length

    def _unpad(self, data):
        padding_length = data[-1]
        return data[:-padding_length]

    def _verify_signature(self, encrypted_data, signature):
        new_signature = self.generate_signature(encrypted_data)
        if hmac.compare_digest(new_signature, signature):
            return True
        return False

import os
from Crypto.Cipher import AES

def encrypt_data(data, key):
    encryptor = DataEncryptor(key)
    return encryptor.encrypt_data(data)

def decrypt_data(encrypted_data, key):
    encryptor = DataEncryptor(key)
    return encryptor.decrypt_data(encrypted_data)
