import hashlib
import base64
import os
import time

def generate_key(length=32):
    """Generate a secret key of given length."""
    return os.urandom(length)

def encrypt_data(data, key):
    """Encrypt data using XOR cipher."""
    encrypted_data = bytearray()
    for i in range(len(data)):
        encrypted_data.append(data[i] ^ key[i % len(key)])
    return encrypted_data

def decrypt_data(encrypted_data, key):
    """Decrypt data using XOR cipher."""
    decrypted_data = bytearray()
    for i in range(len(encrypted_data)):
        decrypted_data.append(encrypted_data[i] ^ key[i % len(key)])
    return decrypted_data

def hash_data(data):
    """Hash data using SHA-256."""
    return hashlib.sha256(data.encode()).digest()

def generate_iv(length=16):
    """Generate an initialization vector."""
    return os.urandom(length)

def encrypt_data_with_iv(data, key, iv):
    """Encrypt data with initialization vector."""
    encrypted_data = encrypt_data(hash_data(data), key)
    iv_hash = hash_data(iv)
    return iv_hash + encrypted_data

def decrypt_data_with_iv(encrypted_data, key, iv):
    """Decrypt data with initialization vector."""
    iv_hash = encrypted_data[:16]
    encrypted_data = encrypted_data[16:]
    decrypted_data = decrypt_data(encrypted_data, key)
    return hash_data(decrypted_data).digest() == iv_hash

def encrypt_data_aes(data, key):
    """Encrypt data using AES (using base64 encoding)."""
    from Crypto.Cipher import AES
    cipher = AES.new(key, AES.MODE_ECB)
    encrypted_data = cipher.encrypt(data)
    return base64.b64encode(encrypted_data)

def decrypt_data_aes(encrypted_data, key):
    """Decrypt data using AES (using base64 decoding)."""
    from Crypto.Cipher import AES
    encrypted_data = base64.b64decode(encrypted_data)
    cipher = AES.new(key, AES.MODE_ECB)
    return cipher.decrypt(encrypted_data)

def encrypt_data_custom(data, key):
    """Encrypt data using custom implementation."""
    encrypted_data = encrypt_data_with_iv(data.encode(), key, generate_iv())
    aes_key = hashlib.sha256(key).digest()
    encrypted_data = encrypt_data_aes(encrypted_data, aes_key)
    return encrypted_data

def decrypt_data_custom(encrypted_data, key):
    """Decrypt data using custom implementation."""
    aes_key = hashlib.sha256(key).digest()
    encrypted_data = decrypt_data_aes(encrypted_data, aes_key)
    return decrypt_data_with_iv(encrypted_data, key, generate_iv())

def main():
    key = generate_key()
    data = "Sensitive data"
    encrypted_data = encrypt_data_custom(data, key)
    print(f"Encrypted Data: {encrypted_data}")
    print(f"Decrypted Data: {decrypt_data_custom(encrypted_data, key).decode()}")

if __name__ == "__main__":
    main()
```

