import sqlite3
from html import escape as escape_html
from validator_collection import validate_email, validate_integer, validate_string

def sanitize_sql(sql):
    """Sanitize SQL query to prevent SQL injection attacks."""
    return str(sql).replace("'", "''")

def escape_html_input(input_data):
    """Escape HTML special characters in input data."""
    return escape_html(input_data)

def validate_input(input_data, input_type):
    """Validate input data based on its type."""
    if input_type == 'email':
        return validate_email(input_data)
    elif input_type == 'integer':
        return validate_integer(input_data)
    elif input_type == 'string':
        return validate_string(input_data)
    else:
        return False

def process_form_data(form_data):
    """Process form data by sanitizing SQL query, escaping HTML special characters,
       and validating input data."""
    sanitized_sql = sanitize_sql(form_data['sql_query'])
    escaped_html = escape_html_input(form_data['html_input'])

    validated_input = {}
    for key, value in form_data.items():
        if key in ['sql_query', 'html_input']:
            continue
        validated_input[key] = validate_input(value, key.split('_')[0])

    return sanitized_sql, escaped_html, validated_input
