import sqlite3
from sqlite3 import Error
import html
import re

def validate_input(data, required_fields):
    """Validate form data"""
    for field in required_fields:
        if field not in data or not data[field]:
            raise ValueError(f"Missing required field: {field}")
        if not isinstance(data[field], str):
            raise ValueError(f"Field {field} must be a string")
    return True

def escape_html(data):
    """Escape HTML characters"""
    return {key: html.escape(value) for key, value in data.items()}

def sanitize_sql(data):
    """Sanitize SQL input"""
    return {key: re.sub(r"[^a-zA-Z0-9_]", "", value) for key, value in data.items()}

def process_form_data(data, required_fields, db_name):
    """Process form data"""
    try:
        # Validate form data
        validate_input(data, required_fields)

        # Escape HTML characters
        data = escape_html(data)

        # Sanitize SQL input
        data = sanitize_sql(data)

        # Connect to SQLite database
        conn = None
        try:
            conn = sqlite3.connect(db_name)
            cursor = conn.cursor()
            # Insert data into database (replace with actual SQL query)
            cursor.execute("INSERT INTO table_name (field1, field2) VALUES (?, ?)", (data['field1'], data['field2']))
            conn.commit()
            return "Data inserted successfully"
        except Error as e:
            return f"Error: {e}"
        finally:
            if conn:
                conn.close()
    except ValueError as e:
        return f"Error: {e}"
