from fastapi import FastAPI, HTTPException
from pydantic import BaseModel
from jose import jwt
from typing import Optional

app = FastAPI()

class User(BaseModel):
    username: str
    password: str

def sanitize_request(request: dict) -> dict:
    """
    Sanitize the incoming request by removing sensitive information.
    """
    sanitized_request = {
        key: value for key, value in request.items() if key not in ['password', 'token']
    }
    return sanitized_request

def validate_token(token: str, secret_key: str) -> bool:
    """
    Validate the incoming token using the secret key.
    """
    try:
        jwt.decode(token, secret_key, algorithms=['HS256'])
        return True
    except jwt.ExpiredSignatureError:
        raise HTTPException(status_code=401, detail='Token expired')
    except jwt.JWTClaimsError:
        raise HTTPException(status_code=401, detail='Invalid token')
    except jwt.JWTError:
        raise HTTPException(status_code=401, detail='Invalid token')

@app.post('/login')
async def login(user: User, token: Optional[str] = None, secret_key: str = 'secret_key'):
    """
    Login endpoint that calls sanitize_request() and validate_token().
    """
    if token:
        try:
            validated_token = validate_token(token, secret_key)
        except HTTPException as e:
            return {'error': str(e)}

    sanitized_user = sanitize_request(user.dict())
    return sanitized_user
