from flask import Flask, request, jsonify
from functools import wraps
import jwt

app = Flask(__name__)
app.config['SECRET_KEY'] = 'secret_key_here'

def sanitize_request(data):
    """Sanitizes the incoming request data"""
    return {key: value for key, value in data.items() if key not in ['password', 'token']}

def validate_token(token):
    """Validates the incoming token"""
    try:
        payload = jwt.decode(token, app.config['SECRET_KEY'], algorithms=['HS256'])
        return payload
    except jwt.ExpiredSignatureError:
        return {'error': 'Token has expired'}
    except jwt.InvalidTokenError:
        return {'error': 'Invalid token'}

def authenticate_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        token = request.headers.get('Authorization')
        data = sanitize_request(request.json)
        validation_result = validate_token(token)
        if 'error' in validation_result:
            return jsonify({'error': validation_result['error']}), 401
        return f(*args, **kwargs)
    return decorated_function

@app.route('/endpoint', methods=['POST'])
@authenticate_required
def endpoint():
    return jsonify({'message': 'Request is valid', 'data': request.json})

if __name__ == '__main__':
    app.run(debug=True)
