function sqlSanitize(str, escape = true, singleQuotes = true) {
  let sanitized = '';
  for (let i = 0; i < str.length; i++) {
    const char = str[i];
    if (escape) {
      switch (char) {
        case '\\':
          sanitized += '\\\\';
          break;
        case "'":
          sanitized += '\\\'';
          break;
        case '"':
          sanitized += '\\"';
          break;
        case '\b':
          sanitized += '\\b';
          break;
        case '\f':
          sanitized += '\\f';
          break;
        case '\n':
          sanitized += '\\n';
          break;
        case '\r':
          sanitized += '\\r';
          break;
        case '\t':
          sanitized += '\\t';
          break;
        default:
          if (char < ' ') {
            sanitized += '\\' + char.charCodeAt(0).toString(8);
          } else {
            sanitized += char;
          }
      }
    } else {
      sanitized += char;
    }
    if (singleQuotes && char === "'") {
      sanitized = sanitized.replace("''", "'");
    }
  }
  return sanitized;
}

function sqlEscape(str) {
