```javascript
function sql_escape(str) {
  let escape_chars = {
    '&': '&amp;',
    '<': '&lt;',
    '>': '&gt;',
    '"': '&quot;',
    "'": '&#x27;',
  };

  let result = '';
  for (let i = 0; i < str.length; i++) {
    let char = str[i];
    if (char in escape_chars) {
      result += escape_chars[char];
    } else if (char === '\\') {
      result += '\\';
    } else if (char === '\n') {
      result += '\\n';
    } else if (char === '\r') {
      result += '\\r';
    } else {
      result += char;
    }
  }

  return "'" + result + "'";
}

function sql_escape_string(s) {
  let result = '';
  for (let i = 0; i < s.length; i++) {
    let char = s[i];
    if (char.match(/[a-zA-Z0-9]/)) {
      result += char;
    } else {
      result += '%' + char.charCodeAt(0).toString(16).toUpperCase();
    }
  }
  return result;
}

function sql_escape_value(str) {
  str = str.toString();
  str = str.replace(/'/g, "''");
  str = sql_escape_string(str);
  return sql_escape(str);
}

console.log(sql_escape_value("Hello, World!"));
console.log(sql_escape_value("John's Car"));
console.log(sql_escape_value("123 Main St."));
console.log(sql_escape_value("' DROP TABLE users; --"));
