function sql_escape(s) {
    var escape_chars = {
        "\0": "\\0",
        "\n": "\\n",
        "\r": "\\r",
        "\t": "\\t",
        "\b": "\\b",
        "\f": "\\f",
        "\'": "\\'",
        "\\": "\\\\",
        "\"": "\\\"",
        "\x00": "\\x00"
    };

    var sanitized = "";
    for (var i = 0; i < s.length; i++) {
        var c = s.charAt(i);
        if (escape_chars[c]) {
            sanitized += escape_chars[c];
        } else if (c.charCodeAt(0) < 32 || c.charCodeAt(0) > 126) {
            sanitized += "\\" + c.charCodeAt(0).toString(16).padStart(2, "0");
        } else {
            sanitized += c;
        }
    }

    return sanitized;
}

function sql_escape(str) {
    var escapeChars = {
        "\0": "\\0",
        "\n": "\\n",
        "\r": "\\r",
        "\t": "\\t",
        "\b": "\\b",
        "\f": "\\f",
        "\x08": "\\b",
        "\x0B": "\\v",
        "\x1A": "\\Z",
        "\'": "\\'",
        "\\": "\\\\",
        "\x22": "\\\"",
        "\x5C": "\\\\",
        "\x2F": "\\/",
        "\x3A": "\\/",
        "\x3C": "<",
        "\x3E": ">",
        "\x5B": "\\[",
        "\x5D": "\\]"
    };
    var result = "";
    for (var i = 0; i < str.length; i++) {
        var charCode = str.charCodeAt(i);
        if (charCode > 127) {
            result += "\\x" + str.charCodeAt(i).toString(16).padStart(2, "0");
        } else if (escapeChars[str[i]]) {
            result += escapeChars[str[i]];
        } else {
            result += str[i];
        }
    }
    return result;
}

