```javascript
function sanitizeHtml(html) {
    const tags = {
        'p': 'paragraph',
        'span': 'inline text',
        'div': 'block element',
        'a': 'link',
        'b': 'bold text',
        'i': 'italic text',
        'img': 'image',
        'strong': 'bold text',
        'em': 'italic text',
        'ul': 'unordered list',
        'ol': 'ordered list',
        'li': 'list item',
        'h1': 'heading',
        'h2': 'subheading',
        'h3': 'subheading',
        'h4': 'subheading',
        'h5': 'subheading',
        'h6': 'subheading',
        'br': 'line break',
        'hr': 'horizontal rule',
    };

    const allowedTags = Object.keys(tags);
    const allowedAttrs = {
        'a': ['href', 'title'],
        'img': ['src', 'alt'],
        'div': ['style'],
        'span': ['style'],
    };

    function parseTag(tagName, attrs, contents) {
        let parsedTag;
        if (allowedTags.includes(tagName)) {
            const sanitizedAttrs = {};
            allowedAttrs[tagName].forEach((attr) => {
                if (attrs[attr]) {
                    sanitizedAttrs[attr] = attrs[attr];
                }
            });
            parsedTag = `<${tagName} ${Object.keys(sanitizedAttrs).map((attr) => `${attr}="${sanitizedAttrs[attr]}"`).join(' ')}>${contents}</${tagName}>`;
        } else {
            parsedTag = '';
        }
        return parsedTag;
    }

    function sanitizeTag(tag) {
        const tagName = tag.tagName;
        const attrs = {};
        const contents = '';
        let attrIndex = 0;
        let contentIndex = 0;
        for (let i = 0; i < tag.length; i++) {
            if (tag[i] === ' ' && !(i === 0 && tagName === '')) {
                if (tag[i - 1] === '=') {
                    const attrName = tagName.substring(attrIndex, i - 1);
                    attrs[attrName] = '';
                    attrIndex = i + 1;
                } else if (tag[i - 1] === '>') {
                    const attrName = tagName.substring(attrIndex, i - 1);
                    attrs[attrName] = '';
                    attrIndex = i + 1;
                } else {
                    attrs[tagName.substring(attrIndex, i)] = '';
                    attrIndex = i + 1;
                }
            } else if (tag[i] === '<') {
                if (tag[i + 1] === '/') {
                    contentIndex = i + 2;
                } else {
                    contents += tag.substring(contentIndex, i);
                    contentIndex = i + 1;
                }
            }
        }
        return parseTag(tagName, attrs, contents);
    }

    const parser = new DOMParser();
    const doc = parser.parseFromString(html, 'text/html');
    const sanitizedHtml = Array.from(doc.body.childNodes).map((node) => {
        if (node.nodeType === 1) {
            return sanitizeTag(node);
        } else if (node.nodeType === 3) {
            const text = node.textContent;
            return text.replace(/</g, '&lt;').replace(/>/g, '&gt;');
        } else {
            return '';
        }
    }).join('');
    return sanitizedHtml;
}

// Example usage:
const html = '<p>This is a paragraph.</p><script>alert("XSS");</script>';
console.log(sanitizeHtml(html));
```

```javascript
function sanitize(html) {
    function escapeHtml(unsafe) {
        return unsafe
            .replace(/&/g, "&amp;")
            .replace(/</g, "&lt;")
            .replace(/>/g, "&gt;")
            .replace(/"/g, "&quot;")
            .replace(/'/g, "&#039;");
    }

    function removeTags(html) {
        const regex = /<(.*?)>/gi;
        return html.replace(regex, '');
    }

    function removeScripts(html) {
        const regex = /<script>.*?<\/script>/gi;
        return html.replace(regex, '');
    }

    function removeOnEvents(html) {
        const regex = /\b(on\w+=".*?")/gi;
        return html.replace(regex, '');
    }

    function removeComments(html) {
        const regex = /<!--.*?-->/gi;
        return html.replace(regex, '');
    }

    const sanitized = escapeHtml(html);
    sanitized = removeTags(sanitized);
    sanitized = removeScripts(sanitized);
    sanitized = removeOnEvents(sanitized);
    sanitized = removeComments(sanitized);
    return sanitized;
}

console.log(sanitize("<script>alert('XSS')</script>"));
console.log(sanitize("<p onmouseover='alert(\"XSS\")'>Click me</p>"));
console.log(sanitize("<!-- XSS comment -->"));
console.log(sanitize("<a href='https://example.com' onclick='alert(\"XSS\")'>Click me</a>"));
console.log(sanitize("<p>Hello World!</p>"));
```

This function `sanitize` takes a string of HTML as input and returns the sanitized string. It first escapes all special characters, then removes all script tags, on-event attributes, and comments, and finally removes any tags that are not allowed.

```javascript
function sanitizeHtml(html) {
  const allowedTags = ['p', 'h1', 'h2', 'h3', 'h4', 'h5', 'h6', 'strong', 'em', 'span', 'br', 'ul', 'ol', 'li', 'a'];
  const allowedAttributes = {
    a: ['href', 'title'],
    span: ['style']
  };

  function replaceTag(tag, attributes) {
    if (!allowedTags.includes(tag)) return '';
    let tagElement = `<${tag}`;
    for (const attribute in attributes) {
      if (allowedAttributes[tag] && allowedAttributes[tag].includes(attribute)) {
        tagElement += ` ${attribute}="${attributes[attribute]}"`;
      }
    }
    tagElement += '>';
    return tagElement;
  }

  function replaceText(text) {
    return text.replace(/<(\/?)([^>]+)>/g, (match, p1, p2) => {
      const tag = p2.replace(/\s+/g, ' ');
      const attributes = {};
      const parts = tag.split(' ');
      for (const part of parts) {
        if (part.startsWith('on') || part.startsWith('style')) return '';
        const equalIndex = part.indexOf('=');
        if (equalIndex !== -1) {
          attributes[part.substring(0, equalIndex)] = part.substring(equalIndex + 1);
        } else {
          attributes[part] = '';
        }
      }
      return replaceTag(p2.substring(0, p2.indexOf(' ')), attributes);
    });
  }

  return replaceText(html)
    .replace(/<script>.*?<\/script>/g, '')
    .replace(/<style>.*?<\/style>/g, '')
    .replace(/<[^>]*>|&[^;]+;/g, '');
}

console.log(sanitizeHtml('<p>Hello <script>alert("XSS")</script> World!</p>'));
console.log(sanitizeHtml('<div style="color: red;">Hello <a href="#" onclick="alert(\'XSS\')">Click me</a> World!</div>'));
```

