```javascript
function sanitizeShellCommand(command) {
    const specialChars = [';', '&', '|', '$', '(', ')', '<', '>', '#', '`'];
    const escapeSequences = ['\\n', '\\t', '\\r', '\\b', '\\f', '\\a'];

    for (const char of specialChars) {
        command = command.replace(new RegExp(char, 'g'), `\\${char}`);
    }

    for (const seq of escapeSequences) {
        command = command.replace(new RegExp(seq, 'g'), `\\${seq}`);
    }

    return command;
}

function escapeRegExp(str) {
    return str.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function replaceQuotes(str) {
    str = str.replace(/"/g, '\\"');
    str = str.replace(/'/g, "\\'");
    return str;
}

function sanitizeInput(input) {
    for (const char of input) {
        if (char.charCodeAt(0) < 32 || char.charCodeAt(0) >= 127) {
            return false;
        }
    }
    return true;
}

function sanitizeShellCommandFull(command) {
    if (!sanitizeInput(command)) {
        throw new Error("Invalid input");
    }

    command = replaceQuotes(command);
    command = escapeRegExp(command);
    command = sanitizeShellCommand(command);

    return command;
}

console.log(sanitizeShellCommandFull("echo;ls"));
console.log(sanitizeShellCommandFull("echo 'Hello, World!'"));
console.log(sanitizeShellCommandFull("echo \"Hello, World!\""));
console.log(sanitizeShellCommandFull("echo $(ls)"));
console.log(sanitizeShellCommandFull("echo $(ls -l)"));
