  return s
    .replace(/\\/g, '\\\\')
    .replace(/\n/g, '\\n')
    .replace(/\t/g, '\\t')
    .replace(/\r/g, '\\r')
    .replace(/\s+/g, ' ')
    .replace(/'/g, "'\\''")
    .replace(/"/g, '\\"')
    .replace(/`/g, '\\`')
    .replace(/</g, '\\<')
    .replace(/>/g, '\\>');
}

function runCommand(command) {
  const shell = require('child_process').exec;
  const escapedCommand = escapeShell(command);
  shell(escapedCommand, (error, stdout, stderr) => {
    if (error) {
      console.error(`Error running command: ${error}`);
    } else {
      console.log(stdout);
