```javascript
function escapeShellArg(arg) {
    return arg.replace(/'/g, "'\\''");
}

function escapeShellCmd(cmd) {
    cmd = cmd.replace('\\', '\\\\');
    cmd = cmd.replace('$', '\\$');
    cmd = cmd.replace('"', '\\"');
    cmd = cmd.replace('\'', '\\\'');
    return cmd;
}

function escapeShell() {
    const args = [];
    const cmd = [];
    let currentArg = '';

    for (const token of this.tokens) {
        if (token.startsWith('"') && currentArg) {
            args.push(escapeShellArg(currentArg));
            currentArg = '';
        }

        if (token.startsWith('"')) {
            currentArg += token;
            continue;
        }

        if (token === '&&' || token === '||' || token === ';' || token === '>>' || token === '<') {
            if (currentArg) {
                args.push(escapeShellArg(currentArg));
                currentArg = '';
            }
            cmd.push(escapeShellCmd(token));
            continue;
        }

        if (currentArg) {
            currentArg += ' ';
        }

        currentArg += token;
    }

    if (currentArg) {
        args.push(escapeShellArg(currentArg));
    }

    if (args.length > 1) {
        cmd.push(args.join(' '));
    } else {
        cmd.push(args[0]);
    }

    return cmd.join(' ');
}

class ShellCommand {
    constructor(tokens) {
        this.tokens = tokens;
    }
}

const shellCmd = new ShellCommand(["ls", "-l", "file.txt"]);

console.log(escapeShell.call(shellCmd));
