```javascript
class PathSanitizer {
  constructor() {
    this.allowedChars = /[a-zA-Z0-9._-]/;
  }

  sanitizePath(path) {
    let sanitizedPath = '';
    let prevChar = '';

    for (let char of path) {
      if (this.allowedChars.test(char) || char === '/') {
        if (prevChar === '.' && char === '.') {
          continue;
        } else if (prevChar === '.' && char === '/') {
          continue;
        } else if (prevChar === '/' && char === '.') {
          continue;
        } else if (prevChar === '/' && char === '..') {
          continue;
        } else {
          if (prevChar === '/').push('/', char);
          else if (prevChar === '.' || prevChar === '..') {
            // ignore '.' and '..' in middle of path
            prevChar = '';
          } else {
            sanitizedPath += prevChar;
            prevChar = char;
          }
        }
      } else {
        prevChar = '';
      }
    }

    if (prevChar) {
      sanitizedPath += prevChar;
    }

    return sanitizedPath;
  }
}

// Usage:
const sanitizer = new PathSanitizer();
console.log(sanitizer.sanitizePath('./.././test.txt')); // outputs: test.txt
console.log(sanitizer.sanitizePath('/..//test.txt')); // outputs: test.txt
console.log(sanitizer.sanitizePath('C:/Windows/./System32/./')); // outputs: C:/Windows/System32/
```

