function sanitizePath(path) {
  const parts = path.split('/');
  const sanitizedPath = [];

  for (let i = 0; i < parts.length; i++) {
    const part = parts[i];

    if (!part || part === '..') {
      sanitizedPath.pop();
    } else if (part !== '.' && !part.includes('..')) {
      sanitizedPath.push(part);
    }
  }

  return '/' + sanitizedPath.join('/');
}

function sanitizePathWithRegex(path) {
  return path.replace(/^\/?[^/]+\/\.\.\//g, '');
}

console.log(sanitizePath('/home/user/.././public'));
console.log(sanitizePathWithRegex('/home/user/.././public'));
```

