  constructor() {
    this.allowedRoots = ['/', 'C:\\', 'D:\\', '\\\\?\\'];
    this.allowedSeparators = ['\\', '/'];
    this.allowedChars = ['.', '_', '-', ' ', '\\', '/', ':', '+', '=', '%', '@', '#', '$', '?', '[', ']', '{', '}', '~', '^', '`', '!', '*', '(', ')', '|', ';', ',', '<', '>', '[', ']'];
  }

  sanitize(path) {
    path = path.replace(/\\/g, '/');
    let root = '';
    let tail = path;

    if (this.allowedRoots.includes(path.split('/')[0])) {
      root = path.split('/')[0];
      tail = path.split('/')[1];
    } else {
      if (this.allowedRoots.includes(path.split('/')[0].split(':')[0])) {
        root = path.split('/')[0].split(':')[0];
        tail = path.split('/')[0].split(':')[1];
      }
    }

    let sanitizedPath = root;

    tail = tail.replace(/[^a-zA-Z0-9\-\_\.\s\/\:]/g, '');

    for (let i = 0; i < tail.length; i++) {
      if (this.allowedChars.includes(tail[i])) {
        sanitizedPath += tail[i];
      } else {
        sanitizedPath += '/';
      }
    }

    sanitizedPath = sanitizedPath.replace(/\/\//g, '/');
    sanitizedPath = sanitizedPath.replace(/\/\//g, '/');

    if (sanitizedPath === '') {
      return '/';
    }

    if (sanitizedPath.endsWith('/')) {
      return sanitizedPath.slice(0, -1);
    }

    return sanitizedPath;
  }
}

const sanitizer = new PathSanitizer();
console.log(sanitizer.sanitize('/path/to/sanitized')); // sanitized
console.log(sanitizer.sanitize('C:\\path\\to\\sanitized')); // sanitized
console.log(sanitizer.sanitize('C:/path/to/sanitized')); // sanitized
console.log(sanitizer.sanitize('//path/to/sanitized')); // sanitized
