const path = require('path');

function isSafePath(filePath) {
  try {
    path.normalize(filePath);
    if (process.platform === 'win32') {
      // On Windows, we need to check for reserved names (e.g., CON, PRN, etc.)
      const reservedNames = ['CON', 'PRN', 'AUX', 'NUL', 'COM1', 'COM2', 'COM3', 'COM4', 'COM5', 'COM6', 'COM7', 'COM8', 'COM9', 'LPT1', 'LPT2', 'LPT3', 'LPT4', 'LPT5', 'LPT6', 'LPT7', 'LPT8', 'LPT9'];
      const filename = path.basename(filePath);
      if (reservedNames.includes(filename.toUpperCase())) {
        return false;
      }
    }
    return true;
  } catch (err) {
    // If path.normalize() throws an error, it means the path is invalid
    return false;
  }
}

// Test cases
console.log(isSafePath('/path/to/safe/file.txt')); // true
console.log(isSafePath('/path/to/reserved/con.txt')); // false (on Windows)
console.log(isSafePath('/path/to/invalid/../file.txt')); // false
```

