const path = require('path');
const fs = require('fs');

function securePath(filePath) {
    const allowedExtensions = ['.jpg', '.jpeg', '.png', '.gif', '.bmp', '.pdf'];
    const allowedDirectories = ['images', 'documents'];

    const directory = path.dirname(filePath);
    const filename = path.basename(filePath);

    if (!allowedDirectories.includes(path.dirname(filePath))) {
        throw new Error('Invalid directory');
    }

    const extension = path.extname(filename);
    if (!allowedExtensions.includes(extension)) {
        throw new Error('Invalid file type');
    }

    return path.resolve(directory, filename);
}

function openFile(filePath) {
    try {
        return fs.readFileSync(filePath, 'utf8');
    } catch (err) {
        if (err.code === 'ENOENT') {
            throw new Error(`File not found: ${filePath}`);
        }
        throw err;
    }
}

// Example usage:
const filePath = securePath('/home/user/images/image.jpg');
try {
    const contents = openFile(filePath);
    console.log(contents);
} catch (err) {
    console.error(err.message);
}
