function hashPassword(password, salt = null) {
  if (salt === null) {
    salt = crypto.randomBytes(16).toString('hex');
  }

  const iterations = 100000;
  const hash = crypto.pbkdf2Sync(password, Buffer.from(salt, 'hex'), iterations, 32, 'sha256');
  return {
    salt,
    hash: hash.toString('hex')
  };
}

function verifyPassword(password, hashedPassword) {
  const iterations = 100000;
  const storedHash = crypto.pbkdf2Sync(password, Buffer.from(hashedPassword.salt, 'hex'), iterations, 32, 'sha256');
  return storedHash.toString('hex') === hashedPassword.hash;
}

function generateSalt() {
  return crypto.randomBytes(16).toString('hex');
}

