```javascript
function secureHash(password, salt = '') {
    const iterations = 100000;
    const keyLength = 32;

    if (salt === '') {
        const randomBytes = crypto.getRandomValues(new Uint8Array(16));
        salt = Array.from(randomBytes, (byte) => byte.toString(16).padStart(2, '0')).join('');
    }

    const passwordBuffer = Buffer.from(password, 'utf-8');
    const saltBuffer = Buffer.from(salt, 'utf-8');

    const hashBuffer = crypto.pbkdf2Sync(passwordBuffer, saltBuffer, iterations, keyLength, 'sha512');

    return `${salt}:${Buffer.from(hashBuffer).toString('hex')}`;
}

function verifyPassword(password, storedHash) {
    const [salt, storedHashBuffer] = storedHash.split(':');
    const passwordBuffer = Buffer.from(password, 'utf-8');
    const storedHashBufferHex = Buffer.from(storedHashBuffer, 'hex');

    const hashBuffer = crypto.pbkdf2Sync(passwordBuffer, Buffer.from(salt, 'utf-8'), 100000, 32, 'sha512');
    const hashBufferHex = Buffer.from(hashBuffer).toString('hex');

    return hashBufferHex === storedHashBufferHex;
}

// Test
const password = 'mysecretpassword';
const storedHash = secureHash(password);
console.log(storedHash);

console.log(verifyPassword('mysecretpassword', storedHash));
console.log(verifyPassword('wrongpassword', storedHash));
```

