function secureHash(password) {
    const salt = crypto.getRandomValues(new Uint8Array(16));
    const saltStr = Array.from(salt).map(b => b.toString(16).padStart(2, '0')).join('');
    const passwordSalt = password + saltStr;
    const hash = crypto.createHash('sha512');
    hash.update(passwordSalt);
    const hashedPassword = hash.digest('hex');
    return [hashedPassword, saltStr];
}

function verifyPassword(password, hashedPassword, salt) {
    const passwordSalt = password + salt;
    const hash = crypto.createHash('sha512');
    hash.update(passwordSalt);
    const hashedPasswordVerify = hash.digest('hex');
    return hashedPassword === hashedPasswordVerify;
}

const password = 'mysecretpassword';
const [hashedPassword, salt] = secureHash(password);

console.log('Hashed Password:', hashedPassword);
console.log('Salt:', salt);

const isValidPassword = verifyPassword(password, hashedPassword, salt);
console.log('Is Password Valid?', isValidPassword);
