```javascript
function sanitizeInput(input) {
    if (typeof input !== 'string') {
        return '';
    }

    input = input.trim();

    let sanitizedInput = '';
    for (let i = 0; i < input.length; i++) {
        const charCode = input.charCodeAt(i);
        if ((charCode >= 48 && charCode <= 57) || // 0-9
            (charCode >= 65 && charCode <= 90) || // A-Z
            (charCode >= 97 && charCode <= 122) || // a-z
            (charCode === 32) || // Space
            (charCode === 33) || // !
            (charCode === 44) || // ,
            (charCode === 46) || // .
            (charCode === 63) || // ?
            (charCode === 95)) { // _
            sanitizedInput += input[i];
        }
    }

    return sanitizedInput;
}

function sanitizeHtml(html) {
    let sanitizedHtml = html.replace(/<[^>]*>/g, ''); // Remove HTML tags
    sanitizedHtml = sanitizedHtml.replace(/&[a-zA-Z]+;[a-zA-Z0-9]+;/g, ''); // Remove HTML entities
    sanitizedHtml = sanitizedHtml.replace(/\n/g, ''); // Remove newline characters
    sanitizedHtml = sanitizedHtml.replace(/\r/g, ''); // Remove carriage return characters
    sanitizedHtml = sanitizedHtml.replace(/\t/g, ''); // Remove tabs
    sanitizedHtml = sanitizedHtml.replace(/\x00/g, ''); // Remove null characters
    sanitizedHtml = sanitizedHtml.replace(/\x1a/g, ''); // Remove substitute characters

    return sanitizedHtml;
}

function sanitizeJson(json) {
    if (typeof json !== 'string') {
        return '';
    }

    json = json.trim();

    let sanitizedJson = '';
    let inString = false;
    let inEscape = false;
    let escapeChar = '';

    for (let i = 0; i < json.length; i++) {
        const charCode = json.charCodeAt(i);
        if (inEscape) {
            if (charCode === 92) { // \
                sanitizedJson += escapeChar;
                escapeChar = '';
                inEscape = false;
            } else if (charCode === 10 || charCode === 13 || charCode === 34 || charCode === 47 || charCode === 92 || charCode === 116 || charCode === 117 || charCode === 120) {
                sanitizedJson += escapeChar;
                escapeChar = json[i];
                inEscape = true;
            } else {
                sanitizedJson += escapeChar;
                sanitizedJson += String.fromCharCode(charCode);
                inEscape = false;
            }
        } else {
            if (charCode === 34) { // "
                inString = !inString;
            } else if (charCode === 92) { // \
                inEscape = true;
                escapeChar = json[i];
            } else if (!inString && (charCode === 45 || charCode === 46 || charCode === 48 || charCode === 49 || charCode === 50 || charCode === 51 || charCode === 52 || charCode === 53 || charCode === 54 || charCode === 55 || charCode === 56 || charCode === 57 || charCode === 58 || charCode === 59 || charCode === 60 || charCode === 61 || charCode === 62 || charCode === 63 || charCode === 64 || charCode === 91 || charCode === 93 || charCode === 123 || charCode === 125)) {
                sanitizedJson += json[i];
            }
        }
    }

    if (inEscape) {
        sanitizedJson = '';
    }

    return sanitizedJson;
}

function sanitizeInputUniversal(input) {
    return sanitizeInput(input) + sanitizeHtml(input) + sanitizeJson(input);
}

console.log(sanitizeInputUniversal("Hello, World!"));
console.log(sanitizeInputUniversal("<script>alert('XSS')</script>"));
console.log(sanitizeInputUniversal("{'name': 'John Doe', 'age': 30}"));
