function stripTags(text) {
    return text.replace(/<\/?[\w\s]+>/g, '');
}

function removeNewLines(text) {
    return text.replace(/[\r\n]/g, '');
}

function removeLeadingTrailingSpaces(text) {
    return text.replace(/^\s+|\s+$/gm, '');
}

function cleanUserSubmission(submission) {
    submission = cleanData(submission);
    submission = stripTags(submission);
    submission = removeNewLines(submission);
    submission = removeLeadingTrailingSpaces(submission);
    return submission;
}

