function encrypt_data(data, key) {
    const encryptedData = [];
    for (let i = 0; i < data.length; i++) {
        const charCode = data.charCodeAt(i);
        const encryptedCharCode = charCode ^ key;
        encryptedData.push(String.fromCharCode(encryptedCharCode));
    }
    return encryptedData.join('');
}

function decrypt_data(encryptedData, key) {
    const decryptedData = [];
    for (let i = 0; i < encryptedData.length; i++) {
        const charCode = encryptedData.charCodeAt(i);
        const decryptedCharCode = charCode ^ key;
        decryptedData.push(String.fromCharCode(decryptedCharCode));
    }
    return decryptedData.join('');
}

function generate_random_key(length) {
    const possibleCharacters = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
    let result = '';
    for (let i = 0; i < length; i++) {
        result += possibleCharacters.charAt(Math.floor(Math.random() * possibleCharacters.length));
    }
    return result;
}

