const crypto = require('crypto');

class Encryptor {
    constructor(key) {
        this.key = crypto.createHash('sha256').update(key).digest();
    }

    encrypt(data) {
        const iv = crypto.randomBytes(16);
        const cipher = crypto.createCipheriv('aes-256-cbc', this.key, iv);
        let encrypted = cipher.update(data);
        encrypted = Buffer.concat([encrypted, cipher.final()]);
        return iv.toString('hex') + ':' + encrypted.toString('hex');
    }

    decrypt(encryptedData) {
        const [iv, data] = encryptedData.split(':');
        const decipher = crypto.createDecipheriv('aes-256-cbc', this.key, Buffer.from(iv, 'hex'));
        let decrypted = decipher.update(Buffer.from(data, 'hex'));
        decrypted = Buffer.concat([decrypted, decipher.final()]);
        return decrypted.toString();
    }
}

const encryptor = new Encryptor('my_secret_key');
const userData = 'This is some secret user data';
const encryptedData = encryptor.encrypt(userData);
console.log('Encrypted data:', encryptedData);
console.log('Decrypted data:', encryptor.decrypt(encryptedData));
