```javascript
function sanitizeSql(data) {
    return data.map(value => typeof value === 'string' ? `'${value}'` : value);
}

function escapeHtml(unsafe) {
    return unsafe
        .replace(/&/g, "&amp;")
        .replace(/</g, "&lt;")
        .replace(/>/g, "&gt;")
        .replace(/"/g, "&quot;")
        .replace(/'/g, "&#039;");
}

function validateInput(data, requiredFields) {
    const errors = {};
    for (const field in requiredFields) {
        if (!data[field]) {
            errors[field] = `${field} is required`;
        }
    }
    return errors;
}

function processFormData(formData) {
    const requiredFields = ['name', 'email', 'password'];
    const sanitizedData = {};
    const errors = validateInput(formData, requiredFields);

    if (Object.keys(errors).length > 0) {
        return { errors, sanitizedData };
    }

    Object.keys(formData).forEach(field => {
        if (['name', 'email', 'password'].indexOf(field) !== -1) {
            sanitizedData[field] = escapeHtml(formData[field]);
        } else {
            sanitizedData[field] = sanitizeSql(formData[field]);
        }
    });

    return { errors: {}, sanitizedData };
}

// Example usage
const formData = {
    name: 'John Doe',
    email: 'john@example.com',
    password: 'password123',
    age: 30,
    country: 'USA'
};

const result = processFormData(formData);
