const express = require('express');
const jwt = require('jsonwebtoken');
const sanitizeHtml = require('sanitize-html');

const app = express();
const port = 3000;

app.use(express.json());

const sanitizeRequest = (req) => {
    const sanitizedBody = {};
    Object.keys(req.body).forEach(key => {
        sanitizedBody[key] = sanitizeHtml(req.body[key], {
            allowedTags: [],
            allowedAttributes: {},
        });
    });
    return sanitizedBody;
};

const validateToken = (req, res, next) => {
    const token = req.header('Authorization').replace('Bearer ', '');
    try {
        const decoded = jwt.verify(token, 'your_secret_key');
        req.user = decoded;
        next();
    } catch (error) {
        res.status(401).send({ error: 'Invalid token' });
    }
};

const checkRequired = (req, res, next) => {
    if (Object.keys(req.body).length === 0) {
        res.status(400).send({ error: 'No data provided' });
    } else {
        next();
    }
};

const secureEndpoint = async (req, res) => {
    try {
        const sanitizedReq = sanitizeRequest(req);
        const validatedToken = await validateToken(req, res);
        checkRequired(req, res, () => {
            res.send({ message: 'Endpoint called successfully' });
        });
    } catch (error) {
        res.status(500).send({ error: 'Server error' });
    }
};

app.post('/secure', secureEndpoint);

app.listen(port, () => {
    console.log(`Server started on port ${port}`);
});
```

You need to replace `'your_secret_key'` with your actual secret key for token verification. 

Please note that error handling is basic and you may want to add more specific error handling based on your needs. 

