```java
public class SQLSanitizer {
    public static String sanitizeSQL(String sql) {
        if (sql == null) {
            return "";
        }

        StringBuilder sanitized = new StringBuilder();

        for (char c : sql.toCharArray()) {
            switch (c) {
                case '\'':
                    sanitized.append("''");
                    break;
                case '\\':
                    sanitized.append("\\\\");
                    break;
                case ';':
                    sanitized.append("\\;"); // Prevent SQL injection
                    break;
                case '--':
                case '#':
                    sanitized.append("/*").append((char) 0); // Prevent comments
                    break;
                case '\\0':
                    sanitized.append("\\0");
                    break;
                case '\\':
                    sanitized.append("\\\\");
                    break;
                default:
                    sanitized.append(c);
            }
        }

        return sanitized.toString();
    }

    public static String sanitizeSQLString(String sqlString) {
        sqlString = sqlString.replace("'", "''");
        sqlString = sqlString.replace("\\", "\\\\");
        sqlString = sqlString.replace(";","");
        sqlString = sqlString.replace("--", "/*").replace("#", "/*");
        return sqlString;
    }
}
