```java
public class SQLSanitizer {

    public static String sanitizeSQL(String input) {
        StringBuilder sanitized = new StringBuilder();

        for (char c : input.toCharArray()) {
            switch (c) {
                case '\\':
                case '\n':
                case '\r':
                case '\t':
                case ';':
                case '\'':
                case '"':
                case '`':
                case '=':
                case '|':
                case '&':
                case '<':
                case '>':
                    sanitized.append('\\').append(c);
                    break;
                case '\'':
                    sanitized.append('\'').append('\'');
                    break;
                case '"':
                    sanitized.append('"').append('"');
                    break;
                case '`':
                    sanitized.append('`').append('`');
                    break;
                case '=':
                    sanitized.append('==');
                    break;
                case '|':
                    sanitized.append('||');
                    break;
                case '&':
                    sanitized.append('&&');
                    break;
                case '<':
                    sanitized.append('<<');
                    break;
                case '>':
                    sanitized.append('>>');
                    break;
                default:
                    sanitized.append(c);
            }
        }

        return sanitized.toString();
    }

    public static String sanitizeIdentifier(String input) {
        StringBuilder sanitized = new StringBuilder();

        for (char c : input.toCharArray()) {
            if (Character.isLetterOrDigit(c) || c == '_' || c == '$') {
                sanitized.append(c);
            } else {
                sanitized.append('_');
            }
        }

        return sanitized.toString().toUpperCase();
    }

    public static void main(String[] args) {
        System.out.println(sanitizeSQL("SELECT * FROM users WHERE name = 'John Doe';"));
        System.out.println(sanitizeIdentifier("select * from users where name = 'john doe';"));
    }
}
