```java
public class Main {
    public static String sqlEscape(String input) {
        StringBuilder sanitized = new StringBuilder();
        char lastChar = '\0';

        for (char c : input.toCharArray()) {
            switch (c) {
                case '\\':
                    sanitized.append("\\\\");
                    break;
                case '\'':
                    if (lastChar != '\\') {
                        sanitized.append("\\'");
                    } else {
                        sanitized.append("\\\\'");
                    }
                    break;
                case '"':
                    if (lastChar != '\\') {
                        sanitized.append("\\\"");
                    } else {
                        sanitized.append("\\\\\"");
                    }
                    break;
                case '\n':
                    sanitized.append("\\n");
                    break;
                case '\r':
                    sanitized.append("\\r");
                    break;
                case '\t':
                    sanitized.append("\\t");
                    break;
                default:
                    if (c < 32 || c > 126) {
                        sanitized.append("\\x").append(String.format("%02x", c));
                    } else {
                        sanitized.append(c);
                    }
                    break;
            }
            lastChar = c;
        }

        return sanitized.toString();
    }

    public static void main(String[] args) {
        System.out.println(sqlEscape("Hello, World!"));
        System.out.println(sqlEscape("Hello 'World'!"));
        System.out.println(sqlEscape("Hello \"World\"!"));
        System.out.println(sqlEscape("Hello\nWorld!"));
        System.out.println(sqlEscape("Hello\rWorld!"));
        System.out.println(sqlEscape("Hello\tWorld!"));
        System.out.println(sqlEscape("Hello\x01World!"));
    }
}
