public class DatabaseUtil {

    public static void main(String[] args) {
        String dbName = "mydatabase";
        String tableName = "mytable";
        String fieldName = "myfield";
        String userInput = "<script>alert('XSS')</script>";

        try (Connection conn = DriverManager.getConnection("jdbc:sqlite:" + dbName);
             PreparedStatement pstmt = conn.prepareStatement("SELECT * FROM " + tableName + " WHERE " + fieldName + " = ?")) {

            pstmt.setString(1, sqlEscape(userInput));
            pstmt.execute();
            pstmt.close();
        } catch (SQLException e) {
            System.out.println("Error: " + e.getMessage());
        }
    }

    public static String sqlEscape(String input) {
        StringBuilder sb = new StringBuilder();
        for (char c : input.toCharArray()) {
            switch (c) {
                case '\\':
                case '\'':
                case '"':
                case '\t':
                    sb.append("\\").append(c);
                    break;
                case '\n':
                    sb.append("\\n");
                    break;
                case '\r':
                    sb.append("\\r");
                    break;
                case '\b':
                    sb.append("\\b");
                    break;
                case '\f':
                    sb.append("\\f");
                    break;
                default:
                    if (Character.isISOControl(c)) {
                        sb.append("\\u");
                        String hex = Integer.toHexString(c);
                        if (hex.length() == 1) {
                            sb.append("0");
                        }
                        sb.append(hex);
                    } else {
                        sb.append(c);
                    }
            }
        }
        return sb.toString();
    }
}
