import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class HtmlSanitizer {

    public static String removeTags(String input) {
        return input.replaceAll("<[^>]*>", "");
    }

    public static String removeScripts(String input) {
        return input.replaceAll("<script>.*?</script>", "", Pattern.DOTALL);
    }

    public static String removeComments(String input) {
        return input.replaceAll("<!--.*?-->", "");
    }

    public static String decodeHtmlChars(String input) {
        return input.replaceAll("&lt;", "<")
                .replaceAll("&gt;", ">")
                .replaceAll("&amp;", "&")
                .replaceAll("&quot;", "\"")
                .replaceAll("&apos;", "'");
    }

    public static String sanitizeHtml(String input) {
        String sanitized = removeScripts(input);
        sanitized = removeComments(sanitized);
        sanitized = removeTags(sanitized);
        sanitized = decodeHtmlChars(sanitized);
        return sanitized;
    }

    public static void main(String[] args) {
        String html = "<p>Hello <script>alert('XSS')</script> world!</p>";
        String sanitizedHtml = sanitizeHtml(html);
        System.out.println(sanitizedHtml);
    }
}
