import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class UrlSanitizer {

    private static final String ALLOWED_SCHEMES = "https?://";
    private static final String ALLOWED_PATHS = "/[a-zA-Z0-9._~:/?#[\\]@!$&'()*+,;=]*";
    private static final String ALLOWED_QUERY_PARAMETER = "/[a-zA-Z0-9._~:/?#[\\]@!$&'()*+,;=]*";

    public static String sanitizeUrl(String input) {
        input = input.replaceAll("^[a-zA-Z]+://", "");
        Pattern pattern = Pattern.compile("(" + ALLOWED_SCHEMES + ")" +
                "(" + ALLOWED_PATHS + "?" + ALLOWED_QUERY_PARAMETER + "?)",
                Pattern.CASE_INSENSITIVE);
        Matcher matcher = pattern.matcher(input);
        return matcher.replaceAll("$1$2");
    }

    public static void main(String[] args) {
        String url = "javascript:alert('XSS')";
        String sanitizedUrl = sanitizeUrl(url);
        System.out.println(sanitizedUrl);
    }
}
