    private static final Pattern ONMOUSEOUT_PATTERN = Pattern.compile("onmouseout=\".*?\"");
    private static final Pattern ONKEYDOWN_PATTERN = Pattern.compile("onkeydown=\".*?\"");
    private static final Pattern ONKEYUP_PATTERN = Pattern.compile("onkeyup=\".*?\"");

    public static String sanitizeHtml(String input) {
        String scriptless = SCRIPT_PATTERN.matcher(input).replaceAll("");
        String styleless = STYLE_PATTERN.matcher(scriptless).replaceAll("");
        String onclickless = ONCLICK_PATTERN.matcher(styleless).replaceAll("");
        String onmouseoverless = ONMOUSEOVER_PATTERN.matcher(onclickless).replaceAll("");
        String onmouseoutless = ONMOUSEOUT_PATTERN.matcher(onmouseoverless).replaceAll("");
        String onkeydownless = ONKEYDOWN_PATTERN.matcher(onmouseoutless).replaceAll("");
        String onkeyupless = ONKEYUP_PATTERN.matcher(onkeydownless).replaceAll("");
        String styleless2 = STYLE_PATTERN.matcher(onkeyupless).replaceAll("");
        return styleless2;
    }

    public static String sanitizeHtmlV2(String input) {
        input = input.replaceAll("<script>.*?</script>", "");
        input = input.replaceAll("<style>.*?</style>", "");
        input = input.replaceAll("onclick=\".*?\"", "");
        input = input.replaceAll("onmouseover=\".*?\"", "");
        input = input.replaceAll("onmouseout=\".*?\"", "");
        input = input.replaceAll("onkeydown=\".*?\"", "");
        input = input.replaceAll("onkeyup=\".*?\"", "");
        input = input.replaceAll("<.*?>", "");
        input = input.replaceAll("<", "&lt;");
        input = input.replaceAll(">", "&gt;");
        return input;
    }

    public static void main(String[] args) {
        System.out.println(sanitizeHtml("<script>alert('XSS')</script>"));
        System.out.println(sanitizeHtmlV2("<script>alert('XSS')</script>"));
    }
}
