            for (char c : input.toCharArray()) {
                if (c == '<') {
                    encoded += "&lt;";
                } else if (c == '>') {
                    encoded += "&gt;";
                } else if (c == '&') {
                    encoded += "&amp;";
                } else {
                    encoded += c;
                }
            }
            return encoded;
        }
        return "";
    }
}

