public class XSSPrevention {
    public static String preventXSS(String input) {
        if (input == null) {
            return "";
        }
        String escaped = input
                .replace("&", "&amp;")
                .replace("<", "&lt;")
                .replace(">", "&gt;")
                .replace("\"", "&quot;")
                .replace("'", "&#x27;");
        return escaped;
    }

    public static String preventXSS(String input, String htmlTag) {
        if (input == null) {
            return "";
        }
        String tag = "<" + htmlTag + ">";
        String escaped = input
                .replace(tag, "&lt;" + htmlTag + "&gt;")
                .replace("&", "&amp;")
                .replace("<", "&lt;")
                .replace(">", "&gt;")
                .replace("\"", "&quot;")
                .replace("'", "&#x27;");
        return escaped;
    }

    public static void main(String[] args) {
        String userInput = "<script>alert('XSS')</script>";
        System.out.println("Unescaped Input: " + userInput);
        System.out.println("Escaped Input: " + preventXSS(userInput));

        String userInput2 = "<img src=1 onerror='alert(\"XSS\")'>";
        System.out.println("Unescaped Input: " + userInput2);
        System.out.println("Escaped Input: " + preventXSS(userInput2, "img"));
    }
}

