import java.util.ArrayList;
import java.util.List;
import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class ShellCommandSanitizer {

    private static final Pattern PATTERN = Pattern.compile("[^a-zA-Z0-9_./\\-\\s]");

    public static String sanitize(String command) {
        return PATTERN.matcher(command).replaceAll("");
    }

    public static List<String> tokenize(String command) {
        List<String> tokens = new ArrayList<>();
        StringBuilder currentToken = new StringBuilder();
        for (char c : command.toCharArray()) {
            if (Character.isWhitespace(c)) {
                if (currentToken.length() > 0) {
                    tokens.add(currentToken.toString());
                    currentToken.setLength(0);
                }
            } else {
                currentToken.append(c);
            }
        }
        if (currentToken.length() > 0) {
            tokens.add(currentToken.toString());
        }
        return tokens;
    }

    public static List<String> sanitizeTokens(List<String> tokens) {
        List<String> sanitizedTokens = new ArrayList<>();
        for (String token : tokens) {
            sanitizedTokens.add(sanitize(token));
        }
        return sanitizedTokens;
    }

    public static String joinTokens(List<String> tokens) {
        StringBuilder sb = new StringBuilder();
        for (String token : tokens) {
            sb.append(token).append(" ");
        }
        return sb.toString().trim();
    }

    public static String sanitizeCommand(String command) {
        List<String> tokens = tokenize(command);
        tokens = sanitizeTokens(tokens);
        return joinTokens(tokens);
    }

    public static void main(String[] args) {
        String command = "ls -l /path/to/file*";
        System.out.println(sanitizeCommand(command));
    }
}
