public class ShellSafety {

    public static String escapeShell(String command) {
        String[] shellEscapeCharacters = {
            "\\",  // backslash
            "\n", // new line
            "\t", // tab
            "\r", // carriage return
            "\b", // backspace
            "\f", // form feed
            "\a", // bell
            '"',  // double quote
            "'",  // single quote
            '$',  // dollar sign
            '(',  // left parenthesis
            ')',  // right parenthesis
            ';',  // semicolon
            '&',  // ampersand
            '|',  // pipe
            '<',  // less than
            '>',  // greater than
            '?',  // question mark
            '*',  // asterisk
            '{',  // left curly brace
            '}',  // right curly brace
            '[',  // left square bracket
            ']'  // right square bracket
        };

        for (String character : shellEscapeCharacters) {
            command = command.replace(character, "\\" + character);
        }

        return command;
    }

    public static void main(String[] args) {
        String command = "echo Hello, World!";
        System.out.println(escapeShell(command));
    }
}
