```java
import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class Main {
    public static String escapeShell(String input) {
        Pattern pattern = Pattern.compile("[^a-zA-Z0-9\\s\\`~\\!\\@\\#\\$\\%\\^\\&\\*\\(\\)\\-\\+\\=\\{\\}\\[\\]\\|\\/\\\\\\<\\>\\,\\.\\?]");
        Matcher matcher = pattern.matcher(input);
        StringBuffer stringBuffer = new StringBuffer();
        while (matcher.find()) {
            String replacement = matcher.group();
            String escaped = escapeChar(replacement);
            matcher.appendReplacement(stringBuffer, escaped);
        }
        matcher.appendTail(stringBuffer);
        return stringBuffer.toString();
    }

    private static String escapeChar(String charStr) {
        switch (charStr) {
            case "\\":
                return "\\\\";
            case "\n":
                return "\\n";
            case "\t":
                return "\\t";
            case "\r":
                return "\\r";
            case "\f":
                return "\\f";
            case "\b":
                return "\\b";
            case "\u0000":
                return "\\0";
            case "\u0001":
                return "\\a";
            case "\u0002":
                return "\\b";
            case "\u0003":
                return "\\t";
            case "\u0004":
                return "\\e";
            case "\u0005":
                return "\\f";
            case "\u0006":
                return "\\u";
            case "\u0007":
                return "\\v";
            case "\u0085":
                return "\\N";
            case "\u2028":
                return "\\L";
            case "\u2029":
                return "\\P";
            default:
                return charStr;
        }
    }

    public static void main(String[] args) {
        System.out.println(escapeShell("Hello World!"));
        System.out.println(escapeShell("Hello \\n World!"));
        System.out.println(escapeShell("Hello \\t World!"));
    }
}
