```java
import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class ShellEscape {
    public static String escapeShell(String input) {
        StringBuilder escaped = new StringBuilder();

        for (char c : input.toCharArray()) {
            switch (c) {
                case '\\':
                    escaped.append("\\\\");
                    break;
                case '\'':
                    escaped.append("\\'");
                    break;
                case '"':
                    escaped.append("\\\"");
                    break;
                case '$':
                    escaped.append("\\$");
                    break;
                case '`':
                    escaped.append("\\`");
                    break;
                case ';':
                    escaped.append("\\;");
                    break;
                case '&':
                    escaped.append("\\&");
                    break;
                case '|':
                    escaped.append("\\|");
                    break;
                case '<':
                    escaped.append("\\<");
                    break;
                case '>':
                    escaped.append("\\>");
                    break;
                default:
                    escaped.append(c);
                    break;
            }
        }

        return escaped.toString();
    }

    public static String escapeShellRegex(String input) {
        Pattern pattern = Pattern.compile("[\\\\\"$`;&|<>]");
        Matcher matcher = pattern.matcher(input);
        return matcher.replaceAll("\\\\$0");
    }

    public static void main(String[] args) {
        System.out.println(escapeShell("Hello World!"));
        System.out.println(escapeShellRegex("Hello World!"));
    }
}
