        Executor executor = new DefaultExecutor();
        executor.setExitValue(1);
        executor.setRedirectErrorStream(true);
        executor.execute(newCommandLine(command));
    }

    public static void main(String[] args) throws IOException, ExecuteException {
        String command = "ls -l";
        executeCommand(command);
    }
}
