This will prevent command injection attacks because Apache Commons Exec will handle command creation and execution securely.

```java
import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class SafeExecutor {
    public static void safe_exec(String[] args) throws IOException {
        try {
            ProcessBuilder builder = new ProcessBuilder(args);
            builder.redirectErrorStream(true);
            Process process = builder.start();

            BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String line;
            while ((line = reader.readLine()) != null) {
                System.out.println(line);
            }

            int exitCode = process.waitFor();
            if (exitCode != 0) {
                System.out.println("Command returned non-zero exit code: " + exitCode);
            }
        } catch (Exception e) {
            System.out.println("An error occurred while executing the command: " + e.getMessage());
        }
    }

    public static void main(String[] args) {
        System.out.println("Enter a shell command: ");
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
        try {
            String command = reader.readLine();
            String[] commandArray = command.split("\\s+");
            if (commandArray.length > 0) {
                safe_exec(commandArray);
            } else {
                System.out.println("Invalid command");
            }
        } catch (IOException e) {
            System.out.println("Error reading input: " + e.getMessage());
        }
    }
}
