        String securePath = securePath(insecurePath);

        try {
            Path filePath = Paths.get(securePath);
            System.out.println("File exists: " + Files.exists(filePath));
            System.out.println("File name: " + filePath.getFileName());
            System.out.println("File parent: " + filePath.getParent());
        } catch (IOException e) {
            System.err.println("Error: " + e.getMessage());
        }
    }

    public static String securePath(String path) {
        if (path == null) {
            return null;
        }

        String[] components = path.split("/");
        StringBuilder securePath = new StringBuilder();

        for (String component : components) {
            if (!component.isEmpty() && !component.equals(".")) {
                if (component.equals("..")) {
                    if (securePath.length() > 0) {
                        securePath.deleteCharAt(securePath.length() - 1);
                    }
                } else {
                    securePath.append("/").append(component);
                }
            }
        }

        return securePath.toString();
    }
}
