    private static final long SALT_BYTE_SIZE = 16;
    private static final long HASH_BYTE_SIZE = 32;

    public static void main(String[] args) throws NoSuchAlgorithmException {
        String password = "mysecretpassword";
        String salt = generateSalt();
        byte[] hashedPassword = hashPassword(password, salt);

        System.out.println("Salt: " + bytesToHex(salt));
        System.out.println("Hashed Password: " + bytesToHex(hashedPassword));
    }

    public static String generateSalt() throws NoSuchAlgorithmException {
        MessageDigest digest = MessageDigest.getInstance("SHA-256");
        byte[] saltBytes = digest.digest(new byte[SALT_BYTE_SIZE]);
        return bytesToHex(saltBytes);
    }

    public static byte[] hashPassword(String password, String salt) throws NoSuchAlgorithmException {
        MessageDigest digest = MessageDigest.getInstance("SHA-256");
        digest.update(salt.getBytes(StandardCharsets.UTF_8));
        digest.update(password.getBytes(StandardCharsets.UTF_8));
        return digest.digest();
    }

    public static String bytesToHex(byte[] bytes) {
        ByteBuffer buffer = ByteBuffer.wrap(bytes);
        StringBuilder hexString = new StringBuilder();
        for (int i = 0; i < bytes.length; i++) {
            hexString.append(String.format("%02x", buffer.get()));
        }
        return hexString.toString();
    }
}
