import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.nio.charset.StandardCharsets;
import java.util.Base64;

public class Main {

    public static void main(String[] args) {
        // User credentials
        String username = "johnDoe";
        String password = "password123";

        // Hash user credentials
        String hashedPassword = hashPassword(password);

        // Verify user credentials
        String inputPassword = "password123";
        if (verifyPassword(inputPassword, hashedPassword)) {
            System.out.println("Login successful");
        } else {
            System.out.println("Invalid credentials");
        }
    }

    public static String hashPassword(String password) {
        try {
            // Generate a random salt
            byte[] salt = new byte[16];
            java.security.SecureRandom.getInstanceStrong().nextBytes(salt);

            // Create a new PBKDF2WithHmacSHA1 key spec with the salt
            SecretKeyFactory f = SecretKeyFactory.getInstance("PBKDF2WithHmacSHA1");
            KeySpec spec = new PBEKeySpec(password.toCharArray(), salt, 65536, 128);
            byte[] hash = f.generateSecret(spec).getEncoded();

            // Combine the salt and the hash
            byte[] result = new byte[salt.length + hash.length];
            System.arraycopy(salt, 0, result, 0, salt.length);
            System.arraycopy(hash, 0, result, salt.length, hash.length);

            // Encode the result as a string
            return Base64.getEncoder().encodeToString(result);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    public static boolean verifyPassword(String password, String hashedPassword) {
        try {
            // Base64 decode the hashed password
            byte[] decodedHash = Base64.getDecoder().decode(hashedPassword);

            // Extract the salt from the decoded hash
            byte[] salt = new byte[16];
            System.arraycopy(decodedHash, 0, salt, 0, 16);

            // Create a new PBKDF2WithHmacSHA1 key spec with the salt
            SecretKeyFactory f = SecretKeyFactory.getInstance("PBKDF2WithHmacSHA1");
            KeySpec spec = new PBEKeySpec(password.toCharArray(), salt, 65536, 128);
            byte[] hash = f.generateSecret(spec).getEncoded();

            // Combine the hash and the salt
            byte[] result = new byte[decodedHash.length];
            System.arraycopy(hash, 0, result, 0, hash.length);

            // Encode the result as a string
            String encodedResult = Base64.getEncoder().encodeToString(result);

            // Check if the encoded result matches the original hashed password
            return encodedResult.equals(hashedPassword);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }
}
