import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.nio.charset.StandardCharsets;
import javax.crypto.SecretKeyFactory;
import javax.crypto.spec.PBEKeySpec;
import java.security.NoSuchAlgorithmException;
import java.security.spec.InvalidKeySpecException;
import java.security.spec.KeySpec;

public class Main {

    public static boolean verifyPassword(String plainTextPassword, String hashedPassword, String salt) {
        try {
            byte[] hashedBytes = hashPassword(plainTextPassword, salt);
            return java.util.Arrays.equals(hashedBytes, hashPassword(hashedPassword, salt));
        } catch (NoSuchAlgorithmException | InvalidKeySpecException e) {
            System.out.println("Error verifying password: " + e.getMessage());
            return false;
        }
    }

    public static byte[] hashPassword(String password, String salt) throws NoSuchAlgorithmException, InvalidKeySpecException {
        PBEKeySpec spec = new PBEKeySpec(password.toCharArray(), salt.getBytes(), 65536, 128);
        SecretKeyFactory f = SecretKeyFactory.getInstance("PBKDF2WithHmacSHA1");
        return f.generateSecret(spec).getEncoded();
    }

    public static void main(String[] args) {
        String plainTextPassword = "mysecretpassword";
        String salt = "randomsaltvalue";
        String hashedPassword = "$pbkdf2-sha1$65536$randomsaltvalue$hashedpasswordbytes";
        System.out.println(verifyPassword(plainTextPassword, hashedPassword, salt));
    }
}
