import java.security.NoSuchAlgorithmException;
import java.security.spec.InvalidKeySpecException;
import java.security.spec.KeySpec;

import javax.crypto.SecretKeyFactory;
import javax.crypto.spec.PBEKeySpec;

public class Main {

    public static boolean verifyPassword(String input, String hashedPassword, String salt) {
        try {
            SecretKeyFactory factory = SecretKeyFactory.getInstance("PBKDF2WithHmacSHA1");
            KeySpec spec = new PBEKeySpec(input.toCharArray(), salt.getBytes(), 65536, 128);
            byte[] newHash = factory.generateSecret(spec).getEncoded();
            return java.util.Arrays.equals(newHash, java.util.Arrays.copyOfRange(hashedPassword.getBytes(), 0, 16));
        } catch (NoSuchAlgorithmException | InvalidKeySpecException e) {
            System.out.println("Error: " + e.getMessage());
            return false;
        }
    }

    public static void main(String[] args) {
