        String hashedPassword = "$2a$10$dj3oQ2x5jwq4hj3oQ2x5jw$q3oQ2x5jwq4hj3oQ2x5jw";
        String salt = "$2a$10$dj3oQ2x5jwq4hj3oQ2x5jw";

        if (verifyPassword(input, hashedPassword, salt)) {
            System.out.println("Login successful");
        } else {
            System.out.println("Login failed");
        }
    }
