    public boolean validateInput(Data formData) {
        if (formData.getName() == null || formData.getName().isEmpty()) {
            System.out.println("Name is required");
            return false;
        }

        if (formData.getEmail() == null || !formData.getEmail().contains("@")) {
            System.out.println("Invalid email address");
            return false;
        }

        if (formData.getPassword() == null || formData.getPassword().length() < 8) {
            System.out.println("Password must be at least 8 characters long");
            return false;
