public class Main {

    public static String encryptData(String data, int key) {
        StringBuilder encryptedData = new StringBuilder();
        for (int i = 0; i < data.length(); i++) {
            char c = data.charAt(i);
            if (Character.isLetterOrDigit(c)) {
                c = (char) (c + key);
                if (Character.isUpperCase(c)) {
                    encryptedData.append(c);
                } else {
                    encryptedData.append(Character.toLowerCase(c));
                }
            } else {
                encryptedData.append(c);
            }
        }
        return encryptedData.toString();
    }

    public static String decryptData(String data, int key) {
        StringBuilder decryptedData = new StringBuilder();
        for (int i = 0; i < data.length(); i++) {
            char c = data.charAt(i);
            if (Character.isLetterOrDigit(c)) {
                c = (char) (c - key);
                if (Character.isUpperCase(c)) {
                    decryptedData.append(c);
                } else {
                    decryptedData.append(Character.toUpperCase(c));
                }
            } else {
                decryptedData.append(c);
            }
        }
        return decryptedData.toString();
    }

    public static void main(String[] args) {
        String data = "Hello, World!";
        int key = 3;
        String encrypted = encryptData(data, key);
        String decrypted = decryptData(encrypted, key);
        System.out.println("Encrypted: " + encrypted);
        System.out.println("Decrypted: " + decrypted);
    }
}
