import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.nio.charset.StandardCharsets;
import java.util.Base64;

public class Main {

    public static void main(String[] args) throws NoSuchAlgorithmException {
        String data = "sensitive_data";
        System.out.println("Original Data: " + data);
        System.out.println("Encrypted Data: " + encryptData(data));
        System.out.println("Decrypted Data: " + decryptData(encryptData(data)));
    }

    public static String encryptData(String data) throws NoSuchAlgorithmException {
        MessageDigest md = MessageDigest.getInstance("SHA-256");
        byte[] hashBytes = md.digest(data.getBytes(StandardCharsets.UTF_8));
        return Base64.getEncoder().encodeToString(hashBytes);
    }

    public static String decryptData(String encryptedData) {
        try {
            byte[] decryptedBytes = Base64.getDecoder().decode(encryptedData);
            MessageDigest md = MessageDigest.getInstance("SHA-256");
            byte[] hashBytes = md.digest(decryptedBytes);
            return new String(hashBytes, StandardCharsets.UTF_8);
        } catch (NoSuchAlgorithmException e) {
            return null;
        }
    }
}
