import java.util.regex.Pattern;
import java.util.regex.Matcher;

public class FormProcessor {
    public static String escapeHtml(String input) {
        StringBuilder out = new StringBuilder();
        for (int i = 0; i < input.length(); i++) {
            char c = input.charAt(i);
            switch (c) {
                case '<':
                    out.append("&lt;");
                    break;
                case '>':
                    out.append("&gt;");
                    break;
                case '&':
                    out.append("&amp;");
                    break;
                case '"':
                    out.append("&quot;");
                    break;
                default:
                    out.append(c);
            }
        }
        return out.toString();
    }

    public static String sanitizeSql(String input) {
        String[] sqlKeywords = {
                "SELECT", "FROM", "WHERE", "AND", "OR", "NOT", "INSERT", "UPDATE", "DELETE",
                "DROP", "CREATE", "ALTER", "TRUNCATE"
        };

        for (String keyword : sqlKeywords) {
            input = input.replace(keyword, "'" + keyword + "'");
        }

        return input;
    }

    public static boolean validateInput(String input, String type) {
        switch (type) {
            case "email":
                String emailPattern = "^[A-Z0-9._%+-]+@[A-Z0-9.-]+\\.[A-Z]{2,6}$";
                return Pattern.matches(emailPattern, input);
            case "phone":
                String phonePattern = "^(\\+\\d{1,2}\\s?)?1-?\\.?\\s?\\(?\\d{3}\\)?[\\s.-]??\\d{3}[\\s.-]??\\d{4}$";
                return Pattern.matches(phonePattern, input);
            case "username":
                String usernamePattern = "^[a-zA-Z0-9]{3,16}$";
                return Pattern.matches(usernamePattern, input);
            default:
                return false;
        }
    }

    public static void processFormData(String name, String email, String phone, String username) {
        name = escapeHtml(name);
        email = escapeHtml(email);
        phone = escapeHtml(phone);
        username = escapeHtml(username);

        name = sanitizeSql(name);
        email = sanitizeSql(email);
        phone = sanitizeSql(phone);
        username = sanitizeSql(username);

        if (validateInput(email, "email") && validateInput(phone, "phone") && validateInput(username, "username")) {
            System.out.println("Form data is valid.");
        } else {
            System.out.println("Form data is invalid.");
        }
    }

    public static void main(String[] args) {
        processFormData("John Doe", "john.doe@example.com", "123-456-7890", "johndoe");
    }
}
