import org.apache.commons.text.StringEscapeUtils;

import java.util.regex.Pattern;
import java.util.regex.Matcher;

public class FormDataProcessor {
    public static String processFormData(String name, String email, String password) {
        // Validate input
        if (!validateInput(name) || !validateInput(email) || !validateInput(password)) {
            return null;
        }

        // Sanitize SQL
        name = sanitizeSql(name);
        email = sanitizeSql(email);
        password = sanitizeSql(password);

        // Escape HTML
        name = StringEscapeUtils.escapeHtml4(name);
        email = StringEscapeUtils.escapeHtml4(email);
        password = StringEscapeUtils.escapeHtml4(password);

        return "Name: " + name + ", Email: " + email + ", Password: " + password;
    }

    private static boolean validateInput(String input) {
        String pattern = "^[a-zA-Z0-9]+$";
        Pattern regex = Pattern.compile(pattern);
        Matcher matcher = regex.matcher(input);
        return matcher.matches();
    }

    private static String sanitizeSql(String input) {
        return input.replace("'", "''");
    }
}
