```java
import java.sql.*;
import java.util.regex.Pattern;

public class FormProcessor {
    public static String processFormData(String name, String email, String website) {
        String nameSanitized = sanitizeSql(name);
        String emailEscaped = escapeHtml(email);
        String websiteValidated = validateInput(website);

        return "Name: " + nameSanitized + "\nEmail: " + emailEscaped + "\nWebsite: " + websiteValidated;
    }

    private static String sanitizeSql(String input) {
        try {
            Connection conn = DriverManager.getConnection("jdbc:sqlite::memory:");
            PreparedStatement stmt = conn.prepareStatement("SELECT ? AS sanitized");
            stmt.setString(1, input);
            ResultSet rs = stmt.executeQuery();
            return rs.getString("sanitized");
        } catch (SQLException e) {
            return "Error sanitizing SQL input: " + e.getMessage();
        }
    }

    private static String escapeHtml(String input) {
        return input.replaceAll("&", "&amp;").replaceAll("<", "&lt;").replaceAll(">", "&gt;");
    }

    private static String validateInput(String input) {
        if (Pattern.matches("^(https?:\\/\\/)?([\\da-z\\.-]+)\\.([a-z\\.]{2,6})([\\/\\w\\.-]*)*\\/?$", input)) {
            return input;
        } else {
            return "Invalid website URL";
        }
    }

    public static void main(String[] args) {
        System.out.println(processFormData("John Doe", "john@example.com", "https://example.com"));
        System.out.println(processFormData("Jane Doe", "jane@example.com", "invalid url"));
    }
}
