import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RestController;
import org.springframework.web.filter.OncePerRequestFilter;

import io.jsonwebtoken.Claims;
import io.jsonwebtoken.ExpiredJwtException;
import io.jsonwebtoken.JwtException;
import io.jsonwebtoken.Jwts;

@RestController
public class MyController {

    @Autowired
    private MyService myService;

    @Autowired
    private UserDetailsService userDetailsService;

    @PostMapping("/api/endpoint")
    public ResponseEntity<Map<String, String>> myEndpoint(@RequestBody Map<String, String> data, HttpServletRequest request) {
        Map<String, String> response = new HashMap<>();
        try {
            String token = request.getHeader("Authorization");
            if (token != null && !token.isEmpty()) {
                token = token.replace("Bearer ", "");
                Claims claims = validateToken(token);
                if (claims != null) {
                    sanitizeRequest(data);
                    Map<String, String> result = myService.myMethod(data);
                    response.put("result", result);
                    response.put("message", "Successful request");
                    return ResponseEntity.status(HttpStatus.OK).body(response);
                } else {
                    response.put("error", "Invalid token");
                    return ResponseEntity.status(HttpStatus.UNAUTHORIZED).body(response);
                }
            } else {
                response.put("error", "Missing token");
                return ResponseEntity.status(HttpStatus.UNAUTHORIZED).body(response);
            }
        } catch (IllegalArgumentException e) {
            response.put("error", "Invalid request");
            return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(response);
        } catch (Exception e) {
            response.put("error", "Something went wrong");
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(response);
        }
    }

    private Claims validateToken(String token) {
        try {
            return Jwts.parser().setSigningKey("secret_key").parseClaimsJws(token).getBody();
        } catch (ExpiredJwtException e) {
            System.out.println("Token is expired");
            return null;
        } catch (JwtException e) {
            System.out.println("Token is invalid");
            return null;
        }
    }

    private void sanitizeRequest(Map<String, String> data) {
        // TO DO: implement sanitize_request() logic here
        // For example:
        for (Map.Entry<String, String> entry : data.entrySet()) {
            if (entry.getValue() != null) {
                data.put(entry.getKey(), entry.getValue().trim());
            }
        }
    }
}

class MyService {
    public Map<String, String> myMethod(Map<String, String> data) {
        // TO DO: implement myMethod logic here
        return data;
    }
}
