import javax.ws.rs.GET;
import javax.ws.rs.POST;
import javax.ws.rs.Path;
import javax.ws.rs.Produces;
import javax.ws.rs.core.MediaType;
import javax.ws.rs.core.Response;

import org.glassfish.jersey.server.ContainerRequest;
import org.glassfish.jersey.server.ContainerResponse;
import org.glassfish.jersey.server.FilterContext;
import org.glassfish.jersey.server.monitoring.RequestEvent;
import org.glassfish.jersey.server.monitoring.RequestEvent.Type;
import org.glassfish.jersey.server.monitoring.RequestLoggingFilter;
import org.glassfish.jersey.server.monitoring.RequestLoggingFilterListener;

import java.util.logging.Level;
import java.util.logging.Logger;

import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

import com.google.gson.Gson;
import com.google.gson.GsonBuilder;

@Path("/")
public class MyResource {

    private static final Logger LOGGER = Logger.getLogger(MyResource.class.getName());

    @GET
    @Path("/api/secured")
    @Produces(MediaType.APPLICATION_JSON)
    public Response securedGetEndpoint() {
        ContainerRequest containerRequest = ContainerRequest.getContainerRequest();
        HttpServletRequest servletRequest = containerRequest.getHttpServletRequest();

        if (!validateToken(servletRequest)) {
            return Response.status(Response.Status.UNAUTHORIZED).build();
        }

        return Response.ok().build();
    }

    @POST
    @Path("/api/secured")
    @Produces(MediaType.APPLICATION_JSON)
    public Response securedPostEndpoint(ContainerRequest containerRequest) {
        try {
            sanitizeRequest(containerRequest);
            Gson gson = new GsonBuilder().create();
            String requestBody = gson.toJson(containerRequest.getEntity());
            LOGGER.log(Level.INFO, "Received request body: {0}", requestBody);

            // Process the request
            return Response.ok().build();
        } catch (Exception ex) {
            return Response.status(Response.Status.BAD_REQUEST).entity("Invalid request").build();
        }
    }

    private void sanitizeRequest(ContainerRequest containerRequest) {
        HttpServletRequest servletRequest = containerRequest.getHttpServletRequest();
        // Sanitize the request here, e.g., remove special characters
        String requestBody = servletRequest.getReader().lines()
                .reduce((acc, line) -> acc + line, "", String::concat);
        servletRequest.getReader().close();

        Gson gson = new GsonBuilder().create();
        try {
            gson.fromJson(requestBody, Object.class);
        } catch (Exception ex) {
            throw new Exception("Invalid request");
        }
    }

    private boolean validateToken(HttpServletRequest servletRequest) {
        // Validate the token here, e.g., by checking the header
        String token = servletRequest.getHeader("Authorization");
        if (token == null || !token.startsWith("Bearer ")) {
            return false;
        }
        return true;
    }
}
