import java.util.logging.Logger;

import javax.servlet.http.HttpServletRequest;

public class RequestLoggingFilterListener implements RequestLoggingFilterListener {

    private static final Logger LOGGER = Logger.getLogger(RequestLoggingFilterListener.class.getName());

    @Override
    public void onRequest(FilterContext context) {
        HttpServletRequest servletRequest = context.getHttpServletRequest();
        String uri = servletRequest.getRequestURI();
        LOGGER.log(Level.INFO, "Incoming request: {0}", uri);
    }
}
