import java.util.Scanner;
import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class UserRegistration {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.println("User Registration");
        System.out.println("1. Register");
        System.out.println("2. Exit");
        System.out.print("Choose an option: ");
        int option = scanner.nextInt();
        scanner.nextLine(); // Consume newline left-over

        while (option != 2) {
            switch (option) {
                case 1:
                    registerUser(scanner);
                    break;
                default:
                    System.out.println("Invalid option. Please choose again.");
            }
            System.out.println("User Registration");
            System.out.println("1. Register");
            System.out.println("2. Exit");
            System.out.print("Choose an option: ");
            option = scanner.nextInt();
            scanner.nextLine(); // Consume newline left-over
        }
        scanner.close();
    }

    public static void registerUser(Scanner scanner) {
        System.out.print("Enter your name: ");
        String name = scanner.nextLine().trim();
        name = sanitizeInput(name);

        System.out.print("Enter your email: ");
        String email = scanner.nextLine().trim();
        email = validateEmail(email);

        System.out.print("Enter your password: ");
        String password = scanner.nextLine().trim().toLowerCase();
        password = securePassword(password);

        System.out.print("Confirm your password: ");
        String confirmPassword = scanner.nextLine().trim().toLowerCase();
        if (!password.equals(confirmPassword)) {
            System.out.println("Passwords do not match. Please try again.");
            registerUser(scanner);
            return;
        }

        System.out.println("Registration successful!");
        System.out.println("Name: " + name);
        System.out.println("Email: " + email);
    }

    public static String sanitizeInput(String input) {
        return input.replaceAll("[^a-zA-Z0-9\\s]", "");
    }

    public static String validateEmail(String email) {
        String emailRegex = "^[A-Z0-9._%+-]+@[A-Z0-9.-]+\\.[A-Z]{2,6}$";
        Pattern emailPattern = Pattern.compile(emailRegex, Pattern.CASE_INSENSITIVE);
        Matcher matcher = emailPattern.matcher(email);
        if (!matcher.find()) {
            System.out.println("Invalid email. Please try again.");
            return validateEmail(scanner.nextLine().trim());
        }
        return email;
    }

    public static String securePassword(String password) {
        if (password.length() < 8) {
            System.out.println("Password must be at least 8 characters long. Please try again.");
            return securePassword(scanner.nextLine().trim());
        }
        if (!password.matches(".*\\d+.*")) {
            System.out.println("Password must contain at least one digit. Please try again.");
            return securePassword(scanner.nextLine().trim());
        }
        if (!password.matches(".*[a-z]+.*") || !password.matches(".*[A-Z]+.*")) {
            System.out.println("Password must contain at least one lowercase and one uppercase letter. Please try again.");
            return securePassword(scanner.nextLine().trim());
        }
        return password;
    }
}
