import java.util.Scanner;
import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class UserRegistration {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.println("User Registration Form");
        while (true) {
            System.out.println("1. Register");
            System.out.println("2. Exit");
            System.out.print("Enter your choice: ");
            int choice = scanner.nextInt();
            scanner.nextLine(); // Consume newline left-over
            switch (choice) {
                case 1:
                    registerUser(scanner);
                    break;
                case 2:
                    System.out.println("Exiting...");
                    return;
                default:
                    System.out.println("Invalid choice. Please try again.");
            }
        }
    }

    public static boolean validateEmail(String email) {
        String emailRegex = "^[a-zA-Z0-9_+&*-]+(?:\\." +
                "[a-zA-Z0-9_+&*-]+)*@" +
                "(?:[a-zA-Z0-9-]+\\.)+[a-zA-Z]{2,7}$";
        Pattern pattern = Pattern.compile(emailRegex);
        if (email == null || email.isEmpty()) {
            return false;
        }
        Matcher matcher = pattern.matcher(email);
        return matcher.matches();
    }

    public static boolean validatePassword(String password) {
        String passwordRegex = "^(?=.*[0-9])(?=.*[a-z])(?=.*[A-Z])(?=.*[!@#$%^&*_=+-]).{8,}$";
        Pattern pattern = Pattern.compile(passwordRegex);
        if (password == null || password.isEmpty()) {
            return false;
        }
        Matcher matcher = pattern.matcher(password);
        return matcher.matches();
    }

    public static void sanitizeInput(String input) {
        input = input.trim();
        input = input.replaceAll("\\s+", " ");
    }

    public static void registerUser(Scanner scanner) {
        System.out.print("Enter your name: ");
        String name = scanner.nextLine();
        sanitizeInput(name);
        System.out.print("Enter your email: ");
        String email = scanner.nextLine();
        if (validateEmail(email)) {
            System.out.print("Enter your password: ");
            String password = scanner.nextLine();
            if (validatePassword(password)) {
                System.out.println("Registration successful!");
            } else {
                System.out.println("Password is not strong enough. Password should have at least 8 characters, one uppercase letter, one lowercase letter, one digit, and one special character.");
            }
        } else {
            System.out.println("Invalid email. Please enter a valid email address.");
        }
    }
}
