def sanitize_sql(input_string):
    sanitized_string = ""
    for char in input_string:
        if char in [";", "--", "//", "'", "\"", "`", "|", "&", "$", "#", "@", "%", "^", "*"]:
            sanitized_string += "\\" + char
        else:
            sanitized_string += char
    return sanitized_string

def main():
    input_string = "SELECT * FROM users WHERE name = 'Robert'); DROP TABLE users; --"
    sanitized_string = sanitize_sql(input_string)
    print("Input String: ", input_string)
    print("Sanitized String: ", sanitized_string)

if __name__ == "__main__":
    main()
