import re

class Sanitizer:
    def __init__(self):
        self.allowed_tags = ['p', 'img', 'br', 'strong', 'em', 'u', 's', 'a', 'span']
        self.allowed_attributes = {
            'img': ['src', 'alt'],
            'a': ['href']
        }

    def sanitize(self, html):
        # Remove comments
        html = re.sub(r'<!--.*?-->', '', html)

        # Remove script and style tags
        html = re.sub(r'<(script|style)[^>]*>.*?<\/\1>', '', html, flags=re.DOTALL)

        # Remove disallowed tags
        for tag in re.findall(r'<(\w+)[^>]*>', html):
            if tag not in self.allowed_tags:
                html = re.sub(rf'<{tag}[^>]*>.*?<\/{tag}>', '', html, flags=re.DOTALL)

        # Remove disallowed attributes
        for tag in re.findall(r'<(\w+)[^>]*>', html):
            if tag in self.allowed_attributes:
                for attribute in re.findall(rf'<{tag}([^>]*)>', html):
                    for attr in re.findall(r'\b(\w+)\b', attribute):
                        if attr not in self.allowed_attributes[tag]:
                            html = re.sub(rf'<{tag}[^>]*{attr}=[^>]*>', '', html)
            else:
                html = re.sub(rf'<{tag}[^>]*>', '', html)

        # Remove on* attributes
        html = re.sub(r'on\w+=', '', html)

        return html


def main():
    sanitizer = Sanitizer()
    html = '<p onclick="alert(1)">Hello <script>alert(2)</script> world!</p>'
    print(sanitizer.sanitize(html))


if __name__ == '__main__':
    main()
