```python
import re
from html import unescape

class HTMLSanitizer:
    def __init__(self):
        self.allowed_tags = ['p', 'img', 'br', 'strong', 'em', 'u', 's', 'a', 'span', 'div']
        self.allowed_attributes = {
            'img': ['src', 'alt'],
            'a': ['href', 'title']
        }

    def sanitize(self, html):
        html = self.remove_disallowed_tags(html)
        html = self.remove_disallowed_attributes(html)
        html = self.remove_on_events(html)
        html = self.remove_style_attributes(html)
        html = self.escape_html_entities(html)
        return html

    def remove_disallowed_tags(self, html):
        pattern = re.compile(r'<([^>]+)>')
        tags = pattern.findall(html)
        for tag in tags:
            if tag.split()[0] not in self.allowed_tags:
                html = html.replace(f'<{tag}>', '')
                html = html.replace(f'</{tag.split()[0]}>', '')
        return html

    def remove_disallowed_attributes(self, html):
        pattern = re.compile(r'<([^>]+)>')
        tags = pattern.findall(html)
        for tag in tags:
            tag_name = tag.split()[0]
            attributes = tag.split()[1:]
            for attribute in attributes:
                if tag_name not in self.allowed_attributes or attribute.split('=')[0] not in self.allowed_attributes.get(tag_name, []):
                    html = html.replace(f'<{tag}>', f'<{tag_name}>')
        return html

    def remove_on_events(self, html):
        pattern = re.compile(r'on\w+=[\'"]?[^\'">]+')
        return pattern.sub('', html)

    def remove_style_attributes(self, html):
        pattern = re.compile(r'style=[\'"]?[^\'">]+')
        return pattern.sub('', html)

    def escape_html_entities(self, html):
        return unescape(html)

def main():
    sanitizer = HTMLSanitizer()
    html = '<p onclick="alert(\'XSS\')">Hello <img src="image.jpg" onerror="alert(\'XSS\')"> World!</p>'
    print(sanitizer.sanitize(html))

if __name__ == '__main__':
    main()
```

```python
import re

class HTMLSanitizer:
    def __init__(self, allowed_tags, allowed_attributes):
        self.allowed_tags = allowed_tags
        self.allowed_attributes = allowed_attributes

    def sanitize(self, html):
        sanitized_html = ""
        in_tag = False
        current_tag = ""
        current_attributes = {}
        for char in html:
            if char == "<":
                in_tag = True
                current_tag = ""
                current_attributes = {}
            elif char == ">":
                in_tag = False
                if current_tag in self.allowed_tags:
                    sanitized_html += f"<{current_tag}"
                    for attribute, value in current_attributes.items():
                        if attribute in self.allowed_attributes:
                            sanitized_html += f" {attribute}='{value}'"
                    sanitized_html += ">"
                else:
                    sanitized_html += "&lt;" + current_tag + "&gt;"
            elif in_tag:
                if char == " ":
                    if current_tag:
                        if current_tag in self.allowed_tags:
                            pass
                        else:
                            current_tag = ""
                            sanitized_html += "&lt;" + current_tag + "&gt;"
                elif char == "=":
                    pass
                elif char == '"':
                    pass
                elif char.isalpha():
                    if current_tag:
                        current_tag += char
                    else:
                        current_tag += char
                elif char == "/":
                    if current_tag:
                        sanitized_html += f"</{current_tag}>"
                        current_tag = ""
                else:
                    if current_tag:
                        current_attributes[current_tag] = char
                    else:
                        pass
            else:
                sanitized_html += char
        return sanitized_html


def main():
    allowed_tags = ["p", "img", "a", "b", "i", "strong", "em"]
    allowed_attributes = ["src", "href", "alt"]
    sanitizer = HTMLSanitizer(allowed_tags, allowed_attributes)
    html = "<p>Hello <img src='image.jpg' onerror='alert(1)'> World!</p>"
    sanitized_html = sanitizer.sanitize(html)
    print(sanitized_html)


if __name__ == "__main__":
    main()
```

