def escape_html(s):
    escape_chars = {
        '&': '&amp;',
        '<': '&lt;',
        '>': '&gt;',
        '"': '&quot;',
        "'": '&#x27;',
    }
    return ''.join(escape_chars.get(c, c) for c in s)

def main():
    test_string = "Hello < World > & 'Python' \"Example\""
    print("Original string:")
    print(test_string)
    print("Escaped string:")
    print(escape_html(test_string))

if __name__ == "__main__":
    main()
