from bs4 import BeautifulSoup
import html

def sanitize_html(html_string):
    soup = BeautifulSoup(html_string, 'html.parser')
    allowed_tags = ['p', 'img', 'br', 'strong', 'em', 'u', 'span', 'a']
    allowed_attributes = {'img': ['src', 'alt'], 'a': ['href', 'title']}

    for tag in soup.find_all(True):
        if tag.name not in allowed_tags:
            tag.unwrap()
        else:
            for attr in list(tag.attrs.keys()):
                if attr not in allowed_attributes.get(tag.name, []):
                    del tag.attrs[attr]

    return str(soup)

def main():
    user_input = "<p>Hello <script>alert('XSS')</script> world!</p>"
    cleaned_input = sanitize_html(user_input)
    print(cleaned_input)

if __name__ == "__main__":
    main()
