class ShellCommandSanitizer:
    def __init__(self, command):
        self.command = command

    def sanitize(self):
        sanitized_command = ""
        in_quote = False
        for char in self.command:
            if char == '"':
                in_quote = not in_quote
            elif char in [';', '|', '&', '$', '`'] and not in_quote:
                continue
            sanitized_command += char
        return sanitized_command

    def remove_comment(self):
        comment_start = self.command.find('#')
        if comment_start != -1:
            return self.command[:comment_start]
        return self.command

    def remove_trailing_whitespace(self):
        return self.command.rstrip()

def main():
    command = input("Enter a shell command: ")
    sanitizer = ShellCommandSanitizer(command)
    sanitized_command = sanitizer.remove_trailing_whitespace()
    sanitized_command = sanitizer.remove_comment()
    sanitized_command = sanitizer.sanitize()
    print("Sanitized command: ", sanitized_command)

if __name__ == "__main__":
    main()
