import shlex

def escape_shell(command):
    return ' '.join(shlex.quote(arg) for arg in command)

def escape_shell_manual(command):
    escaped_command = []
    for arg in command:
        if any(char in arg for char in [' ', '"', '$', '`', '\\', '|', ';', '>', '<', '&']):
            arg = "'" + arg.replace("'", "'\\''") + "'"
        escaped_command.append(arg)
    return ' '.join(escaped_command)

