```python
import os
import posixpath

def sanitize_path(base_dir, rel_path):
    base_dir = base_dir.rstrip(os.sep)
    rel_path = rel_path.lstrip(os.sep)
    abs_path = os.path.abspath(os.path.join(base_dir, rel_path))
    if not abs_path.startswith(base_dir):
        raise ValueError("Directory traversal attempt detected")
    return posixpath.normpath(abs_path).lstrip(os.sep)

class PathSanitizer:
    def __init__(self, base_dir):
        self.base_dir = base_dir

    def sanitize(self, rel_path):
        return sanitize_path(self.base_dir, rel_path)

def main():
    base_dir = "/path/to/base/directory"
    sanitizer = PathSanitizer(base_dir)
    rel_path = "../etc/passwd"
    try:
        sanitized_path = sanitizer.sanitize(rel_path)
        print(sanitized_path)
    except ValueError as e:
        print(e)

if __name__ == "__main__":
    main()
