```python
import os
import urllib.parse

def sanitize_path(path):
    path = urllib.parse.unquote(path)
    path = path.replace('\\', '/')
    path = os.path.normpath(path)
    path = path.strip('/')
    return path

def is_absolute_path(path):
    return os.path.isabs(path)

def is_parent_directory(path):
    return '..' in path

def sanitize_absolute_path(path):
    if is_absolute_path(path):
        path = sanitize_path(path)
        if is_parent_directory(path):
            raise ValueError('Path contains parent directory reference')
        return path
    else:
        raise ValueError('Path is not absolute')

def is_traversable_path(base_path, path):
    sanitized_path = sanitize_absolute_path(os.path.join(base_path, path))
    return os.path.commonpath([base_path, sanitized_path]) == base_path

def sanitize_traversable_path(base_path, path):
    if is_traversable_path(base_path, path):
        return os.path.relpath(path, base_path)
    else:
        raise ValueError('Path is not traversable')

def main():
    base_path = '/var/www/html'
    path = '/var/www/html/../etc/passwd'
    try:
        sanitized_path = sanitize_traversable_path(base_path, path)
        print(f'Sanitized path: {sanitized_path}')
    except ValueError as e:
        print(f'Error: {e}')

if __name__ == '__main__':
    main()
```

