class InputSanitizer:
    def __init__(self):
        self.allowed_chars = set("abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789.-_@ ")

    def sanitize(self, input_str):
        sanitized_str = ""
        for char in input_str:
            if char in self.allowed_chars:
                sanitized_str += char
        return sanitized_str

    def sanitize_int(self, input_str):
        sanitized_str = ""
        for char in input_str:
            if char.isdigit():
                sanitized_str += char
        return sanitized_str

    def sanitize_float(self, input_str):
        sanitized_str = ""
        has_decimal = False
        for char in input_str:
            if char.isdigit():
                sanitized_str += char
            elif char == "." and not has_decimal:
                sanitized_str += char
                has_decimal = True
        return sanitized_str


def main():
    sanitizer = InputSanitizer()
    input_str = input("Enter a string: ")
    print("Sanitized string:", sanitizer.sanitize(input_str))
    input_int = input("Enter an integer: ")
    print("Sanitized integer:", sanitizer.sanitize_int(input_int))
    input_float = input("Enter a float: ")
    print("Sanitized float:", sanitizer.sanitize_float(input_float))


if __name__ == "__main__":
