def sanitize_input(input_str):
    input_str = input_str.strip()
    input_str = remove_special_chars(input_str)
    input_str = remove_numbers(input_str)
    input_str = remove_whitespace(input_str)
    input_str = remove_tags(input_str)
    return input_str

def remove_special_chars(input_str):
    special_chars = "!@#$%^&*()-_=+[]{}|;:,.<>/?`~"
    for char in special_chars:
        input_str = input_str.replace(char, "")
    return input_str

def remove_numbers(input_str):
    return "".join([char for char in input_str if not char.isdigit()])

def remove_whitespace(input_str):
    return input_str.replace(" ", "")

def remove_tags(input_str):
    while "<" in input_str and ">" in input_str:
        start = input_str.find("<")
        end = input_str.find(">")
        input_str = input_str[:start] + input_str[end+1:]
    return input_str

def main():
    user_input = input("Enter your input: ")
    sanitized_input = sanitize_input(user_input)
    print("Sanitized Input: ", sanitized_input)

if __name__ == "__main__":
    main()
```

```python
class InputSanitizer:
    def __init__(self, input_string):
        self.input_string = input_string

    def strip_whitespace(self):
        return self.input_string.strip()

    def remove_special_chars(self, allowed_chars=None):
        if allowed_chars is None:
            allowed_chars = ''
        return ''.join(char for char in self.input_string if char.isalnum() or char in allowed_chars)

    def remove_tags(self):
        import re
        clean = re.compile('<.*?>')
        return re.sub(clean, '', self.input_string)

    def remove_scripts(self):
        import re
        clean = re.compile('javascript:', re.IGNORECASE)
        return re.sub(clean, '', self.input_string)

    def sanitize(self, allowed_chars=None):
        sanitized_string = self.strip_whitespace()
        sanitized_string = self.remove_special_chars(allowed_chars)
        sanitized_string = self.remove_tags()
        sanitized_string = self.remove_scripts()
        return sanitized_string


def sanitize_input(input_string, allowed_chars=None):
    sanitizer = InputSanitizer(input_string)
    return sanitizer.sanitize(allowed_chars)


def main():
    user_input = input("Enter a string: ")
    sanitized_input = sanitize_input(user_input)
    print("Sanitized input:", sanitized_input)


if __name__ == "__main__":
    main()
```

