```python
import html
import re

def sanitize_sql(input_string):
    return re.sub(r"[^a-zA-Z0-9\s]", "", input_string)

def escape_html(input_string):
    return html.escape(input_string)

def validate_input(input_string):
    if not input_string:
        raise ValueError("Input is required")
    if len(input_string) > 100:
        raise ValueError("Input is too long")
    return input_string

def process_form_data(data):
    try:
        sanitized_data = {}
        for key, value in data.items():
            validated_value = validate_input(value)
            sanitized_value = sanitize_sql(validated_value)
            escaped_value = escape_html(sanitized_value)
            sanitized_data[key] = escaped_value
        return sanitized_data
    except ValueError as e:
        print(f"Error: {e}")
        return None

# example usage
if __name__ == "__main__":
    form_data = {
        "name": "<script>alert('XSS')</script>",
        "email": "example@example.com",
        "phone": "123-456-7890"
    }
    processed_data = process_form_data(form_data)
    print(processed_data)
