from flask import Flask, request, jsonify
import jwt

app = Flask(__name__)

def sanitize_request(data):
    return {key: value for key, value in data.items() if key.isalnum()}

def validate_token(token, secret_key):
    try:
        payload = jwt.decode(token, secret_key, algorithms=['HS256'])
        return payload
    except jwt.ExpiredSignatureError:
        return None
    except jwt.InvalidTokenError:
        return None

@app.route('/api/endpoint', methods=['POST'])
def api_endpoint():
    try:
        token = request.headers.get('Authorization')
        if token is None:
            return jsonify({'error': 'Token is missing'}), 401
        token = token.split(' ')[1]
        payload = validate_token(token, 'your_secret_key_here')
        if payload is None:
            return jsonify({'error': 'Invalid token'}), 401
        data = request.get_json()
        sanitized_data = sanitize_request(data)
        # Process sanitized data here
        return jsonify({'message': 'Request processed successfully'}), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(debug=True)
