```javascript
function sanitizeSql(input) {
    let sanitized = "";
    for (let i = 0; i < input.length; i++) {
        let char = input[i];
        if (char === "'" || char === '"' || char === "\\" || char === "%") {
            sanitized += "\\" + char;
        } else if (char === ";") {
            continue;
        } else {
            sanitized += char;
        }
    }
    return sanitized;
}

function sanitizeSqlString(input) {
    return "'" + sanitizeSql(input) + "'";
}

function sanitizeSqlQuery(query, params) {
    let sanitizedQuery = "";
    let paramIndex = 0;
    for (let i = 0; i < query.length; i++) {
        let char = query[i];
        if (char === "?") {
            sanitizedQuery += sanitizeSqlString(params[paramIndex]);
            paramIndex++;
        } else {
            sanitizedQuery += char;
        }
    }
    return sanitizedQuery;
}

// Example usage:
let query = "SELECT * FROM users WHERE name = ? AND email = ?";
let params = ["John Doe", "john@example.com"];
let sanitizedQuery = sanitizeSqlQuery(query, params);
console.log(sanitizedQuery);
