```javascript
function sql_escape(str) {
    return str.replace(/[^a-zA-Z0-9\s]/g, '').replace(/'/g, "''").replace(/"/g, '""');
}

function sql_escape_strict(str) {
    return str.replace(/'/g, "''").replace(/"/g, '""');
}

function sql_query_escape(query, params) {
    for (let i = 0; i < params.length; i++) {
        if (typeof params[i] === 'string') {
            params[i] = sql_escape_strict(params[i]);
        }
        query = query.replace('?', "'" + params[i] + "'");
    }
    return query;
}

// Test the functions
console.log(sql_escape("Hello, World!"));
console.log(sql_escape_strict("Hello, World!"));
console.log(sql_query_escape("SELECT * FROM users WHERE name = ? AND age = ?", ["John Doe", 30]));
