class ShellCommandSanitizer {
  constructor(command) {
    this.command = command;
    this.sanitizedCommand = [];
  }

  sanitize() {
    const tokens = this.tokenizeCommand(this.command);
    for (let token of tokens) {
      if (this.isSafeToken(token)) {
        this.sanitizedCommand.push(token);
      } else {
        throw new Error(`Unsafe token: ${token}`);
      }
    }
    return this.sanitizedCommand.join(' ');
  }

  tokenizeCommand(command) {
    const tokens = [];
    let currentToken = '';
    for (let char of command) {
      if (char === ' ' && currentToken !== '') {
        tokens.push(currentToken);
        currentToken = '';
      } else if (char !== ' ' && char !== '\t' && char !== '\n') {
        currentToken += char;
      }
    }
    if (currentToken !== '') {
      tokens.push(currentToken);
    }
    return tokens;
  }

  isSafeToken(token) {
    const safeCommands = ['ls', 'echo', 'cat', 'pwd', 'cd'];
    const safeOptions = ['-l', '-a', '-d', '-p'];
    if (safeCommands.includes(token)) {
      return true;
    }
    if (safeOptions.includes(token)) {
      return true;
    }
    if (token.startsWith('./') || token.startsWith('../')) {
      return false;
    }
    if (token.includes(';') || token.includes('|') || token.includes('$') || token.includes('`') || token.includes('\\') || token.includes('"') || token.includes("'")) {
      return false;
    }
    return true;
  }
}

function sanitizeCommand(command) {
  const sanitizer = new ShellCommandSanitizer(command);
  try {
    return sanitizer.sanitize();
  } catch (error) {
    return error.message;
  }
}

console.log(sanitizeCommand('ls -l'));
console.log(sanitizeCommand('echo hello world'));
console.log(sanitizeCommand('ls ; rm -rf /'));
