class ShellCommandSanitizer {
  constructor(command) {
    this.command = command;
  }

  sanitize() {
    const sanitizedCommand = [];
    const words = this.command.split(' ');
    for (const word of words) {
      if (this.isSafeWord(word)) {
        sanitizedCommand.push(word);
      } else {
        sanitizedCommand.push(this.escapeWord(word));
      }
    }
    return sanitizedCommand.join(' ');
  }

  isSafeWord(word) {
    return /^[a-zA-Z0-9_\-]+$/.test(word);
  }

  escapeWord(word) {
    return `'${word.replace(/'/g, "'\\''")}'`;
  }
}

function sanitizeShellCommand(command) {
  const sanitizer = new ShellCommandSanitizer(command);
  return sanitizer.sanitize();
}

