```javascript
class ShellCommandSanitizer {
  constructor() {
    this.allowedCommands = ['ls', 'cd', 'mkdir', 'rm', 'cp', 'mv'];
    this.allowedOptions = {
      ls: ['-l', '-a', '-d'],
      cd: [],
      mkdir: ['-p'],
      rm: ['-r', '-f'],
      cp: ['-r'],
      mv: []
    };
    this.allowedArguments = {
      ls: [''],
      cd: [''],
      mkdir: [''],
      rm: [''],
      cp: [''],
      mv: ['']
    };
  }

  sanitize(command) {
    const parts = command.split(' ');
    const commandName = parts[0];
    if (!this.allowedCommands.includes(commandName)) {
      throw new Error(`Forbidden command: ${commandName}`);
    }

    const options = parts.slice(1).filter(part => part.startsWith('-'));
    const arguments_ = parts.slice(1).filter(part => !part.startsWith('-'));

    for (const option of options) {
      if (!this.allowedOptions[commandName].includes(option)) {
        throw new Error(`Forbidden option: ${option} for command ${commandName}`);
      }
    }

    for (const arg of arguments_) {
      if (!this.allowedArguments[commandName].includes(arg)) {
        throw new Error(`Forbidden argument: ${arg} for command ${commandName}`);
      }
    }

    return parts.join(' ');
  }
}

const sanitizer = new ShellCommandSanitizer();

function sanitizeShellCommand(command) {
  try {
    return sanitizer.sanitize(command);
  } catch (error) {
    return error.message;
  }
}

