console.log(sanitizeShellCommand('mkdir -p test'));
console.log(sanitizeShellCommand('rm -rf test'));
console.log(sanitizeShellCommand('cp -r test2 test'));
console.log(sanitizeShellCommand('mv test test2'));
console.log(sanitizeShellCommand('echo test'));
console.log(sanitizeShellCommand('ls -x'));
console.log(sanitizeShellCommand('mkdir test2'));
