function sanitizeCommand(userInput) {
  const allowedCommands = ['ls', 'mkdir', 'rm', 'cp', 'mv'];
  const sanitizedInput = userInput.trim().split(' ');
  const command = sanitizedInput.shift();

  if (!allowedCommands.includes(command)) {
    throw new Error(`Invalid command: ${command}`);
  }

  return [command, ...sanitizedInput];
}

function executeCommand(command, args) {
  const childProcess = require('child_process');
  try {
    const result = childProcess.execFileSync(command, args, { encoding: 'utf-8' });
    return result;
  } catch (error) {
    throw new Error(`Error executing command: ${error}`);
  }
}

function safelyExecuteUserCommand(userInput) {
  try {
    const [command, ...args] = sanitizeCommand(userInput);
    const result = executeCommand(command, args);
    return result;
  } catch (error) {
    throw new Error(`Error executing user command: ${error}`);
  }
}

