```javascript
function sanitizePath(path) {
  const sep = '/';
  const segments = path.split(sep);
  const sanitizedSegments = [];

  for (const segment of segments) {
    if (segment === '..') {
      if (sanitizedSegments.length > 0) {
        sanitizedSegments.pop();
      }
    } else if (segment !== '' && segment !== '.') {
      sanitizedSegments.push(segment);
    }
  }

  const sanitizedPath = sanitizedSegments.join(sep);

  return sep + sanitizedPath;
}

function normalizePath(path) {
  const sep = '/';
  const segments = path.split(sep);
  const normalizedSegments = [];

  for (const segment of segments) {
    if (segment === '..') {
      if (normalizedSegments.length > 0) {
        normalizedSegments.pop();
      }
    } else if (segment === '.') {
      continue;
    } else {
      normalizedSegments.push(segment);
    }
  }

  const normalizedPath = normalizedSegments.join(sep);

  return sep + normalizedPath;
}

function preventTraversalAttack(path) {
  const normalizedPath = normalizePath(path);
  const sanitizedPath = sanitizePath(normalizedPath);

  if (sanitizedPath.startsWith('/..')) {
    throw new Error('Directory traversal attack detected');
  }

  return sanitizedPath;
}

class PathSanitizer {
  constructor(rootDirectory) {
    this.rootDirectory = rootDirectory;
  }

  sanitize(path) {
    const absolutePath = this.rootDirectory + path;
    const normalizedPath = normalizePath(absolutePath);
    const sanitizedPath = preventTraversalAttack(normalizedPath);

    if (sanitizedPath.startsWith(this.rootDirectory)) {
      return sanitizedPath.substring(this.rootDirectory.length);
    } else {
      throw new Error('Path is outside the root directory');
    }
  }
}

const sanitizer = new PathSanitizer('/var/www');
const sanitizedPath = sanitizer.sanitize('/../../etc/passwd');
console.log(sanitizedPath);
