function sanitizePath(path) {
  const rootDir = '/'; // assumed root directory
  const pathParts = path.split('/');
  const sanitizedParts = [];

  for (let i = 0; i < pathParts.length; i++) {
    const part = pathParts[i];
    if (part === '..') {
      if (sanitizedParts.length > 0) {
        sanitizedParts.pop();
      } else {
        throw new Error('Directory traversal attempt detected');
      }
    } else if (part !== '' && part !== '.') {
      sanitizedParts.push(part);
    }
  }

  const sanitizedPath = sanitizedParts.join('/');
  return rootDir + sanitizedPath;
}

function isWithinRootDir(path, rootDir) {
  const resolvedPath = sanitizePath(path);
  return resolvedPath.startsWith(rootDir);
}

function secureJoin(rootDir, path) {
  if (!isWithinRootDir(path, rootDir)) {
    throw new Error('Path is outside the root directory');
  }
  return sanitizePath(path);
}

// Example usage
const rootDir = '/var/www';
const userInput = '../../../etc/passwd';
try {
  const sanitizedPath = secureJoin(rootDir, userInput);
  // Use sanitizedPath for file operations
} catch (error) {
  console.error(error.message);
}
