function validatePath(filePath) {
  try {
    const normalizedPath = path.normalize(filePath);
    if (normalizedPath.startsWith('/')) {
      throw new Error('Path starts with a slash, potential security risk');
    }
    if (normalizedPath.includes('..')) {
      throw new Error('Path contains parent directory traversal, potential security risk');
    }
    if (normalizedPath.includes(':')) {
      throw new Error('Path contains a colon, potential security risk');
    }
    return true;
  } catch (error) {
    console.error(error);
    return false;
  }
}

