```javascript
function hashPassword(password) {
  const passwordBytes = new TextEncoder('utf-8').encode(password);
  const salt = crypto.getRandomValues(new Uint8Array(16));
  const hashedPassword = pbkdf2(passwordBytes, salt, 10000, 64, 'sha512');
  return {
    salt: arrayBufferToHex(salt),
    hash: arrayBufferToHex(hashedPassword)
  };
}

function verifyPassword(password, storedSalt, storedHash) {
  const passwordBytes = new TextEncoder('utf-8').encode(password);
  const salt = hexToArrayBuffer(storedSalt);
  const hashedPassword = pbkdf2(passwordBytes, salt, 10000, 64, 'sha512');
  return arrayBufferToHex(hashedPassword) === storedHash;
}

function pbkdf2(password, salt, iterations, length, algorithm) {
  const passwordBuffer = new Uint8Array(password);
  const saltBuffer = new Uint8Array(salt);
  const key = new Uint8Array(length);
  let block = 1;
  let offset = 0;
  while (offset < length) {
    const blockBuffer = new Uint8Array(saltBuffer.length + 4);
    blockBuffer.set(saltBuffer);
    new DataView(blockBuffer.buffer, saltBuffer.length).setUint32(0, block);
    const blockHash = crypto.subtle.digest(algorithm, blockBuffer);
    let current = new Uint8Array(blockHash);
    for (let i = 1; i < iterations; i++) {
      const next = crypto.subtle.digest(algorithm, current);
      current = new Uint8Array(next);
      for (let j = 0; j < current.length; j++) {
        current[j] ^= new Uint8Array(next)[j];
      }
    }
    const copyLength = Math.min(current.length, length - offset);
    key.set(current.slice(0, copyLength), offset);
    offset += copyLength;
    block++;
  }
  return key.buffer;
}

function arrayBufferToHex(buffer) {
  return Array.prototype.map.call(new Uint8Array(buffer), x => ('00' + x.toString(16)).slice(-2)).join('');
}

function hexToArrayBuffer(hex) {
  const buffer = new ArrayBuffer(Math.ceil(hex.length / 2));
  const view = new DataView(buffer);
  for (let i = 0; i < hex.length; i += 2) {
    view.setUint8(i / 2, parseInt(hex.slice(i, i + 2), 16));
  }
  return buffer;
}

const crypto = window.crypto || window.msCrypto;

const password = 'mysecretpassword';
const hashedPassword = hashPassword(password);
console.log(hashedPassword);
console.log(verifyPassword(password, hashedPassword.salt, hashedPassword.hash));
```

