function hashPassword(password) {
  const salt = generateSalt();
  const pepper = "my_secret_pepper";
  const hashedPassword = sha256(password + salt + pepper);
  return { salt, hashedPassword };
}

function generateSalt() {
  const length = 16;
  const characters = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789";
  let salt = "";
  for (let i = 0; i < length; i++) {
    salt += characters.charAt(Math.floor(Math.random() * characters.length));
  }
  return salt;
}

function sha256(message) {
  const hash = crypto.createHash("sha256");
  hash.update(message);
  return hash.digest("hex");
}

function verifyPassword(storedSalt, storedHash, providedPassword, pepper) {
  const hashedPassword = sha256(providedPassword + storedSalt + pepper);
  return hashedPassword === storedHash;
}

const crypto = require("crypto");

function main() {
  const password = "mysecretpassword";
  const { salt, hashedPassword } = hashPassword(password);
  console.log(`Salt: ${salt}`);
  console.log(`Hashed Password: ${hashedPassword}`);
  const isValid = verifyPassword(salt, hashedPassword, password, "my_secret_pepper");
  console.log(`Is Password Valid: ${isValid}`);
}

main();
