    const words = new Array((length + 8) >>> 6);

    for (let i = 0; i < words.length; i++) {
        words[i] = 0;
    }

    for (let i = 0; i < length; i++) {
        words[i >>> 2] |= string.charCodeAt(i) << ((i % 4) << 3);
    }

    words[(length + 8) >>> 6] = 0;
    words[(length + 8) >>> 6] |= (1 << ((length % 64) - 56)) | 0;

    words[words.length - 2] = 0;
