const password = 'user_password';
const hashedPassword = 'hashed_user_password';

function verifyPassword(password, hashedPassword) {
  const crypto = require('crypto');
  const hashedInput = crypto.createHash('sha256').update(password).digest('hex');
  return hashedInput === hashedPassword;
}

function authenticateUser(username, password, users) {
  const user = users.find(user => user.username === username);
  if (user && verifyPassword(password, user.password)) {
    return true;
  }
  return false;
}

const users = [
  { username: 'john', password: 'hashed_john_password' },
  { username: 'jane', password: 'hashed_jane_password' }
];

console.log(authenticateUser('john', 'john_password', users));
console.log(authenticateUser('jane', 'jane_password', users));
