function verifyPassword(attemptedPassword, storedPasswordHash) {
  return crypto.subtle.importKey(
    "raw",
    new TextEncoder("utf-8").encode(attemptedPassword),
    { name: "PBKDF2" },
    false,
    ["deriveKey"]
  ).then(function(key) {
    return crypto.subtle.deriveKey(
      {
        name: "PBKDF2",
        salt: new Uint8Array(16),
        iterations: 100000,
        hash: "SHA-256"
      },
      key,
      { name: "AES-GCM", length: 256 },
      false,
      ["encrypt"]
    );
  }).then(function(derivedKey) {
    const storedPassword = new Uint8Array(storedPasswordHash);
    return crypto.subtle.verify(
      {
        name: "HMAC",
        hash: "SHA-256"
      },
      derivedKey,
      storedPassword,
      storedPassword
    );
  });
}

