    if (obj.hasOwnProperty(key)) {
      obj[key] = sanitizeInput(obj[key]);
    }
  }
  return obj;
}

function sanitizeArray(arr) {
  return arr.map(sanitizeInput);
}

function escapeHtml(unsafe) {
  return unsafe
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#x27;')
    .replace(/\//g, '&#x2F;');
}

