function validate_input(formData) {
  // Standard validate_input function implementation
  if (formData === null || formData === undefined) {
    throw new Error("Form data is required");
  }
  if (typeof formData !== "object") {
    throw new Error("Form data must be an object");
  }
  for (let key in formData) {
    if (formData.hasOwnProperty(key)) {
      let value = formData[key];
      if (value === null || value === undefined) {
        throw new Error(`Field ${key} is required`);
      }
      if (typeof value !== "string" && typeof value !== "number" && typeof value !== "boolean") {
        throw new Error(`Field ${key} must be a string, number or boolean`);
      }
    }
  }
}

let formData = {
  name: "John Doe",
  age: 30,
  isAdmin: true
};

try {
  validate_input(formData);
  console.log("Form data is valid");
} catch (error) {
  console.error(error.message);
}
