  const html = uncleanHtml.replace(/<.*?>/g, '');
  return html;
}

function cleanSql(input) {
  const sql = input.replace(/[^a-zA-Z0-9\s]/g, '');
  return sql;
}

function main() {
  const userInput = '<script>alert("XSS")</script>';
  const cleanUserInput = cleanData(userInput);
  console.log(cleanUserInput);

  const uncleanHtml = '<p>Hello <b>World</b></p>';
  const cleanHtmlOutput = cleanHtml(uncleanHtml);
  console.log(cleanHtmlOutput);

  const sqlInput = "SELECT * FROM users WHERE name = 'John'; DROP TABLE users;";
  const cleanSqlInput = cleanSql(sqlInput);
  console.log(cleanSqlInput);
}

main();
