function cleanData(data) {
  const regex = /[<>\/\\();|&$]/g;
  return data.replace(regex, '');
}

function cleanHtmlData(data) {
  const htmlEscapes = {
    '&': '&amp;',
    '<': '&lt;',
    '>': '&gt;',
    '"': '&quot;',
    "'": '&#x27;',
    '/': '&#x2F;',
  };

  return data.replace(/[&<>"'\/]/g, (char) => htmlEscapes[char]);
}

function removeMaliciousContent(userSubmission) {
  const cleanedData = cleanData(userSubmission);
  const cleanedHtmlData = cleanHtmlData(cleanedData);
  return cleanedHtmlData;
}

const userInput = '<script>alert("XSS")</script>';
const cleanedInput = removeMaliciousContent(userInput);
console.log(cleanedInput);
