function secureEncrypt(data) {
  const crypto = require('crypto');
  const algorithm = 'aes-256-cbc';
  const key = crypto.randomBytes(32);
  const iv = crypto.randomBytes(16);

  const cipher = crypto.createCipheriv(algorithm, key, iv);
  let encrypted = cipher.update(data, 'utf8', 'hex');
  encrypted += cipher.final('hex');

  return {
    encryptedData: encrypted,
    key: key.toString('hex'),
    iv: iv.toString('hex')
  };
}

function secureDecrypt(encryptedData, key, iv) {
  const crypto = require('crypto');
  const algorithm = 'aes-256-cbc';

  const decipher = crypto.createDecipheriv(algorithm, Buffer.from(key, 'hex'), Buffer.from(iv, 'hex'));
  let decrypted = decipher.update(encryptedData, 'hex', 'utf8');
  decrypted += decipher.final('utf8');

  return decrypted;
}

const userData = "Hello, World!";
const encrypted = secureEncrypt(userData);
console.log(`Encrypted Data: ${encrypted.encryptedData}`);
console.log(`Key: ${encrypted.key}`);
console.log(`IV: ${encrypted.iv}`);

const decrypted = secureDecrypt(encrypted.encryptedData, encrypted.key, encrypted.iv);
console.log(`Decrypted Data: ${decrypted}`);
