const express = require('express');
const app = express();
const jwt = require('jsonwebtoken');
const sanitizer = require('express-validator').sanitize;

function sanitize_request(req) {
  return new Promise((resolve, reject) => {
    req.sanitize('body.*').trim();
    req.sanitize('body.*').escape();
    resolve(req);
  });
}

function validate_token(req) {
  return new Promise((resolve, reject) => {
    const token = req.header('Authorization').replace('Bearer ', '');
    jwt.verify(token, process.env.SECRET_KEY, (err, decoded) => {
      if (err) {
        reject(err);
      } else {
        req.user = decoded;
        resolve(req);
      }
    });
  });
}

app.use(express.json());

app.post('/api/endpoint', async (req, res) => {
  try {
    const sanitizedReq = await sanitize_request(req);
    const validatedReq = await validate_token(sanitizedReq);
    res.send('Request validated and sanitized successfully');
  } catch (error) {
    res.status(401).send('Invalid token or request');
  }
});

app.listen(3000, () => {
  console.log('Server listening on port 3000');
});
