    return validator.isEmail(email);
}

function sanitize_input(input) {
    return input.replace(/[^a-zA-Z0-9\s]/g, '');
}

class User {
    constructor(email, password) {
        this.email = email;
        this.password = secure_password(password);
    }

    register() {
        if (!validate_email(this.email)) {
            throw new Error('Invalid email');
        }
        this.email = sanitize_input(this.email);
        console.log('User registered successfully');
    }

    authenticate(password) {
        const hash = crypto.pbkdf2Sync(password, this.password.salt, 10000, 64, 'sha512').toString('hex');
        return hash === this.password.hash;
    }
}

const user = new User('example@example.com', 'password123');
user.register();
console.log(user.authenticate('password123'));  // true
console.log(user.authenticate('wrongpassword'));  // false
