        String sanitized = input.replace("\\", "\\\\");
        sanitized = sanitized.replace("'", "\\'");
        sanitized = sanitized.replace("\"", "\\\"");
        sanitized = sanitized.replace("%", "\\%");
        sanitized = sanitized.replace("_", "\\_");
        return sanitized;
    }

    public static String quoteSanitizeSql(String input) {
        return "'" + sanitizeSql(input) + "'";
    }

    public static void main(String[] args) {
        System.out.println(quoteSanitizeSql("John's"));
        System.out.println(quoteSanitizeSql("Robert'); DROP TABLE Students; --"));
    }
}
