```java
public class Main {
    public static String sanitizeSql(String input) {
        StringBuilder sanitized = new StringBuilder();
        for (char c : input.toCharArray()) {
            if (c == '\'') {
                sanitized.append("''");
            } else if (c == '\\') {
                sanitized.append("\\\\");
            } else if (c == '\"') {
                sanitized.append("\\\"");
            } else if (c == ';') {
                sanitized.append("\\;");
            } else if (c == '--') {
                sanitized.append("\\-\\-");
            } else {
                sanitized.append(c);
            }
        }
        return sanitized.toString();
    }

    public static void main(String[] args) {
        System.out.println(sanitizeSql("Robert'); DROP TABLE Students; --"));
    }
}
