import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class HtmlSanitizer {
    private static final String[] ALLOWED_TAGS = {"p", "div", "span", "br", "strong", "em", "u", "i", "b", "ul", "ol", "li", "a", "img"};
    private static final String[] ALLOWED_ATTRS = {"href", "src", "alt", "title"};

    public static String sanitize(String html) {
        html = removeDisallowedTags(html);
        html = removeDisallowedAttrs(html);
        html = escapeHtmlEntites(html);
        return html;
    }

    private static String removeDisallowedTags(String html) {
        for (String tag : getDisallowedTags()) {
            Pattern pattern = Pattern.compile("<" + tag + ".*?>", Pattern.CASE_INSENSITIVE);
            Matcher matcher = pattern.matcher(html);
            html = matcher.replaceAll("");
        }
        return html;
    }

    private static String[] getDisallowedTags() {
        String[] disallowedTags = new String[getDisallowedTagCount()];
        int index = 0;
        for (String tag : getAllTags()) {
            boolean isAllowed = false;
            for (String allowedTag : ALLOWED_TAGS) {
                if (tag.equalsIgnoreCase(allowedTag)) {
                    isAllowed = true;
                    break;
                }
            }
            if (!isAllowed) {
                disallowedTags[index++] = tag;
            }
        }
        return disallowedTags;
    }

    private static int getDisallowedTagCount() {
        int count = 0;
        for (String tag : getAllTags()) {
            boolean isAllowed = false;
            for (String allowedTag : ALLOWED_TAGS) {
                if (tag.equalsIgnoreCase(allowedTag)) {
                    isAllowed = true;
                    break;
                }
            }
            if (!isAllowed) {
                count++;
            }
        }
        return count;
    }

    private static String[] getAllTags() {
        String[] allTags = new String[getTagCount()];
        Pattern pattern = Pattern.compile("<(\\w+)", Pattern.CASE_INSENSITIVE);
        Matcher matcher = pattern.matcher(html);
        int index = 0;
        while (matcher.find()) {
            allTags[index++] = matcher.group(1);
        }
        return allTags;
    }

    private static int getTagCount() {
        Pattern pattern = Pattern.compile("<(\\w+)", Pattern.CASE_INSENSITIVE);
        Matcher matcher = pattern.matcher(html);
        int count = 0;
        while (matcher.find()) {
            count++;
        }
        return count;
    }

    private static String removeDisallowedAttrs(String html) {
        Pattern pattern = Pattern.compile("<(\\w+).*?>");
        Matcher matcher = pattern.matcher(html);
        while (matcher.find()) {
            String tag = matcher.group(1);
            String attrs = matcher.group(0).replace("<" + tag + " ", "").replace(">", "");
            String newAttrs = "";
            for (String attr : attrs.split("\\s+")) {
                String attrName = attr.split("=")[0];
                boolean isAllowed = false;
                for (String allowedAttr : ALLOWED_ATTRS) {
                    if (attrName.equalsIgnoreCase(allowedAttr)) {
                        isAllowed = true;
                        break;
                    }
                }
                if (isAllowed) {
                    newAttrs += " " + attr;
                }
            }
            html = html.replace("<" + tag + " " + attrs + ">", "<" + tag + newAttrs + ">");
        }
        return html;
    }

    private static String escapeHtmlEntites(String html) {
        return html.replace("&", "&amp;").replace("<", "&lt;").replace(">", "&gt;").replace("\"", "&quot;").replace("'", "&#x27;");
    }

    public static void main(String[] args) {
        String html = "<p>Hello, <script>alert('XSS')</script> world!</p>";
        System.out.println(sanitize(html));
    }
}
