```java
import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class HtmlSanitizer {

    private static final String[] ALLOWED_TAGS = {"p", "span", "div", "h1", "h2", "h3", "h4", "h5", "h6", "strong", "em", "u", "s", "a", "img"};
    private static final String[] ALLOWED_ATTRIBUTES = {"href", "src", "alt", "title"};

    public static String sanitize(String html) {
        html = removeComments(html);
        html = removeScripts(html);
        html = removeStyles(html);
        html = removeDisallowedTags(html);
        html = removeDisallowedAttributes(html);
        html = removeOnEvents(html);
        html = encodeSpecialChars(html);
        return html;
    }

    private static String removeComments(String html) {
        Pattern pattern = Pattern.compile("<!--.*?-->");
        Matcher matcher = pattern.matcher(html);
        return matcher.replaceAll("");
    }

    private static String removeScripts(String html) {
        Pattern pattern = Pattern.compile("<script>.*?</script>", Pattern.DOTALL);
        Matcher matcher = pattern.matcher(html);
        return matcher.replaceAll("");
    }

    private static String removeStyles(String html) {
        Pattern pattern = Pattern.compile("<style>.*?</style>", Pattern.DOTALL);
        Matcher matcher = pattern.matcher(html);
        return matcher.replaceAll("");
    }

    private static String removeDisallowedTags(String html) {
        Pattern pattern = Pattern.compile("<(.*?)>");
        Matcher matcher = pattern.matcher(html);
        StringBuffer buffer = new StringBuffer();
        while (matcher.find()) {
            String tag = matcher.group(1);
            if (!isAllowedTag(tag)) {
                matcher.appendReplacement(buffer, "");
            } else {
                matcher.appendReplacement(buffer, "<" + tag + ">");
            }
        }
        matcher.appendTail(buffer);
        return buffer.toString();
    }

    private static boolean isAllowedTag(String tag) {
        for (String allowedTag : ALLOWED_TAGS) {
            if (tag.startsWith(allowedTag)) {
                return true;
            }
        }
        return false;
    }

    private static String removeDisallowedAttributes(String html) {
        Pattern pattern = Pattern.compile("<(.*?) (.*?)>");
        Matcher matcher = pattern.matcher(html);
        StringBuffer buffer = new StringBuffer();
        while (matcher.find()) {
            String tag = matcher.group(1);
            String attributes = matcher.group(2);
            String[] attributeArray = attributes.split(" ");
            StringBuilder allowedAttributes = new StringBuilder();
            for (String attribute : attributeArray) {
                if (isAllowedAttribute(attribute)) {
                    allowedAttributes.append(attribute).append(" ");
                }
            }
            if (allowedAttributes.length() > 0) {
                matcher.appendReplacement(buffer, "<" + tag + " " + allowedAttributes.toString().trim() + ">");
            } else {
                matcher.appendReplacement(buffer, "<" + tag + ">");
            }
        }
        matcher.appendTail(buffer);
        return buffer.toString();
    }

    private static boolean isAllowedAttribute(String attribute) {
        for (String allowedAttribute : ALLOWED_ATTRIBUTES) {
            if (attribute.startsWith(allowedAttribute)) {
                return true;
            }
        }
        return false;
    }

    private static String removeOnEvents(String html) {
        Pattern pattern = Pattern.compile("on\\w+=\".*?\"");
        Matcher matcher = pattern.matcher(html);
        return matcher.replaceAll("");
    }

    private static String encodeSpecialChars(String html) {
        html = html.replace("&", "&amp;");
        html = html.replace("<", "&lt;");
        html = html.replace(">", "&gt;");
        html = html.replace("\"", "&quot;");
        html = html.replace("'", "&#x27;");
        return html;
    }

    public static void main(String[] args) {
        String html = "<p>Hello <script>alert('XSS')</script> World!</p>";
        System.out.println(sanitize(html));
    }
}
