import java.util.ArrayList;
import java.util.List;
import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class HtmlSanitizer {
    private static final String[] ALLOWED_TAGS = {"p", "h1", "h2", "h3", "h4", "h5", "h6", "ul", "ol", "li", "a", "img", "strong", "em", "u", "s"};
    private static final String[] ALLOWED_ATTRIBUTES = {"href", "src", "alt", "title"};

    public static String sanitize(String html) {
        html = removeDisallowedTags(html);
        html = removeDisallowedAttributes(html);
        html = escapeHtml(html);
        return html;
    }

    private static String removeDisallowedTags(String html) {
        Pattern pattern = Pattern.compile("<(.*?)>");
        Matcher matcher = pattern.matcher(html);
        StringBuffer buffer = new StringBuffer();
        while (matcher.find()) {
            String tag = matcher.group(1).split("\\s+")[0];
            boolean isAllowed = false;
            for (String allowedTag : ALLOWED_TAGS) {
                if (tag.equalsIgnoreCase(allowedTag)) {
                    isAllowed = true;
                    break;
                }
            }
            if (isAllowed) {
                matcher.appendReplacement(buffer, "<" + tag + ">");
            } else {
                matcher.appendReplacement(buffer, "");
            }
        }
        matcher.appendTail(buffer);
        return buffer.toString();
    }

    private static String removeDisallowedAttributes(String html) {
        Pattern pattern = Pattern.compile("<(.*?)>");
        Matcher matcher = pattern.matcher(html);
        StringBuffer buffer = new StringBuffer();
        while (matcher.find()) {
            String tag = matcher.group(1);
            String[] attributes = tag.split("\\s+");
            List<String> allowedAttributes = new ArrayList<>();
            for (String attribute : attributes) {
                if (attribute.startsWith("href") || attribute.startsWith("src") || attribute.startsWith("alt") || attribute.startsWith("title")) {
                    allowedAttributes.add(attribute);
                }
            }
            String newTag = attributes[0];
            for (String attribute : allowedAttributes) {
                newTag += " " + attribute;
            }
            matcher.appendReplacement(buffer, "<" + newTag + ">");
        }
        matcher.appendTail(buffer);
        return buffer.toString();
    }

    private static String escapeHtml(String html) {
        return html.replace("&", "&amp;")
                .replace("<", "&lt;")
                .replace(">", "&gt;")
                .replace("\"", "&quot;")
                .replace("'", "&#x27;");
    }

    public static void main(String[] args) {
        String html = "<p>Hello, <script>alert('XSS')</script> world!</p>";
        System.out.println(sanitize(html));
    }
}
