public class Main {
    public static String prevent_xss(String input) {
        String[] patterns = {"<", ">", "&", "\"", "'"};
        String[] replacements = {"&lt;", "&gt;", "&amp;", "&quot;", "&#x27;"};

        for (int i = 0; i < patterns.length; i++) {
            input = input.replaceAll(patterns[i], replacements[i]);
        }

        return input;
    }

    public static void main(String[] args) {
        String userInput = "<script>alert('XSS')</script>";
        String safeInput = prevent_xss(userInput);
        System.out.println(safeInput);
    }
}
