import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class Main {
    public static String preventXss(String input) {
        // Remove script tags
        input = input.replaceAll("(?i)<script>.*?</script>", "");

        // Remove HTML tags
        input = input.replaceAll("\\<.*?\\>", "");

        // Remove JavaScript events
        input = input.replaceAll("(?i)on\\w+=", "");

        // Remove JavaScript code
        input = input.replaceAll("(?i)javascript:", "");

        return input;
    }

    public static void main(String[] args) {
        String userInput = "<script>alert('XSS')</script>";
        String safeInput = preventXss(userInput);
        System.out.println(safeInput);
    }
}
