public class ShellCommandSanitizer {
    public static String sanitize(String command) {
        String[] words = command.split("\\s+");
        StringBuilder sanitizedCommand = new StringBuilder();

        for (String word : words) {
            if (word.contains(";") || word.contains("|") || word.contains("&") || word.contains("$") || word.contains("(") || word.contains(")") || word.contains("`") || word.contains("\\") || word.contains("\"") || word.contains("'")) {
                word = "'" + word.replace("'", "'\\''") + "'";
            }
            sanitizedCommand.append(word).append(" ");
        }

        return sanitizedCommand.toString().trim();
    }

    public static void main(String[] args) {
        System.out.println(sanitize("ls -l; echo hello"));
        System.out.println(sanitize("cp /etc/passwd /tmp/passwd | grep root"));
        System.out.println(sanitize("rm -rf / $"));
    }
}
