```java
public class ShellCommandSanitizer {
    public static String sanitizeCommand(String command) {
        command = command.trim();
        StringBuilder sanitizedCommand = new StringBuilder();

        boolean inQuote = false;
        boolean inEscape = false;
        for (char c : command.toCharArray()) {
            if (inEscape) {
                sanitizedCommand.append(c);
                inEscape = false;
            } else if (c == '\\') {
                sanitizedCommand.append(c);
                inEscape = true;
            } else if (c == '"') {
                inQuote = !inQuote;
                sanitizedCommand.append(c);
            } else if (c == ';' || c == '|' || c == '&' || c == '$' || c == '(' || c == ')') {
                if (!inQuote) {
                    throw new RuntimeException("Invalid character in command: " + c);
                } else {
                    sanitizedCommand.append(c);
                }
            } else {
                sanitizedCommand.append(c);
            }
        }

        if (inEscape) {
            throw new RuntimeException("Unclosed escape sequence");
        }

        if (inQuote) {
            throw new RuntimeException("Unclosed quote");
        }

        return sanitizedCommand.toString();
    }

    public static void main(String[] args) {
        System.out.println(sanitizeCommand("echo 'Hello World'"));
        System.out.println(sanitizeCommand("echo \"Hello World\""));
        try {
            System.out.println(sanitizeCommand("echo 'Hello; World'"));
        } catch (RuntimeException e) {
            System.out.println(e.getMessage());
        }
    }
}
