import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class Main {
    public static void main(String[] args) throws IOException, InterruptedException {
        String userInput = "ls -l"; // example user input
        String[] sanitizedCommand = sanitizeCommand(userInput);
        Process process = Runtime.getRuntime().exec(sanitizedCommand);
        BufferedReader output = new BufferedReader(new InputStreamReader(process.getInputStream()));
        String line;
        while ((line = output.readLine()) != null) {
            System.out.println(line);
        }
        output.close();
        process.waitFor();
    }

    public static String[] sanitizeCommand(String command) {
        String[] parts = command.split("\\s+");
        for (int i = 0; i < parts.length; i++) {
            parts[i] = parts[i].replace(";", "").replace("&", "").replace("|", "").replace("$", "");
        }
        return parts;
    }
}
