import java.io.File;
import java.nio.file.Path;
import java.nio.file.Paths;

public class PathSanitizer {
    public static String sanitize(String inputPath, String baseDirectory) {
        // Normalize the input path
        String normalizedPath = inputPath.replace('\\', '/');

        // Split the input path into components
        String[] components = normalizedPath.split("/");

        // Initialize the sanitized path
        StringBuilder sanitizedPath = new StringBuilder();

        // Iterate over the components
        for (String component : components) {
            // Ignore empty components
            if (component.isEmpty()) {
                continue;
            }

            // Check for parent directory traversal
            if (component.equals("..")) {
                // Remove the last component from the sanitized path
                if (sanitizedPath.length() > 0) {
                    String[] sanitizedComponents = sanitizedPath.toString().split("/");
                    String[] newSanitizedComponents = new String[sanitizedComponents.length - 1];
                    System.arraycopy(sanitizedComponents, 0, newSanitizedComponents, 0, sanitizedComponents.length - 1);
                    sanitizedPath = new StringBuilder(String.join("/", newSanitizedComponents));
                }
            } else if (!component.equals(".")) {
                // Append the component to the sanitized path
                sanitizedPath.append(component).append("/");
            }
        }

        // Remove the trailing slash
        if (sanitizedPath.length() > 0) {
            sanitizedPath.deleteCharAt(sanitizedPath.length() - 1);
        }

        // Resolve the sanitized path
        Path baseDirectoryPath = Paths.get(baseDirectory);
        Path resolvedPath = baseDirectoryPath.resolve(sanitizedPath.toString());

        // Check if the resolved path is within the base directory
        if (!resolvedPath.startsWith(baseDirectoryPath)) {
            throw new SecurityException("Directory traversal attack detected");
        }

        return resolvedPath.toString();
    }

    public static void main(String[] args) {
        String inputPath = "../etc/passwd";
        String baseDirectory = "/home/user/data";
        String sanitizedPath = sanitize(inputPath, baseDirectory);
        System.out.println(sanitizedPath);
    }
}
