```java
import java.io.File;
import java.nio.file.Path;
import java.nio.file.Paths;

public class PathSanitizer {
    private String baseDirectory;

    public PathSanitizer(String baseDirectory) {
        this.baseDirectory = baseDirectory;
    }

    public String sanitize(String inputPath) {
        Path absolutePath = new File(baseDirectory).getAbsoluteFile().toPath();
        Path inputAbsolutePath = new File(inputPath).getAbsoluteFile().toPath();

        String normalizedInputPath = inputAbsolutePath.normalize().toString();
        String sanitizedPath = absolutePath.relativize(Paths.get(normalizedInputPath)).toString();

        if (sanitizedPath.startsWith("..")) {
            throw new RuntimeException("Directory traversal attack detected");
        }

        return baseDirectory + File.separator + sanitizedPath;
    }

    public static void main(String[] args) {
        PathSanitizer sanitizer = new PathSanitizer("/home/user/base");
        System.out.println(sanitizer.sanitize("/home/user/base/subdir/file.txt"));
        System.out.println(sanitizer.sanitize("/home/user/base/../subdir/file.txt"));
        try {
            System.out.println(sanitizer.sanitize("/home/user/../subdir/file.txt"));
        } catch (RuntimeException e) {
            System.out.println(e.getMessage());
        }
    }
}
