```java
import java.io.File;
import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class PathSanitizer {
    public static String sanitizePath(String inputPath, String baseDirectory) {
        // Normalize the input path
        String normalizedPath = normalizePath(inputPath);

        // Resolve the absolute path
        String absolutePath = resolveAbsolutePath(normalizedPath, baseDirectory);

        // Check if the absolute path is within the base directory
        if (!isWithinBaseDirectory(absolutePath, baseDirectory)) {
            throw new SecurityException("Directory traversal attack detected");
        }

        return absolutePath;
    }

    private static String normalizePath(String path) {
        // Remove any redundant separators
        path = path.replaceAll("/+", "/");

        // Remove any parent directory references
        path = path.replaceAll("/\\.{2,}", "");

        // Remove any current directory references
        path = path.replaceAll("/\\.", "");

        return path;
    }

    private static String resolveAbsolutePath(String normalizedPath, String baseDirectory) {
        File baseFile = new File(baseDirectory);
        File absoluteFile = new File(baseFile, normalizedPath);

        return absoluteFile.getAbsolutePath();
    }

    private static boolean isWithinBaseDirectory(String absolutePath, String baseDirectory) {
        File absoluteFile = new File(absolutePath);
        File baseFile = new File(baseDirectory);

        return absoluteFile.getAbsolutePath().startsWith(baseFile.getAbsolutePath());
    }

    public static void main(String[] args) {
        String inputPath = "../etc/passwd";
        String baseDirectory = "/var/www/html";

        try {
            String sanitizedPath = sanitizePath(inputPath, baseDirectory);
            System.out.println(sanitizedPath);
        } catch (SecurityException e) {
            System.out.println(e.getMessage());
        }
    }
}
