import java.io.File;
import java.io.FileNotFoundException;
import java.io.FileReader;
import java.io.IOException;

public class Main {
    public static String securePath(String path) {
        // Normalize the path to eliminate any directory traversal attempts
        File file = new File(path);
        String normalizedPath = file.getCanonicalPath();

        // Check if the normalized path starts with the expected directory
        if (!normalizedPath.startsWith("/expected/directory/")) {
            throw new SecurityException("Path is outside the expected directory");
        }

        return normalizedPath;
    }

    public static void main(String[] args) {
        String userInput = "/../../etc/passwd";
        String sanitizedPath = securePath(userInput);

        try (FileReader reader = new FileReader(sanitizedPath)) {
            int ch;
            while ((ch = reader.read()) != -1) {
                System.out.print((char) ch);
            }
        } catch (FileNotFoundException e) {
            System.out.println("File not found");
        } catch (IOException e) {
            System.out.println("Error reading file");
        } catch (SecurityException e) {
            System.out.println("Invalid path: " + e.getMessage());
        }
    }
}
