import java.io.File;
import java.util.regex.Pattern;

public class Main {
    public static String securePath(String path) {
        // Remove any directory traversal attempts
        path = path.replaceAll("\\.\\./", "");

        // Remove any absolute path attempts
        path = path.replaceAll("^/", "");

        // Remove any Windows-style directory traversal attempts
        path = path.replaceAll("\\\\\\.", "");

        // Remove any Windows-style absolute path attempts
        path = path.replaceAll("^\\\\", "");

        return path;
    }

    public static void main(String[] args) {
        String userProvidedPath = "/../../etc/passwd";
        String sanitizedPath = securePath(userProvidedPath);

        try {
            File file = new File(sanitizedPath);
            if (file.exists()) {
                System.out.println("File exists");
            } else {
                System.out.println("File does not exist");
            }
        } catch (Exception e) {
            System.out.println("Error: " + e.getMessage());
        }
    }
}
