import java.nio.charset.StandardCharsets;
import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.util.Base64;

public class PasswordHasher {

    public static String hashPassword(String password, String salt) throws NoSuchAlgorithmException {
        String passwordWithSalt = password + salt;
        byte[] passwordBytes = passwordWithSalt.getBytes(StandardCharsets.UTF_8);
        MessageDigest md = MessageDigest.getInstance("SHA-256");
        byte[] hashedBytes = md.digest(passwordBytes);
        return Base64.getEncoder().encodeToString(hashedBytes);
    }

    public static String generateSalt() {
        String salt = "";
        for (int i = 0; i < 16; i++) {
            String characters = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789";
            int randomIndex = (int) (Math.random() * characters.length());
            salt += characters.charAt(randomIndex);
        }
        return salt;
    }

    public static boolean verifyPassword(String password, String salt, String hashedPassword) throws NoSuchAlgorithmException {
        String hashedInput = hashPassword(password, salt);
        return hashedInput.equals(hashedPassword);
    }

    public static void main(String[] args) throws NoSuchAlgorithmException {
        String password = "mypassword";
        String salt = generateSalt();
        String hashedPassword = hashPassword(password, salt);
        System.out.println("Salt: " + salt);
        System.out.println("Hashed Password: " + hashedPassword);
        System.out.println("Verification: " + verifyPassword(password, salt, hashedPassword));
    }
}
