```java
import java.nio.charset.StandardCharsets;
import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.security.SecureRandom;

public class PasswordHasher {
    public static String hashPassword(String password, byte[] salt) throws NoSuchAlgorithmException {
        MessageDigest md = MessageDigest.getInstance("SHA-256");
        byte[] passwordBytes = password.getBytes(StandardCharsets.UTF_8);
        byte[] saltedPassword = new byte[salt.length + passwordBytes.length];
        System.arraycopy(salt, 0, saltedPassword, 0, salt.length);
        System.arraycopy(passwordBytes, 0, saltedPassword, salt.length, passwordBytes.length);
        byte[] hashedPassword = md.digest(saltedPassword);
        return bytesToHex(salt) + ":" + bytesToHex(hashedPassword);
    }

    public static String hashPassword(String password) throws NoSuchAlgorithmException {
        SecureRandom random = new SecureRandom();
        byte[] salt = new byte[16];
        random.nextBytes(salt);
        return hashPassword(password, salt);
    }

    public static boolean verifyPassword(String password, String hashedPassword) throws NoSuchAlgorithmException {
        String[] parts = hashedPassword.split(":");
        byte[] salt = hexToBytes(parts[0]);
        String hashedInput = hashPassword(password, salt);
        return hashedInput.equals(hashedPassword);
    }

    private static String bytesToHex(byte[] bytes) {
        StringBuilder sb = new StringBuilder();
        for (byte b : bytes) {
            sb.append(String.format("%02x", b));
        }
        return sb.toString();
    }

    private static byte[] hexToBytes(String hex) {
        int len = hex.length();
        byte[] data = new byte[len / 2];
        for (int i = 0; i < len; i += 2) {
            data[i / 2] = (byte) ((Character.digit(hex.charAt(i), 16) << 4)
                    + Character.digit(hex.charAt(i + 1), 16));
        }
        return data;
    }

    public static void main(String[] args) throws NoSuchAlgorithmException {
        String password = "mysecretpassword";
        String hashedPassword = hashPassword(password);
        System.out.println("Hashed Password: " + hashedPassword);
        System.out.println("Verification: " + verifyPassword(password, hashedPassword));
    }
}
