public class InputSanitizer {
    public static String sanitizeInput(String input) {
        if (input == null) {
            return null;
        }
        String sanitized = input.trim();
        sanitized = removeSpecialChars(sanitized);
        sanitized = replaceMultipleSpacesWithSingleSpace(sanitized);
        sanitized = removeLeadingAndTrailingSpaces(sanitized);
        return sanitized;
    }

    private static String removeSpecialChars(String input) {
        StringBuilder sanitized = new StringBuilder();
        for (char c : input.toCharArray()) {
            if (Character.isLetterOrDigit(c) || Character.isWhitespace(c)) {
                sanitized.append(c);
            }
        }
        return sanitized.toString();
    }

    private static String replaceMultipleSpacesWithSingleSpace(String input) {
        return input.replaceAll(" +", " ");
    }

    private static String removeLeadingAndTrailingSpaces(String input) {
        return input.replaceAll("^ +| +$", "");
    }

    public static void main(String[] args) {
        System.out.println(sanitizeInput("   Hello, World!   "));
        System.out.println(sanitizeInput(null));
        System.out.println(sanitizeInput("Hello   World!"));
        System.out.println(sanitizeInput("Hello, World!"));
    }
}
