import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class MaliciousContentRemover {
    public static String cleanData(String input) {
        // Remove HTML tags
        String cleaned = input.replaceAll("<.*?>", "");

        // Remove script tags
        cleaned = cleaned.replaceAll("(?i)<script>.*?</script>", "");

        // Remove SQL injection attempts
        cleaned = cleaned.replaceAll("(?i)SELECT|INSERT|UPDATE|DELETE|DROP|CREATE|ALTER|TRUNCATE", "");

        // Remove cross-site scripting (XSS) attempts
        cleaned = cleaned.replaceAll("(?i)javascript:|vbscript:|expression:|eval\\(", "");

        // Remove SQL injection and XSS special characters
        cleaned = cleaned.replaceAll("[<>\"'\\;]", "");

        return cleaned;
    }

    public static void main(String[] args) {
        String userInput = "<script>alert('XSS')</script> SELECT * FROM users WHERE id = 1";
        String cleanedInput = cleanData(userInput);
        System.out.println(cleanedInput);
    }
}
