public class Main {
    public static String encryptData(String data, int shift) {
        StringBuilder encryptedData = new StringBuilder();
        for (char c : data.toCharArray()) {
            if (Character.isLetter(c)) {
                char base = Character.isUpperCase(c) ? 'A' : 'a';
                encryptedData.append((char) ((c - base + shift) % 26 + base));
            } else {
                encryptedData.append(c);
            }
        }
        return encryptedData.toString();
    }

    public static String decryptData(String data, int shift) {
        return encryptData(data, 26 - shift);
    }

    public static void main(String[] args) {
        String sensitiveData = "Hello, World!";
        int shift = 3;
        String encrypted = encryptData(sensitiveData, shift);
        System.out.println("Encrypted Data: " + encrypted);
        String decrypted = decryptData(encrypted, shift);
        System.out.println("Decrypted Data: " + decrypted);
    }
}
