import java.util.HashMap;
import java.util.Map;

public class FormDataProcessor {
    public static String processFormData(String name, String email, String message) {
        // Validate input
        if (!validateInput(name, email, message)) {
            return "Invalid input";
        }

        // Sanitize SQL
        String sanitizedSql = sanitizeSql(name, email, message);

        // Escape HTML
        String escapedHtml = escapeHtml(sanitizedSql);

        return escapedHtml;
    }

    private static boolean validateInput(String name, String email, String message) {
        if (name == null || name.isEmpty() || email == null || email.isEmpty() || message == null || message.isEmpty()) {
            return false;
        }
        return true;
    }

    private static String sanitizeSql(String name, String email, String message) {
        Map<String, String> data = new HashMap<>();
        data.put("name", name.replace("'", "''"));
        data.put("email", email.replace("'", "''"));
        data.put("message", message.replace("'", "''"));
        return data.toString();
    }

    private static String escapeHtml(String input) {
        return input.replace("&", "&amp;").replace("<", "&lt;").replace(">", "&gt;");
    }

    public static void main(String[] args) {
        System.out.println(processFormData("John Doe", "johndoe@example.com", "Hello World!"));
    }
}
