import java.util.HashMap;
import java.util.Map;
import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class Main {

    public static String sanitizeSql(String input) {
        input = input.replace(";", "");
        input = input.replace("--", "");
        return input;
    }

    public static String escapeHtml(String input) {
        input = input.replace("&", "&amp;");
        input = input.replace("<", "&lt;");
        input = input.replace(">", "&gt;");
        input = input.replace("\"", "&quot;");
        return input;
    }

    public static boolean validateInput(String input) {
        Pattern pattern = Pattern.compile("^[a-zA-Z0-9]+$");
        Matcher matcher = pattern.matcher(input);
        return matcher.matches();
    }

    public static Map<String, String> processFormData(Map<String, String> formData) {
        Map<String, String> processedData = new HashMap<>();

        for (Map.Entry<String, String> entry : formData.entrySet()) {
            String key = entry.getKey();
            String value = entry.getValue();

            if (validateInput(value)) {
                value = sanitizeSql(value);
                value = escapeHtml(value);
                processedData.put(key, value);
            } else {
                processedData.put(key, "Invalid input");
            }
        }

        return processedData;
    }

    public static void main(String[] args) {
        Map<String, String> formData = new HashMap<>();
        formData.put("name", "John Doe");
        formData.put("age", "30");
        formData.put("description", "<script>alert('Hello World')</script>");

        Map<String, String> processedData = processFormData(formData);

        for (Map.Entry<String, String> entry : processedData.entrySet()) {
            System.out.println(entry.getKey() + ": " + entry.getValue());
        }
    }
}
