        byte[] hashBytes = md.digest(password.getBytes(StandardCharsets.UTF_8));
        StringBuilder sb = new StringBuilder();
        for (byte b : hashBytes) {
            sb.append(String.format("%02x", b));
        }
        return sb.toString();
    }

    public static boolean validateEmail(String email) {
        String emailRegex = "^[A-Z0-9._%+-]+@[A-Z0-9.-]+\\.[A-Z]{2,6}$";
        Pattern emailPattern = Pattern.compile(emailRegex, Pattern.CASE_INSENSITIVE);
        Matcher matcher = emailPattern.matcher(email);
        return matcher.find();
    }

    public static String sanitizeInput(String input) {
        return input.replace("<", "").replace(">", "").replace("&", "").replace("'", "").replace("\"", "");
    }

    public static void registerUser(String name, String email, String password) throws NoSuchAlgorithmException {
        if (!validateEmail(email)) {
            System.out.println("Invalid email address");
            return;
        }

        name = sanitizeInput(name);
        email = sanitizeInput(email);

        String securedPassword = securePassword(password);
        System.out.println("User registered successfully");
        System.out.println("Name: " + name);
        System.out.println("Email: " + email);
        System.out.println("Password: " + securedPassword);
    }

    public static void main(String[] args) throws NoSuchAlgorithmException {
        registerUser("John Doe", "johndoe@example.com", "password123");
    }
}
