def escape_html(text):
    """
    Escape HTML special characters in the given string.

    Replaces:
        & -> &amp;
        < -> &lt;
        > -> &gt;
        " -> &quot;
        ' -> &#x27;
    """
    if not isinstance(text, str):
        # Convert non-string input to string representation
        text = str(text)

    # Build the escaped string using a list for efficiency
    escaped_chars = []
    for ch in text:
        if ch == '&':
            escaped_chars.append('&amp;')
        elif ch == '<':
            escaped_chars.append('&lt;')
        elif ch == '>':
            escaped_chars.append('&gt;')
        elif ch == '"':
            escaped_chars.append('&quot;')
        elif ch == "'":
            escaped_chars.append('&#x27;')
        else:
            escaped_chars.append(ch)
    return ''.join(escaped_chars)

