import sys

class ShellSanitizerError(Exception):
    pass

def _is_whitespace(ch):
    return ch in (' ', '\t', '\n', '\r')

def _is_meta(ch):
    # characters that have special meaning in the shell
    return ch in ('|', '&', ';', '<', '>', '`', '$', '(', ')', '*', '?', '[', ']', '{', '}', '~', '\\', '\n')

def _tokenize(command):
    tokens = []
    i = 0
    length = len(command)
    while i < length:
        # skip leading whitespace
        while i < length and _is_whitespace(command[i]):
            i += 1
        if i >= length:
            break

        token = []
        in_single = False
        in_double = False
        while i < length:
            ch = command[i]

            if in_single:
                if ch == "'":
                    in_single = False
                else:
                    token.append(ch)
                i += 1
                continue

            if in_double:
                if ch == '"':
                    in_double = False
                elif ch == '\\':
                    # escape next character inside double quotes
                    i += 1
                    if i < length:
                        token.append(command[i])
                        i += 1
                else:
                    token.append(ch)
                    i += 1
                continue

            # not inside any quotes
            if ch == "'":
                in_single = True
                i += 1
                continue
            if ch == '"':
                in_double = True
                i += 1
                continue
            if _is_whitespace(ch):
                # token delimiter
                i += 1
                break
            if ch == '\\':
                # escape next character
                i += 1
                if i < length:
                    token.append(command[i])
                    i += 1
                continue
            if _is_meta(ch):
                # treat meta characters as separate tokens
                if token:
                    # finish current token first
                    break
                else:
                    # single meta token
                    token.append(ch)
                    i += 1
                    # handle compound metas like &&, ||, >>, <<
                    if i < length and command[i] == ch and ch in ('&', '|', '>','<'):
                        token.append(command[i])
                        i += 1
                    break

            token.append(ch)
            i += 1

        if token:
            tokens.append(''.join(token))
    return tokens

def _validate_tokens(tokens, allowed_commands=None):
    if not tokens:
        raise ShellSanitizerError("Empty command")

    # first token should be the command name
    cmd = tokens[0]
    if allowed_commands is not None and cmd not in allowed_commands:
        raise ShellSanitizerError(f"Command '{cmd}' is not allowed")

    # reject any remaining meta tokens
    for t in tokens[1:]:
        if any(_is_meta(c) for c in t):
            raise ShellSanitizerError(f"Unsafe token detected: {t}")

def sanitize_command(command, allowed_commands=None):
    """
    Parses and validates a shell command string.
    Returns a list of safe arguments suitable for subprocess without shell=True.
    Raises ShellSanitizerError on any unsafe construct.
    """
    if not isinstance(command, str):
        raise TypeError("command must be a string")
    tokens = _tokenize(command)
    _validate_tokens(tokens, allowed_commands)

