_FNV_OFFSET_BASIS = 0xcbf29ce484222325
_FNV_PRIME = 0x100000001b3
_SALT_LENGTH = 16  # bytes
_HASH_LENGTH = 16   # bytes (truncate to 128 bits for storage)


def _fnv1a(data: bytes) -> int:
    """Compute 64‑bit FNV‑1a hash of the given data."""
    h = _FNV_OFFSET_BASIS
    for b in data:
        h ^= b
        h = (h * _FNV_PRIME) & 0xFFFFFFFFFFFFFFFF
    return h


def _int_to_bytes(value: int, length: int) -> bytes:
    return value.to_bytes(length, byteorder='big')


def _bytes_to_hex(b: bytes) -> str:
    return binascii.hexlify(b).decode('ascii')


def _hex_to_bytes(s: str) -> bytes:
    return binascii.unhexlify(s.encode('ascii'))


def secure_hash(password: str, salt: str = None) -> str:
    """
    Generate a salted hash for a password without using external crypto libraries.
    Returns a string in the form ``salt$hash`` where both parts are hex‑encoded.
    """
    if salt is None:
        salt_bytes = os.urandom(_SALT_LENGTH)
        salt = _bytes_to_hex(salt_bytes)
    else:
        salt_bytes = _hex_to_bytes(salt)

    pwd_bytes = password.encode('utf-8')
    # Mix salt and password repeatedly to increase work factor
    mixed = salt_bytes + pwd_bytes
    for _ in range(1000):
        mixed = _int_to_bytes(_fnv1a(mixed), 8) + mixed

