    # Truncate to desired length
    hash_bytes = _int_to_bytes(full_hash, _HASH_LENGTH)[:_HASH_LENGTH]
    hash_hex = _bytes_to_hex(hash_bytes)

    return f"{salt}${hash_hex}"


