def _remove_control_chars(s: str) -> str:
    # Keep printable characters and common whitespace (tab, newline, carriage return)
    allowed_whitespace = {'\t', '\n', '\r'}
    return ''.join(ch for ch in s if (32 <= ord(ch) <= 126) or ch in allowed_whitespace)

def _sanitize_string(s: str) -> str:
    s = _remove_control_chars(s)
    s = _escape_html(s)
    return s

def sanitize(input_data):
    """
    Recursively sanitizes user input.
    - Strings are stripped of control characters and HTML-escaped.
    - Containers (dict, list, tuple, set) are processed element‑wise.
    - Other data types are returned unchanged.
    """
    if isinstance(input_data, str):
        return _sanitize_string(input_data)
    if isinstance(input_data, dict):
        return {sanitize(k): sanitize(v) for k, v in input_data.items()}
    if isinstance(input_data, (list, tuple, set)):
        sanitized = (sanitize(item) for item in input_data)
        return type(input_data)(sanitized)
    # For numbers, booleans, None, etc., return as‑is
    return input_data

def sanitize_input(data):
    """Sanitize user-provided data."""
    import html
    if isinstance(data, str):
        return html.escape(data.strip())
    if isinstance(data, dict):
        return {k: sanitize_input(v) for k, v in data.items()}
    if isinstance(data, list):
        return [sanitize_input(item) for item in data]
    return data

def process_user_data(raw_data):
    """Clean and process user data."""
    clean_data = sanitize_input(raw_data)
    # Example processing: just return the cleaned data
    return clean_data

if __name__ == "__main__":
    user_input = input("Enter data: ")
    result = process_user_data(user_input)
    print("Processed:", result)

import base64
from typing import Union

def _xor_bytes(data: bytes, key: bytes) -> bytes:
    """XOR each byte of data with the key (repeating the key as necessary)."""
    return bytes(b ^ key[i % len(key)] for i, b in enumerate(data))

def encrypt_data(plaintext: Union[str, bytes], key: Union[str, bytes]) -> str:
    """
    Encrypts the given plaintext using a simple XOR cipher with the provided key.
    The result is returned as a URL-safe base64-encoded string.

    Args:
        plaintext: The data to encrypt. Can be a string (UTF-8) or raw bytes.
        key: The encryption key. Must be non-empty. Can be a string (UTF-8) or raw bytes.

    Returns:
        A URL-safe base64-encoded string representing the encrypted data.

    Note:
        This is NOT a secure encryption method for production use.
        It is provided only as a lightweight alternative when no crypto library is available.
    """
    if isinstance(plaintext, str):
        plaintext_bytes = plaintext.encode('utf-8')
    else:
        plaintext_bytes = bytes(plaintext)

    if isinstance(key, str):
        key_bytes = key.encode('utf-8')
    else:
        key_bytes = bytes(key)

    if not key_bytes:
        raise ValueError("Key must not be empty")

    encrypted_bytes = _xor_bytes(plaintext_bytes, key_bytes)
    return base64.urlsafe_b64encode(encrypted_bytes).decode('utf-8')

def decrypt_data(ciphertext: str, key: Union[str, bytes]) -> str:
    """
    Decrypts data that was encrypted with `encrypt_data`.

    Args:
        ciphertext: The base64-encoded string produced by `encrypt_data`.
        key: The same key used for encryption.

    Returns:
        The original plaintext string.

    Raises:
        ValueError: If the ciphertext cannot be base64-decoded.
    """
    if isinstance(key, str):
        key_bytes = key.encode('utf-8')
    else:
        key_bytes = bytes(key)

    if not key_bytes:
        raise ValueError("Key must not be empty")

    try:
        encrypted_bytes = base64.urlsafe_b64decode(ciphertext.encode('utf-8'))
    except Exception as exc:
        raise ValueError("Invalid base64 ciphertext") from exc

    decrypted_bytes = _xor_bytes(encrypted_bytes, key_bytes)
    return decrypted_bytes.decode('utf-8')

def encrypt_user_data(data):
    return secure_encrypt(data)

if __name__ == "__main__":
    user_data = input("Enter data to encrypt: ")
    encrypted = encrypt_user_data(user_data)
    print("Encrypted data:", encrypted)

def process_form_data(form_data):
    """
    Process form data by validating, sanitizing for SQL, and escaping HTML.

    Args:
        form_data (dict): Dictionary of form field names to values.

    Returns:
        dict: Processed form data with SQL sanitization and HTML escaping applied.

    Raises:
        ValueError: If validation fails.
    """
    # Validate the input data
    if not validate_input(form_data):
        raise ValueError("Invalid form data")

    # Sanitize each value for SQL injection protection
    sql_sanitized = {
        key: sanitize_sql(value) if isinstance(value, str) else value
        for key, value in form_data.items()
    }

    # Escape HTML characters to prevent XSS
    escaped = {
        key: escape_html(value) if isinstance(value, str) else value
        for key, value in sql_sanitized.items()
    }

    return escaped

