import re
import bcrypt
import html
import json
from pathlib import Path

USER_DB_PATH = Path("users.json")

def load_user_db():
    if USER_DB_PATH.exists():
        with USER_DB_PATH.open("r", encoding="utf-8") as f:
            return json.load(f)
    return {}

def save_user_db(db):
    with USER_DB_PATH.open("w", encoding="utf-8") as f:
        json.dump(db, f, ensure_ascii=False, indent=2)

def secure_password(password: str) -> bytes:
    """
    Hashes a password using bcrypt.
    Returns the hashed password as bytes.
    """
    if not isinstance(password, str):
        raise TypeError("Password must be a string")
    password_bytes = password.encode("utf-8")
    salt = bcrypt.gensalt()
    hashed = bcrypt.hashpw(password_bytes, salt)
    return hashed

def validate_email(email: str) -> bool:
    """
    Validates an email address using a regex pattern.
    Returns True if valid, False otherwise.
    """
    if not isinstance(email, str):
        return False
    email = email.strip()
    pattern = re.compile(
        r"(^[a-zA-Z0-9!#$%&'*+/=?^_`{|}~-]+"
        r"(?:\.[a-zA-Z0-9!#$%&'*+/=?^_`{|}~-]+)*"
        r"@"
        r"(?:[a-zA-Z0-9-]+\.)+[a-zA-Z]{2,}$)"
    )
    return bool(pattern.match(email))

def sanitize_input(user_input: str) -> str:
    """
    Sanitizes user input to prevent XSS and other injection attacks.
    Escapes HTML characters and strips leading/trailing whitespace.
    """
    if not isinstance(user_input, str):
        raise TypeError("Input must be a string")
    escaped = html.escape(user_input, quote=True)
    return escaped.strip()

def register_user(username: str, password: str, email: str) -> dict:
    """
    Registers a new user after validating and sanitizing inputs.
    Returns a dict with the result status and message.
    """
    # Load existing users
    users = load_user_db()

    # Sanitize username
    username_clean = sanitize_input(username)
    if not username_clean:
        return {"success": False, "message": "Username cannot be empty."}
    if username_clean in users:
        return {"success": False, "message": "Username already exists."}

    # Validate email
    if not validate_email(email):
        return {"success": False, "message": "Invalid email address."}
    email_clean = sanitize_input(email)

    # Secure password
    try:
        hashed_pw = secure_password(password)
    except Exception as e:
        return {"success": False, "message": f"Password error: {str(e)}"}

    # Store user
    users[username_clean] = {
        "email": email_clean,
        "password_hash": hashed_pw.decode("utf-8")  # store as string for JSON
    }
    save_user_db(users)

    return {"success": True, "message": "User registered successfully."}

