function sanitizeSQL(value) {
  if (value === null || value === undefined) return 'NULL';
  let str = String(value);
  // Escape backslashes
  str = str.replace(/\\/g, '\\\\');
  // Escape single quotes by doubling them
  str = str.replace(/'/g, "''");
  // Escape double quotes (optional, for some DBs)
  str = str.replace(/"/g, '\\"');
  // Escape NUL byte
  str = str.replace(/\0/g, '\\0');
  // Escape common whitespace characters
  str = str.replace(/\n/g, '\\n')
           .replace(/\r/g, '\\r')
           .replace(/\t/g, '\\t');
  // Escape other control characters (ASCII 0x01-0x1F)
  str = str.replace(/[\x01-\x1F]/g, function(ch) {
    const hex = ch.charCodeAt(0).toString(16).padStart(2, '0');
    return '\\x' + hex;
  });
  // Return the safely quoted string
  return "'" + str + "'";
}

function sanitizeSQL(input) {
    if (input === null || input === undefined) {
        return 'NULL';
    }
    const str = String(input);
    const map = {
        "\0": "\\0",
        "\b": "\\b",
        "\t": "\\t",
        "\n": "\\n",
        "\r": "\\r",
        "\x1a": "\\Z",
        "'": "''",
        "\"": "\\\"",
        "\\": "\\\\",
        "%": "\\%",
        "_": "\\_",
        ";": "\\;",
        "--": "\\--"
    };
    // Replace each character based on the map
    const escaped = str.replace(/[\0\b\t\n\r\x1a'\"\\%_;-]/g, function (char) {
        // Handle the double-dash comment escape separately
        if (char === "-" && str.substr(this.lastIndex - 1, 2) === "--") {
            return map["--"];
        }
        return map[char] !== undefined ? map[char] : char;
    });
    return "'" + escaped + "'";
}

