function sql_escape(value) {
    if (value === null || value === undefined) return 'NULL';
    const type = typeof value;

    if (type === 'number' || type === 'bigint') {
        return value.toString();
    }
    if (type === 'boolean') {
        return value ? 'TRUE' : 'FALSE';
    }
    if (value instanceof Date) {
        // Format as MySQL datetime literal
        const pad = n => n < 10 ? '0' + n : n;
        const y = value.getFullYear();
        const m = pad(value.getMonth() + 1);
        const d = pad(value.getDate());
        const h = pad(value.getHours());
        const min = pad(value.getMinutes());
        const s = pad(value.getSeconds());
        return `'${y}-${m}-${d} ${h}:${min}:${s}'`;
    }

    // Treat everything else as string
    const str = value.toString();
    const escaped = str.replace(/[\0\x08\x09\x1a\n\r"'\\%_]/g, function (char) {
        switch (char) {
            case "\0": return "\\0";
            case "\b": return "\\b";
            case "\t": return "\\t";
            case "\x1a": return "\\Z";
            case "\n": return "\\n";
            case "\r": return "\\r";
            case "\"":
            case "'":
            case "\\":
                return "\\" + char;
            case "%":
            case "_":
                return "\\" + char;
            default:
                return char;
        }
    });
    return `'${escaped}'`;
}

