  const allowedTags = {
    a: ["href", "title", "target", "rel"],
    b: [],
    strong: [],
    i: [],
    em: [],
    u: [],
    p: [],
    br: [],
    ul: [],
    ol: [],
    li: [],
    span: [],
    div: [],
    img: ["src", "alt", "title", "width", "height"],
    h1: [], h2: [], h3: [], h4: [], h5: [], h6: [],
    table: [], thead: [], tbody: [], tr: [], th: [], td: [],
    blockquote: [], code: [], pre: [], hr: [], small: [], sub: [], sup: [], mark: [], del: [], ins: []
  };

  const allowedSchemes = ["http:", "https:", "mailto:", "tel:", "data:"];
  const allowedDataImageTypes = ["image/png", "image/jpeg", "image/gif", "image/webp"];

  const isValidUrl = (url) => {
    try {
      const parsed = new URL(url, location.origin);
      if (allowedSchemes.includes(parsed.protocol)) {
        if (parsed.protocol === "data:") {
          const [, mime] = parsed.pathname.split(";")[0].split(":");
          return allowedDataImageTypes.includes(mime);
        }
        return true;
      }
    } catch (_) {}
    return false;
  };

  const sanitizeAttribute = (el, attrName, attrValue) => {
    const lowerName = attrName.toLowerCase();

    // Remove any event handlers
    if (lowerName.startsWith("on")) return null;

    // Remove javascript: and other dangerous protocols
    if (["href", "src", "action", "formaction", "xlink:href"].includes(lowerName)) {
      const trimmed = attrValue.trim().replace(/\s+/g, "");
      if (!isValidUrl(trimmed)) return null;
      return { name: lowerName, value: trimmed };
    }

    // Style sanitization – strip any url() or expression()
    if (lowerName === "style") {
      // Simple regex to block url() and expression()
