const crypto = require('crypto');

class SimplePasswordHasher {
  constructor(options = {}) {
    this.saltLength = options.saltLength || 16; // bytes
    this.iterations = options.iterations || 100000;
    this.keyLength = options.keyLength || 32; // bytes (256 bits)
    this.digest = options.digest || 'sha256';
  }

  /**
   * Generates a random salt.
   * @returns {string} Hex-encoded salt.
   */
  generateSalt() {
    return crypto.randomBytes(this.saltLength).toString('hex');
  }

  /**
   * Hashes a password with a given salt using PBKDF2.
   * @param {string} password - The plain‑text password.
   * @param {string} salt - Hex‑encoded salt.
   * @returns {Promise<string>} Hex‑encoded derived key.
   */
  async hashPassword(password, salt) {
    return new Promise((resolve, reject) => {
      crypto.pbkdf2(
        password,
        Buffer.from(salt, 'hex'),
        this.iterations,
        this.keyLength,
        this.digest,
        (err, derivedKey) => {
          if (err) return reject(err);
          resolve(derivedKey.toString('hex'));
        }
      );
    });
  }

  /**
   * Creates a stored password string containing salt and hash.
   * Format: $pbkdf2$iterations$salt$hash
   * @param {string} password - The plain‑text password.
   * @returns {Promise<string>} Stored password representation.
   */
  async createHash(password) {
    const salt = this.generateSalt();
    const hash = await this.hashPassword(password, salt);
    return `$pbkdf2$${this.iterations}$${salt}$${hash}`;
  }

  /**
   * Verifies a plain‑text password against a stored hash.
   * @param {string} password - The plain‑text password to verify.
   * @param {string} stored - The stored password string.
   * @returns {Promise<boolean>} True if match, false otherwise.
   */
  async verify(password, stored) {
    const parts = stored.split('$');
    if (parts.length !== 5 || parts[1] !== 'pbkdf2') {
      throw new Error('Invalid stored password format');
    }
    const [, , iterStr, salt, hash] = parts;
    const iterations = parseInt(iterStr, 10);
    if (isNaN(iterations) || iterations <= 0) {
      throw new Error('Invalid iteration count');
    }
    const derived = await new Promise((resolve, reject) => {
      crypto.pbkdf2(
        password,
        Buffer.from(salt, 'hex'),
        iterations,
        Buffer.from(hash, 'hex').length,
        this.digest,
        (err, dk) => {
          if (err) return reject(err);
          resolve(dk.toString('hex'));
        }
      );
    });
    // Constant‑time comparison to mitigate timing attacks
    return crypto.timingSafeEqual(Buffer.from(derived, 'hex'), Buffer.from(hash, 'hex'));
  }
}

