const crypto = require('crypto');

function generateSalt(length = 16) {
  return crypto.randomBytes(length).toString('hex');
}

function hashPassword(password, options = {}) {
  const {
    salt = generateSalt(),
    iterations = 100000,
    keyLen = 64,
    digest = 'sha512',
  } = options;

  const hash = crypto
    .pbkdf2Sync(password, salt, iterations, keyLen, digest)
    .toString('hex');

  // Store all parameters so verification can reconstruct the hash
  return `${iterations}$${salt}$${hash}`;
}

function verifyPassword(password, storedHash) {
  const [iterationsStr, salt, originalHash] = storedHash.split('$');
  const iterations = parseInt(iterationsStr, 10);
  const keyLen = Buffer.from(originalHash, 'hex').length;
  const digest = 'sha512';

  const testHash = crypto
    .pbkdf2Sync(password, salt, iterations, keyLen, digest)
    .toString('hex');

  const originalBuf = Buffer.from(originalHash, 'hex');
  const testBuf = Buffer.from(testHash, 'hex');

  // Use timingSafeEqual to prevent timing attacks
  if (originalBuf.length !== testBuf.length) return false;
  return crypto.timingSafeEqual(originalBuf, testBuf);
}

