function secure_hash(password) {
  // FNV-1a 64-bit hash implementation using BigInt
  const FNV_OFFSET_BASIS = 14695981039346656037n;
  const FNV_PRIME = 1099511628211n;
  const MOD_MASK = (1n << 64n) - 1n; // keep within 64 bits

  let hash = FNV_OFFSET_BASIS;
  for (let i = 0; i < password.length; i++) {
    hash ^= BigInt(password.charCodeAt(i));
    hash = (hash * FNV_PRIME) & MOD_MASK;
  }

  // Produce a hex string (16 characters for 64 bits)
  let hex = hash.toString(16);
  return hex.padStart(16, '0');
}

