  }
  try {
    const isValid = validate_token(token); // assumes validate_token is defined elsewhere
    if (!isValid) {
      return res.status(401).json({ error: 'Invalid token' });
    }
    next();
  } catch (err) {
    return res.status(401).json({ error: 'Token validation error' });
  }
}

