function strToBytes(str) {
  const encoder = new TextEncoder();
  return encoder.encode(str);
}
function bytesToStr(bytes) {
  const decoder = new TextDecoder();
  return decoder.decode(bytes);
}
function bytesToBase64(bytes) {
  let binary = "";
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}
function base64ToBytes(b64) {
  const binary = atob(b64);
  const len = binary.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binary.charCodeAt(i);
  }
  return bytes;
}
function deriveKey(passwordBytes, length) {
  const key = new Uint8Array(length);
  for (let i = 0; i < length; i++) {
    key[i] = passwordBytes[i % passwordBytes.length];
  }
  return key;
}
function encrypt_data(plainText, password) {
  // WARNING: This is a very weak XOR‑based encryption.
  // Do NOT use for real sensitive data.
  const plainBytes = strToBytes(plainText);
  const passwordBytes = strToBytes(password);
  const key = deriveKey(passwordBytes, plainBytes.length);
  const cipherBytes = new Uint8Array(plainBytes.length);
  for (let i = 0; i < plainBytes.length; i++) {
    cipherBytes[i] = plainBytes[i] ^ key[i];
  }
  return bytesToBase64(cipherBytes);
}
function decrypt_data(cipherBase64, password) {
  const cipherBytes = base64ToBytes(cipherBase64);
  const passwordBytes = strToBytes(password);
  const key = deriveKey(passwordBytes, cipherBytes.length);
  const plainBytes = new Uint8Array(cipherBytes.length);
  for (let i = 0; i < cipherBytes.length; i++) {
    plainBytes[i] = cipherBytes[i] ^ key[i];
  }
  return bytesToStr(plainBytes);
}

