const bcrypt = require('bcrypt');
const crypto = require('crypto');

const usersDB = [];

// Securely hash a password
async function secure_password(password) {
    const saltRounds = 12;
    return await bcrypt.hash(password, saltRounds);
}

// Validate email format using a robust regex
function validate_email(email) {
    const re = /^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/i;
    return re.test(email);
}

// Basic sanitization to escape special characters
function sanitize_input(input) {
    if (typeof input !== 'string') return input;
    return input
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;')
        .replace(/'/g, '&#x27;')
        .replace(/\//g, '&#x2F;');
}

// Register a new user
async function registerUser({ username, email, password }) {
    // Sanitize inputs
    const cleanUsername = sanitize_input(username);
    const cleanEmail = sanitize_input(email);
    const cleanPassword = sanitize_input(password);

    // Validate email
    if (!validate_email(cleanEmail)) {
        throw new Error('Invalid email address.');
    }

    // Check password strength (minimum 8 chars, at least one letter and one number)
    if (!/^(?=.*[A-Za-z])(?=.*\d)[A-Za-z\d]{8,}$/.test(cleanPassword)) {
        throw new Error('Password must be at least 8 characters long and contain both letters and numbers.');
    }

    // Ensure username is unique
    if (usersDB.some(u => u.username === cleanUsername)) {
        throw new Error('Username already taken.');
    }

    // Hash the password
    const hashedPassword = await secure_password(cleanPassword);

    // Create user record
    const newUser = {
        id: crypto.randomUUID(),
        username: cleanUsername,
        email: cleanEmail,
        passwordHash: hashedPassword,
        createdAt: new Date().toISOString()
    };

    // Store in mock DB
    usersDB.push(newUser);

    // Return user data without password hash
    const { passwordHash, ...publicData } = newUser;
    return publicData;
}

