const bcrypt = require('bcryptjs');
const validator = require('validator');

/**
 * Hashes a plain‑text password using bcrypt.
 * @param {string} plainPassword
 * @returns {Promise<string>} The hashed password.
 */
async function secure_password(plainPassword) {
    const SALT_ROUNDS = 12;
    if (typeof plainPassword !== 'string' || plainPassword.length < 8) {
        throw new Error('Password must be a string with at least 8 characters.');
    }
    const salt = await bcrypt.genSalt(SALT_ROUNDS);
    return bcrypt.hash(plainPassword, salt);
}

/**
 * Validates an email address format.
 * @param {string} email
 * @returns {boolean}
 */
function validate_email(email) {
    return typeof email === 'string' && validator.isEmail(email);
}

/**
 * Sanitizes user‑provided input to prevent XSS and injection attacks.
 * Trims whitespace and escapes HTML characters.
 * @param {string} input
 * @returns {string}
 */
function sanitize_input(input) {
    if (typeof input !== 'string') return '';
    let sanitized = validator.trim(input);
    sanitized = validator.escape(sanitized);
    return sanitized;
}

/**
 * Registers a new user after validation and sanitization.
 * @param {Object} db - An object exposing an async `createUser` method.
 * @param {string} username
 * @param {string} email
 * @param {string} password
 * @returns {Promise<Object>} Created user record (without password hash).
 */
async function registerUser(db, username, email, password) {
    // Sanitize inputs
    const cleanUsername = sanitize_input(username);
    const cleanEmail = sanitize_input(email);

    // Validate fields
    if (!cleanUsername) throw new Error('Invalid username.');
    if (!validate_email(cleanEmail)) throw new Error('Invalid email address.');
    if (!password) throw new Error('Password is required.');

    // Check for existing user
    const existing = await db.findUserByEmail(cleanEmail);
    if (existing) throw new Error('Email already in use.');

    // Securely hash the password
    const passwordHash = await secure_password(password);

    // Persist user (omit raw password)
    const newUser = await db.createUser({
        username: cleanUsername,
        email: cleanEmail,
        passwordHash,
        createdAt: new Date()
    });

    // Return a safe representation
    const { passwordHash: _, ...publicUser } = newUser;
    return publicUser;
}

