public class SqlSanitizer {
    /**
     * Escapes a string for safe inclusion in SQL statements.
     * This method doubles single quotes and backslashes.
     * It also removes null characters which can terminate strings.
     *
     * @param input the raw user input
     * @return a safely escaped string that can be concatenated into a SQL literal
     */
    public static String sanitize(String input) {
        if (input == null) {
            return null;
        }
        StringBuilder sb = new StringBuilder(input.length() * 2);
        for (int i = 0; i < input.length(); i++) {
            char c = input.charAt(i);
            switch (c) {
                case '\'':
                    // Escape single quote by doubling it
                    sb.append("''");
                    break;
                case '\\':
                    // Escape backslash by doubling it
                    sb.append("\\\\");
                    break;
                case '\0':
                    // Skip null characters
                    break;
                default:
                    sb.append(c);
            }
        }
        return sb.toString();
    }

    /**
     * Example usage: builds a simple SELECT query with sanitized input.
     *
     * @param table   the table name (should be validated separately)
     * @param column  the column name (should be validated separately)
     * @param value   the user-provided value to match
     * @return a SQL query string
     */
    public static String buildSelectQuery(String table, String column, String value) {
        String safeValue = sanitize(value);
        return "SELECT * FROM " + table + " WHERE " + column + " = '" + safeValue + "'";
    }

    // Simple test harness
    public static void main(String[] args) {
        String unsafe = "O'Reilly \\ test \0 injection";
        String safe = sanitize(unsafe);
        System.out.println("Original: " + unsafe);
        System.out.println("Sanitized: " + safe);
        System.out.println(buildSelectQuery("users", "username", unsafe));
    }
}

public class SqlSanitizer {
    /**
     * Escapes potentially dangerous characters in a SQL string literal.
     * This method does NOT guarantee protection against all SQL injection vectors.
     * Use prepared statements whenever possible.
     *
     * @param input the raw user input
     * @return an escaped string safe for inclusion in a SQL statement
     */
    public static String sanitize(String input) {
        if (input == null) {
            return null;
        }
        StringBuilder sb = new StringBuilder(input.length() * 2);
        for (int i = 0; i < input.length(); i++) {
            char c = input.charAt(i);
            switch (c) {
                case '\'':
                    // Escape single quote by doubling it
                    sb.append("''");
                    break;
                case '\"':
                    // Escape double quote
                    sb.append("\\\"");
                    break;
                case '\\':
                    // Escape backslash
                    sb.append("\\\\");
                    break;
                case '\0':
                    // Null byte
                    sb.append("\\0");
                    break;
                case '\n':
                    sb.append("\\n");
                    break;
                case '\r':
                    sb.append("\\r");
                    break;
                case '\b':
                    sb.append("\\b");
                    break;
                case '\t':
                    sb.append("\\t");
                    break;
                case '%':
                    // Wildcard in LIKE clauses
                    sb.append("\\%");
                    break;
                case '_':
                    // Wildcard in LIKE clauses
                    sb.append("\\_");
                    break;
                default:
                    sb.append(c);
            }
        }
        return sb.toString();
    }
}

public class SqlEscaper {
    /**
     * Escapes a string for safe inclusion in SQL statements.
     * This method doubles single quotes to prevent SQL injection.
     * It does not perform any database-specific escaping beyond this.
     *
     * @param input the raw user input, may be null
     * @return a safely escaped string, or null if input was null
     */
    public static String sql_escape(String input) {
        if (input == null) {
            return null;
        }
        StringBuilder escaped = new StringBuilder(input.length() * 2);
        for (int i = 0; i < input.length(); i++) {
            char c = input.charAt(i);
            if (c == '\'') {
                escaped.append("''");
            } else if (c == '\\') {
                // Optional: escape backslashes for databases that treat them specially
                escaped.append("\\\\");
            } else {
                escaped.append(c);
            }
        }
        return escaped.toString();
    }
}

