        response.getWriter().write("<!DOCTYPE html>");
        response.getWriter().write("<html><head><title>Safe Output</title></head><body>");
        response.getWriter().write("<p>User Input: " + safeInput + "</p>");
        response.getWriter().write("</body></html>");
    }
}

import re
import sys

class ShellCommandSanitizer:
    _allowed_pattern = re.compile(r'^[a-zA-Z0-9_\-./@:=+%$,\'" ]+$')
    _dangerous_chars = {
        ';': r'\;',
        '&': r'\&',
        '|': r'\|',
        '`': r'\`',
        '$': r'\$',
        '>': r'\>',
        '<': r'\<',
        '*': r'\*',
        '?': r'\?',
        '~': r'\~',
        '(': r'\(',
        ')': r'\)',
        '[': r'\[',
        ']': r'\]',
        '{': r'\{',
        '}': r'\}',
        '\\': r'\\',
        '\n': r' ',
        '\r': r' '
    }

    @classmethod
    def sanitize(cls, command: str) -> str:
        if not isinstance(command, str):
            raise TypeError("Command must be a string")
        if not cls._allowed_pattern.match(command):
            raise ValueError("Command contains disallowed characters")
        sanitized = []
        for ch in command:
            if ch in cls._dangerous_chars:
                sanitized.append(cls._dangerous_chars[ch])
            else:
                sanitized.append(ch)
        return ''.join(sanitized)

def main():
    if len(sys.argv) < 2:
