import java.util.ArrayList;
import java.util.List;

public class ShellCommandSanitizer {

    private static final String UNSAFE_CHARS = ";|&`$><*?~\\!#%()[]{}\"'";

    public static List<String> sanitize(String command) throws IllegalArgumentException {
        if (command == null) {
            throw new IllegalArgumentException("Command cannot be null");
        }
        List<String> tokens = tokenize(command);
        for (String token : tokens) {
            if (containsUnsafe(token)) {
                throw new IllegalArgumentException("Unsafe characters detected in token: " + token);
            }
        }
        return tokens;
    }

    private static List<String> tokenize(String command) {
        List<String> tokens = new ArrayList<>();
        StringBuilder current = new StringBuilder();
        boolean inSingleQuote = false;
        boolean inDoubleQuote = false;
        boolean escapeNext = false;

        for (int i = 0; i < command.length(); i++) {
            char c = command.charAt(i);

            if (escapeNext) {
                current.append(c);
                escapeNext = false;
                continue;
            }

            if (c == '\\') {
                // Escape next character unless inside single quotes
                if (!inSingleQuote) {
                    escapeNext = true;
                    continue;
                } else {
                    current.append(c);
                    continue;
                }
            }

            if (c == '\'' && !inDoubleQuote) {
                inSingleQuote = !inSingleQuote;
                continue;
            }

            if (c == '\"' && !inSingleQuote) {
                inDoubleQuote = !inDoubleQuote;
                continue;
            }

            if (Character.isWhitespace(c) && !inSingleQuote && !inDoubleQuote) {
                if (current.length() > 0) {
                    tokens.add(current.toString());
                    current.setLength(0);
                }
                continue;
            }

            current.append(c);
        }

        if (escapeNext) {
            throw new IllegalArgumentException("Trailing escape character in command");
        }
        if (inSingleQuote || inDoubleQuote) {
            throw new IllegalArgumentException("Unclosed quote in command");
        }
        if (current.length() > 0) {
            tokens.add(current.toString());
        }
        return tokens;
    }

    private static boolean containsUnsafe(String token) {
        for (int i = 0; i < token.length(); i++) {
            char c = token.charAt(i);
            if (UNSAFE_CHARS.indexOf(c) >= 0) {
                // Allow safe characters inside quotes that were already stripped
                // but reject them if they appear unescaped in the token.
                return true;
            }
        }
        return false;
    }

    // Helper to reconstruct a safe command line for display or logging
    public static String rebuildCommand(List<String> tokens) {
        StringBuilder sb = new StringBuilder();
        for (String token : tokens) {
            if (needsQuoting(token)) {
                sb.append('\'').append(token.replace("'", "'\\''")).append('\'');
            } else {
                sb.append(token);
            }
            sb.append(' ');
        }
        // Remove trailing space
        if (sb.length() > 0) {
            sb.setLength(sb.length() - 1);
        }
        return sb.toString();
    }

