public class ShellUtils {

    /**
     * Escapes a string so it can be safely used as a single argument in a POSIX shell command.
     * The implementation wraps the input in single quotes and safely handles any existing
     * single quotes by breaking the quoting, inserting an escaped quote, and reopening.
     *
     * Example:
     *   input:  O'Reilly & Co.
     *   output: 'O'"'"'Reilly & Co.'
     *
     * @param input the raw string to escape; may be {@code null}
     * @return a safely escaped string suitable for inclusion in a shell command,
     *         or {@code null} if the input was {@code null}
     */
    public static String escapeShell(String input) {
        if (input == null) {
            return null;
        }
        // Replace each single quote with the sequence '\'' which safely ends the current
        // single-quoted string, inserts a literal single quote, and starts a new single-quoted string.
        String escaped = input.replace("'", "'\"'\"'");
        // Wrap the whole thing in single quotes.
        return "'" + escaped + "'";
    }

    // Example usage
    public static void main(String[] args) {
        String unsafe = "O'Reilly && rm -rf /";
        String safe = escapeShell(unsafe);
        System.out.println("Original: " + unsafe);
        System.out.println("Escaped : " + safe);
        // The output can be used in a command like:
        // ProcessBuilder pb = new ProcessBuilder("sh", "-c", "echo " + safe);
    }
}

public class ShellEscape {

    /**
     * Escapes a string to be safely used as a single argument in a POSIX shell command.
     * It wraps the argument in single quotes and properly escapes any embedded single quotes.
     *
     * Example:
     *   input:  O'Reilly & Co.
     *   output: 'O'\''Reilly & Co.'
     *
     * @param arg the raw argument string
     * @return a safely escaped argument
     */
    public static String escapeShellArg(String arg) {
        if (arg == null) {
            return "''";
        }
        // Replace each single quote with: '\'' (end quote, escaped quote, start quote)
        return "'" + arg.replace("'", "'\\''") + "'";
    }

    /**
     * Escapes a command string by prefixing potentially dangerous shell metacharacters with a backslash.
     * This is similar to PHP's escapeshellcmd. It does NOT quote the whole command;
     * it only neutralises characters that have special meaning to the shell.
     *
     * Characters escaped:  # & ; ` | * ? ~ < > ^ ( ) [ ] { } $ \ " '
     *
     * @param cmd the raw command string
     * @return the command string with metacharacters escaped
     */
    public static String escapeShellCmd(String cmd) {
        if (cmd == null) {
            return "";
        }
        StringBuilder sb = new StringBuilder(cmd.length());
        for (char c : cmd.toCharArray()) {
            switch (c) {
                case '#':
                case '&':
                case ';':
                case '`':
                case '|':
                case '*':
                case '?':
                case '~':
                case '<':
                case '>':
                case '^':
                case '(':
                case ')':
                case '[':
                case ']':
                case '{':
                case '}':
                case '$':
                case '\\':
                case '"':
                case '\'':
                    sb.append('\\').append(c);
                    break;
                default:
                    sb.append(c);
            }
        }
        return sb.toString();
    }

    /**
     * Convenience method that first escapes the command and then each argument.
     * It builds a full safe command line suitable for execution via Runtime.exec or ProcessBuilder.
     *
     * @param command the command (e.g., "grep")
     * @param args    the arguments to the command
     * @return a safely escaped command line string
     */
    public static String buildSafeCommand(String command, String... args) {
        StringBuilder sb = new StringBuilder();
        sb.append(escapeShellCmd(command));
        for (String arg : args) {
            sb.append(' ');
            sb.append(escapeShellArg(arg));
        }
        return sb.toString();
    }

    // Example usage:
    // String safe = ShellEscape.buildSafeCommand("grep", "-i", "O'Reilly & Co.", "file.txt");
    // System.out.println(safe);
}

public class ShellEscapeUtil {

    /**
     * Escapes a string so it can be safely used as a single argument in a POSIX shell command.
     * The implementation wraps the input in single quotes and properly escapes any embedded
     * single quotes by closing the current quoting, inserting an escaped single quote,
     * and reopening the quoting.
     *
     * Example:
     *   input:  O'Reilly & Co.
     *   output: 'O'"'"'Reilly & Co.'
     *
     * @param input the raw string to be escaped; may be {@code null}
     * @return a safely escaped string suitable for inclusion in a shell command
     */
    public static String escapeShell(String input) {
        if (input == null) {
            return "''";
        }

        // If the string is empty, return two single quotes which represent an empty string in the shell
        if (input.isEmpty()) {
            return "''";
        }

        // Fast path: if the string contains no single quotes, we can simply wrap it in single quotes
        if (!input.contains("'")) {
            return "'" + input + "'";
        }

        // General case: replace each single quote with the sequence '\'' (close, escaped quote, reopen)
        StringBuilder escaped = new StringBuilder(input.length() + 10);
        escaped.append('\'');
        for (int i = 0; i < input.length(); i++) {
            char c = input.charAt(i);
            if (c == '\'') {
                escaped.append("'\"'\"'");
            } else {
                escaped.append(c);
            }
        }
        escaped.append('\'');

        return escaped.toString();
    }

    // Example usage
    public static void main(String[] args) {
        String[] testCases = {
            "simple",
            "O'Reilly & Co.",
            "",
            null,
            "path/with spaces/",
            "command; rm -rf /",
            "`rm -rf /`",
            "multi\nline"
        };

        for (String tc : testCases) {
            System.out.println("Original: " + (tc == null ? "null" : tc));
            System.out.println("Escaped : " + escapeShell(tc));
            System.out.println();
        }
    }
}

import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.util.Arrays;
import java.util.List;

public class SecureShellExecutor {

    // Define a whitelist of allowed commands (example)
    private static final List<String> ALLOWED_COMMANDS = Arrays.asList(
            "ls", "pwd", "whoami", "date", "echo"
    );

    public static void main(String[] args) {
        System.out.print("Enter command: ");
        try (BufferedReader reader = new BufferedReader(new InputStreamReader(System.in))) {
            String userInput = reader.readLine();
            if (userInput != null && !userInput.trim().isEmpty()) {
                safeExec(userInput.trim());
            } else {
                System.out.println("No command entered.");
            }
        } catch (IOException e) {
            System.err.println("Error reading input: " + e.getMessage());
        }
    }

    /**
     * Executes a shell command securely by validating against a whitelist
     * and using ProcessBuilder without invoking a shell interpreter.
     *
     * @param commandLine the full command line entered by the user
     */
    private static void safeExec(String commandLine) {
        // Split the command line into arguments (simple whitespace split)
        String[] parts = commandLine.split("\\s+");
        if (parts.length == 0) {
            System.out.println("Empty command.");
            return;
        }

        String command = parts[0];
        if (!ALLOWED_COMMANDS.contains(command)) {
            System.out.println("Command not allowed: " + command);
            return;
        }

        ProcessBuilder pb = new ProcessBuilder(parts);
        pb.redirectErrorStream(true);
        try {
            Process process = pb.start();
            try (BufferedReader procReader = new BufferedReader(
                    new InputStreamReader(process.getInputStream()))) {
                String line;
                while ((line = procReader.readLine()) != null) {
                    System.out.println(line);
                }
            }
            int exitCode = process.waitFor();
            System.out.println("Process exited with code: " + exitCode);
        } catch (IOException e) {
            System.err.println("IO error during command execution: " + e.getMessage());
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            System.err.println("Command execution interrupted.");
        }
    }
}

import java.io.BufferedReader;
import java.io.InputStreamReader;
import java.util.ArrayList;
import java.util.List;
import java.util.Scanner;

public class SecureShellRunner {

    private static final List<String> ALLOWED_COMMANDS = List.of(
            "ls", "pwd", "whoami", "date", "echo"
    );

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter command: ");
        String userInput = scanner.nextLine().trim();
        safeExec(userInput);
    }

    private static void safeExec(String input) {
        if (input.isEmpty()) {
            System.err.println("No command provided.");
            return;
        }

        String[] parts = input.split("\\s+");
        String command = parts[0];

        if (!ALLOWED_COMMANDS.contains(command)) {
            System.err.println("Command not allowed: " + command);
            return;
        }

        List<String> commandList = new ArrayList<>();
        for (String part : parts) {
            commandList.add(part);
        }

        ProcessBuilder pb = new ProcessBuilder(commandList);
        pb.redirectErrorStream(true);

        try {
            Process process = pb.start();
            try (BufferedReader reader = new BufferedReader(
                    new InputStreamReader(process.getInputStream()))) {
                String line;
                while ((line = reader.readLine()) != null) {
                    System.out.println(line);
                }
            }
            int exitCode = process.waitFor();
            System.out.println("Process exited with code: " + exitCode);
        } catch (Exception e) {
            System.err.println("Error executing command: " + e.getMessage());
        }
    }
}

import java.io.BufferedReader;
import java.io.InputStreamReader;
import java.util.regex.Pattern;

public class SafeShellExecutor {

    private static final Pattern SAFE_COMMAND_PATTERN = Pattern.compile("^[a-zA-Z0-9_\\-./\\\\ ]+$");

    public static void main(String[] args) {
        try (BufferedReader reader = new BufferedReader(new InputStreamReader(System.in))) {
            System.out.print("Enter command to execute: ");
            String userInput = reader.readLine();
            safeExec(userInput);
        } catch (Exception e) {
            System.err.println("Error: " + e.getMessage());
        }
    }

    public static void safeExec(String command) throws Exception {
        if (command == null || command.trim().isEmpty()) {
            throw new IllegalArgumentException("Command cannot be empty");
        }

        if (!SAFE_COMMAND_PATTERN.matcher(command).matches()) {
            throw new IllegalArgumentException("Command contains unsafe characters");
        }

        // Split command into tokens to avoid shell interpretation
        String[] tokens = command.trim().split("\\s+");
        ProcessBuilder pb = new ProcessBuilder(tokens);
        pb.redirectErrorStream(true);
        Process process = pb.start();

        try (BufferedReader procReader = new BufferedReader(new InputStreamReader(process.getInputStream()))) {
            String line;
            while ((line = procReader.readLine()) != null) {
                System.out.println(line);
            }
        }

        int exitCode = process.waitFor();
        System.out.println("Process exited with code: " + exitCode);
    }
}

import java.nio.file.Path;
import java.nio.file.Paths;
import java.nio.file.InvalidPathException;
import java.nio.file.LinkOption;
import java.io.IOException;

public class PathSanitizer {

    private final Path baseDirectory;

    public PathSanitizer(String baseDir) {
        if (baseDir == null) {
            throw new IllegalArgumentException("Base directory cannot be null");
        }
        this.baseDirectory = Paths.get(baseDir).toAbsolutePath().normalize();
        if (!baseDirectory.toFile().exists() || !baseDirectory.toFile().isDirectory()) {
            throw new IllegalArgumentException("Base directory must exist and be a directory: " + baseDirectory);
        }
    }

    /**
     * Returns a sanitized absolute Path that is guaranteed to be inside the configured base directory.
     *
     * @param userInputPath the path supplied by the user (relative or absolute)
     * @return a safe absolute Path within the base directory
     * @throws SecurityException if the resulting path would escape the base directory
     * @throws InvalidPathException if the userInputPath is malformed
     */
    public Path sanitize(String userInputPath) {
        if (userInputPath == null) {
            throw new IllegalArgumentException("User input path cannot be null");
        }

        Path userPath;
        try {
            userPath = Paths.get(userInputPath);
        } catch (InvalidPathException e) {
            throw new IllegalArgumentException("Invalid path: " + userInputPath, e);
        }

        // Resolve against base directory and normalize to eliminate "..", ".", and symbolic links
        Path resolved = baseDirectory.resolve(userPath).normalize();

        // Verify that the resolved path is still within the base directory
        if (!resolved.startsWith(baseDirectory)) {
            throw new SecurityException("Path traversal attempt detected: " + userInputPath);
        }

        return resolved;
    }

    /**
     * Checks whether a given user-supplied path would be safe (i.e., stays within the base directory) without
     * actually performing any I/O.
     *
     * @param userInputPath the path supplied by the user
     * @return true if the path is safe, false otherwise
     */
    public boolean isSafe(String userInputPath) {
        try {
            sanitize(userInputPath);
            return true;
        } catch (Exception e) {
            return false;
        }
    }

    // Example usage
    public static void main(String[] args) throws IOException {
        // Define a base directory where all file operations are allowed
        PathSanitizer sanitizer = new PathSanitizer("/var/www/uploads");

        // Example user inputs
        String[] inputs = {
            "images/photo.jpg",
            "../etc/passwd",
            "/absolute/path/outside.txt",
            "subdir/../subdir2/file.txt"
        };

        for (String input : inputs) {
            try {
                Path safePath = sanitizer.sanitize(input);
                System.out.println("User input: " + input);
                System.out.println("Sanitized path: " + safePath);
            } catch (SecurityException se) {
                System.out.println("User input: " + input);
                System.out.println("Rejected: " + se.getMessage());
            }
        }
    }
}

import java.io.IOException;
import java.nio.file.LinkOption;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.nio.file.Files;

public final class PathSanitizer {
    private final Path baseDirectory;

    public PathSanitizer(String baseDir) throws IOException {
        if (baseDir == null) {
            throw new IllegalArgumentException("Base directory cannot be null");
        }
        Path base = Paths.get(baseDir).toAbsolutePath().normalize();
        if (!Files.isDirectory(base)) {
            throw new IllegalArgumentException("Base directory does not exist or is not a directory: " + base);
        }
        this.baseDirectory = base;
    }

    /**
     * Sanitizes a user-supplied path, ensuring it resolves within the configured base directory.
     *
     * @param userPath the path supplied by the user (may be relative or absolute)
     * @return a normalized, absolute Path that is guaranteed to be inside the base directory
     * @throws IOException if an I/O error occurs while resolving the path
     * @throws SecurityException if the resolved path attempts to escape the base directory
     */
    public Path sanitize(String userPath) throws IOException, SecurityException {
        if (userPath == null) {
            throw new IllegalArgumentException("User path cannot be null");
        }

        // Resolve the user path against the base directory without allowing it to be absolute
        Path resolved = baseDirectory.resolve(userPath).normalize();

        // Resolve symbolic links without following them to avoid unexpected traversal
        Path realPath = resolved.toRealPath(LinkOption.NOFOLLOW_LINKS);

        // Ensure the final path starts with the base directory
        if (!realPath.startsWith(baseDirectory)) {
            throw new SecurityException("Attempted directory traversal detected: " + userPath);
        }

        return realPath;
    }

    // Simple demonstration
    public static void main(String[] args) {
        try {
            // Define a safe root directory (adjust as needed)
            String safeRoot = System.getProperty("user.dir") + "/safe_root";

            // Ensure the directory exists
            Files.createDirectories(Paths.get(safeRoot));

            PathSanitizer sanitizer = new PathSanitizer(safeRoot);

            // Example user inputs
            String[] inputs = {
                "documents/report.txt",
                "../outside.txt",
                "/absolute/path/evil.txt",
                "subdir/../subdir2/file.txt",
                "symlinked/../secret.txt"
            };

            for (String input : inputs) {
                try {
                    Path safePath = sanitizer.sanitize(input);
                    System.out.println("Original: " + input + " => Sanitized: " + safePath);
                } catch (SecurityException se) {
                    System.out.println("Original: " + input + " => BLOCKED (" + se.getMessage() + ")");
                }
            }
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

import java.nio.file.Path;
