import java.nio.file.LinkOption;
import java.nio.file.Files;
import java.io.IOException;

public class PathSanitizer {

    private final Path baseDirectory;

    public PathSanitizer(String baseDirectory) {
        if (baseDirectory == null) {
            throw new IllegalArgumentException("Base directory cannot be null");
        }
        Path basePath = Paths.get(baseDirectory).toAbsolutePath().normalize();
        if (!Files.isDirectory(basePath)) {
            throw new IllegalArgumentException("Base directory must exist and be a directory: " + basePath);
        }
        this.baseDirectory = basePath;
    }

    /**
     * Sanitizes a user‑supplied path, ensuring it resolves within the configured base directory.
     *
     * @param userPath the raw path supplied by the user (may be relative or absolute)
     * @return a normalized absolute Path that is guaranteed to stay inside the base directory,
     *         or {@code null} if the path is unsafe.
     */
    public Path sanitize(String userPath) {
        if (userPath == null || userPath.isBlank()) {
            return null;
        }

        Path resolved;
        try {
            // Convert to a Path object; reject malformed inputs early.
            Path rawPath = Paths.get(userPath);
            // Resolve against the base directory if the user supplied a relative path.
            if (rawPath.isAbsolute()) {
                resolved = rawPath.normalize();
            } else {
                resolved = baseDirectory.resolve(rawPath).normalize();
            }
        } catch (InvalidPathException e) {
            // Path contains illegal characters or syntax.
            return null;
        }

        // Prevent paths that climb above the base directory.
        if (!resolved.startsWith(baseDirectory)) {
            return null;
        }

        // Optional: ensure the target actually exists and is not a symlink that points outside.
        try {
            Path realPath = resolved.toRealPath(LinkOption.NOFOLLOW_LINKS);
            if (!realPath.startsWith(baseDirectory)) {
                return null;
            }
            return realPath;
        } catch (IOException e) {
            // Path does not exist or cannot be accessed; treat as unsafe.
            return null;
        }
    }

    // Example usage
    public static void main(String[] args) {
        PathSanitizer sanitizer = new PathSanitizer("/var/www/public");

        String[] testInputs = {
            "images/photo.jpg",
            "../etc/passwd",
            "/etc/passwd",
            "subdir/../secret.txt",
            "subdir/./file.txt",
            "symlink/../../outside.txt"
        };

        for (String input : testInputs) {
            Path safe = sanitizer.sanitize(input);
            System.out.println("Input: " + input + " => " + (safe != null ? safe : "REJECTED"));
        }
    }
}

