import java.security.MessageDigest;
import java.security.SecureRandom;
import java.util.Base64;
import java.util.Arrays;

public class PasswordHasher {
    private static final int SALT_LENGTH = 16; // bytes
    private static final int HASH_ITERATIONS = 10000;
    private static final int HASH_LENGTH = 32; // SHA-256 output size in bytes

    public static String hashPassword(String password) throws Exception {
        byte[] salt = generateSalt();
        byte[] hash = computeHash(password.getBytes("UTF-8"), salt);
        String saltB64 = Base64.getEncoder().encodeToString(salt);
        String hashB64 = Base64.getEncoder().encodeToString(hash);
        return saltB64 + "$" + hashB64;
    }

    public static boolean verifyPassword(String password, String stored) throws Exception {
        String[] parts = stored.split("\\$");
        if (parts.length != 2) {
            return false;
        }
        byte[] salt = Base64.getDecoder().decode(parts[0]);
        byte[] expectedHash = Base64.getDecoder().decode(parts[1]);
        byte[] actualHash = computeHash(password.getBytes("UTF-8"), salt);
        return constantTimeEquals(expectedHash, actualHash);
    }

    private static byte[] generateSalt() {
        SecureRandom sr = new SecureRandom();
        byte[] salt = new byte[SALT_LENGTH];
        sr.nextBytes(salt);
        return salt;
    }

    private static byte[] computeHash(byte[] passwordBytes, byte[] salt) throws Exception {
        MessageDigest md = MessageDigest.getInstance("SHA-256");
        // Initial digest: hash(salt || password)
        md.update(salt);
        md.update(passwordBytes);
        byte[] digest = md.digest();

        // Perform additional iterations: hash(salt || previousDigest)
        for (int i = 1; i < HASH_ITERATIONS; i++) {
            md.reset();
            md.update(salt);
            md.update(digest);
            digest = md.digest();
        }

        // Ensure output length matches HASH_LENGTH (SHA-256 already does)
        if (digest.length > HASH_LENGTH) {
            return Arrays.copyOf(digest, HASH_LENGTH);
        } else if (digest.length < HASH_LENGTH) {
            byte[] padded = new byte[HASH_LENGTH];
            System.arraycopy(digest, 0, padded, 0, digest.length);
            return padded;
        } else {
            return digest;
        }
    }

    // Constant-time comparison to prevent timing attacks
    private static boolean constantTimeEquals(byte[] a, byte[] b) {
        if (a.length != b.length) {
            return false;
        }
        int result = 0;
        for (int i = 0; i < a.length; i++) {
            result |= a[i] ^ b[i];
        }
        return result == 0;
    }
}

