public class InputSanitizer {
    public static String cleanData(String input) {
        if (input == null) {
            return null;
        }

        // Remove script tags and content
        String sanitized = input.replaceAll("(?i)<script.*?>.*?</script>", "");

        // Remove inline event handlers (e.g., onclick, onload)
        sanitized = sanitized.replaceAll("(?i)on\\w+\\s*=\\s*\"[^\"]*\"", "");
        sanitized = sanitized.replaceAll("(?i)on\\w+\\s*=\\s*'[^']*'", "");

        // Remove javascript: URIs
        sanitized = sanitized.replaceAll("(?i)javascript:", "");

        // Escape HTML special characters to prevent HTML injection
        sanitized = sanitized
                .replace("&", "&amp;")
                .replace("<", "&lt;")
                .replace(">", "&gt;")
                .replace("\"", "&quot;")
                .replace("'", "&#x27;");

        // Basic SQL injection mitigation: remove common SQL meta-characters
        sanitized = sanitized.replaceAll("(['\";--])", "");

        return sanitized;
    }
}

