                .replace("&", "&amp;")
                .replace("<", "&lt;")
                .replace(">", "&gt;")
                .replace("\"", "&quot;")
                .replace("'", "&#x27;")
                .replace("/", "&#x2F;");

        // 5. Trim whitespace
        sanitized = sanitized.trim();

        return sanitized;
    }

    // Example usage
    public static void main(String[] args) {
        String maliciousInput = "<script>alert('hack');</script><b>Hello</b>'; DROP TABLE users; --";
        String safeOutput = clean_data(maliciousInput);
        System.out.println("Original: " + maliciousInput);
        System.out.println("Sanitized: " + safeOutput);
    }
}

public class DataSanitizer {
    /**
     * Removes potentially malicious content from the given user submission.
     * This method performs basic sanitization such as:
     * <ul>
     *   <li>Escaping HTML tags</li>
     *   <li>Removing script tags</li>
     *   <li>Stripping SQL injection patterns</li>
     *   <li>Eliminating control characters</li>
     * </ul>
     *
     * @param input the raw user submission
     * @return a sanitized version of the input
     */
    public static String clean_data(String input) {
        if (input == null) {
            return null;
        }

        // 1. Remove null bytes and other control characters (except line breaks)
        String sanitized = input.replaceAll("[\\x00-\\x08\\x0B\\x0C\\x0E-\\x1F\\x7F]", "");

        // 2. Encode HTML entities to prevent XSS
        sanitized = sanitized
                .replace("&", "&amp;")
                .replace("<", "&lt;")
                .replace(">", "&gt;")
                .replace("\"", "&quot;")
                .replace("'", "&#x27;")
                .replace("/", "&#x2F;");

        // 3. Remove any remaining script tags (case‑insensitive)
        sanitized = sanitized.replaceAll("(?i)<script.*?>.*?</script>", "");

        // 4. Remove inline event handlers (e.g., onclick, onload)
        sanitized = sanitized.replaceAll("(?i)on\\w+\\s*=\\s*(['\"]).*?\\1", "");

        // 5. Strip common SQL injection patterns
        String[] sqlPatterns = {
                "(?i)\\bSELECT\\b", "(?i)\\bINSERT\\b", "(?i)\\bUPDATE\\b",
                "(?i)\\bDELETE\\b", "(?i)\\bDROP\\b", "(?i)\\bTRUNCATE\\b",
                "(?i)\\bEXEC\\b", "(?i)\\bUNION\\b", "(?i)\\bOR\\b\\s+1=1",
                "(?i)\\bAND\\b\\s+1=1", "(?i)\\b--\\b", "(?i)\\b#\\b"
        };
        for (String pattern : sqlPatterns) {
            sanitized = sanitized.replaceAll(pattern, "");
        }

        // 6. Collapse multiple spaces into a single space
        sanitized = sanitized.replaceAll("\\s{2,}", " ").trim();

        return sanitized;
    }

    // Example usage
    public static void main(String[] args) {
        String maliciousInput = "<script>alert('XSS');</script>SELECT * FROM users WHERE name='admin' --";
        String safeOutput = clean_data(maliciousInput);
        System.out.println("Sanitized output: " + safeOutput);
    }
}

public class SimpleEncryptor {
    public static String encryptData(String data, String key) {
        if (data == null || key == null) {
            throw new IllegalArgumentException("Data and key must not be null");
        }
        byte[] dataBytes = data.getBytes(java.nio.charset.StandardCharsets.UTF_8);
        byte[] keyBytes = key.getBytes(java.nio.charset.StandardCharsets.UTF_8);
        byte[] encrypted = new byte[dataBytes.length];
        for (int i = 0; i < dataBytes.length; i++) {
            encrypted[i] = (byte) (dataBytes[i] ^ keyBytes[i % keyBytes.length]);
        }
        return java.util.Base64.getEncoder().encodeToString(encrypted);
    }

    public static String decryptData(String encryptedBase64, String key) {
        if (encryptedBase64 == null || key == null) {
            throw new IllegalArgumentException("Encrypted data and key must not be null");
        }
        byte[] encrypted = java.util.Base64.getDecoder().decode(encryptedBase64);
        byte[] keyBytes = key.getBytes(java.nio.charset.StandardCharsets.UTF_8);
        byte[] decrypted = new byte[encrypted.length];
        for (int i = 0; i < encrypted.length; i++) {
            decrypted[i] = (byte) (encrypted[i] ^ keyBytes[i % keyBytes.length]);
        }
        return new String(decrypted, java.nio.charset.StandardCharsets.UTF_8);
    }

    // Example usage
    public static void main(String[] args) {
        String original = "Sensitive information";
        String key = "mySecretKey";
        String encrypted = encryptData(original, key);
        String decrypted = decryptData(encrypted, key);
        System.out.println("Original: " + original);
        System.out.println("Encrypted (Base64): " + encrypted);
        System.out.println("Decrypted: " + decrypted);
    }
}

