import org.apache.commons.text.StringEscapeUtils;

public class FormProcessor {

    public static Map<String, String> processFormData(Map<String, String> inputData) {
        Map<String, String> processedData = new HashMap<>();
        for (Entry<String, String> entry : inputData.entrySet()) {
            String field = entry.getKey();
            String value = entry.getValue();

            if (!validateInput(field, value)) {
                // Skip or handle invalid input as needed
                continue;
            }

            String sanitizedValue = sanitizeSql(value);
            String escapedValue = escapeHtml(sanitizedValue);
            processedData.put(field, escapedValue);
        }
        return processedData;
    }

    private static boolean validateInput(String fieldName, String value) {
        // Basic validation placeholder: non-null and not empty
        return value != null && !value.trim().isEmpty();
    }

    private static String sanitizeSql(String value) {
        // Simple SQL sanitization: escape single quotes, double quotes, backslashes, and semicolons
        if (value == null) {
            return null;
        }
        return value.replaceAll("(['\"\\\\;])", "\\\\$1");
    }

    private static String escapeHtml(String value) {
        // Use Apache Commons Text for HTML escaping
        if (value == null) {
            return null;
        }
        return StringEscapeUtils.escapeHtml4(value);
    }
}

