@RestController
@RequestMapping("/api")
@Validated
class SecureApiController {

    private final TokenService tokenService;
    private final Sanitizer sanitizer;

    public SecureApiController(TokenService tokenService, Sanitizer sanitizer) {
        this.tokenService = tokenService;
        this.sanitizer = sanitizer;
    }

    @PostMapping("/secure")
    public ResponseEntity<?> handleSecureRequest(
            @RequestHeader("Authorization") @NotBlank String authHeader,
            @RequestBody @NotNull Map<String, Object> rawPayload) {

        // Extract token (Bearer token assumed)
        String token = extractBearerToken(authHeader);
        if (token == null || !tokenService.validateToken(token)) {
            return ResponseEntity.status(HttpStatus.UNAUTHORIZED)
                    .body(Map.of("error", "Invalid or missing token"));
        }

        // Sanitize incoming data
        Map<String, Object> sanitizedPayload = sanitizer.sanitizeRequest(rawPayload);
        if (sanitizedPayload == null) {
            return ResponseEntity.status(HttpStatus.BAD_REQUEST)
                    .body(Map.of("error", "Payload contains prohibited content"));
        }

        // Business logic placeholder
        Map<String, Object> response = new HashMap<>();
        response.put("status", "success");
        response.put("data", sanitizedPayload);
        return ResponseEntity.ok(response);
    }

    private String extractBearerToken(String authHeader) {
        if (authHeader != null && authHeader.toLowerCase().startsWith("bearer ")) {
            return authHeader.substring(7).trim();
        }
        return null;
    }
}

