@Component
class Sanitizer {
    private static final Pattern PROHIBITED_PATTERN = Pattern.compile("[<>\"'%;)(&+]");

    public Map<String, Object> sanitizeRequest(Map<String, Object> input) {
        try {
            return deepSanitize(input);
        } catch (IllegalArgumentException e) {
            return null;
        }
    }

    @SuppressWarnings("unchecked")
    private Map<String, Object> deepSanitize(Map<String, Object> map) {
        Map<String, Object> sanitized = new HashMap<>();
        for (Map.Entry<String, Object> entry : map.entrySet()) {
            String cleanKey = sanitizeString(entry.getKey());
            Object value = entry.getValue();
            if (value instanceof String) {
                sanitized.put(cleanKey, sanitizeString((String) value));
            } else if (value instanceof Map) {
                sanitized.put(cleanKey, deepSanitize((Map<String, Object>) value));
            } else if (value instanceof Iterable) {
                sanitized.put(cleanKey, sanitizeIterable((Iterable<?>) value));
            } else {
                sanitized.put(cleanKey, value);
            }
        }
        return sanitized;
    }

    private Object sanitizeIterable(Iterable<?> iterable) {
        // For simplicity, return as-is; extend if needed
        return iterable;
    }

    private String sanitizeString(String input) {
        if (input == null) {
            return null;
        }
        if (PROHIBITED_PATTERN.matcher(input).find()) {
            throw new IllegalArgumentException("Prohibited characters detected");
        }
        return input;
    }
}

