    @PostMapping("/process")
    public ResponseEntity<?> processRequest(@RequestBody Map<String, Object> rawPayload,
                                            @RequestHeader("Authorization") String authHeader) {
        try {
            // Validate token
            String token = extractToken(authHeader);
            if (!validateToken(token)) {
                return ResponseEntity.status(HttpStatus.UNAUTHORIZED).body("Invalid token");
            }

            // Sanitize request data
            Map<String, Object> sanitizedPayload = sanitizeRequest(rawPayload);

            // Business logic placeholder
            // ...

            return ResponseEntity.ok(sanitizedPayload);
        } catch (Exception e) {
            return ResponseEntity.status(HttpStatus.BAD_REQUEST).body("Invalid request");
        }
    }

    private String extractToken(String authHeader) {
        if (authHeader != null && authHeader.startsWith("Bearer ")) {
            return authHeader.substring(7);
        }
        return null;
    }

    private boolean validateToken(String token) {
        if (token == null) {
            return false;
        }
        try {
            // Replace "your-secret-key" with your actual secret key
            Jws<Claims> claims = Jwts.parserBuilder()
                    .setSigningKey(Keys.hmacShaKeyFor("your-secret-key-your-secret-key".getBytes()))
                    .build()
                    .parseClaimsJws(token);
            // Additional checks (expiration, audience, etc.) can be added here
            return true;
        } catch (JwtException | IllegalArgumentException e) {
            return false;
        }
    }

    private Map<String, Object> sanitizeRequest(Map<String, Object> raw) {
        return raw.entrySet().stream()
                .collect(java.util.stream.Collectors.toMap(
                        Map.Entry::getKey,
                        e -> sanitizeValue(e.getValue())
                ));
    }

    private Object sanitizeValue(Object value) {
        if (value instanceof String) {
            // Escape HTML to prevent XSS
            return StringEscapeUtils.escapeHtml4((String) value);
        } else if (value instanceof Map) {
            // Recursively sanitize nested maps
            return sanitizeRequest((Map<String, Object>) value);
        } else if (value instanceof Iterable) {
            // Recursively sanitize collections
            java.util.List<Object> sanitizedList = new java.util.ArrayList<>();
            for (Object item : (Iterable<?>) value) {
                sanitizedList.add(sanitizeValue(item));
            }
            return sanitizedList;
        }
        // For other types (numbers, booleans, etc.) return as is
        return value;
    }
}

