@RestController
@RequestMapping("/api")
public class SecureEndpointController {

    private static final Pattern TOKEN_PATTERN = Pattern.compile("^[A-Za-z0-9\\-_=]+\\.[A-Za-z0-9\\-_=]+\\.[A-Za-z0-9\\-_=]+$");
    private final ObjectMapper objectMapper = new ObjectMapper();

    @PostMapping("/process")
    public ResponseEntity<String> processRequest(@RequestHeader("Authorization") String authHeader,
                                                 @RequestBody String rawBody) {
        try {
            // Validate token
            String token = extractToken(authHeader);
            if (!validateToken(token)) {
                throw new ResponseStatusException(HttpStatus.UNAUTHORIZED, "Invalid token");
            }

            // Sanitize request
            Map<String, Object> sanitizedData = sanitizeRequest(rawBody);
            // Business logic here using sanitizedData
            // For demo, just return a success message with echoed data
            String response = objectMapper.writeValueAsString(Map.of(
                    "status", "success",
                    "data", sanitizedData
            ));
            return ResponseEntity.ok(response);
        } catch (ResponseStatusException e) {
            throw e;
        } catch (Exception e) {
            throw new ResponseStatusException(HttpStatus.BAD_REQUEST, "Invalid request payload", e);
        }
    }

    private String extractToken(String authHeader) {
        if (authHeader == null || !authHeader.startsWith("Bearer ")) {
            throw new ResponseStatusException(HttpStatus.UNAUTHORIZED, "Missing or malformed Authorization header");
        }
        return authHeader.substring(7);
    }

    private boolean validateToken(String token) {
        // Basic format check for JWT; replace with real verification (e.g., JJWT, Auth0)
        if (token == null || !TOKEN_PATTERN.matcher(token).matches()) {
            return false;
        }
        // TODO: Verify signature, expiration, audience, etc.
        return true;
    }

    private Map<String, Object> sanitizeRequest(String rawJson) throws Exception {
        // Parse JSON into a mutable map
        Map<String, Object> data = objectMapper.readValue(rawJson, new TypeReference<>() {});
        // Recursively sanitize all string values
        sanitizeMap(data);
        return data;
    }

    @SuppressWarnings("unchecked")
    private void sanitizeMap(Map<String, Object> map) {
        for (Map.Entry<String, Object> entry : map.entrySet()) {
            Object val = entry.getValue();
            if (val instanceof String) {
                entry.setValue(sanitizeString((String) val));
            } else if (val instanceof Map) {
                sanitizeMap((Map<String, Object>) val);
            } else if (val instanceof Iterable) {
                sanitizeIterable((Iterable<?>) val);
            }
        }
    }

    private void sanitizeIterable(Iterable<?> iterable) {
        for (Object item : iterable) {
            if (item instanceof String) {
                // Strings inside collections are not directly replaceable in the original collection,
                // so you may need to copy to a new collection if mutability is required.
                // For simplicity, this example does not modify collection elements.
            } else if (item instanceof Map) {
                sanitizeMap((Map<String, Object>) item);
            } else if (item instanceof Iterable) {
                sanitizeIterable((Iterable<?>) item);
            }
        }
    }

    private String sanitizeString(String input) {
        if (input == null) {
            return null;
        }
        // Basic HTML/JS escaping to prevent XSS; extend as needed
        return input
                .replace("&", "&amp;")
                .replace("<", "&lt;")
                .replace(">", "&gt;")
                .replace("\"", "&quot;")
                .replace("'", "&#x27;")
                .replace("/", "&#x2F;");
    }
}

