public class RegistrationService {
    private static final Pattern EMAIL_PATTERN = Pattern.compile(
            "^[A-Z0-9._%+-]+@[A-Z0-9.-]+\\.[A-Z]{2,}$",
            Pattern.CASE_INSENSITIVE);

    /**
     * Validates the e‑mail address format.
     *
     * @param email the e‑mail to validate
     * @return true if the e‑mail matches the pattern, false otherwise
     */
    public static boolean validateEmail(String email) {
        if (email == null) {
            return false;
        }
        Matcher matcher = EMAIL_PATTERN.matcher(email);
        return matcher.find();
    }

    /**
     * Sanitizes user input by escaping HTML special characters.
     *
     * @param input raw user input
     * @return sanitized string safe for storage/display
     */
    public static String sanitizeInput(String input) {
        if (input == null) {
            return null;
        }
        StringBuilder sb = new StringBuilder();
        for (char c : input.toCharArray()) {
            switch (c) {
                case '<':
                    sb.append("&lt;");
                    break;
                case '>':
                    sb.append("&gt;");
                    break;
                case '&':
                    sb.append("&amp;");
                    break;
                case '"':
                    sb.append("&quot;");
                    break;
                case '\'':
                    sb.append("&#x27;");
                    break;
                case '/':
                    sb.append("&#x2F;");
                    break;
                default:
                    sb.append(c);
            }
        }
        return sb.toString();
    }

    /**
     * Generates a BCrypt hash of the supplied password.
     *
     * @param password plain‑text password
     * @return BCrypt hashed password
     */
    public static String securePassword(String password) {
        if (password == null) {
            throw new IllegalArgumentException("Password cannot be null");
        }
        return BCrypt.hashpw(password, BCrypt.gensalt(12));
    }

    /**
     * Registers a new user after sanitizing inputs, validating the e‑mail,
