import re

class HTMLSanitizer:
    def __init__(self, allowed_tags, allowed_attributes):
        self.allowed_tags = allowed_tags
        self.allowed_attributes = allowed_attributes

    def sanitize(self, html):
        html = self.remove_comments(html)
        html = self.remove_scripts(html)
        html = self.remove_styles(html)
        html = self.remove_disallowed_tags(html)
        html = self.remove_disallowed_attributes(html)
        return html

    def remove_comments(self, html):
        return re.sub(r'<!--.*?-->', '', html, flags=re.DOTALL)

    def remove_scripts(self, html):
        return re.sub(r'<script.*?>.*?</script>', '', html, flags=re.DOTALL | re.IGNORECASE)

    def remove_styles(self, html):
        return re.sub(r'<style.*?>.*?</style>', '', html, flags=re.DOTALL | re.IGNORECASE)

    def remove_disallowed_tags(self, html):
        pattern = r'<(/?)(' + '|'.join([tag for tag in self.get_all_tags(html) if tag not in self.allowed_tags]) + r')\b.*?>'
        return re.sub(pattern, self.replace_disallowed_tags, html, flags=re.IGNORECASE)

    def get_all_tags(self, html):
        return set(re.findall(r'<(\w+)\b', html))

    def replace_disallowed_tags(self, match):
        if match.group(1) == '/':
            return '</' + match.group(2) + '>'
        else:
            return ''

    def remove_disallowed_attributes(self, html):
        pattern = r'<(\w+)\b([^>]*)>'
        return re.sub(pattern, self.filter_attributes, html)

    def filter_attributes(self, match):
        tag = match.group(1)
        attributes = match.group(2)
        if tag not in self.allowed_tags:
            return '<' + tag + '>'
        allowed_attributes = self.allowed_attributes.get(tag, [])
        filtered_attributes = ' '.join([attr for attr in re.findall(r'\b(\w+)\s*=\s*"[^"]*"', attributes) if attr in allowed_attributes])
        return '<' + tag + ' ' + filtered_attributes + '>'

def main():
    allowed_tags = ['p', 'span', 'a', 'img']
    allowed_attributes = {
        'a': ['href'],
        'img': ['src', 'alt']
    }
    sanitizer = HTMLSanitizer(allowed_tags, allowed_attributes)
    html = '<p>Hello <script>alert("XSS")</script> world!</p><a href="javascript:alert(\'XSS\')">Click me</a><img src="image.jpg" onerror="alert(\'XSS\')">'

    print(sanitizer.sanitize(html))

if __name__ == "__main__":
    main()
```

```python
import re

class HTMLSanitizer:
    def __init__(self, allowed_tags, allowed_attributes):
        self.allowed_tags = allowed_tags
        self.allowed_attributes = allowed_attributes

    def sanitize(self, html):
        # Remove script and style tags
        html = re.sub(r'<(script|style).*?>.*?<\/\1>', '', html, flags=re.DOTALL)

        # Remove tags that are not allowed
        html = re.sub(r'<\/?(\w+).*?>', self._check_tag, html)

        # Remove attributes that are not allowed
        html = re.sub(r'<(\w+)([^>]*)>', self._check_attributes, html)

        # Remove 'on*' attributes
        html = re.sub(r' on\w+=[\'"]?[^\'"]*[\'"]?', '', html)

        return html

    def _check_tag(self, match):
        tag = match.group(1)
        if tag in self.allowed_tags:
            return match.group(0)
        else:
            return ''

    def _check_attributes(self, match):
        tag = match.group(1)
        attributes = match.group(2)
        allowed_attributes = self.allowed_attributes.get(tag, [])
        attributes = re.sub(r'(\w+)=[\'"]?[^\'"]*[\'"]?', self._check_attribute(allowed_attributes), attributes)
        return f'<{tag}{attributes}>'

    def _check_attribute(self, allowed_attributes):
        def check(match):
            attribute = match.group(1)
            if attribute in allowed_attributes:
                return match.group(0)
            else:
                return ''
        return check


# Example usage:
allowed_tags = ['p', 'b', 'i', 'u', 'img']
allowed_attributes = {
    'img': ['src', 'alt']
}

sanitizer = HTMLSanitizer(allowed_tags, allowed_attributes)
html = '<p>Hello <script>alert("XSS")</script> world!<img src="image.jpg" onerror="alert(\'XSS\')"> <b>Bold text</b></p>'
print(sanitizer.sanitize(html))
