```python
import re

class HTMLSanitizer:
    def __init__(self, allowed_tags=None, allowed_attributes=None):
        self.allowed_tags = allowed_tags if allowed_tags else ['p', 'img', 'br', 'strong', 'em', 'span']
        self.allowed_attributes = allowed_attributes if allowed_attributes else {'img': ['src', 'alt']}

    def sanitize(self, html):
        html = self._remove_comments(html)
        html = self._remove_script_and_style(html)
        html = self._sanitize_tags(html)
        return html

    def _remove_comments(self, html):
        return re.sub(r'<!--.*?-->', '', html, flags=re.DOTALL)

    def _remove_script_and_style(self, html):
        return re.sub(r'<(script|style).*?>.*?<\/\1>', '', html, flags=re.DOTALL | re.IGNORECASE)

    def _sanitize_tags(self, html):
        def replace_tag(match):
            tag = match.group(1).lower()
            if tag in self.allowed_tags:
                return self._sanitize_attributes(match.group(0), tag)
            else:
                return ''

        return re.sub(r'<([^>]+)>', replace_tag, html)

    def _sanitize_attributes(self, tag, tag_name):
        def replace_attribute(match):
            attribute = match.group(1).lower()
            if attribute in self.allowed_attributes.get(tag_name, []):
                return match.group(0)
            else:
                return ''

        tag = re.sub(r'\s+([^\s=]+)="[^"]*"', replace_attribute, tag)
        tag = re.sub(r'\s+([^\s=]+)', replace_attribute, tag)
        return tag

def main():
    sanitizer = HTMLSanitizer()
    html = '<p>Hello <script>alert("XSS")</script> world! <img src="image.jpg" onerror="alert(\'XSS\')">'
    print(sanitizer.sanitize(html))

if __name__ == '__main__':
    main()
```

