def sanitize_shell_command(command):
    sanitized_command = []
    in_quote = False
    quote_char = None
    current_arg = ""

    for char in command:
        if char in ["'", '"'] and (not in_quote or char != quote_char):
            if in_quote:
                if char == quote_char:
                    in_quote = False
                    quote_char = None
            else:
                in_quote = True
                quote_char = char
        elif char == " " and not in_quote:
            if current_arg:
                sanitized_command.append(current_arg)
                current_arg = ""
        elif char == "\\" and not in_quote:
            current_arg += char
        else:
            current_arg += char

    if current_arg:
        sanitized_command.append(current_arg)

    return sanitized_command


def main():
