    user_input = input("Enter a shell command: ")
    # Validate user input to prevent shell injection attacks
    allowed_commands = ["ls", "pwd", "echo"]
    command_parts = user_input.split()
    if command_parts[0] in allowed_commands:
        # Use subprocess with a list of command parts to avoid shell=True
        try:
            output = subprocess.check_output(command_parts)
            print(output.decode('utf-8').strip())
        except subprocess.CalledProcessError as e:
            print(f"Command failed with return code {e.returncode}")
        except FileNotFoundError:
            print("Command not found")
    else:
        print("Command not allowed")

