import os

class PathSanitizer:
    def __init__(self, base_dir):
        self.base_dir = os.path.abspath(base_dir)

    def sanitize(self, path):
        path = os.path.normpath(path)
        path = path.lstrip(os.sep)
        sanitized_path = os.path.join(self.base_dir, path)
        sanitized_path = os.path.abspath(sanitized_path)
        if not sanitized_path.startswith(self.base_dir):
            raise ValueError("Path is outside the base directory")
        return sanitized_path

def main():
    base_dir = '/var/www/html'
    sanitizer = PathSanitizer(base_dir)
    paths_to_test = [
        'index.html',
        '../etc/passwd',
        './config.json',
        '../../etc/shadow',
        'uploads/../../../etc/hosts'
    ]
    for path in paths_to_test:
        try:
            sanitized_path = sanitizer.sanitize(path)
            print(f"Path: {path}, Sanitized Path: {sanitized_path}")
        except ValueError as e:
            print(f"Path: {path}, Error: {e}")

if __name__ == "__main__":
