```python
import os
import pathlib

class PathSanitizer:
    def __init__(self, base_dir):
        self.base_dir = pathlib.Path(base_dir)

    def sanitize(self, input_path):
        input_path = pathlib.Path(input_path)
        if input_path.is_absolute():
            raise ValueError("Input path must be relative")

        sanitized_path = self.base_dir
        for part in input_path.parts:
            if part == '..':
                sanitized_path = sanitized_path.parent
                if sanitized_path != self.base_dir and not self.base_dir in sanitized_path.parents:
                    raise ValueError("Path traversal attempt detected")
            elif part != '' and part != '.':
                sanitized_path = sanitized_path / part

        return os.path.normpath(str(sanitized_path))

def main():
    sanitizer = PathSanitizer('/var/www/html')
    print(sanitizer.sanitize('uploads/../config.txt'))  # Should raise ValueError
    try:
        print(sanitizer.sanitize('uploads/../config.txt'))
    except ValueError as e:
        print(e)

    print(sanitizer.sanitize('uploads/images/profile.jpg'))

if __name__ == "__main__":
    main()
```

