import os
import pathlib

def secure_path(user_provided_path, base_directory):
    base_directory = pathlib.Path(base_directory)
    user_provided_path = pathlib.Path(user_provided_path)

    if user_provided_path.is_absolute():
        return None

    sanitized_path = (base_directory / user_provided_path).resolve()

    if not sanitized_path.is_relative_to(base_directory.resolve()):
        return None

    return sanitized_path

def main():
    base_dir = '/var/www/html'
    user_input = '../etc/passwd'
    sanitized = secure_path(user_input, base_dir)

    if sanitized:
        try:
            with open(sanitized, 'r') as file:
                print(file.read())
        except FileNotFoundError:
            print("File not found.")
        except Exception as e:
            print(f"An error occurred: {e}")
    else:
        print("Invalid path.")

if __name__ == "__main__":
    main()
```

