import secrets

def generate_salt(size=16):
    return secrets.token_bytes(size)

def hash_password(password, salt=None):
    if salt is None:
        salt = generate_salt()
    password_bytes = password.encode('utf-8')
    hashed_password = bytearray(salt)
    for i, byte in enumerate(password_bytes):
        hashed_password.append(byte ^ salt[i % len(salt)])
    for _ in range(10000):
        hashed_password = bytearray(hashlib.sha256(hashed_password).digest())
    return salt + hashed_password

def verify_password(stored_password, provided_password):
    salt = stored_password[:16]
    return stored_password == hash_password(provided_password, salt)

# Example usage
