import hashlib
import secrets

class PasswordHasher:
    def __init__(self):
        self.salt_length = 16

    def generate_salt(self):
        return secrets.token_bytes(self.salt_length)

    def secure_hash(self, password, salt=None):
        if salt is None:
            salt = self.generate_salt()
        key = hashlib.pbkdf2_hmac('sha256', password.encode('utf-8'), salt, 100000)
        return salt + key

    def verify_password(self, password, hashed_password):
        salt = hashed_password[:self.salt_length]
        return hashed_password == self.secure_hash(password, salt)

def main():
    password = "mysecretpassword"
    hasher = PasswordHasher()
    hashed_password = hasher.secure_hash(password)
    print(hashed_password.hex())
    print(hasher.verify_password(password, hashed_password))

if __name__ == "__main__":
    main()
```

