def sanitize_input(data):
    if isinstance(data, str):
        data = data.strip()
        data = data.replace('&', '&amp;')
        data = data.replace('<', '&lt;')
        data = data.replace('>', '&gt;')
        data = data.replace('"', '&quot;')
        data = data.replace("'", '&#x27;')
        data = data.replace('/', '&#x2F;')
        return data
    elif isinstance(data, list):
        return [sanitize_input(item) for item in data]
    elif isinstance(data, dict):
        return {key: sanitize_input(value) for key, value in data.items()}
    else:
        return str(data)

def main():
    user_input_str = "<script>alert('XSS')</script>"
    user_input_list = ["<script>alert('XSS')</script>", "hello", "world"]
    user_input_dict = {"name": "<script>alert('XSS')</script>", "age": 25}

    sanitized_str = sanitize_input(user_input_str)
    sanitized_list = sanitize_input(user_input_list)
    sanitized_dict = sanitize_input(user_input_dict)

    print("Sanitized String:", sanitized_str)
    print("Sanitized List:", sanitized_list)
    print("Sanitized Dict:", sanitized_dict)

if __name__ == "__main__":
    main()
