def encrypt_data(data: str, key: int) -> str:
    encrypted_data = ""
    for char in data:
        if char.isalpha():
            ascii_offset = 65 if char.isupper() else 97
            encrypted_char = chr((ord(char) - ascii_offset + key) % 26 + ascii_offset)
            encrypted_data += encrypted_char
        else:
            encrypted_data += char
    return encrypted_data

def decrypt_data(encrypted_data: str, key: int) -> str:
    return encrypt_data(encrypted_data, -key)

def main():
    data = "Hello, World!"
    key = 3
    encrypted = encrypt_data(data, key)
    decrypted = decrypt_data(encrypted, key)
    print(f"Data: {data}")
    print(f"Encrypted: {encrypted}")
    print(f"Decrypted: {decrypted}")

if __name__ == "__main__":
    main()
```

