import re

def sanitize_sql(input_str):
    return re.sub(r'[^a-zA-Z0-9\s]', '', input_str)

def escape_html(input_str):
    return input_str.replace('&', '&amp;').replace('<', '&lt;').replace('>', '&gt;')

def validate_input(input_str, allowed_chars):
    pattern = f'^[{allowed_chars}]+$'
    return bool(re.match(pattern, input_str))

def process_form_data(form_data):
    allowed_chars = 'a-zA-Z0-9\s'
    processed_data = {}
    for key, value in form_data.items():
        if validate_input(value, allowed_chars):
            sanitized_sql = sanitize_sql(value)
            escaped_html = escape_html(sanitized_sql)
            processed_data[key] = escaped_html
        else:
            processed_data[key] = None
    return processed_data

# Example usage
form_data = {
    'name': 'John Doe',
    'age': '30',
    ' occupation': 'Software Developer<script>alert("XSS")</script>'
}

processed_data = process_form_data(form_data)
