class HTMLSanitizer {
  constructor(allowedTags, allowedAttributes) {
    this.allowedTags = allowedTags;
    this.allowedAttributes = allowedAttributes;
  }

  sanitize(html) {
    const self = this;
    const sanitizedHtml = html.replace(/<(\/?)(\w+)[^>]*>/g, function(match, closing, tagName) {
      if (closing === '/') {
        return self.isAllowedTag(tagName) ? match : '';
      } else {
        return self.sanitizeTag(match, tagName);
      }
    });
    return sanitizedHtml.replace(/&/g, '&amp;')
                        .replace(/</g, '&lt;')
                        .replace(/>/g, '&gt;')
                        .replace(/"/g, '&quot;')
                        .replace(/'/g, '&#x27;');
  }

  isAllowedTag(tagName) {
    return this.allowedTags.includes(tagName.toLowerCase());
  }

  sanitizeTag(match, tagName) {
    if (!this.isAllowedTag(tagName)) return '';

    const attributeRegex = /\b(\w+)\s*=\s*"([^"]*)"/g;
    let attributes = '';
    let attributeMatch;

    while ((attributeMatch = attributeRegex.exec(match)) !== null) {
      const attributeName = attributeMatch[1];
      const attributeValue = attributeMatch[2];

      if (this.isAllowedAttribute(tagName, attributeName)) {
        attributes += ` ${attributeName}="${this.escapeAttribute(attributeValue)}"`;
      }
    }

    return `<${tagName}${attributes}>`;
  }

  isAllowedAttribute(tagName, attributeName) {
    const allowedAttributesForTag = this.allowedAttributes[tagName.toLowerCase()];
    return allowedAttributesForTag && allowedAttributesForTag.includes(attributeName.toLowerCase());
  }

  escapeAttribute(value) {
    return value.replace(/&/g, '&amp;')
                .replace(/"/g, '&quot;')
                .replace(/'/g, '&#x27;')
                .replace(/</g, '&lt;')
                .replace(/>/g, '&gt;');
  }
}

const sanitizer = new HTMLSanitizer(['p', 'span', 'a'], {
  'a': ['href']
});

const dirtyHtml = '<p onclick="alert(\'XSS\')">Hello <a href="javascript:alert(\'XSS\')">world</a>!</p><script>alert("XSS")</script>';
const cleanHtml = sanitizer.sanitize(dirtyHtml);
console.log(cleanHtml);
```

```javascript
class HTMLSanitizer {
  constructor() {
    this.allowedTags = ['p', 'img', 'br', 'strong', 'em', 'span', 'ul', 'ol', 'li', 'a'];
    this.allowedAttributes = {
      img: ['src', 'alt'],
      a: ['href']
    };
  }

  sanitize(html) {
    const self = this;
    const sanitizedHtml = html.replace(/<(\/?)(\w+)[^>]*>/g, function(match, closing, tag) {
      if (closing === '/') {
        return self.closeTag(tag);
      } else {
        return self.openTag(tag, match);
      }
    });
    return sanitizedHtml.replace(/&/g, '&amp;')
                         .replace(/</g, '&lt;')
                         .replace(/>/g, '&gt;')
                         .replace(/"/g, '&quot;')
                         .replace(/'/g, '&#x27;');
  }

  openTag(tag, match) {
    if (this.allowedTags.includes(tag)) {
      const attributes = this.getAttributes(match);
      const sanitizedAttributes = this.sanitizeAttributes(tag, attributes);
      return `<${tag}${sanitizedAttributes}>`;
    } else {
      return '';
    }
  }

  closeTag(tag) {
    if (this.allowedTags.includes(tag)) {
      return `</${tag}>`;
    } else {
      return '';
    }
  }

  getAttributes(match) {
    const attributeRegex = /\b(\w+)\s*=\s*"([^"]*)"/g;
    const attributes = {};
    let attributeMatch;
    while ((attributeMatch = attributeRegex.exec(match)) !== null) {
      attributes[attributeMatch[1]] = attributeMatch[2];
    }
    return attributes;
  }

  sanitizeAttributes(tag, attributes) {
    if (!this.allowedAttributes[tag]) {
      return '';
    }
    const sanitizedAttributes = [];
    for (const attribute in attributes) {
      if (this.allowedAttributes[tag].includes(attribute)) {
        sanitizedAttributes.push(`${attribute}="${attributes[attribute]}"`);
      }
    }
    return sanitizedAttributes.length > 0 ? ' ' + sanitizedAttributes.join(' ') : '';
  }
}

function sanitizeHtml(html) {
  const sanitizer = new HTMLSanitizer();
  return sanitizer.sanitize(html);
}

// Example usage
const unsanitizedHtml = '<p onclick="alert(\'XSS\')">Hello <img src="image.jpg" onerror="alert(\'XSS\')"> World!</p><script>alert("XSS");</script>';
const sanitizedHtml = sanitizeHtml(unsanitizedHtml);
```

```javascript
class HTMLSanitizer {
  constructor(allowedTags, allowedAttributes) {
    this.allowedTags = allowedTags;
    this.allowedAttributes = allowedAttributes;
  }

  sanitize(html) {
    const self = this;
    const sanitizedHtml = html.replace(/<(\/?)(\w+)[^>]*>/g, function(match, close, tag) {
      if (close === '/') {
        return self.closeTag(tag);
      } else {
        return self.openTag(tag, match);
      }
    });

    return sanitizedHtml.replace(/&/g, '&amp;')
                        .replace(/</g, '&lt;')
                        .replace(/>/g, '&gt;')
                        .replace(/"/g, '&quot;')
                        .replace(/'/g, '&#x27;');
  }

  openTag(tag, match) {
    if (this.allowedTags.includes(tag)) {
      const attributes = this.parseAttributes(match);
      const sanitizedAttributes = this.sanitizeAttributes(tag, attributes);
      return `<${tag}${sanitizedAttributes ? ' ' + sanitizedAttributes : ''}>`;
    } else {
      return '';
    }
  }

  closeTag(tag) {
    if (this.allowedTags.includes(tag)) {
      return `</${tag}>`;
    } else {
      return '';
    }
  }

  parseAttributes(match) {
    const attributeRegex = /\b(\w+)\s*=\s*"([^"]*)"/g;
    const attributes = {};
    let attributeMatch;

    while ((attributeMatch = attributeRegex.exec(match)) !== null) {
      attributes[attributeMatch[1]] = attributeMatch[2];
    }

    return attributes;
  }

  sanitizeAttributes(tag, attributes) {
    const sanitizedAttributes = [];

    for (const attribute in attributes) {
      if (this.allowedAttributes[tag] && this.allowedAttributes[tag].includes(attribute)) {
        sanitizedAttributes.push(`${attribute}="${attributes[attribute]}"`);
      }
    }

    return sanitizedAttributes.join(' ');
  }
}

const sanitizer = new HTMLSanitizer(['p', 'span', 'a'], {
  a: ['href']
});

const dirtyHtml = '<p onclick="alert(\'XSS\')">Hello <a href="javascript:alert(\'XSS\')">world</a>!</p><script>alert("XSS")</script>';
