function prevent_xss(input) {
    const entityMap = {
        '&': '&amp;',
        '<': '&lt;',
        '>': '&gt;',
        '"': '&quot;',
        "'": '&#39;',
        '/': '&#x2F;',
        '`': '&#x60;',
        '=': '&#x3D;'
    };

    return String(input).replace(/[&<>"'`=\/]/g, function (s) {
        return entityMap[s];
    });
}

