function sanitizeShellCommand(command) {
    let sanitizedCommand = "";
    let inQuote = false;
    let quoteChar = null;

    for (let i = 0; i < command.length; i++) {
        const char = command[i];

        if (char === " " && !inQuote) {
            if (sanitizedCommand && sanitizedCommand[sanitizedCommand.length - 1] !== " ") {
                sanitizedCommand += " ";
            }
            continue;
        }

        if ((char === "'" || char === '"') && (i === 0 || command[i - 1] !== "\\")) {
            if (!inQuote) {
                inQuote = true;
                quoteChar = char;
            } else if (quoteChar === char) {
                inQuote = false;
                quoteChar = null;
            } else {
                sanitizedCommand += char;
            }
            continue;
        }

        if (char === "\\" && !inQuote) {
            continue;
        }

        if (char === ";" || char === "&" || char === "|" || char === "$" || char === "(" || char === ")" || char === "`") {
            if (!inQuote) {
                throw new Error(`Forbidden character '${char}' at position ${i}`);
            }
        }

        sanitizedCommand += char;
    }

    if (inQuote) {
        throw new Error("Unbalanced quotes");
    }

    return sanitizedCommand.trim().split(/\s+/);
}

