function sanitizeShellCommand(command) {
    let sanitizedCommand = '';
    let inQuote = false;
    let quoteChar = null;

    for (let i = 0; i < command.length; i++) {
        const char = command[i];

        if (char === ' ' && !inQuote) {
            if (sanitizedCommand && sanitizedCommand !== ' ') {
                sanitizedCommand += ' ';
            }
            continue;
        }

        if ((char === '"' || char === "'") && (i === 0 || command[i-1] !== '\\')) {
            if (!inQuote) {
                inQuote = true;
                quoteChar = char;
            } else if (quoteChar === char) {
                inQuote = false;
                quoteChar = null;
            } else {
                sanitizedCommand += char;
            }
            continue;
        }

        if (char === '\\' && i < command.length - 1) {
            const nextChar = command[i+1];
            if (inQuote && nextChar === quoteChar) {
                sanitizedCommand += nextChar;
                i++;
                continue;
            }
            if (!inQuote && [' ', '\\', '"', "'"].includes(nextChar)) {
                sanitizedCommand += nextChar;
                i++;
                continue;
            }
        }

        if (!inQuote && [';', '&', '|', '$', '(', ')', '`', '<', '>'].includes(char)) {
            throw new Error(`Forbidden character '${char}' at position ${i}`);
        }

        sanitizedCommand += char;
    }

    if (inQuote) {
        throw new Error('Unbalanced quotes in command');
    }

    return sanitizedCommand.trim().split(/\s+/);
}

