function sanitizePath(inputPath, baseDirectory) {
  const path = require('path');

  // Normalize the input path to eliminate any OS-specific differences
  const normalizedInputPath = path.normalize(inputPath);

  // Remove any leading slashes or drive letters to simplify the path
  const strippedInputPath = normalizedInputPath.replace(/^\/+/, '').replace(/^[A-Z]:/i, '');

  // Join the base directory with the sanitized input path
  const joinedPath = path.join(baseDirectory, strippedInputPath);

  // Resolve the joined path to eliminate any .. or . segments
  const resolvedPath = path.resolve(joinedPath);

  // Check if the resolved path is within the base directory
  if (!resolvedPath.startsWith(baseDirectory)) {
    throw new Error('Path traversal attack detected');
  }

  // Return the sanitized path relative to the base directory
  return path.relative(baseDirectory, resolvedPath);
}

// Example usage
