const path = require('path');
const fs = require('fs');

function validatePath(filePath) {
    try {
        // Check if the path is absolute
        if (!path.isAbsolute(filePath)) {
            return false;
        }

        // Resolve the path to remove any relative path components
        const resolvedPath = path.resolve(filePath);

        // Check if the resolved path is within a safe directory
        // For example, let's assume the safe directory is the current working directory
        const safeDir = process.cwd();
        if (!resolvedPath.startsWith(safeDir)) {
            return false;
        }

        // Check if the file exists and is a file
        const stats = fs.statSync(resolvedPath);
        if (!stats.isFile()) {
            return false;
        }

        return true;
    } catch (err) {
        return false;
    }
}

// Example usage:
const filePath = '/path/to/your/file.txt';
if (validatePath(filePath)) {
    console.log(`${filePath} is a safe path.`);
} else {
    console.log(`${filePath} is not a safe path.`);
}
