const path = require('path');
const fs = require('fs');

function validatePath(filePath) {
    try {
        // Normalize the path to eliminate any traversal attempts
        const normalizedPath = path.normalize(filePath);

        // Check if the normalized path is still within the expected directory
        if (normalizedPath.startsWith('..')) {
            return false;
        }

        // Check if the path is absolute
        if (path.isAbsolute(normalizedPath)) {
            return false;
        }

        // Attempt to resolve the path to check for any symbolic links
        const resolvedPath = fs.realpathSync(normalizedPath);

        // If the resolved path is outside the expected directory, it's not safe
        if (!resolvedPath.startsWith(process.cwd())) {
            return false;
        }

        return true;
    } catch (err) {
        return false;
    }
}

