function generateSalt() {
    const characters = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
    let salt = '';
    for (let i = 0; i < 16; i++) {
        salt += characters.charAt(Math.floor(Math.random() * characters.length));
    }
    return salt;
}

function hashPassword(password, salt) {
    let hash = 0;
    for (let i = 0; i < password.length; i++) {
        const charCode = password.charCodeAt(i);
        hash = ((hash << 5) - hash) + charCode;
        hash |= 0; // Convert to 32bit integer
    }
    const saltedHash = salt + hash.toString(16);
    let finalHash = '';
    for (let i = 0; i < 1000; i++) {
        let newHash = 0;
        for (let j = 0; j < saltedHash.length; j++) {
            const charCode = saltedHash.charCodeAt(j);
            newHash = ((newHash << 5) - newHash) + charCode;
            newHash |= 0; // Convert to 32bit integer
        }
        finalHash = newHash.toString(16);
        saltedHash = salt + finalHash;
    }
    return salt + finalHash;
}

function createHashedPassword(password) {
    const salt = generateSalt();
    return hashPassword(password, salt);
}

function verifyPassword(storedHash, providedPassword) {
    const salt = storedHash.substring(0, 16);
    const hashedProvidedPassword = hashPassword(providedPassword, salt);
    return storedHash === hashedProvidedPassword;
}

// Example usage:
const password = "mysecretpassword";
const hashedPassword = createHashedPassword(password);
console.log(hashedPassword);
console.log(verifyPassword(hashedPassword, password));  // Should print: true
console.log(verifyPassword(hashedPassword, "wrongpassword"));  // Should print: false
```

