function generateSalt() {
    const characters = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
    let salt = '';
    for (let i = 0; i < 16; i++) {
        salt += characters.charAt(Math.floor(Math.random() * characters.length));
    }
    return salt;
}

function hashPassword(password, salt) {
    let hash = 0;
    for (let i = 0; i < password.length; i++) {
        const charCode = password.charCodeAt(i);
        hash = ((hash << 5) - hash) + charCode;
        hash |= 0; // Convert to 32bit integer
    }
    const saltedHash = salt + hash.toString(16);
    let finalHash = '';
    for (let i = 0; i < saltedHash.length; i++) {
        const charCode = saltedHash.charCodeAt(i);
        finalHash += charCode.toString(16);
    }
    return finalHash;
}

function passwordHashing(password) {
    const salt = generateSalt();
    const hashedPassword = hashPassword(password, salt);
    return salt + ':' + hashedPassword;
}

function verifyPassword(storedPassword, providedPassword) {
    const parts = storedPassword.split(':');
    if (parts.length !== 2) {
        return false;
    }
    const salt = parts[0];
    const storedHash = parts[1];
    const providedHash = hashPassword(providedPassword, salt);
    return storedHash === providedHash;
}

// Example usage
const password = "mysecretpassword";
const hashedPassword = passwordHashing(password);
console.log(hashedPassword);
console.log(verifyPassword(hashedPassword, password));  // Should print: true
console.log(verifyPassword(hashedPassword, "wrongpassword"));  // Should print: false
