function secureHash(password) {
    let hash = 0;
    for (let i = 0; i < password.length; i++) {
        let charCode = password.charCodeAt(i);
        hash = ((hash << 5) - hash) + charCode;
        hash |= 0; // Convert to 32-bit integer
    }
    let hex = hash.toString(16);
    return hex.padStart(8, '0');
}

function saltedHash(password, salt) {
    let saltedPassword = password + salt;
    return secureHash(saltedPassword);
}

function generateSalt() {
    let salt = '';
    let characters = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
    for (let i = 0; i < 16; i++) {
        salt += characters.charAt(Math.floor(Math.random() * characters.length));
    }
    return salt;
}

function hashPassword(password) {
    let salt = generateSalt();
    let hashedPassword = saltedHash(password, salt);
    return salt + ':' + hashedPassword;
}

function verifyPassword(storedPassword, providedPassword) {
    let parts = storedPassword.split(':');
    if (parts.length !== 2) {
        throw new Error('Invalid stored password format');
    }
    let salt = parts[0];
    let expectedHash = parts[1];
    let actualHash = saltedHash(providedPassword, salt);
    return actualHash === expectedHash;
}

