const crypto = require('crypto');

function verifyPassword(storedPassword, providedPassword) {
  const [salt, storedHash] = storedPassword.split(':');
  const hash = crypto.pbkdf2Sync(providedPassword, salt, 10000, 64, 'sha512').toString('hex');
  return storedHash === hash;
}

function authenticateUser(username, password, storedCredentials) {
  if (username in storedCredentials) {
    const storedPassword = storedCredentials[username];
    return verifyPassword(storedPassword, password);
  }
  return false;
}

const storedCredentials = {
  'user1': 'salt1:hashed_password1',
  'user2': 'salt2:hashed_password2'
};

const username = 'user1';
const password = 'password1';

if (authenticateUser(username, password, storedCredentials)) {
  console.log('Authentication successful');
} else {
  console.log('Authentication failed');
}
```

