function clean_data(input_data) {
    if (typeof input_data !== 'string') {
        throw new TypeError('Input data must be a string');
    }

    const escapeHtml = (str) => {
        return str.replace(/&/g, '&amp;')
            .replace(/</g, '&lt;')
            .replace(/>/g, '&gt;')
            .replace(/"/g, '&quot;')
            .replace(/'/g, '&#x27;');
    };

    const removeScriptTags = (str) => {
        return str.replace(/<script.*?>.*?<\/script>/gi, '');
    };

    const removeMaliciousChars = (str) => {
        return str.replace(/[<>]/g, '');
    };

    input_data = escapeHtml(input_data);
    input_data = removeScriptTags(input_data);
    input_data = removeMaliciousChars(input_data);

    return input_data;
}

