function encrypt_data(data, key) {
    let encrypted_data = "";
    for (let i = 0; i < data.length; i++) {
        let charCode = data.charCodeAt(i);
        let keyCode = key.charCodeAt(i % key.length);
        let encryptedCharCode = charCode + keyCode;
        encrypted_data += String.fromCharCode(encryptedCharCode);
    }
    return btoa(encrypted_data);
}

function decrypt_data(encrypted_data, key) {
    let decoded_data = atob(encrypted_data);
    let decrypted_data = "";
    for (let i = 0; i < decoded_data.length; i++) {
        let charCode = decoded_data.charCodeAt(i);
        let keyCode = key.charCodeAt(i % key.length);
        let decryptedCharCode = charCode - keyCode;
        decrypted_data += String.fromCharCode(decryptedCharCode);
    }
    return decrypted_data;
}

let data = "Sensitive Information";
let key = "secretkey";
let encrypted = encrypt_data(data, key);
console.log("Encrypted Data: ", encrypted);
let decrypted = decrypt_data(encrypted, key);
console.log("Decrypted Data: ", decrypted);
