function processFormData(data) {
  const validateInput = (input) => {
    // Simple validation, can be extended based on requirements
    if (typeof input !== 'string') return false;
    return input.trim() !== '';
  };

  const escapeHtml = (str) => {
    return str.replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#039;');
  };

  const sanitizeSql = (input) => {
    // This is a very basic SQL sanitizer. Real applications should use parameterized queries or an ORM.
    return input.replace(/[^a-zA-Z0-9\s]/g, '');
  };

  const processedData = {};

  for (const key in data) {
    if (validateInput(data[key])) {
      const sanitized = sanitizeSql(data[key]);
      processedData[key] = escapeHtml(sanitized);
    } else {
      processedData[key] = null; // or throw an error, based on the requirement
    }
  }

  return processedData;
}

// Example usage:
const formData = {
  name: 'John Doe',
  email: 'johndoe@example.com'
};

