const crypto = require('crypto');
const validator = require('validator');
const escapeHtml = require('escape-html');

class User {
  constructor(username, email, password) {
    this.username = username;
    this.email = email;
    this.password = password;
  }

  static securePassword(password) {
    const salt = crypto.randomBytes(16).toString('hex');
    const hash = crypto.pbkdf2Sync(password, salt, 1000, 64, 'sha512').toString('hex');
    return { salt, hash };
  }

  static validateEmail(email) {
    return validator.isEmail(email);
  }

  static sanitizeInput(input) {
    return escapeHtml(input);
  }

  static registerUser(username, email, password) {
    username = User.sanitizeInput(username);
    email = User.sanitizeInput(email);

    if (!User.validateEmail(email)) {
      throw new Error('Invalid email');
    }

    const { salt, hash } = User.securePassword(password);
    const user = new User(username, email, hash);
    user.salt = salt;
    // Save user to database
    return user;
  }
}

// Example usage
try {
  const user = User.registerUser('testUser', 'test@example.com', 'password123');
  console.log(user);
} catch (error) {
  console.error(error.message);
}
