public class SQLSanitizer {
    public static String sanitizeSQL(String input) {
        if (input == null) {
            return "NULL";
        }

        StringBuilder sanitized = new StringBuilder();
        for (char c : input.toCharArray()) {
            switch (c) {
                case '\'':
                    sanitized.append("''");
                    break;
                case '\\':
                    sanitized.append("\\\\");
                    break;
                case '\0':
                    sanitized.append("\\0");
                    break;
                default:
                    sanitized.append(c);
            }
        }

        return "'" + sanitized.toString() + "'";
    }

    public static void main(String[] args) {
        System.out.println(sanitizeSQL("Hello, World!"));
        System.out.println(sanitizeSQL("It's a test"));
        System.out.println(sanitizeSQL(null));
    }
}
