                case '\t': 
                    sanitized.append("\\t");
                    break;
                case '\b': 
                    sanitized.append("\\b");
                    break;
                case '\f': 
                    sanitized.append("\\f");
                    break;
                default:
                    sanitized.append(c);
            }
        }

        sanitized.append("'");
        return sanitized.toString();
    }

    public static void main(String[] args) {
        System.out.println(sanitizeSQL("Hello, World!"));
        System.out.println(sanitizeSQL("It's a test"));
        System.out.println(sanitizeSQL(null));
