```java
import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class HtmlSanitizer {
    private static final String[] allowedTags = {"p", "img", "br", "strong", "em", "span", "ul", "ol", "li", "a"};
    private static final String[] allowedAttributes = {"src", "alt", "title", "href"};

    public static String sanitize(String html) {
        html = html.replaceAll("(?i)<(script|style|iframe|object|embed|applet).*?>.*?<\\/\\1>", "");
        html = removeDisallowedTags(html);
        html = removeDisallowedAttributes(html);
        html = removeEventHandlers(html);
        return html;
    }

    private static String removeDisallowedTags(String html) {
        Pattern pattern = Pattern.compile("(?i)<(/?)([^>]+)>");
        Matcher matcher = pattern.matcher(html);
        StringBuffer stringBuffer = new StringBuffer();
        while (matcher.find()) {
            String tag = matcher.group(2).split("\\s+")[0].toLowerCase();
            if (isAllowedTag(tag)) {
                matcher.appendReplacement(stringBuffer, "<" + matcher.group(1) + matcher.group(2) + ">");
            } else {
                matcher.appendReplacement(stringBuffer, "");
            }
        }
        matcher.appendTail(stringBuffer);
        return stringBuffer.toString();
    }

    private static boolean isAllowedTag(String tag) {
        for (String allowedTag : allowedTags) {
            if (tag.equals(allowedTag)) {
                return true;
            }
        }
        return false;
    }

    private static String removeDisallowedAttributes(String html) {
        Pattern pattern = Pattern.compile("(?i)<([^>]+)>");
        Matcher matcher = pattern.matcher(html);
        StringBuffer stringBuffer = new StringBuffer();
        while (matcher.find()) {
            String tag = matcher.group(1).split("\\s+")[0].toLowerCase();
            String attributes = matcher.group(1).replaceFirst("^\\S+\\s*", "");
            String sanitizedAttributes = sanitizeAttributes(attributes);
            matcher.appendReplacement(stringBuffer, "<" + tag + " " + sanitizedAttributes + ">");
        }
        matcher.appendTail(stringBuffer);
        return stringBuffer.toString().replaceAll("\\s+>", ">");
    }

    private static String sanitizeAttributes(String attributes) {
        Pattern pattern = Pattern.compile("(?i)(\\S+)\\s*=\\s*\"(.*?)\"");
        Matcher matcher = pattern.matcher(attributes);
        StringBuffer stringBuffer = new StringBuffer();
        while (matcher.find()) {
            String attribute = matcher.group(1).toLowerCase();
            if (isAllowedAttribute(attribute)) {
                matcher.appendReplacement(stringBuffer, attribute + "=\"" + matcher.group(2) + "\" ");
            }
        }
        matcher.appendTail(stringBuffer);
        return stringBuffer.toString().trim();
    }

    private static boolean isAllowedAttribute(String attribute) {
        for (String allowedAttribute : allowedAttributes) {
            if (attribute.equals(allowedAttribute)) {
                return true;
            }
        }
        return false;
    }

    private static String removeEventHandlers(String html) {
        return html.replaceAll("(?i)on\\w+\\s*=\\s*\"(.*?)\"", "");
    }

    public static void main(String[] args) {
        String html = "<p onclick=\"alert('XSS')\">Hello <img src=\"image.jpg\" onerror=\"alert('XSS')\"> World!</p><script>alert('XSS')</script>";
        System.out.println(sanitize(html));
    }
}
```

