import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class HtmlSanitizer {

    private static final String[] allowedTags = {"p", "img", "br", "strong", "em", "span", "ul", "ol", "li", "a"};
    private static final String[] allowedAttributes = {"src", "alt", "href"};

    public static String sanitize(String html) {
        html = html.replaceAll("(?i)<(script|style|iframe|object|embed|applet).*?>.*?<\\/\\1>", "");
        html = removeDisallowedTags(html);
        html = removeDisallowedAttributes(html);
        html = removeEventHandlers(html);
        return html;
    }

    private static String removeDisallowedTags(String html) {
        Pattern pattern = Pattern.compile("(?i)<(/?)([^>]+)>");
        Matcher matcher = pattern.matcher(html);
        StringBuffer buffer = new StringBuffer();
        while (matcher.find()) {
            String tag = matcher.group(2).split("\\s+")[0].toLowerCase();
            if (isAllowedTag(tag)) {
                matcher.appendReplacement(buffer, "<" + matcher.group(1) + matcher.group(2) + ">");
            } else {
                matcher.appendReplacement(buffer, "");
            }
        }
        matcher.appendTail(buffer);
        return buffer.toString();
    }

    private static boolean isAllowedTag(String tag) {
        for (String allowedTag : allowedTags) {
            if (tag.equals(allowedTag)) {
                return true;
            }
        }
        return false;
    }

    private static String removeDisallowedAttributes(String html) {
        Pattern pattern = Pattern.compile("(?i)<([^>]+)>");
        Matcher matcher = pattern.matcher(html);
        StringBuffer buffer = new StringBuffer();
        while (matcher.find()) {
            String tagContent = matcher.group(1);
            String[] parts = tagContent.split("\\s+");
            StringBuilder sb = new StringBuilder(parts[0]);
            for (int i = 1; i < parts.length; i++) {
                String attribute = parts[i].split("=")[0].toLowerCase();
                if (isAllowedAttribute(attribute)) {
                    sb.append(" ").append(parts[i]);
                }
            }
            matcher.appendReplacement(buffer, "<" + sb.toString() + ">");
        }
        matcher.appendTail(buffer);
        return buffer.toString();
    }

    private static boolean isAllowedAttribute(String attribute) {
        for (String allowedAttribute : allowedAttributes) {
            if (attribute.equals(allowedAttribute)) {
                return true;
            }
        }
        return false;
    }

    private static String removeEventHandlers(String html) {
        Pattern pattern = Pattern.compile("(?i)on\\w+\\s*?=\\s*?[\"][^\"]*?[\"]");
        Matcher matcher = pattern.matcher(html);
        return matcher.replaceAll("");
    }

    public static void main(String[] args) {
        String html = "<p onclick='alert(1)'>Hello <img src='image.jpg' onerror='alert(2)'> World!</p><script>alert(3)</script>";
        System.out.println(sanitize(html));
    }
}
