```java
import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class HtmlSanitizer {
    private static final String[] allowedTags = {"p", "img", "br", "strong", "em", "span", "ul", "ol", "li", "a"};
    private static final String[] allowedAttributes = {"src", "alt", "href"};

    public static String sanitize(String html) {
        html = html.replaceAll("(?i)<script>.*?</script>", "");
        html = removeDisallowedTags(html);
        html = removeDisallowedAttributes(html);
        return html;
    }

    private static String removeDisallowedTags(String html) {
        Pattern pattern = Pattern.compile("<(.*?)>");
        Matcher matcher = pattern.matcher(html);
        StringBuffer stringBuffer = new StringBuffer();
        while (matcher.find()) {
            String tag = matcher.group(1).split("\\s+")[0].toLowerCase();
            if (!isAllowedTag(tag)) {
                matcher.appendReplacement(stringBuffer, "");
            } else {
                matcher.appendReplacement(stringBuffer, matcher.group(0));
            }
        }
        matcher.appendTail(stringBuffer);
        return stringBuffer.toString();
    }

    private static boolean isAllowedTag(String tag) {
        for (String allowedTag : allowedTags) {
            if (tag.equals(allowedTag)) {
                return true;
            }
        }
        return false;
    }

    private static String removeDisallowedAttributes(String html) {
        Pattern pattern = Pattern.compile("<(.*?)>");
        Matcher matcher = pattern.matcher(html);
        StringBuffer stringBuffer = new StringBuffer();
        while (matcher.find()) {
            String tag = matcher.group(1);
            String[] parts = tag.split("\\s+");
            StringBuilder sb = new StringBuilder("<" + parts[0]);
            for (int i = 1; i < parts.length; i++) {
                String attribute = parts[i].split("=")[0].trim().toLowerCase();
                if (isAllowedAttribute(attribute)) {
                    sb.append(" ").append(parts[i]);
                }
            }
            if (parts.length > 1) {
                sb.append(">");
                matcher.appendReplacement(stringBuffer, sb.toString());
            } else {
                matcher.appendReplacement(stringBuffer, matcher.group(0));
            }
        }
        matcher.appendTail(stringBuffer);
        return stringBuffer.toString();
    }

    private static boolean isAllowedAttribute(String attribute) {
        for (String allowedAttribute : allowedAttributes) {
            if (attribute.equals(allowedAttribute)) {
                return true;
            }
        }
        return false;
    }

    public static void main(String[] args) {
        String html = "<p>Hello <script>alert('XSS')</script> world! <img src='image.jpg' onerror='alert(\"XSS\")'> <a href='https://www.example.com'>Example</a></p>";
        System.out.println(sanitize(html));
    }
}
