import org.owasp.html.HtmlPolicyBuilder;
import org.owasp.html.PolicyFactory;

public class HtmlSanitizer {
    private static final PolicyFactory POLICY = new HtmlPolicyBuilder()
            .allowElements("p", "b", "i", "u", "em", "strong")
            .allowAttributes("style").onElements("p")
            .toFactory();

    public static String sanitizeHtml(String html) {
        return POLICY.sanitize(html);
    }

    public static void main(String[] args) {
        String userInput = "<p style='color: red'>Hello, <script>alert('XSS')</script> world!</p>";
        String sanitizedHtml = sanitizeHtml(userInput);
        System.out.println(sanitizedHtml);
    }
}
