```java
public class ShellCommandSanitizer {

    public static String sanitize(String command) {
        StringBuilder sanitizedCommand = new StringBuilder();
        boolean inQuote = false;
        boolean escapeNext = false;

        for (char c : command.toCharArray()) {
            if (escapeNext) {
                sanitizedCommand.append(c);
                escapeNext = false;
            } else if (c == '\\') {
                escapeNext = true;
                sanitizedCommand.append(c);
            } else if (c == '"') {
                inQuote = !inQuote;
                sanitizedCommand.append(c);
            } else if (Character.isWhitespace(c) && !inQuote) {
                // Replace multiple whitespaces with a single space
                if (sanitizedCommand.length() == 0 || sanitizedCommand.charAt(sanitizedCommand.length() - 1) != ' ') {
                    sanitizedCommand.append(' ');
                }
            } else if (!Character.isWhitespace(c) || inQuote) {
                sanitizedCommand.append(c);
            }
        }

        // Remove leading and trailing whitespaces
        while (sanitizedCommand.length() > 0 && Character.isWhitespace(sanitizedCommand.charAt(0))) {
            sanitizedCommand.deleteCharAt(0);
        }
        while (sanitizedCommand.length() > 0 && Character.isWhitespace(sanitizedCommand.charAt(sanitizedCommand.length() - 1))) {
            sanitizedCommand.deleteCharAt(sanitizedCommand.length() - 1);
        }

        return sanitizedCommand.toString();
    }

    public static void main(String[] args) {
        System.out.println(sanitize("   ls   -l   "));
        System.out.println(sanitize("echo \"Hello World\""));
        System.out.println(sanitize("echo Hello\\ World"));
    }
}
