```java
public class ShellCommandSanitizer {

    public static String sanitize(String command) {
        StringBuilder sanitizedCommand = new StringBuilder();
        boolean inQuote = false;
        for (char c : command.toCharArray()) {
            if (c == '"') {
                inQuote = !inQuote;
                sanitizedCommand.append(c);
            } else if (Character.isWhitespace(c) && !inQuote) {
                sanitizedCommand.append(' ');
            } else if (isSpecialChar(c) && !inQuote) {
                // escape special characters
                sanitizedCommand.append('\\').append(c);
            } else {
                sanitizedCommand.append(c);
            }
        }
        return sanitizedCommand.toString().trim().replaceAll("\\s+", " ");
    }

    private static boolean isSpecialChar(char c) {
        String specialChars = "|&;(){}<>~*?$!#`\\[]";
        return specialChars.indexOf(c) != -1;
    }

    public static void main(String[] args) {
        System.out.println(sanitize("ls -l | grep keyword"));
        System.out.println(sanitize("echo \"Hello World\""));
        System.out.println(sanitize("rm -rf /path/to/file"));
    }
}
