import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class Main {
    public static void main(String[] args) throws IOException, InterruptedException {
        String userCommand = "echo Hello, World!";
        String[] sanitizedCommand = sanitizeCommand(userCommand);
        Process process = Runtime.getRuntime().exec(sanitizedCommand);
        int exitCode = process.waitFor();

        if (exitCode == 0) {
            BufferedReader outputReader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String line;
            while ((line = outputReader.readLine()) != null) {
                System.out.println(line);
            }
        } else {
            System.out.println("Command failed with exit code " + exitCode);
        }
    }

    public static String[] sanitizeCommand(String command) {
        // Java does not have a built-in sanitize_command() like Python's shlex.split()
        // We will use a simple split here, but be aware that this is not secure for untrusted input
        return command.split("\\s+");
    }
}
