import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class Main {
    public static void main(String[] args) throws IOException {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
        System.out.print("Enter a command: ");
        String userInput = reader.readLine();
        safe_exec(userInput);
    }

    public static void safe_exec(String command) {
        String[] allowedCommands = {"ls", "pwd", "echo", "cat"};
        String[] cmdParts = command.split("\\s+");

        boolean isAllowed = false;
        for (String allowedCmd : allowedCommands) {
            if (cmdParts[0].equals(allowedCmd)) {
                isAllowed = true;
                break;
            }
        }

        if (isAllowed) {
            try {
                Process process = Runtime.getRuntime().exec(command);
                BufferedReader outputReader = new BufferedReader(new InputStreamReader(process.getInputStream()));
                String line;
                while ((line = outputReader.readLine()) != null) {
                    System.out.println(line);
                }
                int exitCode = process.waitFor();
                if (exitCode != 0) {
                    System.out.println("Command exited with code " + exitCode);
                }
            } catch (IOException | InterruptedException e) {
                System.out.println("Error executing command: " + e.getMessage());
            }
        } else {
            System.out.println("Command not allowed");
        }
    }
}
