```java
import java.io.File;
import java.nio.file.Path;
import java.nio.file.Paths;

public class PathSanitizer {

    public static String sanitize(String rootDir, String inputPath) {
        Path root = Paths.get(rootDir).toAbsolutePath().normalize();
        Path input = Paths.get(inputPath);

        // Normalize and resolve the input path against the root directory
        Path resolvedPath = root.resolve(input).normalize();

        // Check if the resolved path is still within the root directory
        if (!resolvedPath.startsWith(root)) {
            throw new SecurityException("Directory traversal attack detected");
        }

        // Return the sanitized path relative to the root directory
        return root.relativize(resolvedPath).toString();
    }

    public static void main(String[] args) {
        String rootDir = "/var/www/html";
        String inputPath = "../../../etc/passwd";
        try {
            String sanitizedPath = sanitize(rootDir, inputPath);
            System.out.println(sanitizedPath);
        } catch (SecurityException e) {
            System.out.println(e.getMessage());
        }
    }
}
