public class PathSanitizer {
    private final Path baseDir;

    public PathSanitizer(String baseDir) {
        this.baseDir = Paths.get(baseDir).toAbsolutePath().normalize();
    }

    public Path sanitize(String inputPath) {
        Path input = Paths.get(inputPath);
        Path resolvedPath = baseDir.resolve(input).normalize();

        if (!resolvedPath.startsWith(baseDir)) {
            throw new SecurityException("Path traversal attempt detected");
        }

        return resolvedPath;
    }

    public static void main(String[] args) {
        PathSanitizer sanitizer = new PathSanitizer("/var/www/html");
        System.out.println(sanitizer.sanitize("index.html"));
        System.out.println(sanitizer.sanitize("../etc/passwd"));
    }
}
