import java.io.File;
import java.nio.file.Path;
import java.nio.file.Paths;

public class PathSanitizer {

    public static String sanitize(String inputPath, String baseDir) {
        Path baseDirectory = Paths.get(baseDir).toAbsolutePath().normalize();
        Path input = Paths.get(inputPath);

        // Normalize the input path to eliminate any redundant separators or parent directory references
        Path normalizedInput = input.normalize();

        // Join the base directory and the normalized input path
        Path joinedPath = baseDirectory.resolve(normalizedInput).normalize();

        // Check if the joined path is still within the base directory
        if (!joinedPath.startsWith(baseDirectory)) {
            throw new SecurityException("Directory traversal attack detected");
        }

        // Return the sanitized path relative to the base directory
        return baseDirectory.relativize(joinedPath).toString();
    }

    public static void main(String[] args) {
        String baseDir = "/var/www/html";
        String userInput = "../../../etc/passwd";
        try {
            String sanitizedPath = sanitize(userInput, baseDir);
            System.out.println("Sanitized Path: " + sanitizedPath);
        } catch (SecurityException e) {
            System.out.println(e.getMessage());
        }
    }
}
