public class Main {
    public static String securePath(String userInputPath, String baseDir) {
        File baseFile = new File(baseDir);
        File userFile = new File(baseFile, userInputPath);
        String canonicalPath;
        try {
            canonicalPath = userFile.getCanonicalPath();
        } catch (Exception e) {
            return null;
        }
        if (!canonicalPath.startsWith(baseDir)) {
            return null;
        }
        return canonicalPath;
    }

    public static void main(String[] args) {
        String userInputPath = "../etc/passwd";
        String baseDir = "/var/www/html";
        String sanitizedPath = securePath(userInputPath, baseDir);
        if (sanitizedPath != null) {
            try {
                File file = new File(sanitizedPath);
                // Open the file
                System.out.println("File opened successfully: " + file.getAbsolutePath());
            } catch (Exception e) {
                System.out.println("Error opening file: " + e.getMessage());
            }
        } else {
            System.out.println("Invalid file path");
        }
    }
