        // Check if the path is absolute
        if (normalizedPath.isAbsolute()) {
            // If the path is absolute, check if it's within a safe directory
            // For this example, let's assume /safe/dir is the safe directory
            Path safeDir = Paths.get("/safe/dir");
            if (!normalizedPath.startsWith(safeDir)) {
                return null; // Path is not within a safe directory
            }
        }

        // Additional checks can be added here, such as checking the file extension or contents

        return normalizedPath;
    }
