```java
import java.security.SecureRandom;
import java.nio.charset.StandardCharsets;

public class PasswordHasher {
    private static final String CHARACTERS = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789";
    private static final int SALT_SIZE = 16;
    private static final int ITERATIONS = 10000;
    private static final int KEY_SIZE = 32;

    public static String hashPassword(String password) {
        String salt = generateSalt();
        byte[] hashedPassword = pbkdf2(password, salt);
        return salt + ":" + bytesToHex(hashedPassword);
    }

    public static boolean verifyPassword(String password, String hashedPassword) {
        String[] parts = hashedPassword.split(":");
        if (parts.length != 2) {
            throw new RuntimeException("Invalid hashed password");
        }
        String salt = parts[0];
        byte[] expectedHash = hexToBytes(parts[1]);
        byte[] actualHash = pbkdf2(password, salt);
        return constantTimeCompare(expectedHash, actualHash);
    }

    private static String generateSalt() {
        SecureRandom random = new SecureRandom();
        StringBuilder salt = new StringBuilder(SALT_SIZE);
        for (int i = 0; i < SALT_SIZE; i++) {
            salt.append(CHARACTERS.charAt(random.nextInt(CHARACTERS.length())));
        }
        return salt.toString();
    }

    private static byte[] pbkdf2(String password, String salt) {
        byte[] passwordBytes = password.getBytes(StandardCharsets.UTF_8);
        byte[] saltBytes = salt.getBytes(StandardCharsets.UTF_8);
        byte[] key = new byte[KEY_SIZE];
        for (int i = 1; i <= ITERATIONS; i++) {
            byte[] hmac = hmacSha256(passwordBytes, saltBytes, i);
            if (i == 1) {
                System.arraycopy(hmac, 0, key, 0, KEY_SIZE);
            } else {
                for (int j = 0; j < KEY_SIZE; j++) {
                    key[j] ^= hmac[j];
                }
            }
        }
        return key;
    }

    private static byte[] hmacSha256(byte[] key, byte[] data, int blockIndex) {
        javax.crypto.Mac mac;
        try {
            mac = javax.crypto.Mac.getInstance("HmacSHA256");
            mac.init(new javax.crypto.spec.SecretKeySpec(key, "HmacSHA256"));
            byte[] block = new byte[data.length + 4];
            System.arraycopy(data, 0, block, 0, data.length);
            block[data.length] = (byte) (blockIndex >> 24);
            block[data.length + 1] = (byte) (blockIndex >> 16);
            block[data.length + 2] = (byte) (blockIndex >> 8);
            block[data.length + 3] = (byte) blockIndex;
            return mac.doFinal(block);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    private static String bytesToHex(byte[] bytes) {
        StringBuilder hex = new StringBuilder();
        for (byte b : bytes) {
            hex.append(String.format("%02x", b));
        }
        return hex.toString();
    }

    private static byte[] hexToBytes(String hex) {
        int len = hex.length();
        byte[] bytes = new byte[len / 2];
        for (int i = 0; i < len; i += 2) {
            bytes[i / 2] = (byte) ((Character.digit(hex.charAt(i), 16) << 4) + Character.digit(hex.charAt(i + 1), 16));
        }
        return bytes;
    }

    private static boolean constantTimeCompare(byte[] a, byte[] b) {
        if (a.length != b.length) {
            return false;
        }
        int result = 0;
        for (int i = 0; i < a.length; i++) {
            result |= a[i] ^ b[i];
        }
        return result == 0;
    }

    public static void main(String[] args) {
        String password = "mysecretpassword";
        String hashedPassword = hashPassword(password);
        System.out.println("Hashed Password: " + hashedPassword);
        System.out.println("Verification: " + verifyPassword(password, hashedPassword));
    }
}
