```java
import java.nio.charset.StandardCharsets;
import java.security.SecureRandom;
import java.util.Base64;

public class PasswordHasher {
    private static final int SALT_SIZE = 16;
    private static final int ITERATIONS = 10000;
    private static final int KEY_SIZE = 256;

    public static String hashPassword(String password) {
        byte[] salt = generateSalt(SALT_SIZE);
        byte[] hashedPassword = pbkdf2(password, salt, ITERATIONS, KEY_SIZE);
        return Base64.getEncoder().encodeToString(salt) + ":" + Base64.getEncoder().encodeToString(hashedPassword);
    }

    public static boolean verifyPassword(String password, String hashedPassword) {
        String[] parts = hashedPassword.split(":");
        if (parts.length != 2) {
            throw new RuntimeException("Invalid hashed password format");
        }
        byte[] salt = Base64.getDecoder().decode(parts[0]);
        byte[] expectedHash = Base64.getDecoder().decode(parts[1]);
        byte[] actualHash = pbkdf2(password, salt, ITERATIONS, KEY_SIZE);
        return slowEquals(expectedHash, actualHash);
    }

    private static byte[] generateSalt(int size) {
        SecureRandom random = new SecureRandom();
        byte[] salt = new byte[size];
        random.nextBytes(salt);
        return salt;
    }

    private static byte[] pbkdf2(String password, byte[] salt, int iterations, int keySize) {
        javax.crypto.SecretKeyFactory skf;
        try {
            skf = javax.crypto.SecretKeyFactory.getInstance("PBKDF2WithHmacSHA256");
            javax.crypto.spec.PBEKeySpec spec = new javax.crypto.spec.PBEKeySpec(password.toCharArray(), salt, iterations, keySize);
            return skf.generateSecret(spec).getEncoded();
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    private static boolean slowEquals(byte[] a, byte[] b) {
        int diff = a.length ^ b.length;
        for (int i = 0; i < a.length && i < b.length; i++) {
            diff |= a[i] ^ b[i];
        }
        return diff == 0;
    }

    public static void main(String[] args) {
        String password = "mysecretpassword";
        String hashedPassword = hashPassword(password);
        System.out.println(hashedPassword);
        System.out.println(verifyPassword(password, hashedPassword));  // prints: true
        System.out.println(verifyPassword("wrongpassword", hashedPassword));  // prints: false
    }
}
