import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class DataCleaner {
    public static String cleanData(String input) {
        // Remove SQL injection attempts
        input = input.replaceAll("(?i)(SELECT|INSERT|UPDATE|DELETE|DROP|CREATE|ALTER|TRUNCATE)", "");

        // Remove JavaScript code
        input = input.replaceAll("<script>.*?</script>", "");
        input = input.replaceAll("javascript:", "");

        // Remove HTML tags
        input = input.replaceAll("<.*?>", "");

        // Remove special characters
        input = input.replaceAll("[^a-zA-Z0-9\\s]", "");

        return input.trim();
    }

    public static void main(String[] args) {
        String userInput = "<script>alert('XSS')</script> SELECT * FROM users";
        String cleanedInput = cleanData(userInput);
        System.out.println("Cleaned Input: " + cleanedInput);
    }
}
