public class Main {
    public static String encrypt_data(String data) {
        StringBuilder encrypted_data = new StringBuilder();
        for (char c : data.toCharArray()) {
            encrypted_data.append((char) (c + 3));
        }
        return encrypted_data.toString();
    }

    public static String decrypt_data(String encrypted_data) {
        StringBuilder decrypted_data = new StringBuilder();
        for (char c : encrypted_data.toCharArray()) {
            decrypted_data.append((char) (c - 3));
        }
        return decrypted_data.toString();
    }

    public static void main(String[] args) {
        String data = "Hello, World!";
        String encrypted = encrypt_data(data);
        System.out.println("Encrypted: " + encrypted);
        System.out.println("Decrypted: " + decrypt_data(encrypted));
    }
}
