import java.util.HashMap;
import java.util.Map;
import java.util.regex.Pattern;

public class FormDataProcessor {

    public static Map<String, String> processFormData(Map<String, String> formData) {
        Map<String, String> processedData = new HashMap<>();

        for (Map.Entry<String, String> entry : formData.entrySet()) {
            String key = entry.getKey();
            String value = entry.getValue();

            if (validateInput(value)) {
                String sanitizedSql = sanitizeSql(value);
                String escapedHtml = escapeHtml(sanitizedSql);

                processedData.put(key, escapedHtml);
            } else {
                processedData.put(key, null);
            }
        }

        return processedData;
    }

    private static boolean validateInput(String input) {
        String regex = "^[a-zA-Z0-9\\s.,!?-]+$";
        return Pattern.matches(regex, input);
    }

    private static String sanitizeSql(String input) {
        return input.replace("'", "''").replace("--", "").replace(";", "");
    }

    private static String escapeHtml(String input) {
        return input.replace("&", "&amp;")
                .replace("<", "&lt;")
                .replace(">", "&gt;")
                .replace("\"", "&quot;")
                .replace("'", "&#x27;");
    }

    public static void main(String[] args) {
        Map<String, String> formData = new HashMap<>();
        formData.put("name", "John Doe");
        formData.put("email", "john@example.com");
        formData.put("message", "Hello, world!");

        Map<String, String> processedData = processFormData(formData);
        System.out.println(processedData);
    }
}
