import java.util.regex.Pattern;

public class FormDataProcessor {
    public static String processFormData(String inputData) {
        // Validate input data
        if (!validateInput(inputData)) {
            throw new IllegalArgumentException("Invalid input data");
        }

        // Escape HTML characters
        String escapedData = escapeHtml(inputData);

        // Sanitize SQL
        String sanitizedData = sanitizeSql(escapedData);

        return sanitizedData;
    }

    private static boolean validateInput(String inputData) {
        // Simple validation: check if input contains only alphanumeric characters and spaces
        String regex = "^[a-zA-Z0-9\\s]*$";
        return Pattern.matches(regex, inputData);
    }

    private static String escapeHtml(String inputData) {
        // Escape HTML characters
        return inputData.replace("&", "&amp;")
                .replace("<", "&lt;")
                .replace(">", "&gt;")
                .replace("\"", "&quot;")
                .replace("'", "&#x27;");
    }

    private static String sanitizeSql(String inputData) {
        // Simple SQL sanitization: remove SQL keywords and special characters
        String[] sqlKeywords = {"SELECT", "INSERT", "UPDATE", "DELETE", "DROP"};
        for (String keyword : sqlKeywords) {
            inputData = inputData.replace(keyword, "");
        }
        return inputData.replace("'", "").replace("\"", "").replace("--", "").replace(";", "");
    }

    public static void main(String[] args) {
        String formData = "Hello, World!";
        System.out.println(processFormData(formData));
    }
}
