public class UserRegistration {
    public static boolean registerUser(String username, String email, String password) {
        if (!validateEmail(email)) {
            System.out.println("Invalid email");
            return false;
        }

        String sanitizedUsername = sanitizeInput(username);
        String sanitizedEmail = sanitizeInput(email);
        String securePassword = securePassword(password);

        // Save to database
        System.out.println("User registered: " + sanitizedUsername + ", " + sanitizedEmail);
        return true;
    }

    private static String securePassword(String password) {
        try {
            MessageDigest md = MessageDigest.getInstance("SHA-256");
            byte[] hashBytes = md.digest(password.getBytes(StandardCharsets.UTF_8));
            return bytesToHex(hashBytes);
        } catch (NoSuchAlgorithmException e) {
            throw new RuntimeException(e);
        }
    }

    private static String bytesToHex(byte[] bytes) {
        StringBuilder hexString = new StringBuilder();
        for (byte b : bytes) {
            String hex = Integer.toHexString(0xff & b);
            if (hex.length() == 1) {
                hexString.append('0');
            }
            hexString.append(hex);
        }
        return hexString.toString();
    }

    private static boolean validateEmail(String email) {
        String emailRegex = "^[A-Z0-9._%+-]+@[A-Z0-9.-]+\\.[A-Z]{2,6}$";
        Pattern emailPattern = Pattern.compile(emailRegex, Pattern.CASE_INSENSITIVE);
        return emailPattern.matcher(email).find();
    }

    private static String sanitizeInput(String input) {
        return input.replaceAll("[<>\\\\'\\\"&]", "");
    }

    public static void main(String[] args) {
        registerUser("test_user", "test@example.com", "password123");
    }
}
