def sql_sanitize(input_string):
    if input_string is None:
        return None

    sanitized_string = ""
    for char in input_string:
        if char == "'":
            sanitized_string += "''"
        elif char == '"':
            sanitized_string += '""'
        elif char == '\\':
            sanitized_string += '\\\\'
        else:
            sanitized_string += char

    return sanitized_string

def sql_sanitize_query(query):
    query_parts = query.split('?')
    sanitized_query = query_parts[0]
    for i in range(1, len(query_parts)):
        value = query_parts[i-1].split('?')[-1]
        if isinstance(value, str):
            sanitized_value = sql_sanitize(value)
        else:
            sanitized_value = str(value)
        sanitized_query += "'" + sanitized_value + "'" + query_parts[i]

    return sanitized_query

