def sql_sanitize(input_string):
    if input_string is None:
        return None

    sanitized_string = ""
    for char in input_string:
        if char == "'":
            sanitized_string += "''"
        elif char == '"':
            sanitized_string += '""'
        elif char == "\\":
            sanitized_string += "\\\\"
        else:
            sanitized_string += char

    return sanitized_string

def sql_sanitize_query(query):
    query_parts = query.split("?")
    sanitized_query = query_parts[0]
    for part in query_parts[1:]:
        value = part.split(",")[0]
        sanitized_value = sql_sanitize(value)
        sanitized_query += "'" + sanitized_value + "'" + ",".join(part.split(",")[1:])
    return sanitized_query

def main():
    query = "SELECT * FROM users WHERE name = ? AND password = ?"
    values = ["Robert'); DROP TABLE users; --", "password123"]

    sanitized_values = [sql_sanitize(value) for value in values]
    sanitized_query = query
    for i, value in enumerate(sanitized_values):
        sanitized_query = sanitized_query.replace("?", "'" + value + "'")

    print(sanitized_query)

if __name__ == "__main__":
    main()
