            sanitized_string += '""'
        elif char == '\\':
            sanitized_string += '\\\\'
        else:
            sanitized_string += char

    return sanitized_string

def sql_query(table_name, columns, conditions=None):
    column_str = ", ".join(columns)
    query = f"SELECT {column_str} FROM {table_name}"

    if conditions:
        condition_str = " AND ".join(conditions)
        query += f" WHERE {condition_str}"

    return query

def main():
    user_input_name = "Robert'); DROP TABLE Students; --"
    sanitized_name = sql_sanitize(user_input_name)
    print(sanitized_name)

    columns = ["Name", "Age"]
    conditions = [f"Name = '{sanitized_name}'", "Age > 18"]
    query = sql_query("Students", columns, conditions)
    print(query)

if __name__ == "__main__":
    main()
