import re

class HTMLSanitizer:
    def __init__(self):
        self.allowed_tags = ['p', 'img', 'br', 'strong', 'em', 'span', 'a', 'ul', 'ol', 'li', 'h1', 'h2', 'h3', 'h4', 'h5', 'h6']
        self.allowed_attributes = {
            'img': ['src', 'alt'],
            'a': ['href', 'title']
        }

    def sanitize(self, html):
        html = self.remove_scripts(html)
        html = self.remove_style(html)
        html = self.remove_iframe(html)
        html = self.remove_disallowed_tags(html)
        html = self.remove_disallowed_attributes(html)
        return html

    def remove_scripts(self, html):
        return re.sub(r'<script>.*?</script>', '', html, flags=re.DOTALL)

    def remove_style(self, html):
        return re.sub(r'<style>.*?</style>', '', html, flags=re.DOTALL)

    def remove_iframe(self, html):
        return re.sub(r'<iframe>.*?</iframe>', '', html, flags=re.DOTALL)

    def remove_disallowed_tags(self, html):
        for tag in re.findall(r'<(\w+).*?>', html):
            if tag not in self.allowed_tags:
                html = re.sub(rf'<{tag}.*?>.*?<\/{tag}>', '', html, flags=re.DOTALL)
                html = re.sub(rf'<{tag}.*?>', '', html)
        return html

    def remove_disallowed_attributes(self, html):
        for tag, attributes in self.allowed_attributes.items():
            for match in re.finditer(rf'<{tag}([^>]*)>', html):
                attrs = match.group(1)
                for attr in re.findall(r'\b(\w+)\s*=\s*"[^"]*"', attrs):
                    if attr not in attributes:
                        html = re.sub(rf'{attr}\s*=\s*"[^"]*"', '', html)
        return html

def main():
    html = '<p>Hello <script>alert("XSS")</script> world!</p><img src="image.jpg" onerror="alert(\'XSS\')">'
    sanitizer = HTMLSanitizer()
    print(sanitizer.sanitize(html))

if __name__ == '__main__':
    main()
