    html_escape_table = {
        "&": "&amp;",
        '"': "&quot;",
        "'": "&apos;",
        ">": "&gt;",
        "<": "&lt;",
    }
    return "".join(html_escape_table.get(c, c) for c in s)

def main():
    print(escape_html("<hello> world & python"))
    print(escape_html("'hello' world & python"))
    print(escape_html('"hello" world & python'))

if __name__ == "__main__":
    main()
```

