import re

class Sanitizer:
    def __init__(self):
        self.whitelist = set('abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789._-')

    def sanitize(self, command):
        tokens = self.tokenize(command)
        sanitized_tokens = [self.sanitize_token(token) for token in tokens]
        return ' '.join(sanitized_tokens)

    def tokenize(self, command):
        tokens = []
        current_token = ''
        in_quote = False
        for char in command:
            if char in [' ', '\t'] and not in_quote:
                if current_token:
                    tokens.append(current_token)
                    current_token = ''
            elif char in ['"', "'"] and not in_quote:
                in_quote = True
                current_token += char
            elif char == in_quote:
                in_quote = False
                current_token += char
            else:
                current_token += char
        if current_token:
            tokens.append(current_token)
        return tokens

    def sanitize_token(self, token):
        sanitized_token = ''
        for char in token:
            if char in self.whitelist:
                sanitized_token += char
            elif char.isdigit():
                sanitized_token += char
            else:
                sanitized_token += '_'
        return re.sub(r'^[^a-zA-Z_]+', '', sanitized_token)

def main():
    sanitizer = Sanitizer()
    commands = [
        'echo Hello World',
        'ls -l; rm -rf /',
        'python script.py --arg1="value1" --arg2=\'value2\'',
        'curl http://example.com/$(rm -rf /)'
    ]
    for command in commands:
        print(f'Original: {command}')
        print(f'Sanitized: {sanitizer.sanitize(command)}')
        print()

if __name__ == '__main__':
    main()
```

```python
import re

class Sanitizer:
    def __init__(self, allowed_chars=None, allowed_commands=None):
        if allowed_chars is None:
            allowed_chars = set('abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789._/-')
        if allowed_commands is None:
            allowed_commands = set(['ls', 'cd', 'mkdir', 'rm', 'cp', 'mv', 'find', 'grep', 'echo'])
        self.allowed_chars = allowed_chars
        self.allowed_commands = allowed_commands

    def sanitize(self, command):
        command = command.strip()
        if not command:
            return None
        parts = self.split_command(command)
        if not parts:
            return None
        if parts[0] not in self.allowed_commands:
            return None
        sanitized_parts = []
        for part in parts:
            sanitized_part = self.sanitize_part(part)
            if not sanitized_part:
                return None
            sanitized_parts.append(sanitized_part)
        return ' '.join(sanitized_parts)

    def split_command(self, command):
        parts = []
        current_part = ''
        quote = None
        for char in command:
            if quote:
                if char == quote:
                    quote = None
                else:
                    current_part += char
            elif char in [' ', '\t']:
                if current_part:
                    parts.append(current_part)
                    current_part = ''
            elif char in ['"', "'"]:
                quote = char
                current_part += char
            else:
                current_part += char
        if current_part:
            parts.append(current_part)
        return parts

    def sanitize_part(self, part):
        sanitized_part = ''
        for char in part:
            if char in self.allowed_chars:
                sanitized_part += char
            else:
                return None
        return sanitized_part


def main():
    sanitizer = Sanitizer()
    commands = [
        'ls -l',
        'cd ~',
        'mkdir test',
        'rm -rf test',
        'cp test /etc/passwd',
        'mv test /etc/passwd',
        'find . -name test',
        'grep test *',
        'echo test',
        'test; ls',
        'test|ls',
        'test&ls',
    ]
    for command in commands:
        sanitized_command = sanitizer.sanitize(command)
        print(f'Command: {command}, Sanitized: {sanitized_command}')


if __name__ == '__main__':
    main()
```

```python
import re

class Sanitizer:
    def __init__(self, allowed_chars=None, allowed_commands=None):
        self.allowed_chars = allowed_chars if allowed_chars else set('abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789_.-')
        self.allowed_commands = allowed_commands if allowed_commands else set()

    def sanitize(self, command):
        command = self.remove_disallowed_chars(command)
        command = self.split_command(command)
        command = self.validate_command(command)
        return ' '.join(command)

    def remove_disallowed_chars(self, command):
        return ''.join(c for c in command if c in self.allowed_chars or c in [' ', '&', '|', ';', '$', '`', '\\', '\'', '"'])

    def split_command(self, command):
        parts = []
        current_part = ''
        quote_char = None
        for c in command:
            if quote_char:
                if c == quote_char:
                    quote_char = None
                else:
                    current_part += c
            elif c in [' ', '&', '|', ';']:
                if current_part:
                    parts.append(current_part)
                    current_part = ''
                parts.append(c)
            elif c in ['\'', '"']:
                quote_char = c
                current_part += c
            else:
                current_part += c
        if current_part:
            parts.append(current_part)
        return parts

    def validate_command(self, parts):
        if not parts:
            return []
        command = parts[0]
        if command not in self.allowed_commands and command not in ['cd', 'pwd', 'ls', 'echo']:
            return []
        sanitized_parts = [command]
        for part in parts[1:]:
            if part in ['&', '|', ';']:
                sanitized_parts.append(part)
            elif part.startswith('$'):
                sanitized_parts.append(part)
            elif re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', part):
                sanitized_parts.append(part)
            elif re.match(r'^".*"$', part):
                sanitized_parts.append(part)
            elif re.match(r'^\'.*\'$', part):
                sanitized_parts.append(part)
        return sanitized_parts

def main():
    sanitizer = Sanitizer()
    command = input("Enter a command: ")
    sanitized_command = sanitizer.sanitize(command)
    print(sanitized_command)

if __name__ == "__main__":
    main()
```

