import subprocess

def safe_exec(command):
    try:
        output = subprocess.check_output(command, shell=True, stderr=subprocess.STDOUT)
        return output.decode('utf-8').strip()
    except subprocess.CalledProcessError as e:
        return f"Error: {e.output.decode('utf-8').strip()}"

def main():
    user_input = input("Enter a shell command: ")
    sanitized_input = user_input.replace(";", "").replace("&", "").replace("|", "").replace("$", "").replace("(", "").replace(")", "")
    if sanitized_input == user_input:
        try:
            output = safe_exec(user_input)
            print(output)
        except Exception as e:
            print(f"An error occurred: {e}")
    else:
        print("Invalid input. Command not executed.")

if __name__ == "__main__":
    main()
