```python
import os
import pathlib

class PathSanitizer:
    def __init__(self, base_path):
        self.base_path = pathlib.Path(base_path).resolve()

    def sanitize(self, input_path):
        input_path = pathlib.Path(input_path)
        absolute_input_path = input_path.resolve()

        try:
            relative_path = absolute_input_path.relative_to(self.base_path)
        except ValueError:
            return None

        sanitized_path = self.base_path / relative_path
        return sanitized_path

def main():
    sanitizer = PathSanitizer('/var/www/html')

    paths_to_test = [
        '../etc/passwd',
        './static/css/style.css',
        '/static/js/script.js',
        '../../../etc/shadow',
        'static/../static/images/logo.png',
    ]

    for path in paths_to_test:
        sanitized = sanitizer.sanitize(path)
        if sanitized:
            print(f'Input: {path}, Sanitized: {sanitized}')
        else:
            print(f'Input: {path}, Sanitized: None (Rejected)')

if __name__ == "__main__":
    main()
