import os

def secure_path(path):
    return os.path.normpath(os.path.join(os.getcwd(), path))

def open_file_securely(file_path):
    secure_filepath = secure_path(file_path)
    if os.path.commonpath([os.getcwd(), secure_filepath]) != os.getcwd():
        raise ValueError("Invalid file path")
    try:
        with open(secure_filepath, 'r') as file:
            return file.read()
    except FileNotFoundError:
        return None

# Usage example
if __name__ == "__main__":
    user_input = "../test.txt"
    print(open_file_securely(user_input))
