```python
import os
import secrets

def generate_salt(size=32):
    return secrets.token_bytes(size)

def pbkdf2(password, salt, iterations=100000):
    password_bytes = password.encode('utf-8')
    if len(password_bytes) == 0:
        password_bytes = b'\x00'
    derived_key = pbkdf2_hmac('sha256', password_bytes, salt, iterations)
    return derived_key

def pbkdf2_hmac(algorithm, password, salt, iterations):
    if algorithm == 'sha256':
        h = sha256_hash
    else:
        raise ValueError('Unsupported algorithm')

    derived_key = b''
    for i in range(1, iterations + 1):
        if i == 1:
            u = h(salt + password)
        else:
            u = h(u)
        derived_key += u
    return derived_key[:32]

def sha256_hash(data):
    h = sha256_state = [0x6a09e667, 0xbb67ae85, 0x3c6ef372, 0xa54ff53a,
                         0x510e527f, 0x9b05688c, 0x1f83d9ab, 0x5be0cd19]

    for block in split_blocks(data):
        w = [0] * 64
        for t in range(16):
            w[t] = int.from_bytes(block[t * 4:t * 4 + 4], 'big')

        for t in range(16, 64):
            s0 = rotate(w[t - 15], 7) ^ rotate(w[t - 15], 18) ^ (w[t - 15] >> 3)
            s1 = rotate(w[t - 2], 17) ^ rotate(w[t - 2], 19) ^ (w[t - 2] >> 10)
            w[t] = (w[t - 16] + s0 + w[t - 7] + s1) & 0xffffffff

        a, b, c, d, e, f, g, h = h
        for t in range(64):
            S1 = rotate(e, 6) ^ rotate(e, 11) ^ rotate(e, 25)
            ch = (e & f) ^ ((~e) & g)
            temp1 = (h + S1 + ch + 0x428a2f98 + w[t]) & 0xffffffff
            S0 = rotate(a, 2) ^ rotate(a, 13) ^ rotate(a, 22)
            maj = (a & b) ^ (a & c) ^ (b & c)
            temp2 = (S0 + maj) & 0xffffffff

            h = g
            g = f
            f = e
            e = (d + temp1) & 0xffffffff
            d = c
            c = b
            b = a
            a = (temp1 + temp2) & 0xffffffff

    for i, x in enumerate([a, b, c, d, e, f, g, h]):
        h[i] = (h[i] + sha256_state[i]) & 0xffffffff

    return bytes.fromhex('{:08x}{:08x}{:08x}{:08x}{:08x}{:08x}{:08x}{:08x}'.format(*h))

def rotate(n, b):
    return ((n << b) | (n >> (32 - b))) & 0xffffffff

def split_blocks(data):
    for i in range(0, len(data), 64):
        yield data[i:i + 64]

def hash_password(password):
    salt = generate_salt()
    key = pbkdf2(password, salt)
    return salt + b'$' + key

def verify_password(stored_password, provided_password):
    salt = stored_password[:32]
    stored_key = stored_password[33:]
    provided_key = pbkdf2(provided_password, salt)
    return provided_key == stored_key

# Example usage:
if __name__ == "__main__":
    password = "mysecretpassword"
    stored_password = hash_password(password)
    print("Stored Password: ", stored_password.hex())
    print("Verification: ", verify_password(stored_password, password))
```

```python
import os
import binascii

def secure_hash(password):
    salt = os.urandom(32)
    key = pbkdf2_hmac('sha256', password.encode('utf-8'), salt, 100000)
    return binascii.hexlify(salt + key).decode('utf-8')

def pbkdf2_hmac(hash_name, password, salt, iterations):
    if not isinstance(password, bytes):
        password = password.encode('utf-8')
    if not isinstance(salt, bytes):
        salt = salt.encode('utf-8')
    if not isinstance(iterations, int):
        raise TypeError('Iterations must be an integer')
    if iterations < 1:
        raise ValueError('Iterations must be at least 1')

    digest_size = get_digest_size(hash_name)
    hash_func = get_hash_func(hash_name)

    derived_key = b''

    for i in range((digest_size + len(password) - 1) // len(password)):
        u = xor(password, i + 1)
        for _ in range(iterations):
            u = hash_func(u)
        if i == 0:
            derived_key = u
        else:
            derived_key = xor(derived_key, u)

    return derived_key

def get_digest_size(hash_name):
    sizes = {
        'sha256': 32,
        'sha512': 64,
    }
    return sizes.get(hash_name, 32)

def get_hash_func(hash_name):
    if hash_name == 'sha256':
        return lambda x: hashlib.sha256(x).digest()
    elif hash_name == 'sha512':
        return lambda x: hashlib.sha512(x).digest()
    else:
        try:
            return lambda x: __import__('hashlib').new(hash_name, x).digest()
        except ImportError:
            raise ValueError('Unsupported hash name')

def xor(s, n):
    return bytes(x ^ n for x in s)

def verify_password(stored_password, provided_password):
    salt = bytes.fromhex(stored_password[:64])
    stored_password = bytes.fromhex(stored_password[64:])
    key = pbkdf2_hmac('sha256', provided_password.encode('utf-8'), salt, 100000)
    return stored_password == key

import hashlib
if __name__ == "__main__":
    password = "mysecretpassword"
    hashed_password = secure_hash(password)
    print(hashed_password)
    print(verify_password(hashed_password, password))
```

