class Sanitizer:
    def __init__(self):
        self.allowed_tags = []
        self.allowed_attributes = {}

    def sanitize(self, input_string):
        if not input_string:
            return ""

        sanitized_string = ""
        i = 0
        while i < len(input_string):
            if input_string[i] == "<":
                if input_string[i+1:i+2] == "/":
                    tag_end = self.find_tag_end(input_string, i+2)
                    if tag_end != -1:
                        i = tag_end + 1
                    else:
                        i += 1
                else:
                    tag_end = self.find_tag_end(input_string, i+1)
                    if tag_end != -1:
                        tag = input_string[i+1:tag_end]
                        if self.is_allowed_tag(tag):
                            sanitized_string += "<" + tag + ">"
                        i = tag_end + 1
                    else:
                        i += 1
            elif input_string[i].isalnum() or input_string[i].isspace():
                sanitized_string += input_string[i]
                i += 1
            else:
                i += 1

        return sanitized_string

    def find_tag_end(self, input_string, start_index):
        for i in range(start_index, len(input_string)):
            if input_string[i] == ">":
                return i
        return -1

    def is_allowed_tag(self, tag):
        parts = tag.split()
        tag_name = parts[0].lower()
        if tag_name in [t.lower() for t in self.allowed_tags]:
            attributes = self.parse_attributes(parts[1:])
            if self.validate_attributes(tag_name, attributes):
                return True
        return False

    def parse_attributes(self, attributes):
        parsed_attributes = {}
        for attribute in attributes:
            if "=" in attribute:
                key, value = attribute.split("=")
                parsed_attributes[key.strip().lower()] = value.strip().strip('"').strip("'")
        return parsed_attributes

    def validate_attributes(self, tag_name, attributes):
        if tag_name in self.allowed_attributes:
            allowed_attributes = self.allowed_attributes[tag_name]
            for attribute in attributes:
                if attribute not in allowed_attributes:
                    return False
            return True
        return len(attributes) == 0

    def add_allowed_tag(self, tag, attributes=None):
        self.allowed_tags.append(tag)
        if attributes:
            self.allowed_attributes[tag] = attributes

def main():
    sanitizer = Sanitizer()
    sanitizer.add_allowed_tag("b")
    sanitizer.add_allowed_tag("i")
    sanitizer.add_allowed_tag("u", ["style"])

    user_input = "<b>Hello</b> <script>alert('XSS')</script> <i>world</i> <u style=\"color: red\">!</u>"
    print(sanitizer.sanitize(user_input))

if __name__ == "__main__":
    main()
```

```python
class Sanitizer:
    def __init__(self):
        self.sanitize_options = {
            'strip_tags': True,
            'strip_whitespace': True,
            'escape_html': True,
            'trim': True,
            'remove_null_bytes': True,
        }

    def sanitize(self, input_string):
        if not isinstance(input_string, str):
            return ""

        sanitized_string = input_string

        if self.sanitize_options['strip_tags']:
            sanitized_string = self.strip_tags(sanitized_string)

        if self.sanitize_options['strip_whitespace']:
            sanitized_string = self.strip_whitespace(sanitized_string)

        if self.sanitize_options['escape_html']:
            sanitized_string = self.escape_html(sanitized_string)

        if self.sanitize_options['trim']:
            sanitized_string = self.trim(sanitized_string)

        if self.sanitize_options['remove_null_bytes']:
            sanitized_string = self.remove_null_bytes(sanitized_string)

        return sanitized_string

    def strip_tags(self, input_string):
        import re
        return re.sub(r'<.*?>', '', input_string)

    def strip_whitespace(self, input_string):
        return re.sub(r'\s+', ' ', input_string)

    def escape_html(self, input_string):
        return input_string.replace('&', '&amp;').replace('<', '&lt;').replace('>', '&gt;')

    def trim(self, input_string):
        return input_string.strip()

    def remove_null_bytes(self, input_string):
        return input_string.replace('\x00', '')

def main():
    sanitizer = Sanitizer()
    user_input = "<script>alert('XSS')</script>   Hello, World! \x00"
    sanitized_input = sanitizer.sanitize(user_input)
    print(sanitized_input)

if __name__ == "__main__":
    main()
```

```python
class Sanitizer:
    def __init__(self):
        self.allowed_tags = []
        self.allowed_attributes = {}

    def sanitize(self, input_string):
        if not input_string:
            return ""

        sanitized_string = ""
        i = 0
        while i < len(input_string):
            if input_string[i] == "<":
                if input_string[i+1:i+2] == "/":
                    tag_name = ""
                    i += 2
                    while i < len(input_string) and input_string[i] != ">":
                        tag_name += input_string[i]
                        i += 1
                    if tag_name and tag_name not in self.allowed_tags:
                        i += 1
                    else:
                        sanitized_string += "<" + "/" + tag_name + ">"
                else:
                    tag_name = ""
                    i += 1
                    while i < len(input_string) and input_string[i] != " " and input_string[i] != ">":
                        tag_name += input_string[i]
                        i += 1
                    if tag_name and tag_name in self.allowed_tags:
                        sanitized_string += "<" + tag_name
                        attributes = {}
                        while i < len(input_string) and input_string[i] != ">":
                            if input_string[i] == " ":
                                attribute_name = ""
                                i += 1
                                while i < len(input_string) and input_string[i] != "=":
                                    attribute_name += input_string[i]
                                    i += 1
                                if attribute_name:
                                    value = ""
                                    i += 2
                                    if input_string[i] == '"':
                                        i += 1
                                        while i < len(input_string) and input_string[i] != '"':
                                            value += input_string[i]
                                            i += 1
                                        i += 1
                                    if attribute_name in self.allowed_attributes.get(tag_name, []):
                                        attributes[attribute_name] = value
                        for attribute, value in attributes.items():
                            sanitized_string += " " + attribute + '="' + value + '"'
                        sanitized_string += ">"
            else:
                sanitized_string += input_string[i]
                i += 1
        return sanitized_string

    def clean(self, input_string):
        return ''.join(char for char in input_string if char.isalnum() or char.isspace())

def main():
    sanitizer = Sanitizer()
    sanitizer.allowed_tags = ['b', 'i', 'u']
    sanitizer.allowed_attributes = {'b': ['style'], 'i': ['class']}
    user_input = "<b style=\"font-size: 20px\">Hello</b> <script>alert('xss')</script> <i class=\"test\" >Italic</i> & <u>Underlined</u>"
    sanitized = sanitizer.sanitize(user_input)
    cleaned = sanitizer.clean(user_input)
    print("Sanitized: ", sanitized)
    print("Cleaned: ", cleaned)

if __name__ == "__main__":
    main()
```

