```python
def generate_key(password):
    key = 0
    for char in password:
        key = (key * 31 + ord(char)) % (2**32)
    return key

def encrypt_data(data, password):
    key = generate_key(password)
    encrypted_data = bytearray()
    for i, byte in enumerate(data.encode()):
        encrypted_byte = byte ^ ((key >> (i % 4 * 8)) & 0xFF)
        encrypted_data.append(encrypted_byte)
    return bytes(encrypted_data).hex()

def decrypt_data(encrypted_data, password):
    key = generate_key(password)
    encrypted_bytes = bytearray.fromhex(encrypted_data)
    data = bytearray()
    for i, byte in enumerate(encrypted_bytes):
        decrypted_byte = byte ^ ((key >> (i % 4 * 8)) & 0xFF)
        data.append(decrypted_byte)
    return bytes(data).decode()

# Example usage:
if __name__ == "__main__":
    password = "mysecretpassword"
    data = "Sensitive information"
    encrypted_data = encrypt_data(data, password)
    print(f"Encrypted data: {encrypted_data}")
    decrypted_data = decrypt_data(encrypted_data, password)
    print(f"Decrypted data: {decrypted_data}")
