from flask import Flask, request, jsonify
import jwt

app = Flask(__name__)
app.config['SECRET_KEY'] = 'your-secret-key'

def sanitize_request(request_data):
    sanitized_data = {}
    for key, value in request_data.items():
        sanitized_data[key] = value.strip() if isinstance(value, str) else value
    return sanitized_data

def validate_token(token):
    try:
        payload = jwt.decode(token, app.config['SECRET_KEY'], algorithms=['HS256'])
        return payload
    except jwt.ExpiredSignatureError:
        return None
    except jwt.InvalidTokenError:
        return None

@app.route('/api/endpoint', methods=['POST'])
def secure_endpoint():
    token = request.headers.get('Authorization')
    if not token:
        return jsonify({'error': 'Missing token'}), 401

    payload = validate_token(token)
    if not payload:
        return jsonify({'error': 'Invalid token'}), 401

    request_data = request.get_json()
    sanitized_data = sanitize_request(request_data)

    # Process sanitized data
    return jsonify({'message': 'Data processed successfully', 'data': sanitized_data}), 200

if __name__ == '__main__':
    app.run(debug=True)
