function sqlSanitize(input) {
  if (typeof input !== 'string') {
    throw new Error('Input must be a string');
  }

  return input
    .replace(/\\/g, '\\\\')
    .replace(/'/g, "\\'")
    .replace(/"/g, '\\"')
    .replace(/\n/g, '\\n')
    .replace(/\r/g, '\\r')
    .replace(/%/g, '\\%')
    .replace(/_/g, '\\_');
}

function sqlSanitizeIdentifier(input) {
  if (typeof input !== 'string') {
    throw new Error('Input must be a string');
  }

  return '"' + input
    .replace(/"/g, '""')
    .replace(/\`/g, '\\`')
    .replace(/\\/g, '\\\\') + '"';
}
