function sqlSanitize(input) {
  if (typeof input !== 'string') {
    throw new Error('Input must be a string');
  }

  return input
    .replace(/\\/g, '\\\\')
    .replace(/'/g, "''")
    .replace(/"/g, '\\"')
    .replace(/\n/g, '\\n')
    .replace(/\r/g, '\\r')
    .replace(/\x00/g, '\\0');
}

function sqlSanitizeQuery(query, ...params) {
  params = params.map(sqlSanitize);
  return query.replace(/%s/g, () => sqlSanitize(params.shift()));
}

// Example usage:
const query = "SELECT * FROM users WHERE name = '%s' AND password = '%s'";
const sanitizedQuery = sqlSanitizeQuery(query, "John Doe", "my_password");
console.log(sanitizedQuery);
