function sqlSanitize(input) {
  if (typeof input !== 'string') {
    throw new Error('Input must be a string');
  }

  return input
    .replace(/\\/g, '\\\\')
    .replace(/'/g, "''")
    .replace(/"/g, '\\"')
    .replace(/\n/g, '\\n')
    .replace(/\r/g, '\\r')
    .replace(/%/g, '\\%')
    .replace(/_/g, '\\_');
}

function sqlSanitizeQuery(query, params) {
  let sanitizedQuery = query;
  Object.keys(params).forEach(key => {
    const sanitizedValue = sqlSanitize(params[key].toString());
    sanitizedQuery = sanitizedQuery.replace(`:${key}`, `'${sanitizedValue}'`);
  });
  return sanitizedQuery;
}

// Example usage:
const query = "SELECT * FROM users WHERE name = :name AND password = :password";
const params = { name: "John Doe", password: "mysecretpassword" };
const sanitizedQuery = sqlSanitizeQuery(query, params);
