class HtmlSanitizer {
  constructor(allowedTags, allowedAttributes) {
    this.allowedTags = allowedTags || [];
    this.allowedAttributes = allowedAttributes || {};
  }

  sanitize(html) {
    const parser = new DOMParser();
    const doc = parser.parseFromString(html, 'text/html');
    this.sanitizeNode(doc.body);
    return doc.body.outerHTML;
  }

  sanitizeNode(node) {
    if (node.nodeType === Node.ELEMENT_NODE) {
      this.sanitizeElement(node);
    } else if (node.nodeType === Node.TEXT_NODE) {
      node.textContent = this.escapeHtml(node.textContent);
    }

    for (let child = node.firstChild; child; child = child.nextSibling) {
      this.sanitizeNode(child);
    }
  }

  sanitizeElement(node) {
    if (!this.isAllowedTag(node.tagName.toLowerCase())) {
      this.replaceElementWithChildren(node);
      return;
    }

    this.sanitizeAttributes(node);
  }

  isAllowedTag(tag) {
    return this.allowedTags.length === 0 || this.allowedTags.includes(tag);
  }

  sanitizeAttributes(node) {
    for (let attr = node.attributes.length - 1; attr >= 0; attr--) {
      const name = node.attributes[attr].name.toLowerCase();
      if (!this.isAllowedAttribute(node.tagName.toLowerCase(), name)) {
        node.removeAttribute(node.attributes[attr].name);
      }
    }
  }

  isAllowedAttribute(tag, attr) {
    return (
      (this.allowedAttributes[tag] && this.allowedAttributes[tag].includes(attr)) ||
      (this.allowedAttributes['*'] && this.allowedAttributes['*'].includes(attr))
    );
  }

  replaceElementWithChildren(node) {
    const parent = node.parentNode;
    const children = Array.from(node.childNodes);
    node.remove();
    children.forEach((child) => parent.appendChild(child));
  }

  escapeHtml(unsafe) {
    return unsafe
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#039;');
  }
}

// Usage example
const sanitizer = new HtmlSanitizer(['p', 'span'], {
  p: ['style'],
  span: ['class'],
});

const unsanitizedHtml = '<p style="color: red">Hello <script>alert("XSS")</script> world!</p><span class="blue">This is a span</span>';
const sanitizedHtml = sanitizer.sanitize(unsanitizedHtml);
console.log(sanitizedHtml);
```

```javascript
class HtmlSanitizer {
  constructor(allowedTags, allowedAttributes) {
    this.allowedTags = allowedTags || [];
    this.allowedAttributes = allowedAttributes || {};
  }

  sanitize(html) {
    const parser = new DOMParser();
    const doc = parser.parseFromString(html, 'text/html');
    this.sanitizeNode(doc.body);
    return doc.body.innerHTML;
  }

  sanitizeNode(node) {
    if (node.nodeType === Node.ELEMENT_NODE) {
      this.sanitizeElement(node);
    } else if (node.nodeType === Node.TEXT_NODE) {
      this.sanitizeText(node);
    }

    for (let child of node.childNodes) {
      this.sanitizeNode(child);
    }
  }

  sanitizeElement(node) {
    if (!this.isTagAllowed(node.tagName.toLowerCase())) {
      this.replaceElementWithChildren(node);
    } else {
      this.sanitizeAttributes(node);
    }
  }

  sanitizeText(node) {
    node.textContent = this.escapeHtml(node.textContent);
  }

  isTagAllowed(tag) {
    return this.allowedTags.includes(tag);
  }

  sanitizeAttributes(node) {
    for (let attr of node.attributes) {
      if (!this.isAttributeAllowed(node.tagName.toLowerCase(), attr.name)) {
        node.removeAttribute(attr.name);
      }
    }
  }

  isAttributeAllowed(tag, attr) {
    if (!this.allowedAttributes[tag]) return false;
    return this.allowedAttributes[tag].includes(attr);
  }

  replaceElementWithChildren(node) {
    while (node.firstChild) {
      node.parentNode.insertBefore(node.firstChild, node);
    }
    node.parentNode.removeChild(node);
  }

  escapeHtml(unsafe) {
    return unsafe
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#039;');
  }
}

function main() {
  const sanitizer = new HtmlSanitizer(['p', 'img'], {
    img: ['src', 'alt'],
    p: []
  });

  const unsanitizedHtml = '<p onclick="alert(\'XSS\')">Hello <img src="image.jpg" onerror="alert(\'XSS\')"> World!</p>';
  const sanitizedHtml = sanitizer.sanitize(unsanitizedHtml);
  console.log(sanitizedHtml);
}

main();
