```javascript
class HTMLSanitizer {
  constructor(allowedTags, allowedAttributes) {
    this.allowedTags = allowedTags || [];
    this.allowedAttributes = allowedAttributes || {};
  }

  sanitize(html) {
    const parser = new DOMParser();
    const doc = parser.parseFromString(html, 'text/html');
    this.sanitizeNode(doc.body);
    return doc.body.innerHTML;
  }

  sanitizeNode(node) {
    if (node.nodeType === Node.ELEMENT_NODE) {
      this.sanitizeElement(node);
    } else if (node.nodeType === Node.TEXT_NODE) {
      this.sanitizeText(node);
    }

    for (let child of node.childNodes) {
      this.sanitizeNode(child);
    }
  }

  sanitizeElement(node) {
    if (!this.isTagAllowed(node.tagName)) {
      this.replaceElementWithChildren(node);
    } else {
      this.sanitizeAttributes(node);
    }
  }

  replaceElementWithChildren(node) {
    const parent = node.parentNode;
    while (node.firstChild) {
      parent.insertBefore(node.firstChild, node);
    }
    parent.removeChild(node);
  }

  sanitizeText(node) {
    node.textContent = this.escapeHtml(node.textContent);
  }

  sanitizeAttributes(node) {
    for (let attr of node.attributes) {
      if (!this.isAttributeAllowed(node.tagName, attr.name)) {
        node.removeAttribute(attr.name);
      }
    }
  }

  isTagAllowed(tag) {
    return this.allowedTags.includes(tag.toLowerCase());
  }

  isAttributeAllowed(tag, attr) {
    const allowedAttrs = this.allowedAttributes[tag.toLowerCase()];
    return allowedAttrs && allowedAttrs.includes(attr.toLowerCase());
  }

  escapeHtml(str) {
    return str
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#x27;');
  }
}

function main() {
  const sanitizer = new HTMLSanitizer(['p', 'span'], {
    'p': ['style'],
    'span': ['class']
  });

  const html = '<p style="color: red">Hello <script>alert("XSS")</script> world!</p><span class="foo"> Foo <img src="bar.jpg" onerror="alert(\'XSS\')"> </span>';
  console.log(sanitizer.sanitize(html));
}

main();
