```javascript
function sanitizeCommand(command) {
  const allowedChars = /^[a-zA-Z0-9._\/\s\-\+\=\[\]\{\}\(\)\<\>\&\|\!\~\*]*$/;
  const quotedString = /^"[^"]*"$|^'[^']*'$|^`[^`]*`$/;

  function isQuoted(str) {
    return quotedString.test(str);
  }

  function sanitizeArg(arg) {
    if (isQuoted(arg)) {
      return arg.replace(/^["'`](.*)["'`]$/, (match, p1) => p1);
    } else {
      return arg.replace(/[^\w\/\.\-]+/g, '');
    }
  }

  function splitCommand(cmd) {
    const args = [];
    let arg = '';
    let quoteChar = null;
    let escapeNext = false;

    for (let i = 0; i < cmd.length; i++) {
      const c = cmd[i];

      if (escapeNext) {
        arg += c;
        escapeNext = false;
      } else if (c === '\\') {
        escapeNext = true;
      } else if (quoteChar === null && (c === ' ' || c === '\t')) {
        if (arg) {
          args.push(arg);
          arg = '';
        }
      } else if (quoteChar === null && (c === '"' || c === "'" || c === '`')) {
        quoteChar = c;
        arg += c;
      } else if (quoteChar && c === quoteChar) {
        arg += c;
        quoteChar = null;
      } else {
        arg += c;
      }
    }

    if (arg) {
      args.push(arg);
    }

    return args;
  }

  const args = splitCommand(command);

  return args.map(arg => {
    if (allowedChars.test(arg)) {
      return sanitizeArg(arg);
    } else {
      return '';
    }
  }).filter(arg => arg !== '');
}

// test
console.log(sanitizeCommand('echo "hello world"'));
console.log(sanitizeCommand('echo \'hello world\''));
console.log(sanitizeCommand('echo `hello world`'));
console.log(sanitizeCommand('echo hello; world'));
console.log(sanitizeCommand('echo hello$(world)'));
```

