function sanitizeShellCommand(command) {
  const allowedChars = /^[a-zA-Z0-9._\/\s\-\+\=\>\<\&\(\)\[\]\{\}\|\~\!\>\<\>\<\>\&]+$/;
  const quotedChars = /^[\'\"]$/;

  let sanitizedCommand = '';
  let quote = null;

  for (let i = 0; i < command.length; i++) {
    const char = command[i];

    if (quotedChars.test(char)) {
      if (quote === null || char === quote) {
        quote = quote === char ? null : char;
      } else {
        sanitizedCommand += char;
      }
    } else if (quote !== null) {
      sanitizedCommand += char;
    } else if (allowedChars.test(char)) {
      sanitizedCommand += char;
    } else {
      sanitizedCommand += '\\' + char;
    }
  }

  return sanitizedCommand;
}

// Test
console.log(sanitizeShellCommand("echo Hello World!"));
console.log(sanitizeShellCommand("echo 'Hello World!'"));
console.log(sanitizeShellCommand('echo "Hello World!"'));
```

```javascript
function sanitizeShellCommand(command) {
  const allowedChars = /^[a-zA-Z0-9._\/\s\-\+\=\>\<\&\(\)\[\]\{\}\|\~\`\']*$/;
  const quoted = [];
  let inQuote = false;
  let currentArg = '';

  for (let i = 0; i < command.length; i++) {
    const char = command[i];

    if (char === '"') {
      inQuote = !inQuote;
      quoted.push(currentArg);
      currentArg = '';
    } else if (char === ' ' && !inQuote) {
      if (currentArg !== '') {
        quoted.push(currentArg);
        currentArg = '';
      }
    } else {
      if (allowedChars.test(char)) {
        currentArg += char;
      } else {
        throw new Error(`Invalid character in command: ${char}`);
      }
    }
  }

  if (currentArg !== '') {
    quoted.push(currentArg);
  }

  const sanitizedArgs = quoted.map(arg => {
    return arg.replace(/[^a-zA-Z0-9._\/\-\+\=\>\<\&\(\)\[\]\{\}\|\~\`\']*/g, '');
  });

  return sanitizedArgs.filter(arg => arg !== '');
}

function isValidSanitizedCommand(command) {
  try {
    const sanitizedCommand = sanitizeShellCommand(command);
    return sanitizedCommand.join(' ') === command;
  } catch (e) {
    return false;
  }
}

// Test
console.log(sanitizeShellCommand('echo "Hello World"')); 
console.log(isValidSanitizedCommand('echo "Hello World"')); 
console.log(isValidSanitizedCommand('echo; "Hello World"')); 
console.log(sanitizeShellCommand('rm -rf /')); 
console.log(isValidSanitizedCommand('rm -rf /'));
```

