const childProcess = require('child_process');

function safe_exec(command, callback) {
    const allowedCommands = ['ls', 'pwd', 'echo', 'date', 'whoami'];
    const commandParts = command.split(' ');
    if (!allowedCommands.includes(commandParts[0])) {
        callback(new Error('Command not allowed'));
        return;
    }
    childProcess.exec(command, (error, stdout, stderr) => {
        if (error) {
            callback(error);
        } else {
            callback(null, stdout);
        }
    });
}

// Example usage:
safe_exec('ls -l', (err, result) => {
    if (err) {
        console.error(err);
    } else {
        console.log(result);
    }
});

safe_exec('pwd', (err, result) => {
    if (err) {
        console.error(err);
    } else {
        console.log(result);
    }
});

