```javascript
const childProcess = require('child_process');

function safe_exec(command) {
    return new Promise((resolve, reject) => {
        const options = {
            shell: '/bin/bash',
            stdio: 'inherit'
        };

        childProcess.exec(command, options, (error, stdout, stderr) => {
            if (error) {
                reject(stderr);
            } else {
                resolve(stdout);
            }
        });
    });
}

// Example usage
const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});

readline.question('Enter a command: ', async (command) => {
    try {
        const userInput = command.trim();
        if (!userInput) {
            console.log('No command provided.');
            return readline.close();
        }

        // Basic input validation and sanitization
        if (!/^[a-zA-Z0-9\s\-\/]+$/.test(userInput)) {
            console.log('Invalid characters in command.');
            return readline.close();
        }

        // Prevent sensitive commands
        const blockedCommands = ['rm', 'mkfs', 'shutdown', 'reboot', 'init'];
        if (blockedCommands.some(blocked => userInput.includes(blocked))) {
            console.log('Command not allowed.');
            return readline.close();
        }

        const output = await safe_exec(userInput);
        console.log(output);
        readline.close();
    } catch (error) {
        console.error(`Error executing command: ${error}`);
        readline.close();
    }
});
```

