```javascript
function sanitizePath(basePath, requestedPath) {
  const path = require('path');
  const normalize = (p) => path.normalize(p).replace(/\\/g, '/');

  basePath = normalize(basePath);
  requestedPath = normalize(requestedPath);

  const basePathParts = basePath.split('/');
  const requestedPathParts = requestedPath.split('/');

  const sanitizedPathParts = [];

  for (const part of requestedPathParts) {
    if (part === '..') {
      if (sanitizedPathParts.length > 0) {
        sanitizedPathParts.pop();
      }
    } else if (part !== '' && part !== '.') {
      sanitizedPathParts.push(part);
    }
  }

  let sanitizedPath = basePath + '/' + sanitizedPathParts.join('/');

  if (!sanitizedPath.startsWith(basePath)) {
    throw new Error('Directory traversal attack detected');
  }

  return sanitizedPath;
}

// Example usage:
const basePath = '/var/www/html';
const requestedPath = '../../etc/passwd';

try {
  const sanitizedPath = sanitizePath(basePath, requestedPath);
  console.log(sanitizedPath);
} catch (error) {
  console.error(error.message);
}
