const path = require('path');

function sanitizePath(inputPath) {
  const stack = [];
  const segments = inputPath.split(path.sep);

  for (let segment of segments) {
    if (segment === '..') {
      if (stack.length > 0) {
        stack.pop();
      }
    } else if (segment !== '' && segment !== '.') {
      stack.push(segment);
    }
  }

  return stack.join(path.sep);
}

function normalizePath(inputPath) {
  return path.normalize(sanitizePath(inputPath));
}

function isWithinBase(basePath, targetPath) {
  const base = path.resolve(basePath);
  const target = path.resolve(targetPath);

  return target.startsWith(base + path.sep) || target === base;
}

// Example usage:
const basePath = '/var/www';
const userInput = '../etc/passwd';

const sanitized = sanitizePath(userInput);
const normalized = normalizePath(userInput);

console.log(`Sanitized: ${sanitized}`);
console.log(`Normalized: ${normalized}`);
console.log(`Is within base: ${isWithinBase(basePath, normalized)}`);
