```javascript
function sanitizePath(inputPath) {
  const pathComponents = inputPath.split('/');
  const sanitizedComponents = [];

  for (const component of pathComponents) {
    if (component === '..') {
      if (sanitizedComponents.length > 0) {
        sanitizedComponents.pop();
      }
    } else if (component !== '' && component !== '.') {
      sanitizedComponents.push(component);
    }
  }

  return sanitizedComponents.join('/');
}

function normalizePath(basePath, inputPath) {
  const absoluteBasePath = basePath.split('/').filter(c => c !== '');
  const sanitizedPath = sanitizePath(inputPath);
  const pathComponents = sanitizedPath.split('/').filter(c => c !== '');

  const fullPath = [...absoluteBasePath, ...pathComponents];
  const normalizedPath = fullPath.join('/');

  return '/' + normalizedPath;
}

function validatePath(basePath, inputPath) {
  const normalizedPath = normalizePath(basePath, inputPath);
  const basePathRegex = new RegExp('^' + basePath.replace('/', '\\/'));
  return basePathRegex.test(normalizedPath);
}

// usage
const basePath = '/var/www';
const inputPath = '../etc/passwd';

if (validatePath(basePath, inputPath)) {
  const sanitized = normalizePath(basePath, inputPath);
  console.log(sanitized);
} else {
  console.log('Directory traversal attack detected');
}
