function securePath(userProvidedPath) {
    return path.normalize(userProvidedPath);
}

function openFileSecurely(userProvidedPath) {
    const sanitizedPath = securePath(userProvidedPath);
    try {
        fs.accessSync(sanitizedPath, fs.constants.R_OK);
        const fileContent = fs.readFileSync(sanitizedPath, 'utf8');
        return fileContent;
    } catch (err) {
        if (err.code === 'ENOENT') {
            console.log(`File not found: ${sanitizedPath}`);
        } else if (err.code === 'EACCES') {
            console.log(`Permission denied: ${sanitizedPath}`);
        } else {
            console.log(`An error occurred: ${err}`);
        }
        return null;
    }
}
