```javascript
function generateSalt() {
    let salt = '';
    for (let i = 0; i < 16; i++) {
        salt += Math.floor(Math.random() * 36).toString(36);
    }
    return salt;
}

function sha256(message) {
    const encoder = new TextEncoder();
    const data = encoder.encode(message);
    return crypto.subtle.digest('SHA-256', data).then((hash) => {
        return Array.from(new Uint8Array(hash)).map((b) => b.toString(16).padStart(2, '0')).join('');
    });
}

async function hashPassword(password) {
    const salt = generateSalt();
    const pepper = 'your_secret_pepper_here';
    const passwordWithSaltAndPepper = password + salt + pepper;
    const hashedPassword = await sha256(passwordWithSaltAndPepper);
    return `${salt}$${hashedPassword}`;
}

async function verifyPassword(storedPassword, providedPassword) {
    const [salt, storedHash] = storedPassword.split('$');
    const pepper = 'your_secret_pepper_here';
    const passwordWithSaltAndPepper = providedPassword + salt + pepper;
    const hashedPassword = await sha256(passwordWithSaltAndPepper);
    return hashedPassword === storedHash;
}

// Example usage:
async function main() {
    const password = 'mysecretpassword';
    const hashedPassword = await hashPassword(password);
    console.log(hashedPassword);

    const isValid = await verifyPassword(hashedPassword, password);
    console.log(isValid); // Should print: true

    const isInvalid = await verifyPassword(hashedPassword, 'wrongpassword');
    console.log(isInvalid); // Should print: false
}

main();
