```javascript
function sanitizeInput(input) {
  if (typeof input !== 'string') {
    return input;
  }

  input = input.trim();
  input = input.replace(/<script>.*?<\/script>/gi, '');
  input = input.replace(/<.*?>/g, '');
  input = input.replace(/&/g, '&amp;');
  input = input.replace(/</g, '&lt;');
  input = input.replace(/>/g, '&gt;');
  input = input.replace(/"/g, '&quot;');
  input = input.replace(/'/g, '&#x27;');
  input = input.replace(/\//g, '&#x2F;');
  input = input.replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F-\x9F]/g, '');
  return input;
}

function sanitizeObject(obj) {
  if (typeof obj !== 'object') {
    return obj;
  }

  for (let key in obj) {
    if (typeof obj[key] === 'string') {
      obj[key] = sanitizeInput(obj[key]);
    } else if (typeof obj[key] === 'object') {
      obj[key] = sanitizeObject(obj[key]);
    }
  }
  return obj;
}

function sanitizeArray(arr) {
  if (!Array.isArray(arr)) {
    return arr;
  }

  for (let i = 0; i < arr.length; i++) {
    if (typeof arr[i] === 'string') {
      arr[i] = sanitizeInput(arr[i]);
    } else if (typeof arr[i] === 'object') {
      arr[i] = sanitizeObject(arr[i]);
    }
  }
  return arr;
}

// usage
let userInput = '<script>alert(1)</script> test <b>bold</b>';
let userObject = {name: 'John <b>Doe</b>', age: 30, address: {street: 'Main <i>Street</i>'}};
let userArray = ['<script>alert(2)</script>', {name: 'Jane <b>Doe</b>', age: 25}];

console.log(sanitizeInput(userInput));
console.log(sanitizeObject(userObject));
console.log(sanitizeArray(userArray));
```

