function sanitizeInput(input) {
  if (typeof input !== 'string') {
    return input;
  }

  input = input.trim();
  input = input.replace(/<script>.*?<\/script>/gi, '');
  input = input.replace(/<\/?script.*?>/gi, '');
  input = input.replace(/<style>.*?<\/style>/gi, '');
  input = input.replace(/<\/?style.*?>/gi, '');
  input = input.replace(/javascript:/gi, '');
  input = input.replace(/vbscript:/gi, '');
  input = input.replace(/expression:/gi, '');
  input = input.replace(/eval\(/gi, '');
  input = input.replace(/unescape\(/gi, '');
  input = input.replace(/&#x27;/g, '');
  input = input.replace(/&#x2F;/g, '');
  input = input.replace(/&#x5C;/g, '');
  input = input.replace(/'/g, '');
  input = input.replace(/"/g, '');
  input = input.replace(/\\/g, '');
  input = input.replace(/;/g, '');
  input = input.replace(/</g, '&lt;');
  input = input.replace(/>/g, '&gt;');
  input = input.replace(/`/g, '');
  input = input.replace(/,/g, '');
  input = input.replace(/\(/g, '');
  input = input.replace(/\)/g, '');

  return input;
}

function sanitizeObject(obj) {
  if (typeof obj !== 'object') {
    return obj;
  }

  for (let key in obj) {
    if (typeof obj[key] === 'string') {
      obj[key] = sanitizeInput(obj[key]);
    } else if (typeof obj[key] === 'object') {
      obj[key] = sanitizeObject(obj[key]);
    }
  }

  return obj;
}

function sanitizeArray(arr) {
  if (!Array.isArray(arr)) {
    return arr;
  }

  for (let i = 0; i < arr.length; i++) {
    if (typeof arr[i] === 'string') {
      arr[i] = sanitizeInput(arr[i]);
    } else if (typeof arr[i] === 'object') {
      arr[i] = sanitizeObject(arr[i]);
    }
  }

  return arr;
}

// Test
let userInput = {
  name: '<script>alert("XSS")</script> John',
  desc: 'Hello, world!',
  arr: ['<script>alert("XSS")</script>', 'Hello, world!'],
  obj: {
    foo: '<script>alert("XSS")</script>',
    bar: 'Hello, world!'
  }
};

let sanitizedInput = sanitizeObject(userInput);
console.log(sanitizedInput);
