function encrypt_data(data, key) {
    let encryptedData = "";
    for (let i = 0; i < data.length; i++) {
        let charCode = data.charCodeAt(i);
        let keyCharCode = key.charCodeAt(i % key.length);
        let encryptedCharCode = charCode ^ keyCharCode;
        encryptedData += String.fromCharCode(encryptedCharCode);
    }
    return encryptedData;
}

function decrypt_data(encryptedData, key) {
    let decryptedData = "";
    for (let i = 0; i < encryptedData.length; i++) {
        let charCode = encryptedData.charCodeAt(i);
        let keyCharCode = key.charCodeAt(i % key.length);
        let decryptedCharCode = charCode ^ keyCharCode;
        decryptedData += String.fromCharCode(decryptedCharCode);
    }
    return decryptedData;
}

let data = "Hello, World!";
let key = "secret";
let encrypted = encrypt_data(data, key);
console.log(`Encrypted: ${encrypted}`);
let decrypted = decrypt_data(encrypted, key);
