const crypto = require('crypto');

function secureEncrypt(data, key) {
    const iv = crypto.randomBytes(16);
    const cipher = crypto.createCipheriv('aes-256-cbc', key, iv);
    const encrypted = Buffer.concat([cipher.update(data), cipher.final()]);
    return iv.toString('hex') + ':' + encrypted.toString('hex');
}

function secureDecrypt(encryptedData, key) {
    const parts = encryptedData.split(':');
    const iv = Buffer.from(parts.shift(), 'hex');
    const encryptedText = Buffer.from(parts.join(':'), 'hex');
    const decipher = crypto.createDecipheriv('aes-256-cbc', key, iv);
    const decrypted = Buffer.concat([decipher.update(encryptedText), decipher.final()]);
    return decrypted.toString();
}

// Example usage
const key = crypto.randomBytes(32); // 256-bit key
const userData = 'Sensitive user data';

const encryptedData = secureEncrypt(userData, key);
console.log('Encrypted data:', encryptedData);

const decryptedData = secureDecrypt(encryptedData, key);
console.log('Decrypted data:', decryptedData);
```

```javascript
const crypto = require('crypto');

function secureEncrypt(data, key) {
    if (typeof data !== 'string') {
        throw new Error('Data must be a string');
    }

    if (typeof key !== 'string') {
        throw new Error('Key must be a string');
    }

    const iv = crypto.randomBytes(16);
    const cipher = crypto.createCipheriv('aes-256-cbc', key, iv);
    let encrypted = cipher.update(data, 'utf8', 'hex');
    encrypted = encrypted + cipher.final('hex');
    return iv.toString('hex') + ':' + encrypted;
}

function secureDecrypt(encryptedData, key) {
    if (typeof encryptedData !== 'string') {
        throw new Error('Encrypted data must be a string');
    }

    if (typeof key !== 'string') {
        throw new Error('Key must be a string');
    }

    const parts = encryptedData.split(':');
    if (parts.length !== 2) {
        throw new Error('Invalid encrypted data');
    }

    const iv = Buffer.from(parts.shift(), 'hex');
    const encryptedText = parts.join(':');
    const decipher = crypto.createDecipheriv('aes-256-cbc', key, iv);
    let decrypted = decipher.update(encryptedText, 'hex', 'utf8');
    decrypted = decrypted + decipher.final('utf8');
    return decrypted;
}

// Example usage:
const key = crypto.randomBytes(32).toString('hex');
const data = 'This is some secret data';

const encrypted = secureEncrypt(data, key);
console.log('Encrypted:', encrypted);

const decrypted = secureDecrypt(encrypted, key);
console.log('Decrypted:', decrypted);
```

