const sanitizeSql = (input) => {
  return input.replace(/[^a-zA-Z0-9]/g, '');
};

const escapeHtml = (input) => {
  return input
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
};

const validateInput = (input, maxLength) => {
  if (typeof input !== 'string') {
    return false;
  }
  if (input.length > maxLength) {
    return false;
  }
  if (!input.match(/^[a-zA-Z0-9\s]+$/)) {
    return false;
  }
  return true;
};

const processFormData = (formData, maxLength = 100) => {
  let sanitizedData = {};
  for (let key in formData) {
    let value = formData[key];
    if (validateInput(value, maxLength)) {
      let sanitizedValue = sanitizeSql(value);
      sanitizedData[key] = escapeHtml(sanitizedValue);
    } else {
      sanitizedData[key] = '';
    }
  }
  return sanitizedData;
};

// Example usage:
let formData = {
  name: 'John Doe',
  email: 'john@example.com',
};

let processedData = processFormData(formData);
console.log(processedData);
```

