public class Main {
    public static String sanitizeSql(String input) {
        if (input == null) {
            return null;
        }

        StringBuilder sanitized = new StringBuilder();
        for (char c : input.toCharArray()) {
            switch (c) {
                case '\'':
                    sanitized.append('\'').append('\'');
                    break;
                case '"':
                    sanitized.append('"').append('"');
                    break;
                case '\\':
                    sanitized.append('\\').append('\\');
                    break;
                default:
                    sanitized.append(c);
            }
        }
        return sanitized.toString();
    }

    public static String createSanitizedQuery(String query, String[] params) {
        String[] sanitizedParams = new String[params.length];
        for (int i = 0; i < params.length; i++) {
            sanitizedParams[i] = "'" + sanitizeSql(params[i]) + "'";
        }

        String paramString = String.join(",", sanitizedParams);
        return String.format(query, paramString);
    }

    public static void main(String[] args) {
        String query = "SELECT * FROM users WHERE name IN (%s)";
        String[] params = {"Robert'); DROP TABLE students; --", "John"};
        System.out.println(createSanitizedQuery(query, params));
    }
}
