public class Main {
    public static String sqlEscape(String input) {
        if (input == null) {
            return "NULL";
        }

        StringBuilder sb = new StringBuilder();
        for (char c : input.toCharArray()) {
            switch (c) {
                case '\'':
                    sb.append('\'').append('\'');
                    break;
                case '"':
                    sb.append('"').append('"');
                    break;
                default:
                    sb.append(c);
            }
        }
        return "'" + sb.toString() + "'";
    }

    public static void main(String[] args) {
        System.out.println(sqlEscape("Hello, World!"));
        System.out.println(sqlEscape("It's a beautiful day"));
        System.out.println(sqlEscape(null));
    }
}
