```java
import java.util.HashSet;
import java.util.Set;
import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class HtmlSanitizer {
    private static final Set<String> ALLOWED_TAGS = new HashSet<>();
    private static final Set<String> ALLOWED_ATTRIBUTES = new HashSet<>();

    static {
        ALLOWED_TAGS.add("p");
        ALLOWED_TAGS.add("img");
        ALLOWED_TAGS.add("br");
        ALLOWED_TAGS.add("strong");
        ALLOWED_TAGS.add("em");
        ALLOWED_TAGS.add("u");
        ALLOWED_TAGS.add("s");

        ALLOWED_ATTRIBUTES.add("src");
        ALLOWED_ATTRIBUTES.add("alt");
    }

    public static String sanitize(String html) {
        return sanitize(html, ALLOWED_TAGS, ALLOWED_ATTRIBUTES);
    }

    public static String sanitize(String html, Set<String> allowedTags, Set<String> allowedAttributes) {
        StringBuilder sanitizedHtml = new StringBuilder();

        Pattern tagPattern = Pattern.compile("<(/?[^>]+)>");
        Matcher tagMatcher = tagPattern.matcher(html);

        while (tagMatcher.find()) {
            String tag = tagMatcher.group(1);
            if (tag.startsWith("/")) {
                String tagName = tag.substring(1).toLowerCase();
                if (allowedTags.contains(tagName)) {
                    sanitizedHtml.append("<").append(tag).append(">");
                }
            } else {
                String[] parts = tag.split("\\s+");
                String tagName = parts[0].toLowerCase();

                if (allowedTags.contains(tagName)) {
                    sanitizedHtml.append("<").append(tagName);

                    for (int i = 1; i < parts.length; i++) {
                        String attribute = parts[i];
                        Pattern attributePattern = Pattern.compile("([^=]+)=(.*)");
                        Matcher attributeMatcher = attributePattern.matcher(attribute);

                        if (attributeMatcher.matches()) {
                            String attributeName = attributeMatcher.group(1).trim().toLowerCase();
                            String attributeValue = attributeMatcher.group(2).trim().replaceAll("^['\"]|['\"]$", "");

                            if (allowedAttributes.contains(attributeName)) {
                                sanitizedHtml.append(" ").append(attributeName).append("=\"").append(escape(attributeValue)).append("\"");
                            }
                        }
                    }

                    sanitizedHtml.append(">");
                }
            }
        }

        tagMatcher.appendTail(sanitizedHtml);

        sanitizedHtml = new StringBuilder(sanitizedHtml.toString().replaceAll("<script>.*?</script>", ""));
        sanitizedHtml = new StringBuilder(sanitizedHtml.toString().replaceAll("javascript:", ""));

        return sanitizedHtml.toString();
    }

    private static String escape(String attributeValue) {
        return attributeValue.replace("&", "&amp;")
                .replace("<", "&lt;")
                .replace(">", "&gt;")
                .replace("\"", "&quot;")
                .replace("'", "&#x27;");
    }

    public static void main(String[] args) {
        String html = "<p>Hello <img src='image.jpg' onerror='alert(\"XSS\")'> World!</p>";
        System.out.println(sanitize(html));
    }
}
