public class ShellCommandSanitizer {

    private static final String[] allowedChars = {"a-zA-Z0-9_.-/"};

    public static boolean isValidCommand(String command) {
        for (char c : command.toCharArray()) {
            boolean valid = false;
            for (String allowedChar : allowedChars) {
                if (allowedChar.indexOf(c) != -1) {
                    valid = true;
                    break;
                }
            }
            if (!valid) {
                return false;
            }
        }
        return true;
    }

    public static String sanitizeCommand(String command) {
        StringBuilder sanitizedCommand = new StringBuilder();
        for (char c : command.toCharArray()) {
            boolean valid = false;
            for (String allowedChar : allowedChars) {
                if (allowedChar.indexOf(c) != -1) {
                    valid = true;
                    break;
                }
            }
            if (valid) {
                sanitizedCommand.append(c);
            }
        }
        return sanitizedCommand.toString();
    }

    public static void main(String[] args) {
        String command = "echo Hello World!";
