import java.io.File;
import java.util.ArrayList;
import java.util.List;

public class PathSanitizer {

    private String basePath;

    public PathSanitizer(String basePath) {
        this.basePath = basePath;
    }

    public String sanitize(String path) {
        List<String> stack = new ArrayList<>();
        File file = new File(basePath);
        stack.add(file.getAbsolutePath());

        String[] components = path.split(File.separator);

        for (String component : components) {
            if (component.equals("..")) {
                if (stack.size() > 1) {
                    stack.remove(stack.size() - 1);
                }
            } else if (!component.equals(".") && !component.isEmpty()) {
                stack.add(component);
            }
        }

        String sanitizedPath = String.join(File.separator, stack);

        return sanitizedPath;
    }

    public static void main(String[] args) {
        PathSanitizer sanitizer = new PathSanitizer("/var/www/html");
        System.out.println(sanitizer.sanitize("uploads/.././images/./logo.png"));
    }
}
