import java.io.File;
import java.util.ArrayList;
import java.util.List;

public class PathSanitizer {

    private String basePath;

    public PathSanitizer(String basePath) {
        this.basePath = basePath;
    }

    public String sanitize(String path) {
        // Normalize base path
        File baseFile = new File(basePath);
        basePath = baseFile.getAbsolutePath();

        // Split path into components
        String[] components = path.split("/");

        // Initialize stack with base path
        List<String> stack = new ArrayList<>();
        stack.add(basePath);

        // Process each component
        for (String component : components) {
            if (component.isEmpty() || component.equals(".")) {
                continue;
            } else if (component.equals("..")) {
                if (stack.size() > 1) {
                    stack.remove(stack.size() - 1);
                }
            } else {
                stack.add(component);
            }
        }

        // Join stack into sanitized path
        String sanitizedPath = String.join(File.separator, stack);

        return sanitizedPath;
    }

    public static void main(String[] args) {
        PathSanitizer sanitizer = new PathSanitizer("/var/www/html");
        System.out.println(sanitizer.sanitize("uploads/.././images/./logo.png"));
    }
}
