import java.io.File;
import java.util.ArrayList;
import java.util.List;

public class PathSanitizer {

    public static String sanitizePath(String basePath, String requestedPath) {
        File baseFile = new File(basePath);
        File requestedFile = new File(baseFile, requestedPath);

        List<String> stack = new ArrayList<>();
        String[] components = requestedFile.toPath().toString().split(File.separator);

        for (String component : components) {
            if (component.equals("..")) {
                if (!stack.isEmpty()) {
                    stack.remove(stack.size() - 1);
                }
            } else if (!component.equals(".") && !component.isEmpty()) {
                stack.add(component);
            }
        }

        StringBuilder sanitizedPath = new StringBuilder();
        for (String part : stack) {
            sanitizedPath.append(part).append(File.separator);
        }

        File sanitizedFile = new File(baseFile, sanitizedPath.toString());
        return sanitizedFile.getCanonicalPath();
    }

    public static boolean isWithinBasePath(String basePath, String sanitizedPath) throws Exception {
        File baseFile = new File(basePath).getCanonicalFile();
        File sanitizedFile = new File(sanitizedPath).getCanonicalFile();

        return sanitizedFile.toPath().startsWith(baseFile.toPath());
    }

    public static String secureFileAccess(String basePath, String requestedPath) throws Exception {
        String sanitizedPath = sanitizePath(basePath, requestedPath);
        if (isWithinBasePath(basePath, sanitizedPath)) {
            return sanitizedPath;
        } else {
            throw new SecurityException("Access to " + requestedPath + " is forbidden");
        }
    }

    public static void main(String[] args) throws Exception {
        String basePath = "/var/www/html";
        String requestedPath = "../../../etc/passwd";

        try {
            String securedPath = secureFileAccess(basePath, requestedPath);
            System.out.println("Secured Path: " + securedPath);
        } catch (SecurityException e) {
            System.out.println(e.getMessage());
        }
    }
}
