import java.io.File;
import java.io.FileNotFoundException;
import java.util.Scanner;

public class Main {
    public static String securePath(String userProvidedPath) {
        // Normalize the path to eliminate any redundant separators or parent directory references
        String normalizedPath = new File(userProvidedPath).getPath();

        // Check if the normalized path is absolute
        File file = new File(normalizedPath);
        if (file.isAbsolute()) {
            // If absolute, ensure it's within a safe directory
            String safeDirectory = "/path/to/safe/directory"; // Define your safe directory
            if (!normalizedPath.startsWith(safeDirectory)) {
                throw new SecurityException("Path not within safe directory");
            }
        } else {
            // If relative, convert to absolute and check
            String absolutePath = new File(System.getProperty("user.dir"), normalizedPath).getPath();
            if (!absolutePath.startsWith(new File(System.getProperty("user.dir")).getPath() + "/safe/directory")) { // Adjust as needed
                throw new SecurityException("Path not within safe directory");
            }
        }

        return normalizedPath;
    }

    public static void main(String[] args) {
        try {
            String userProvidedPath = "/unsafe/path/../file.txt";
            String sanitizedPath = securePath(userProvidedPath);
            File file = new File(sanitizedPath);
            Scanner scanner = new Scanner(file);
            while (scanner.hasNextLine()) {
                System.out.println(scanner.nextLine());
            }
            scanner.close();
        } catch (FileNotFoundException e) {
            System.err.println("File not found");
        } catch (SecurityException e) {
            System.err.println(e.getMessage());
        }
    }
}
