import java.io.File;
import java.io.FileNotFoundException;

public class Main {
    public static String securePath(String userInput) {
        // Normalize the path to eliminate any redundant separators or parent directory references
        String normalizedPath = new File(userInput).getPath();

        // Check if the normalized path is absolute
        File file = new File(normalizedPath);
        if (file.isAbsolute()) {
            // If absolute, ensure it's within a safe directory
            String safeDirectory = "/safe/directory"; // Define your safe directory here
            File safeDir = new File(safeDirectory);
            try {
                String canonicalPath = file.getCanonicalPath();
                String safeCanonicalPath = safeDir.getCanonicalPath();
                if (canonicalPath.startsWith(safeCanonicalPath)) {
                    return canonicalPath;
                } else {
                    throw new SecurityException("Path not within safe directory");
                }
            } catch (Exception e) {
                throw new SecurityException(e);
            }
        } else {
            // If not absolute, consider it as a relative path to the current working directory
            // and ensure it's not trying to access parent directories
            if (!normalizedPath.startsWith("..")) {
                return normalizedPath;
            } else {
                throw new SecurityException("Path trying to access parent directories");
            }
        }
    }

    public static void main(String[] args) {
        try {
            String userProvidedPath = "../etc/passwd"; // Example user input
            String sanitizedPath = securePath(userProvidedPath);
            System.out.println("Sanitized path: " + sanitizedPath);
            // Proceed with opening the file using the sanitized path
        } catch (SecurityException e) {
            System.err.println("Security exception: " + e.getMessage());
        } catch (Exception e) {
            System.err.println("An error occurred: " + e.getMessage());
        }
    }
}
