import java.security.SecureRandom;
import java.nio.charset.StandardCharsets;
import java.math.BigInteger;

public class PasswordHasher {

    private static final int SALT_SIZE = 16;
    private static final int ITERATIONS = 10000;
    private static final int KEY_SIZE = 32;

    public static String hashPassword(String password) {
        byte[] salt = generateSalt(SALT_SIZE);
        byte[] hashedPassword = pbkdf2(password.getBytes(StandardCharsets.UTF_8), salt, ITERATIONS, KEY_SIZE);
        return bytesToHex(salt) + ":" + bytesToHex(hashedPassword);
    }

    public static boolean verifyPassword(String password, String hashedPassword) {
        String[] parts = hashedPassword.split(":");
        if (parts.length != 2) {
            throw new IllegalArgumentException("Invalid hashed password format");
        }
        byte[] salt = hexToBytes(parts[0]);
        byte[] expectedHash = hexToBytes(parts[1]);
        byte[] actualHash = pbkdf2(password.getBytes(StandardCharsets.UTF_8), salt, ITERATIONS, KEY_SIZE);
        return slowEquals(expectedHash, actualHash);
    }

    private static byte[] generateSalt(int size) {
        SecureRandom random = new SecureRandom();
        byte[] salt = new byte[size];
        random.nextBytes(salt);
        return salt;
    }

    private static byte[] pbkdf2(byte[] password, byte[] salt, int iterations, int keySize) {
        int blockSize = 20;
        byte[] dk = new byte[keySize];
        int blockNumber = 1;
        while (dk.length < keySize) {
            byte[] block = pbkdf2Block(password, salt, iterations, blockNumber);
            int copyLen = Math.min(block.length, dk.length - dk.length % block.length);
            System.arraycopy(block, 0, dk, dk.length - copyLen, copyLen);
            blockNumber++;
        }
        return dk;
    }

    private static byte[] pbkdf2Block(byte[] password, byte[] salt, int iterations, int blockNumber) {
        byte[] u = new byte[salt.length + 4];
        System.arraycopy(salt, 0, u, 0, salt.length);
        u[u.length - 4] = (byte) ((blockNumber >> 24) & 0xff);
        u[u.length - 3] = (byte) ((blockNumber >> 16) & 0xff);
        u[u.length - 2] = (byte) ((blockNumber >> 8) & 0xff);
        u[u.length - 1] = (byte) (blockNumber & 0xff);

        byte[] T = hmacSha1(password, u);

        byte[] temp = new byte[T.length];
        System.arraycopy(T, 0, temp, 0, T.length);

        for (int i = 1; i < iterations; i++) {
            T = hmacSha1(password, T);
            for (int j = 0; j < T.length; j++) {
                temp[j] ^= T[j];
            }
        }
        return temp;
    }

    private static byte[] hmacSha1(byte[] key, byte[] data) {
        java.security.KeyFactory kf;
        try {
            kf = java.security.KeyFactory.getInstance("HmacSHA1");
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
        javax.crypto.Mac mac;
        try {
            mac = javax.crypto.Mac.getInstance("HmacSHA1");
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
        try {
            mac.init(kf.generateSecret(key));
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
        try {
            return mac.doFinal(data);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    private static String bytesToHex(byte[] bytes) {
        BigInteger bi = new BigInteger(1, bytes);
        return String.format("%0" + (bytes.length << 1) + "x", bi);
    }

    private static byte[] hexToBytes(String hex) {
        int len = hex.length();
        byte[] data = new byte[len / 2];
