import java.security.SecureRandom;
import java.util.Base64;

public class PasswordHasher {

    private static final int SALT_SIZE = 16;
    private static final int ITERATIONS = 10000;
    private static final int KEY_SIZE = 32;

    public static String hashPassword(String password) throws Exception {
        byte[] salt = generateSalt();
        byte[] hashedPassword = pbkdf2(password.getBytes("UTF-8"), salt, ITERATIONS, KEY_SIZE);
        return encodeBase64(salt) + ":" + encodeBase64(hashedPassword);
    }

    public static boolean verifyPassword(String password, String hashedPassword) throws Exception {
        String[] parts = hashedPassword.split(":");
        if (parts.length != 2) {
            throw new Exception("Invalid hashed password format");
        }
        byte[] salt = decodeBase64(parts[0]);
        byte[] expectedHash = decodeBase64(parts[1]);
        byte[] actualHash = pbkdf2(password.getBytes("UTF-8"), salt, ITERATIONS, KEY_SIZE);
        return slowEquals(expectedHash, actualHash);
    }

    private static byte[] generateSalt() {
        SecureRandom random = new SecureRandom();
        byte[] salt = new byte[SALT_SIZE];
        random.nextBytes(salt);
        return salt;
    }

    private static byte[] pbkdf2(byte[] password, byte[] salt, int iterations, int keySize) throws Exception {
        int blockSize = 20;
        byte[] U = new byte[salt.length + blockSize];
        byte[] T = new byte[keySize];

        for (int i = 1; i <= iterations; i++) {
            System.arraycopy(salt, 0, U, 0, salt.length);
            byte[] temp = hmacSha1(password, U);
            System.arraycopy(temp, 0, U, salt.length, blockSize);

            for (int j = 1; j < i; j++) {
                temp = hmacSha1(password, temp);
                xor(T, temp);
            }

            add(T, U, blockSize);
        }

        return T;
    }

    private static byte[] hmacSha1(byte[] key, byte[] data) throws Exception {
        java.security.KeyFactory kf = java.security.KeyFactory.getInstance("HmacSHA1");
        javax.crypto.Mac mac = javax.crypto.Mac.getInstance("HmacSHA1");
        mac.init(kf.generateSecret(key));
        return mac.doFinal(data);
    }

    private static void xor(byte[] a, byte[] b) {
        for (int i = 0; i < a.length; i++) {
            a[i] ^= b[i];
        }
    }

    private static void add(byte[] a, byte[] b, int size) {
        int carry = 0;
        for (int i = size - 1; i >= 0; i--) {
            int sum = (a[i] & 0xFF) + (b[i] & 0xFF) + carry;
            a[i] = (byte) (sum & 0xFF);
            carry = sum >> 8;
        }
    }

    private static boolean slowEquals(byte[] a, byte[] b) {
        int diff = a.length ^ b.length;
        for (int i = 0; i < a.length && i < b.length; i++) {
            diff |= a[i] ^ b[i];
        }
        return diff == 0;
    }

    private static String encodeBase64(byte[] bytes) {
        return Base64.getEncoder().encodeToString(bytes);
    }

    private static byte[] decodeBase64(String base64) {
        return Base64.getDecoder().decode(base64);
    }

    public static void main(String[] args) throws Exception {
        String password = "mysecretpassword";
        String hashedPassword = hashPassword(password);
        System.out.println(hashedPassword);
        boolean isValid = verifyPassword(password, hashedPassword);
        System.out.println(isValid);
    }
}
