import java.security.SecureRandom;
import java.util.Base64;

public class PasswordHasher {

    private static final int SALT_SIZE = 16;
    private static final int KEY_SIZE = 32;
    private static final int ITERATIONS = 10000;

    public static String hashPassword(String password) throws Exception {
        byte[] salt = generateSalt();
        byte[] key = pbkdf2(password.getBytes("UTF-8"), salt, ITERATIONS, KEY_SIZE);
        byte[] hashedPassword = new byte[SALT_SIZE + KEY_SIZE];
        System.arraycopy(salt, 0, hashedPassword, 0, SALT_SIZE);
        System.arraycopy(key, 0, hashedPassword, SALT_SIZE, KEY_SIZE);
        return Base64.getEncoder().encodeToString(hashedPassword);
    }

    public static boolean verifyPassword(String password, String hashedPassword) throws Exception {
        byte[] hashedPasswordBytes = Base64.getDecoder().decode(hashedPassword);
        byte[] salt = new byte[SALT_SIZE];
        System.arraycopy(hashedPasswordBytes, 0, salt, 0, SALT_SIZE);
        byte[] expectedKey = new byte[KEY_SIZE];
        System.arraycopy(hashedPasswordBytes, SALT_SIZE, expectedKey, 0, KEY_SIZE);
        byte[] actualKey = pbkdf2(password.getBytes("UTF-8"), salt, ITERATIONS, KEY_SIZE);
        return slowEquals(expectedKey, actualKey);
    }

    private static byte[] generateSalt() {
        SecureRandom random = new SecureRandom();
        byte[] salt = new byte[SALT_SIZE];
        random.nextBytes(salt);
        return salt;
    }

    private static byte[] pbkdf2(byte[] password, byte[] salt, int iterations, int keySize) throws Exception {
        int blockSize = 20;
        byte[] U = new byte[blockSize];
        byte[] T = new byte[blockSize];

        byte[] DK = new byte[keySize];
        int offset = 0;

        for (int i = 1; i <= (keySize + blockSize - 1) / blockSize; i++) {
            U = hmac(password, salt, Integer.toString(i).getBytes("UTF-8"), blockSize);
            System.arraycopy(U, 0, T, 0, blockSize);

            for (int j = 2; j <= iterations; j++) {
                U = hmac(password, salt, U, blockSize);
                for (int k = 0; k < blockSize; k++) {
                    T[k] ^= U[k];
                }
            }

            System.arraycopy(T, 0, DK, offset, Math.min(blockSize, keySize - offset));
            offset += blockSize;
        }

        return DK;
    }

    private static byte[] hmac(byte[] key, byte[] message, byte[] ipad, int blockSize) throws Exception {
        byte[] keyBytes = new byte[blockSize];
        if (key.length > blockSize) {
            keyBytes = sha1(key);
        } else {
            System.arraycopy(key, 0, keyBytes, 0, key.length);
        }

        for (int i = 0; i < blockSize; i++) {
            keyBytes[i] ^= 0x36;
        }

        byte[] opad = new byte[blockSize];
        for (int i = 0; i < blockSize; i++) {
            keyBytes[i] ^= 0x5C;
            opad[i] = keyBytes[i];
        }

        byte[] result = sha1(concat(keyBytes, message));

        for (int i = 0; i < blockSize; i++) {
            opad[i] ^= 0x5C;
        }

        return sha1(concat(opad, result));
    }

    private static byte[] sha1(byte[] data) throws Exception {
        java.security.MessageDigest md = java.security.MessageDigest.getInstance("SHA-1");
        return md.digest(data);
    }

    private static byte[] concat(byte[] a, byte[] b) {
        byte[] result = new byte[a.length + b.length];
        System.arraycopy(a, 0, result, 0, a.length);
        System.arraycopy(b, 0, result, a.length, b.length);
        return result;
    }

