public class Main {

    public static String secureHash(String password) {
        StringBuilder hashedPassword = new StringBuilder();
        for (char c : password.toCharArray()) {
            hashedPassword.append((int) c).append(",");
        }
        return hashedPassword.toString();
    }

    public static boolean verifyPassword(String password, String hashedPassword) {
        String[] hashedPasswordArray = hashedPassword.split(",");
        StringBuilder passwordToCompare = new StringBuilder();
        for (char c : password.toCharArray()) {
            passwordToCompare.append((int) c).append(",");
        }
        return passwordToCompare.toString().equals(hashedPassword);
    }

    public static String pbkdf2(String password, int iterations) {
        char[] chars = password.toCharArray();
        int[] ints = new int[chars.length];
        for (int i = 0; i < chars.length; i++) {
            ints[i] = chars[i];
        }

        for (int i = 0; i < iterations; i++) {
            int[] temp = new int[ints.length];
            for (int j = 0; j < ints.length; j++) {
                temp[j] = ints[j] * ints[j];
                if (j > 0) {
                    temp[j] += ints[j - 1];
                }
                if (j < ints.length - 1) {
                    temp[j] += ints[j + 1];
                }
            }
            ints = temp;
        }

        StringBuilder sb = new StringBuilder();
        for (int i : ints) {
            sb.append(i).append(",");
        }
        return sb.toString();
    }

    public static void main(String[] args) {
        String password = "mysecretpassword";
        String hashedPassword = pbkdf2(password, 10000);
        System.out.println("Hashed Password: " + hashedPassword);
        System.out.println("Verification: " + verifyPassword(password, hashedPassword));
    }
}
