public class Sanitizer {

    public static String sanitize(String input) {
        if (input == null) {
            return "";
        }

        input = trim(input);
        input = removeSpecialChars(input);
        input = removeScriptTags(input);
        input = removeHtmlTags(input);
        input = escapeHtml(input);

        return input;
    }

    private static String trim(String input) {
        return input.replaceAll("^\\s+|\\s+$", "");
    }

    private static String removeSpecialChars(String input) {
        return input.replaceAll("[^a-zA-Z0-9\\s.,!?-]", "");
    }

    private static String removeScriptTags(String input) {
        return input.replaceAll("<script>.*?</script>", "");
    }

    private static String removeHtmlTags(String input) {
        return input.replaceAll("<.*?>", "");
    }

    private static String escapeHtml(String input) {
        return input
                .replace("&", "&amp;")
                .replace("<", "&lt;")
                .replace(">", "&gt;")
                .replace("\"", "&quot;")
                .replace("'", "&#x27;");
    }

    public static void main(String[] args) {
        System.out.println(sanitize("<script>alert('XSS')</script> Hello World!"));
        System.out.println(sanitize("   Hello   World!   "));
        System.out.println(sanitize(null));
        System.out.println(sanitize("!@#$%^&*()_+"));
    }
}
