import javax.validation.ConstraintViolation;
import javax.validation.Validation;
import javax.validation.Validator;
import javax.validation.ValidatorFactory;
import java.util.Set;

public class FormDataValidator {

    public static void validateInput(FormData formData) {
        ValidatorFactory factory = Validation.buildDefaultValidatorFactory();
        Validator validator = factory.getValidator();
        Set<ConstraintViolation<FormData>> violations = validator.validate(formData);

        if (!violations.isEmpty()) {
            for (ConstraintViolation<FormData> violation : violations) {
                System.out.println(violation.getMessage());
            }
            throw new RuntimeException("Invalid form data");
        }
    }

    public static class FormData {
        private String name;
        private String email;

        public FormData(String name, String email) {
            this.name = name;
            this.email = email;
        }

        public String getName() {
            return name;
        }

        public void setName(String name) {
            this.name = name;
        }

        public String getEmail() {
            return email;
        }

        public void setEmail(String email) {
            this.email = email;
        }
    }

    public static void main(String[] args) {
        FormData formData = new FormData("John Doe", "johndoe@example.com");
        validateInput(formData);
    }
}
