import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class Sanitizer {

    public static String cleanData(String input) {
        // Remove script tags
        input = input.replaceAll("<script>.*?</script>", "");

        // Remove html tags
        input = input.replaceAll("<.*?>", "");

        // Remove special characters
        input = input.replaceAll("[^a-zA-Z0-9\\s.,!?-]", "");

        // Remove SQL injection keywords
        String[] sqlInjectionKeywords = {"SELECT", "FROM", "WHERE", "DROP", "TABLE", "INSERT", "UPDATE", "DELETE", "JOIN", "UNION"};
        for (String keyword : sqlInjectionKeywords) {
            input = input.replaceAll("(?i)" + Pattern.quote(keyword), "");
        }

        // Remove JavaScript keywords
        String[] jsKeywords = {"javascript", "jscript", "vbscript", "mocha", "livescript"};
        for (String keyword : jsKeywords) {
            input = input.replaceAll("(?i)" + Pattern.quote(keyword), "");
        }

        return input;
    }

    public static void main(String[] args) {
        String userInput = "<script>alert('XSS')</script> SELECT * FROM users";
        String cleanedInput = cleanData(userInput);
        System.out.println(cleanedInput);
    }
}
