import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class DataCleaner {
    public static String cleanData(String input) {
        // Remove HTML tags
        String noTags = input.replaceAll("<.*?>", "");

        // Remove JavaScript code
        String noJs = noTags.replaceAll("javascript:.*?", "");

        // Remove SQL injection attempts
        String noSqlInjection = noJs.replaceAll(".*?(SELECT|INSERT|UPDATE|DELETE|DROP|CREATE|ALTER|TRUNCATE).*?", "");

        // Remove special characters
        String clean = noSqlInjection.replaceAll("[^a-zA-Z0-9\\s.,!?-]", "");

        return clean;
    }

    public static void main(String[] args) {
