public class Main {

    public static String encrypt_data(String data, int key) {
        StringBuilder encrypted_data = new StringBuilder();
        for (char c : data.toCharArray()) {
            encrypted_data.append((char) (c + key));
        }
        return encrypted_data.toString();
    }

    public static String decrypt_data(String encrypted_data, int key) {
        StringBuilder decrypted_data = new StringBuilder();
        for (char c : encrypted_data.toCharArray()) {
            decrypted_data.append((char) (c - key));
        }
        return decrypted_data.toString();
    }

    public static void main(String[] args) {
        String data = "Hello, World!";
        int key = 3;
        String encrypted = encrypt_data(data, key);
        System.out.println("Encrypted: " + encrypted);
        String decrypted = decrypt_data(encrypted, key);
        System.out.println("Decrypted: " + decrypted);
    }
}
