```java
import javax.crypto.Cipher;
import javax.crypto.KeyGenerator;
import javax.crypto.SecretKey;
import javax.crypto.spec.SecretKeySpec;
import java.nio.charset.StandardCharsets;
import java.security.NoSuchAlgorithmException;
import java.security.SecureRandom;
import java.util.Base64;

public class Main {

    public static void main(String[] args) throws Exception {
        String userData = "This is some secret user data";
        String encryptedData = encrypt(userData);
        String decryptedData = decrypt(encryptedData);

        System.out.println("User Data: " + userData);
        System.out.println("Encrypted Data: " + encryptedData);
        System.out.println("Decrypted Data: " + decryptedData);
    }

    public static String encrypt(String data) throws Exception {
        KeyGenerator keyGen = KeyGenerator.getInstance("AES");
        keyGen.init(128);
        SecretKey secretKey = keyGen.generateKey();
        Cipher cipher = Cipher.getInstance("AES");
        cipher.init(Cipher.ENCRYPT_MODE, secretKey);
        byte[] encryptedBytes = cipher.doFinal(data.getBytes(StandardCharsets.UTF_8));
        String encodedKey = Base64.getEncoder().encodeToString(secretKey.getEncoded());
        String encodedEncryptedBytes = Base64.getEncoder().encodeToString(encryptedBytes);
        return encodedKey + ":" + encodedEncryptedBytes;
    }

    public static String decrypt(String encryptedData) throws Exception {
        String[] parts = encryptedData.split(":");
        if (parts.length != 2) {
            throw new Exception("Invalid encrypted data format");
        }
        String encodedKey = parts[0];
        String encodedEncryptedBytes = parts[1];

        byte[] decodedKey = Base64.getDecoder().decode(encodedKey);
        SecretKey secretKey = new SecretKeySpec(decodedKey, 0, decodedKey.length, "AES");

        byte[] decodedEncryptedBytes = Base64.getDecoder().decode(encodedEncryptedBytes);
        Cipher cipher = Cipher.getInstance("AES");
        cipher.init(Cipher.DECRYPT_MODE, secretKey);
        byte[] decryptedBytes = cipher.doFinal(decodedEncryptedBytes);
        return new String(decryptedBytes, StandardCharsets.UTF_8);
    }
}
