import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class Sanitizer {
    public static String sanitizeSql(String input) {
        return input.replaceAll("[^a-zA-Z0-9\\s]", "");
    }

    public static String escapeHtml(String input) {
        return input.replace("&", "&amp;")
                .replace("<", "&lt;")
                .replace(">", "&gt;")
                .replace("\"", "&quot;")
                .replace("'", "&#x27;");
    }

    public static boolean validateInput(String input) {
        String regex = "^[a-zA-Z0-9\\s]+$";
        Pattern pattern = Pattern.compile(regex);
        Matcher matcher = pattern.matcher(input);
        return matcher.matches();
    }

    public static String processFormData(String input) {
        if (validateInput(input)) {
            String sanitizedInput = sanitizeSql(input);
            String escapedInput = escapeHtml(sanitizedInput);
            return escapedInput;
        } else {
            return "Invalid input";
        }
    }

    public static void main(String[] args) {
        System.out.println(processFormData("Hello World"));
        System.out.println(processFormData("Hello < World"));
        System.out.println(processFormData("Robert'); DROP TABLE Students; --"));
    }
}
