import javax.ws.rs.core.MediaType;
import javax.ws.rs.core.Response;

import com.auth0.jwt.JWTVerifier;
import com.auth0.jwt.exceptions.JWTVerificationException;
import com.auth0.jwt.interfaces.DecodedJWT;

@Path("/api/secure-endpoint")
public class SecureEndpoint {

    @POST
    @Consumes(MediaType.APPLICATION_JSON)
    @Produces(MediaType.APPLICATION_JSON)
    public Response secureEndpoint(Map<String, String> incomingData) {
        try {
            // Validate token
            String token = incomingData.get("token");
            DecodedJWT decodedJWT = validateToken(token);

            // Sanitize request data
            Map<String, String> sanitizedData = sanitizeRequest(incomingData);

            // Process sanitized data
            String message = "Token is valid and data is sanitized: " + sanitizedData.toString();
            return Response.ok(message).build();
        } catch (Exception e) {
            return Response.serverError().entity(e.getMessage()).build();
        }
    }

    private DecodedJWT validateToken(String token) throws JWTVerificationException {
        // Initialize JWT verifier
        String secretKey = "your-secret-key";
        JWTVerifier verifier = com.auth0.jwt.JWT.require(com.auth0.jwt.algorithms.Algorithm.HMAC256(secretKey)).build();

        // Verify token
        return verifier.verify(token);
    }

    private Map<String, String> sanitizeRequest(Map<String, String> incomingData) {
        Map<String, String> sanitizedData = new HashMap<>();
        for (Map.Entry<String, String> entry : incomingData.entrySet()) {
            String key = entry.getKey();
            String value = entry.getValue();

            // Remove leading/trailing whitespaces
            value = value.trim();

            // Remove special characters
            value = value.replaceAll("[^a-zA-Z0-9\\s]", "");

            sanitizedData.put(key, value);
        }
        return sanitizedData;
    }
}
