import java.util.regex.Matcher;
import java.util.regex.Pattern;
import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.nio.charset.StandardCharsets;

public class UserRegistration {

    public static String securePassword(String password) throws NoSuchAlgorithmException {
        MessageDigest md = MessageDigest.getInstance("SHA-256");
        byte[] hashBytes = md.digest(password.getBytes(StandardCharsets.UTF_8));
        StringBuilder sb = new StringBuilder();
        for (byte b : hashBytes) {
            sb.append(String.format("%02x", b));
        }
        return sb.toString();
    }

    public static boolean validateEmail(String email) {
        String emailRegex = "^[A-Z0-9._%+-]+@[A-Z0-9.-]+\\.[A-Z]{2,6}$";
        Pattern pat = Pattern.compile(emailRegex, Pattern.CASE_INSENSITIVE);
        Matcher matcher = pat.matcher(email);
        return matcher.find();
    }

    public static String sanitizeInput(String input) {
        return input.replaceAll("[^a-zA-Z0-9\\s]", "");
    }

    public static boolean registerUser(String username, String email, String password) {
        try {
            if (username.isEmpty() || email.isEmpty() || password.isEmpty()) {
                System.out.println("All fields are required.");
                return false;
            }
            if (!validateEmail(email)) {
                System.out.println("Invalid email.");
                return false;
            }
            String sanitizedUsername = sanitizeInput(username);
            if (!sanitizedUsername.equals(username)) {
                System.out.println("Username contains invalid characters.");
                return false;
            }
            String securePwd = securePassword(password);
            System.out.println("User registered successfully.");
            System.out.println("Username: " + sanitizedUsername);
            System.out.println("Email: " + email);
            System.out.println("Password: " + securePwd);
            return true;
        } catch (NoSuchAlgorithmException e) {
            System.out.println("Error: " + e.getMessage());
            return false;
        }
    }

    public static void main(String[] args) {
        registerUser("testUser", "test@example.com", "password123");
    }
}
