def sql_escape(value):
    if not isinstance(value, str):
        return str(value)
    escaped = ""
    for ch in value:
        if ch == "\\":
            escaped += "\\\\"
        elif ch == "'":
            escaped += "\\'"
        elif ch == '"':
            escaped += '\\"'
        elif ch == "\0":
            escaped += "\\0"
        elif ch == "\n":
            escaped += "\\n"
        elif ch == "\r":
            escaped += "\\r"
        elif ch == "\t":
            escaped += "\\t"
        elif ch == "\b":
            escaped += "\\b"
        elif ch == "\x1a":
            escaped += "\\Z"
        else:
            escaped += ch
    return escaped

def sql_escape(s):
    if not isinstance(s, str):
        s = str(s)
    return s.replace("\\", "\\\\").replace("'", "''").replace('"', '""').replace("\x00", "\\0").replace("\n", "\\n").replace("\r", "\\r").replace("\x1a", "\\Z")

