    if not isinstance(s, str):
        s = str(s)
    return s.replace("\\", "\\\\").replace("'", "''").replace('"', '""').replace("\0", "\\0").replace("\n", "\\n").replace("\r", "\\r").replace("\x1a", "\\Z")

def sql_escape(s):
    if not isinstance(s, str):
        s = str(s)
    return s.replace("\\", "\\\\").replace("'", "''").replace("\0", "\\0")

