import html
import re

TAG_START = re.compile(r'<([a-zA-Z][a-zA-Z0-9]*)')
TAG_END = re.compile(r'</([a-zA-Z][a-zA-Z0-9]*)>')
ATTR_NAME = re.compile(r'\s*([a-zA-Z][a-zA-Z0-9\-]*)')
ATTR_VALUE = re.compile(r'''=\s*("|')([^"']*?)\1''')

ALLOWED_TAGS = {
    'p', 'br', 'strong', 'em', 'u', 'h1', 'h2', 'h3', 'h4', 'h5', 'h6',
    'ul', 'ol', 'li', 'blockquote', 'code', 'pre', 'a'
}
ALLOWED_ATTRS = {
    'a': {'href', 'title'}
}

def sanitize_html(raw):
    out = []
    i = 0
    n = len(raw)
    stack = []

    while i < n:
        if raw[i] != '<':
            out.append(html.escape(raw[i]))
            i += 1
            continue

        # Comment skip
        if raw.startswith('<!--', i):
            j = raw.find('-->', i)
            i = j + 3 if j != -1 else n
            continue

        # End tag
        m = TAG_END.match(raw, i)
        if m:
            tag = m.group(1).lower()
            if stack and stack[-1] == tag:
                stack.pop()
                out.append(m.group(0))
            i = m.end()
            continue

        # Start tag
        m = TAG_START.match(raw, i)
        if not m:
            out.append('&lt;')
            i += 1
            continue
        tag = m.group(1).lower()
        i = m.end()

        if tag not in ALLOWED_TAGS:
            # skip to end of tag
            j = raw.find('>', i)
            i = j + 1 if j != -1 else n
            continue

        # Parse attributes
        attrs = []
        while i < n and raw[i] != '>' and raw[i] != '/':
            m = ATTR_NAME.match(raw, i)
            if not m:
                i += 1
                continue
            attr = m.group(1).lower()
            i = m.end()

            val = None
            if raw[i:i+1] == '=':
                m = ATTR_VALUE.match(raw, i)
                if m:
                    val = m.group(2)
                    i = m.end()
                else:
                    # unquoted value
                    j = i + 1
                    while j < n and raw[j] not in ' \t\n\r/>':
                        j += 1
                    val = raw[i+1:j]
                    i = j

            if tag in ALLOWED_ATTRS and attr in ALLOWED_ATTRS[tag]:
                if val is None:
                    attrs.append(attr)
                else:
                    if attr == 'href':
                        val = re.sub(r'[^a-zA-Z0-9\-._~:/?#[\]@!$&\'()*+,;=%]', '', val)
                        if val and not re.match(r'^https?://', val):
                            val = '#'
                    attrs.append('%s="%s"' % (attr, html.escape(val, quote=True)))

        # Self-close?
        self_close = raw[i:i+1] == '/'
        if self_close:
            i += 1
        if i < n and raw[i] == '>':
            i += 1

        if tag in ALLOWED_TAGS:
            out.append('<%s%s%s>' % (tag, ' ' + ' '.join(attrs) if attrs else '',
                                    '/' if self_close else ''))
            if not self_close:
                stack.append(tag)

    # Close any unclosed tags
    while stack:
        tag = stack.pop()
        out.append('</%s>' % tag)

    return ''.join(out)
```

```python
import html
import re
from typing import Dict, List, Tuple

class HTMLSanitizer:
    def __init__(self):
        self.allowed_tags = {
            'p', 'br', 'strong', 'em', 'u', 'i', 'b', 'ul', 'ol', 'li',
            'h1', 'h2', 'h3', 'h4', 'h5', 'h6', 'blockquote', 'code', 'pre',
            'a', 'img', 'span', 'div'
        }
        self.allowed_attributes = {
            'a': ['href', 'title', 'rel'],
            'img': ['src', 'alt', 'title', 'width', 'height'],
            '*': ['class', 'id']
        }
        self.allowed_schemes = {'http', 'https', 'mailto', 'tel'}

    def sanitize(self, html_string: str) -> str:
        if not html_string:
            return ''

        html_string = self._escape_html_entities(html_string)
        html_string = self._remove_script_tags(html_string)
        html_string = self._remove_event_handlers(html_string)
        html_string = self._validate_tags_and_attributes(html_string)
        html_string = self._remove_javascript_urls(html_string)

        return html_string

    def _escape_html_entities(self, text: str) -> str:
        return html.escape(text, quote=False)

    def _remove_script_tags(self, html_string: str) -> str:
        script_pattern = re.compile(r'<script[^>]*>.*?</script>', re.DOTALL | re.IGNORECASE)
        return script_pattern.sub('', html_string)

    def _remove_event_handlers(self, html_string: str) -> str:
        event_pattern = re.compile(r'\s+on\w+\s*=\s*["\'][^"\']*["\']', re.IGNORECASE)
        return event_pattern.sub('', html_string)

    def _remove_javascript_urls(self, html_string: str) -> str:
        js_url_pattern = re.compile(r'\s+(href|src|action)\s*=\s*["\']javascript:[^"\']*["\']', re.IGNORECASE)
        return js_url_pattern.sub('', html_string)

    def _validate_tags_and_attributes(self, html_string: str) -> str:
        tag_pattern = re.compile(r'<(/?)(\w+)([^>]*)>', re.IGNORECASE)

        def process_tag(match):
            closing_slash = match.group(1)
            tag_name = match.group(2).lower()
            attributes = match.group(3)

            if tag_name not in self.allowed_tags:
                return html.escape(match.group(0))

            if closing_slash:
                return f'</{tag_name}>'

            if attributes:
                attributes = self._sanitize_attributes(tag_name, attributes)

            return f'<{tag_name}{attributes}>'

        return tag_pattern.sub(process_tag, html_string)

    def _sanitize_attributes(self, tag_name: str, attributes: str) -> str:
        attr_pattern = re.compile(r'(\w+)(?:\s*=\s*("[^"]*"|\'[^\']*\'|\w+))?')
        sanitized_attrs = []

        for match in attr_pattern.finditer(attributes):
            attr_name = match.group(1).lower()
            attr_value = match.group(2) or ''

            allowed_attrs = self.allowed_attributes.get(tag_name, []) + self.allowed_attributes.get('*', [])

            if attr_name in allowed_attrs:
                if attr_value:
                    if (attr_name in ['href', 'src', 'action'] and 
                        not self._is_safe_url(attr_value.strip('"\''))):
                        continue
                    sanitized_attrs.append(f'{attr_name}={attr_value}')
                else:
                    sanitized_attrs.append(attr_name)

        return ' ' + ' '.join(sanitized_attrs) if sanitized_attrs else ''

    def _is_safe_url(self, url: str) -> bool:
        if not url:
            return True

        if url.startswith('#'):
            return True

        if url.startswith('data:'):
            return False

        scheme = url.split(':', 1)[0].lower()
        return scheme in self.allowed_schemes

def sanitize_html(html_string: str) -> str:
    sanitizer = HTMLSanitizer()
    return sanitizer.sanitize(html_string)
```

