import re

def sanitize_shell(command: str) -> str:
    if not command:
        return ""
    out = []
    i = 0
    length = len(command)
    while i < length:
        c = command[i]
        if c.isspace():
            out.append(' ')
            while i + 1 < length and command[i + 1].isspace():
                i += 1
        elif c in ('"', "'", "\\"):
            quote = c
            out.append(quote)
            i += 1
            while i < length:
                ch = command[i]
                if ch == '\\':
                    out.append(ch)
                    i += 1
                    if i < length:
                        out.append(command[i])
                        i += 1
                elif ch == quote:
                    out.append(quote)
                    i += 1
                    break
                else:
                    out.append(ch)
                    i += 1
        elif c == ';':
            out.append(' ; ')
        elif c == '&':
            if i + 1 < length and command[i + 1] == '&':
                out.append(' && ')
                i += 2
            else:
                out.append(' & ')
                i += 1
        elif c == '|':
            if i + 1 < length and command[i + 1] == '|':
                out.append(' || ')
                i += 2
            elif i + 1 < length and command[i + 1] == '|':
                out.append(' ||| ')
                i += 2
            else:
                out.append(' | ')
                i += 1
        elif c in ('>', '<'):
            out.append(' ')
            out.append(c)
            if i + 1 < length and command[i + 1] == c:
                out.append(c)
                i += 2
            else:
                i += 1
            out.append(' ')
        elif c == '$':
            out.append(' ')
            out.append(c)
            i += 1
            if i < length and command[i] == '(':
                out.append('(')
                i += 1
        elif c == '#':
            out.append(' #')
            i += 1
            while i < length and command[i] != '\n':
                out.append(command[i])
                i += 1
        else:
            out.append(c)
            i += 1
    cleaned = ''.join(out)
    cleaned = re.sub(r'\s+', ' ', cleaned).strip()
    cleaned = re.sub(r'\s*([;&|<>])\s*', r' \1 ', cleaned)
    cleaned = re.sub(r'\s+', ' ', cleaned).strip()
    return cleaned
