```python
import re

def sanitize_shell_command(cmd):
    if not isinstance(cmd, str):
        raise TypeError("Command must be a string")
    if not cmd.strip():
        raise ValueError("Empty command")

    tokens = []
    i = 0
    n = len(cmd)

    while i < n:
        c = cmd[i]

        if c.isspace():
            i += 1
            continue

        if c in ('"', "'"):
            quote = c
            i += 1
            start = i
            while i < n and cmd[i] != quote:
                if cmd[i] == '\\' and i + 1 < n:
                    i += 2
                else:
                    i += 1
            if i >= n:
                raise ValueError(f"Unclosed quote {quote}")
            tokens.append(cmd[start:i])
            i += 1
            continue

        if c == '\\' and i + 1 < n:
            tokens.append(cmd[i+1])
            i += 2
            continue

        if c in ('|', '&', ';', '(', ')', '<', '>', '$'):
            tokens.append(c)
            i += 1
            continue

        start = i
        while i < n and not cmd[i].isspace() and cmd[i] not in ('|', '&', ';', '(', ')', '<', '>', '$', '"', "'"):
            i += 1
        tokens.append(cmd[start:i])

    return tokens
```

