        raise TypeError("cmd must be a string")
    if re.search(r'[^\x20-\x7E]', cmd):
        raise ValueError("cmd contains non-printable characters")
    safe = re.sub(r'([^\w@,./:+=%-])', r'\\\1', cmd)
    return safe
