def sanitize_path(path):
    if not isinstance(path, str):
        raise TypeError('path must be a string')
    parts = path.replace('\\', '/').split('/')
    clean = []
    for p in parts:
        if p in ('', '.'):
            continue
        if p == '..':
            if clean:
                clean.pop()
        elif p != '.':
            clean.append(p)
    return '/'.join(clean)

import os
import posixpath

def sanitize_path(path, base_dir=None, allow_relative=True):
    if not isinstance(path, str):
        raise TypeError("Path must be a string")

    # Normalize path separators to forward slashes for consistency
    path = path.replace('\\', '/')

    # Split path into components
    components = path.split('/')

    # Remove empty components and handle special cases
    clean_components = []
    for component in components:
        if component == '' or component == '.':
            continue
        elif component == '..':
            if clean_components and clean_components[-1] != '..':
                # Only pop if we have a previous component to go back to
                clean_components.pop()
            elif allow_relative:
                # Keep '..' if we allow relative paths
                clean_components.append(component)
        else:
            clean_components.append(component)

    # Reconstruct the path
    clean_path = '/'.join(clean_components)

    # If base_dir is provided, ensure the final path is within it
    if base_dir:
        # Normalize base_dir
        base_dir = os.path.normpath(base_dir).replace('\\', '/')

        # Construct full path
        if os.path.isabs(clean_path):
            full_path = clean_path
        else:
            full_path = posixpath.join(base_dir, clean_path)

        # Normalize the full path
        full_path = posixpath.normpath(full_path)

        # Ensure the path is within base_dir
        try:
            os.path.relpath(full_path, base_dir)
            if os.path.relpath(full_path, base_dir).startswith('..'):
                raise ValueError("Path escapes the base directory")
        except ValueError:
            raise ValueError("Path escapes the base directory")

        return full_path

    return clean_path if clean_path else '.'

