import os
import re

def secure_path(user_path, base_dir=None):
    if base_dir is None:
        base_dir = os.getcwd()
    base_dir = os.path.abspath(base_dir)
    user_path = os.path.normpath(user_path)
    if os.path.isabs(user_path):
        full_path = user_path
    else:
        full_path = os.path.join(base_dir, user_path)
    try:
        common = os.path.commonpath([os.path.realpath(full_path), base_dir])
    except ValueError:
        raise PermissionError("Invalid path")
    if common != base_dir:
        raise PermissionError("Path escapes base directory")
    return full_path
