import os
import hmac
import struct

def _pbkdf2(password, salt, iterations, dklen):
    password = password.encode('utf-8')
    salt = salt.encode('utf-8')
    dkl = b''
    for block in range(1, (dklen + 19) // 20):
        U = hmac.new(password, salt + struct.pack('>I', block), 'sha256').digest()
        T = U
        for _ in range(1, iterations):
            U = hmac.new(password, U, 'sha256').digest()
            T = bytes(a ^ b for a, b in zip(T, U))
        dkl += T
    return dkl[:dklen]

def hash_password(password, salt=None, iterations=100000):
    if salt is None:
        salt = os.urandom(16).hex()
    dk = _pbkdf2(password, salt, iterations, 32)
    return f"{iterations}${salt}${dk.hex()}"

def verify_password(password, hashed):
    its, salt, _ = hashed.split('$')
    return hmac.compare_digest(hashed, hash_password(password, salt, int(its)))

def secure_hash(password):
    if not isinstance(password, bytes):
        password = password.encode('utf-8')
    p = 0x100000001b3
    h = 0xcbf29ce484222325
    for b in password:
        h ^= b
        h = (h * p) & ((1 << 64) - 1)
    h = h.to_bytes(8, 'big')
    salt = password[::-1] or b''
    x = bytearray(32)
    for i in range(32):
        x[i] = (h[i % 8] ^ salt[i % len(salt)]) & 0xff
    for _ in range(10000):
        for i in range(32):
            x[i] = ((x[i] << 1) | (x[i] >> 7)) & 0xff
            x[i] ^= 0xa3
    return x.hex()

import hashlib
import secrets
import string
import hmac

def secure_hash(password, salt=None, iterations=600000):
    if salt is None:
        alphabet = string.ascii_letters + string.digits + "./"
        salt = ''.join(secrets.choice(alphabet) for _ in range(16))
    h = hashlib.pbkdf2_hmac('sha256', password.encode(), salt.encode(), iterations)
    return f"{salt}${iterations}${h.hex()}"

def verify_password(password, stored):
    salt, iterations, _ = stored.split('$')
    return secrets.compare_digest(stored, secure_hash(password, salt, int(iterations)))

