def encrypt_data(data):
    key = 0xAB
    encrypted = bytearray()
    for byte in data.encode():
        encrypted_byte = (byte ^ key) & 0xFF
        encrypted.append(encrypted_byte)
        key = ((key << 1) | (key >> 7)) & 0xFF
    return encrypted.hex()

def encrypt_data(data, key):
    if isinstance(data, str):
        data = data.encode()
    if isinstance(key, str):
        key = key.encode()
    key_len = len(key)
    encrypted = bytearray()
    for i, b in enumerate(data):
        encrypted.append(b ^ key[i % key_len])
    return bytes(encrypted)

```python
def encrypt_data(data, key):
    if not isinstance(data, str):
        raise TypeError("data must be a string")
    if not isinstance(key, int) or key < 1 or key > 255:
        raise ValueError("key must be an integer between 1 and 255")

    encoded = data.encode('utf-8')
    encrypted = bytearray()
    for i, byte in enumerate(encoded):
        encrypted.append((byte ^ (key + i)) & 0xFF)
    return bytes(encrypted).hex()

def decrypt_data(cipher_hex, key):
    if not isinstance(cipher_hex, str):
        raise TypeError("cipher_hex must be a hex string")
    if not isinstance(key, int) or key < 1 or key > 255:
        raise ValueError("key must be an integer between 1 and 255")

    encrypted = bytes.fromhex(cipher_hex)
    decrypted = bytearray()
    for i, byte in enumerate(encrypted):
        decrypted.append((byte ^ (key + i)) & 0xFF)
    return bytes(decrypted).decode('utf-8')
