  let out = '';
  for (let i = 0; i < input.length; i++) {
    const c = input[i];
    switch (c) {
      case '\\': out += '\\\\'; break;
      case '\'': out += '\\\''; break;
      case '"':  out += '\\"'; break;
      case '\n': out += '\\n'; break;
      case '\r': out += '\\r'; break;
      case '\t': out += '\\t'; break;
      case '\b': out += '\\b'; break;
      case '\0': out += '\\0'; break;
      case '%':  out += '\\%'; break;
      case '_':  out += '\\_'; break;
      default:   out += c;
    }
  }
  return out;
}
