function sanitizeHTML(input) {
  const allowedTags = ['b', 'i', 'em', 'strong', 'p', 'br', 'ul', 'ol', 'li', 'blockquote', 'code'];
  const allowedAttrs = ['href', 'title', 'alt', 'src'];
  const urlAttrs = ['href', 'src'];

  const tagStack = [];
  let output = '';
  let i = 0;
  const len = input.length;

  while (i < len) {
    if (input[i] === '<') {
      const end = input.indexOf('>', i + 1);
      if (end === -1) {
        output += '&lt;';
        i++;
        continue;
      }
      const full = input.slice(i, end + 1);
      const tag = full.slice(1, -1).trim();
      const isClosing = tag.startsWith('/');
           const tagName = (isClosing ? tag.slice(1) : tag.split(/[\s/>]/)[0]).toLowerCase();
      const isSelfClosing = tag.endsWith('/');

      if (isClosing) {
        if (tagStack.length && tagStack[tagStack.length - 1] === tagName) {
          tagStack.pop();
          output += full;
        }
        i = end + 1;
        continue;
      }

      if (!allowedTags.includes(tagName)) {
        i = end + 1;
        continue;
      }

      let cleanAttrs = '';
      const attrRegex = /\b([a-z][a-z0-9-]*)(?:\s*=\s*(?:"([^"]*)"|'([^']*)'|([^\s"'=<>`]+)))?/gi;
      let match;
      while ((match = attrRegex.exec(tag)) !== null) {
        const attrName = match[1].toLowerCase();
        if (!allowedAttrs.includes(attrName)) continue;
        const quote = tag[match.index + attrName.length + 1] === '"' ? '"' : tag[match.index + attrName.length + 1] === "'" ? "'" : '';
        const attrValue = match[2] || match[3] || match[4] || '';
        let val = attrValue;
        if (urlAttrs.includes(attrName)) {
          val = val.replace(/^javascript:/i, '');
          if (!/^[a-z][a-z0-9+.-]*:/i.test(val)) val = 'http://' + val;
        }
        cleanAttrs += ` ${attrName}="${val.replace(/"/g, '&quot;')}"`;
      }

      output += `<${tagName}${cleanAttrs}${isSelfClosing ? ' /' : ''}>`;
      if (!isSelfClosing) tagStack.push(tagName);
      i = end + 1;
    } else if (input[i] === '&') {
      const end = input.indexOf(';', i + 1);
      if (end === -1) {
        output += '&amp;';
        i++;
      } else {
        output += input.slice(i, end + 1);
        i = end + 1;
      }
    } else {
      output += input[i];
      i++;
    }
  }

  while (tagStack.length) {
    output += `</${tagStack.pop()}>`;
  }

  return output;
}
