function sanitizeHTML(input) {
  const doc = new DOMParser().parseFromString(input, 'text/html');
  const walker = document.createTreeWalker(
    doc.body,
    NodeFilter.SHOW_ELEMENT,
    null,
    false
  );
  const allowedTags = new Set([
    'p', 'br', 'strong', 'em', 'u', 'h1', 'h2', 'h3', 'h4', 'h5', 'h6',
    'ul', 'ol', 'li', 'blockquote', 'code', 'pre'
  ]);
  const allowedAttrs = new Set(['href', 'title', 'src', 'alt']);
  const remove = [];
  let node;
  while (node = walker.nextNode()) {
    const tag = node.tagName.toLowerCase();
    if (!allowedTags.has(tag)) {
      remove.push(node);
      continue;
    }
    for (const attr of Array.from(node.attributes)) {
      const name = attr.name.toLowerCase();
      if (!allowedAttrs.has(name)) {
        node.removeAttribute(attr.name);
        continue;
      }
      if (name === 'href' || name === 'src') {
        const val = attr.value.trim().toLowerCase();
        if (!val.startsWith('http:') && !val.startsWith('https:') && !val.startsWith('/')) {
          node.removeAttribute(attr.name);
        }
      }
      if (name.startsWith('on')) {
        node.removeAttribute(attr.name);
      }
    }
  }
  remove.forEach(n => n.parentNode.replaceWith(document.createTextNode(n.textContent)));
  return doc.body.innerHTML.replace(/javascript:/gi, '');
}
```

```javascript
function sanitizeHTML(html) {
  const allowedTags = new Set(['p', 'br', 'strong', 'em', 'u', 'i', 'b', 'span', 'div', 'ul', 'ol', 'li', 'a', 'h1', 'h2', 'h3', 'h4', 'h5', 'h6']);
  const allowedAttributes = new Set(['href', 'title', 'class', 'id']);
  const voidElements = new Set(['br', 'hr', 'img', 'input', 'meta', 'link', 'area', 'base', 'col', 'embed', 'source', 'track', 'wbr']);
  const doc = new DOMParser().parseFromString(html, 'text/html');
  const body = doc.body;

  function walk(node) {
    const toRemove = [];
    for (let i = 0; i < node.childNodes.length; i++) {
      const child = node.childNodes[i];
      if (child.nodeType === Node.ELEMENT_NODE) {
        const tag = child.tagName.toLowerCase();
        if (!allowedTags.has(tag)) {
          toRemove.push(child);
          continue;
        }

        const attrs = Array.from(child.attributes);
        for (const attr of attrs) {
          if (!allowedAttributes.has(attr.name.toLowerCase())) {
            child.removeAttribute(attr.name);
          } else {
            const val = attr.value;
            if (attr.name.toLowerCase() === 'href' && !/^https?:\/\//i.test(val)) {
              child.removeAttribute(attr.name);
            } else {
              child.setAttribute(attr.name, val.replace(/[\x00-\x1F\x7F-\x9F]/g, ''));
            }
          }
        }

        if (tag === 'a') {
          child.setAttribute('rel', 'noopener noreferrer');
          child.setAttribute('target', '_blank');
        }

        walk(child);
      } else if (child.nodeType === Node.TEXT_NODE) {
        child.nodeValue = child.nodeValue.replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F-\x9F]/g, '');
      } else {
        toRemove.push(child);
      }
    }

    toRemove.forEach(n => n.remove());
  }

  walk(body);

  return body.innerHTML;
}
