```javascript
function sanitizeShellCommand(input) {
  const WHITESPACE = /\s/;
  const METACHARS = /[;&|`$(){}[\]<>~\n\r]/;
  const ESCAPE = '\\';
  const SINGLE_QUOTE = "'";
  const DOUBLE_QUOTE = '"';

  let out = '';
  let i = 0;
  const len = input.length;

  while (i < len) {
    const ch = input[i];

    if (ch === ESCAPE) {
      if (i + 1 < len) {
        const next = input[i + 1];
        if (next === '\n') {
          out += ' ';
          i += 2;
        } else if (next === ESCAPE || next === SINGLE_QUOTE || next === DOUBLE_QUOTE || WHITESPACE.test(next)) {
          out += next;
          i += 2;
        } else {
          out += next;
          i += 2;
        }
      } else {
        out += ' ';
        i++;
      }
    } else if (ch === SINGLE_QUOTE) {
      out += SINGLE_QUOTE;
      i++;
      while (i < len && input[i] !== SINGLE_QUOTE) {
        out += input[i++];
      }
      if (i < len) {
        out += SINGLE_QUOTE;
        i++;
      }
    } else if (ch === DOUBLE_QUOTE) {
      out += DOUBLE_QUOTE;
      i++;
      while (i < len && input[i] !== DOUBLE_QUOTE) {
        if (input[i] === ESCAPE && i + 1 < len && (input[i + 1] === DOUBLE_QUOTE || input[i + 1] === ESCAPE || input[i + 1] === '$' || input[i + 1] === '`')) {
          out += input[i + 1];
          i += 2;
        } else {
          out += input[i++];
        }
      }
      if (i < len) {
        out += DOUBLE_QUOTE;
        i++;
      }
    } else if (METACHARS.test(ch)) {
      out += ESCAPE + ch;
      i++;
    } else if (WHITESPACE.test(ch)) {
      out += ' ';
      i++;
    } else {
      out += ch;
      i++;
    }
  }

  return out.trim();
}
