```javascript
function sanitizeShellCommand(input) {
    if (typeof input !== 'string') return '';
    let out = '';
    let inSingle = false;
    let inDouble = false;
    let escaped = false;
    for (let i = 0; i < input.length; i++) {
        const c = input[i];
        if (escaped) {
            out += '\\' + c;
            escaped = false;
            continue;
        }
        if (c === '\\') {
            escaped = true;
            continue;
        }
        if (c === "'" && !inDouble) {
            inSingle = !inSingle;
            out += c;
            continue;
        }
        if (c === '"' && !inSingle) {
            inDouble = !inDouble;
            out += c;
            continue;
        }
        if (!inSingle && !inDouble && /[;&|`]/.test(c)) {
            continue;
        }
        out += c;
    }
    if (escaped) out += '\\';
    return out.trim().replace(/\s+/g, ' ');
}
