```javascript
function sanitizeShellCommand(input) {
  const output = [];
  let i = 0;
  const len = input.length;
  let inSingle = false;
  let inDouble = false;
  let token = '';

  function pushToken() {
    if (token) {
      output.push(token);
      token = '';
    }
  }

  while (i < len) {
    const c = input[i];

    if (inSingle) {
      if (c === "'") {
        inSingle = false;
        pushToken();
      } else {
        token += c;
      }
    } else if (inDouble) {
      if (c === '"') {
        inDouble = false;
        pushToken();
      } else if (c === '\\') {
        if (i + 1 < len) {
          const next = input[++i];
          token += next;
        } else {
          token += '\\';
        }
      } else {
        token += c;
      }
    } else {
      if (c === "'") {
        pushToken();
        inSingle = true;
      } else if (c === '"') {
        pushToken();
        inDouble = true;
      } else if (c === '\\') {
        if (i + 1 < len) {
          const next = input[++i];
          token += next;
        } else {
          token += '\\';
        }
      } else if (c === ' ' || c === '\t' || c === '\n') {
        pushToken();
      } else {
        token += c;
      }
    }
    i++;
  }

  pushToken();
  return output;
}
