const { execSync } = require('child_process');

function sanitize_command(cmd) {
  if (typeof cmd !== 'string') throw new TypeError('Command must be a string');
  cmd = cmd.trim();
  if (cmd.length === 0) throw new Error('Empty command');
  if (/[;&|`$]/.test(cmd)) throw new Error('Command contains forbidden characters');
  return cmd;
}

function runUserCommand(userCmd) {
  const safeCmd = sanitize_command(userCmd);
  return execSync(safeCmd, { encoding: 'utf8', timeout: 5000 });
}

module.exports = { sanitize_command, runUserCommand };
