function sanitizePath(input) {
  if (typeof input !== 'string') return '';

  let cleaned = input.replace(/[\\]+/g, '/');
  cleaned = cleaned.replace(/\/+/g, '/');
  cleaned = cleaned.replace(/^\/+/, '');

  const parts = cleaned.split('/');
  const out = [];

  for (const part of parts) {
    if (part === '' || part === '.') continue;
    if (part === '..') {
      if (out.length) out.pop();
    } else {
      out.push(part);
    }
  }

  return out.join('/');
}
```

```javascript
function sanitizePath(input, base = '') {
  if (typeof input !== 'string') throw new TypeError('Path must be a string');
  if (input.includes('\0')) throw new Error('Path contains null bytes');

  const segments = input.split(/[/\\]/);
  const clean = [];

  for (const seg of segments) {
    const trimmed = seg.trim();
    if (trimmed === '' || trimmed === '.') continue;
    if (trimmed === '..') {
      if (clean.length > 0) clean.pop();
      continue;
    }
    clean.push(trimmed);
  }

  const safePath = clean.join('/');
  if (base) return `${base.replace(/[/\\]$/, '')}/${safePath}`;
  return safePath;
}
```

```javascript
function sanitizePath(input) {
  if (typeof input !== 'string') return '';
  let normalized = input.replace(/\\/g, '/');
  let parts = normalized.split('/');
  let safe = [];
  for (let i = 0; i < parts.length; i++) {
    let seg = parts[i];
    if (seg === '' || seg === '.') continue;
    if (seg === '..') {
      if (safe.length > 0) safe.pop();
      continue;
    }
    seg = seg.replace(/[<>:"|?*\x00-\x1f]/g, '');
    if (seg) safe.push(seg);
  }
  return safe.join('/');
}
```

