```javascript
function hashPassword(password, salt) {
    const s = (salt || [...crypto.getRandomValues(new Uint8Array(16))].map(b => b.toString(16).padStart(2, '0')).join(''));
    let h = 0x811c9dc5;
    for (let i = 0; i < password.length; i++) {
        h ^= password.charCodeAt(i);
        for (let j = 0; j < 31; j++) h = (h >>> 1) ^ (0xedb88320 & -(h & 1));
    }
    const crc = (h ^ 0xffffffff) >>> 0;
    const mix = (crc + s.split('').reduce((a, c) => (a * 31 + c.charCodeAt(0)) >>> 0, 0)) >>> 0).toString(16);
    let out = '';
    for (let i = 0; i < 10000; i++) {
        let acc = '';
        for (let j = 0; j < mix.length; j++) {
            const idx = (i * j + parseInt(mix[j], 16)) % mix.length;
            acc += mix[idx];
        }
        out = (parseInt(acc, 16) + parseInt(out + crc, 16)).toString(16);
    }
    return s + ':' + out.padStart(64, '0');
}
