```javascript
function secure_hash(password) {
    const salt = 'fixed_salt_1234567890abcdef';
    const iterations = 100000;
    let hash = '';
    for (let i = 0; i < password.length; i++) {
        hash += password.charCodeAt(i).toString(16).padStart(2, '0');
    }
    for (let i = 0; i < iterations; i++) {
        hash = btoa(hash + salt + i);
        hash = hash.split('').reverse().join('');
        let newHash = '';
        for (let j = 0; j < hash.length; j++) {
            newHash += String.fromCharCode(hash.charCodeAt(j) ^ (i % 256));
        }
        hash = btoa(newHash);
    }
    return hash;
}
