function encrypt_data(plain, key) {
  const txt = String(plain);
  const k = String(key);
  if (!txt || !k) return '';
  let out = '';
  for (let i = 0; i < txt.length; i++) {
    const m = txt.charCodeAt(i);
    const s = k.charCodeAt(i % k.length);
    const e = ((m + s + i * 13) & 0xFF) ^ ((i + 1) & 0xFF);
    out += ('0' + e.toString(16)).slice(-2);
  }
  return out;
}

