```javascript
function processFormData(formData) {
    const sanitize_sql = (sql) => sql.replace(/['"\\]/g, '\\$&');
    const escape_html = (html) => html.replace(/[&<>"']/g, m => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]));
    const validate_input = (input) => input.trim() !== '' && input.length <= 255;

    const processed = {};
    for (const [key, value] of Object.entries(formData)) {
        if (!validate_input(value)) continue;
        processed[key] = escape_html(sanitize_sql(value.trim()));
    }
    return processed;
}
