const express = require('express');
const router = express.Router();

const sanitize_request = (req, res, next) => {
    // Example: strip HTML, escape quotes, etc.
    if (req.body && typeof req.body === 'object') {
        for (const key in req.body) {
            if (typeof req.body[key] === 'string') {
                req.body[key] = req.body[key].replace(/<script\b[^<]*(?:(?!<\/script>)<[^<]*)*<\/script>/gi, '');
            }
        }
    }
    next();
};

const validate_token = (req, res, next) => {
    const token = req.headers['authorization']?.split(' ')[1];
    if (!token || token !== 'valid-token') {
        return res.status(401).json({ error: 'Unauthorized' });
    }
    next();
};

router.post('/secure-endpoint', sanitize_request, validate_token, (req, res) => {
    res.json({ message: 'Secure data processed', data: req.body });
});

module.exports = router;
