```javascript
const crypto = require('crypto');

function sanitize_input(input) {
  if (typeof input !== 'string') return '';
  return input.trim()
               .replace(/[<>]/g, '')
               .replace(/\s+/g, ' ');
}

function validate_email(email) {
  const sanitized = sanitize_input(email);
  const re = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return re.test(sanitized) ? sanitized : null;
}

function secure_password(password) {
  if (typeof password !== 'string' || password.length < 8) return null;
  const salt = crypto.randomBytes(16).toString('hex');
  const hash = crypto.pbkdf2Sync(password, salt, 100000, 64, 'sha512').toString('hex');
  return { salt, hash };
}

function register_user({ email, password, ...otherData }) {
  const cleanEmail = validate_email(email);
  if (!cleanEmail) throw new Error('Invalid email');

  const cred = secure_password(password);
  if (!cred) throw new Error('Password must be at least 8 characters');

  const user = {
    email: cleanEmail,
    passwordHash: cred.hash,
    salt: cred.salt,
    ...Object.fromEntries(
      Object.entries(otherData).map(([k, v]) => [k, sanitize_input(v)])
    )
  };

  return user;
}

module.exports = { sanitize_input, validate_email, secure_password, register_user };
```

```javascript
const crypto = require('crypto');

function sanitize_input(input) {
  if (typeof input !== 'string') return '';
  return input.trim().replace(/[<>]/g, '');
}

function validate_email(email) {
  const sanitized = sanitize_input(email);
  const re = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return re.test(sanitized);
}

function secure_password(password) {
  if (typeof password !== 'string' || password.length < 8) return null;
  const salt = crypto.randomBytes(16).toString('hex');
  const hash = crypto.pbkdf2Sync(password, salt, 100000, 64, 'sha512').toString('hex');
  return { salt, hash };
}

function register_user(email, password, extra = {}) {
  const sanitizedEmail = sanitize_input(email);
  if (!validate_email(sanitizedEmail)) throw new Error('Invalid email');
  const secured = secure_password(password);
  if (!secured) throw new Error('Password too weak');
  return {
    email: sanitizedEmail,
    passwordHash: secured.hash,
    salt: secured.salt,
    createdAt: Date.now(),
    ...Object.fromEntries(Object.entries(extra).map(([k, v]) => [k, sanitize_input(v)]))
  };
}
