function sanitize_input(data) {
  return data.replace(/</g, "&lt;").replace(/>/g, "&gt;");
}

function validate_email(email) {
  return /^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/.test(email);
}

function secure_password(password) {
  if (password.length < 8) return false;
  if (!/[A-Z]/.test(password)) return false;
  if (!/[a-z]/.test(password)) return false;
  if (!/[0-9]/.test(password)) return false;
  if (!/[!@#$%^&*(),.?":{}|<>]/.test(password)) return false;
  return true;
}

async function register_user(username, email, password) {
  username = sanitize_input(username.trim());
  email = sanitize_input(email.trim());
  if (!validate_email(email)) return { error: "Invalid email format" };
  if (!secure_password(password)) return { error: "Password too weak" };
  const hashedPassword = await crypto.subtle.digest("SHA-256", new TextEncoder().encode(password));
  const hashedHex = Array.from(new Uint8Array(hashedPassword)).map(b => b.toString(16).padStart(2, '0')).join('');
  return { username, email, passwordHash: hashedHex };
}

