        "b", "i", "u", "em", "strong", "p", "br", "div", "span", "ul", "ol", "li", "a", "img", "h1", "h2", "h3", "h4", "h5", "h6"
    ));

    private static final Set<String> ALLOWED_ATTRS = new HashSet<>(Arrays.asList(
        "href", "title", "alt", "src", "width", "height"
    ));

    public static String sanitize(String html) {
        if (html == null) return "";
        StringBuilder out = new StringBuilder();
        StringBuilder tag = null;
        StringBuilder attr = null;
        StringBuilder val = null
        boolean inTag = false;
        boolean inClose = false;
        boolean inAttr = false;
        boolean inQuote = false;
        boolean inSingleQuote = false;
        char quote = 0;
        int i = 0;
        int n = html.length();
        while (i < n) {
            char c = html.charAt(i);
            if (inTag) {
                if (c == '>') {
                    inTag = false;
                    String tagName = tag.toString().toLowerCase(Locale.ROOT).trim();
                    if (tagName.startsWith("/")) tagName = tagName.substring(1);
                    if (!ALLOWED_TAGS.contains(tagName)) {
                        // skip
                    } else {
                        out.append('<').append(tag).append('>');
                    }
                    tag = null;
                } else {
                    tag.append(c);
                }
            } else if (inAttr) {
                if (!inQuote && (c == '"' || c == '\'')) {
                    inQuote = true;
                    quote = c;
                    if (c == '\'') inSingleQuote = true;
                } else if (inQuote && ((c == quote && !inSingleQuote) || (c == '\'' && inSingleQuote))) {
                    inQuote = false;
                    inSingleQuote = false;
                    String attrName = attr.toString().toLowerCase(Locale.ROOT).trim();
                    String attrVal = val.toString();
                    if (ALLOWED_ATTRS.contains(attrName)) {
                        out.append(' ').append(attrName);
                        if (attrVal.length() > 0) {
                            out.append("=\"").append(escapeHtml(attrVal)).append('"');
                        }
                    }
                    attr = null;
                    val = null;
                    inAttr = false;
                } else if (!inQuote && c == ' ') {
                    String attrName = attr.toString().toLowerCase(Locale.ROOT).trim();
                    if (ALLOWED_ATTRS.contains(attrName)) {
                        out.append(' ').append(attrName);
                    }
                    attr = null;
                    inAttr = false;
                } else {
                    if (inQuote) {
                        val.append(c);
                    } else {
                        attr.append(c);
                    }
                }
            } else {
                if (c == '<') {
                    tag = new StringBuilder();
                    inTag = true;
                    inClose = false;
                    inAttr = false;
                    inQuote = false;
                    inSingleQuote = false;
                    attr = null;
                    val = null;
                } else {
                    out.append(escapeHtml(String.valueOf(c)));
                }
            }
            i++;
        }
        return out.toString();
    }

    private static String escapeHtml(String s) {
        StringBuilder sb = new StringBuilder();
        for (char c : s.toCharArray()) {
            switch (c) {
                case '&': sb.append("&amp;"); break;
                case '<': sb.append("&lt;"); break;
                case '>': sb.append("&gt;"); break;
                case '"': sb.append("&quot;"); break;
                case '\'': sb.append("&#39;"); break;
                default: sb.append(c);
            }
        }
        return sb.toString();
    }

    public static void main(String[] args) {
        String input = "<script>alert('xss')</script><b onclick=\"alert('x')\">bold</b><a href=\"javascript:alert('x')\">link</a>";
        System.out.println(sanitize(input));
    }
}
