import java.util.*;
import java.util.regex.*;

public class HtmlSanitizer {

    private static final Set<String> ALLOWED_TAGS = new HashSet<>(Arrays.asList(
        "b", "i", "u", "em", "strong", "small", "mark", "del", "ins", "sub", "sup",
        "p", "br", "div", "span", "h1", "h2", "h3", "h4", "h5", "h6",
        "ul", "ol", "li", "blockquote", "code", "pre", "hr", "a"
    ));

    private static final Set<String> ALLOWED_ATTRS = new HashSet<>(Arrays.asList("href", "title"));

    public static String sanitize(String html) {
        if (html == null || html.isEmpty()) return "";
        StringBuilder out = new StringBuilder();
        StringBuilder tagBuf = new StringBuilder();
        boolean inTag = false;
        boolean inClosing = false;
        for (int i = 0; i < html.length(); i++) {
            char c = html.charAt(i);
            if (c == '<') {
                inTag = true;
                inClosing = false;
                tagBuf.setLength(0);
            } else if (inTag && c == '/') {
                if (tagBuf.length() == 0) inClosing = true;
                tagBuf.append(c);
            } else if (inTag && c == '>') {
                inTag = false;
                String tag = tagBuf.toString().trim();
                if (!tag.isEmpty()) {
                    String tagName = extractTagName(tag);
                    if (ALLOWED_TAGS.contains(tagName.toLowerCase())) {
                        if (inClosing) {
                            out.append("</").append(tagName).append(">");
                        } else {
                            String attrs = extractAttributes(tag);
                            out.append("<").append(tagName);
                            if (!attrs.isEmpty()) {
                                out.append(" ").append(attrs);
                            }
                            out.append(">");
                        }
                    }
                }
            } else if (inTag) {
                tagBuf.append(c);
            } else {
                out.append(escapeHtml(c));
            }
        }
        return out.toString();
    }

    private static String extractTagName(String tag) {
        int sp = tag.indexOf(' ');
        return sp == -1 ? tag : tag.substring(0, sp);
    }

    private static String extractAttributes(String tag) {
        int sp = tag.indexOf(' ');
        if (sp == -1) return "";
        StringBuilder clean = new StringBuilder();
        String rest = tag.substring(sp + 1);
        Pattern p = Pattern.compile("(\\w+)\\s*=\\s*(?:\"([^\"]*)\"|'([^']*)')");
        Matcher m = p.matcher(rest);
        while (m.find()) {
            String name = m.group(1).toLowerCase();
            if (ALLOWED_ATTRS.contains(name)) {
                String val = m.group(2) != null ? m.group(2) : m.group(3);
                if ("href".equals(name) && !isSafeUrl(val)) continue;
                clean.append(name).append("=\"").append(escapeHtml(val)).append("\" ");
            }
        }
        return clean.toString().trim();
    }

    private static boolean isSafeUrl(String url) {
        return url != null && (url.startsWith("/") || url.startsWith("https://") || url.startsWith("http://"));
    }

    private static String escapeHtml(String s) {
        if (s == null) return "";
        StringBuilder sb = new StringBuilder();
        for (char c : s.toCharArray()) {
            sb.append(escapeHtml(c));
        }
        return sb.toString();
    }

    private static String escapeHtml(char c) {
        switch (c) {
            case '&': return "&amp;";
            case '<': return "&lt;";
            case '>': return "&gt;";
            case '"': return "&quot;";
            case '\'': return "&#39;";
            default: return String.valueOf(c);
        }
    }

    public static void main(String[] args) {
        String input = "<script>alert('xss')</script><b onmouseover=alert(1)>bold</b><a href=\"javascript:alert(1)\">link</a>";
        System.out.println(sanitize(input));
    }
}
