```java
import java.util.*;
import java.util.regex.*;

public class HtmlSanitizer {

    private static final Set<String> ALLOWED_TAGS = new HashSet<>(Arrays.asList(
        "p", "br", "b", "i", "u", "em", "strong", "small", "mark", "del", "ins", "sub", "sup",
        "h1", "h2", "h3", "h4", "h5", "h6",
        "ul", "ol", "li",
        "table", "thead", "tbody", "tfoot", "tr", "td", "th",
        "blockquote", "code", "pre",
        "a", "img", "span", "div"
    ));

    private static final Set<String> ALLOWED_ATTRS = new HashSet<>(Arrays.asList(
        "href", "title", "alt", "src", "width", "height", "class"
    ));

    private static final Pattern TAG_PATTERN = Pattern.compile("</?([a-zA-Z][a-zA-Z0-9]*)\\b([^>]*)>");
    private static final Pattern ATTR_PATTERN = Pattern.compile("\\s([a-zA-Z][a-zA-Z0-9]*)\\s*=\\s*(?:\"([^\"]*)\"|'([^']*)')");

    public static String sanitize(String html) {
        if (html == null || html.isEmpty()) return "";
        StringBuilder out = new StringBuilder();
        int len = html.length();
        int i = 0;
        while (i < len) {
            char c = html.charAtAt(i);
            if (c == '<') {
                int tagEnd = html.indexOf('>', i);
                if (tagEnd == -1) break;
                String tagChunk = html.substring(i, tagEnd + 1);
                Matcher m = TAG_PATTERN.matcher(tagChunk);
                if (m.find()) {
                    String tagName = m.group(1).toLowerCase();
                    if (ALLOWED_TAGS.contains(tagName)) {
                        String attrs = m.group(2);
                        out.append("<").append(tagName);
                        if (attrs != null && !attrs.isEmpty()) {
                            attrs = sanitizeAttributes(attrs, tagName);
                            if (!attrs.isEmpty()) out.append(" ").append(attrs);
                        }
                        out.append(">");
                    }
                }
                i = tagEnd + 1;
            } else {
                out.append(c);
                i++;
            }
        }
        return out.toString();
    }

    private static String sanitizeAttributes(String attrs, String tagName) {
        StringBuilder clean = new StringBuilder();
        Matcher m = ATTR_PATTERN.matcher(attrs);
        while (m.find()) {
            String name = m.group(1).toLowerCase();
            String value = m.group(2) != null ? m.group(2) : m.group(3);
            if (ALLOWED_ATTRS.contains(name)) {
                if ("href".equals(name) || "src".equals(name)) {
                    if (value == null || value.trim().isEmpty()) continue;
                    value = value.trim();
                    if (value.startsWith("javascript:") || value.startsWith("data:")) continue;
                }
                clean.append(name).append("=\"").append(escapeHtml(value)).append("\" ");
            }
        }
        return clean.toString().trim();
    }

    private static String escapeHtml(String s) {
        if (s == null) return "";
        return s.replace("&", "&amp;")
                  .replace("<", "&lt;")
                  .replace(">", "&gt;")
                  .replace("\"", "&quot;");
    }
}
