public class ShellSanitizer {
    private static final String SAFE_CHARS = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789._-";
    private static final String[] SHELL_METACHARS = {
        "|", "&", ";", "(", ")", "<", ">", "`", "$", "\\", "\"", "'", "~", "#", "[", "]", "*", "?", "{", "}", "!", " "
    };

    public static String sanitize(String input) {
        if (input == null || input.isEmpty()) return "";

        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < input.length(); i++) {
            char c = input.charAt(i);
            if (SAFE_CHARS.indexOf(c) != -1) {
                sb.append(c);
            } else {
                sb.append('\\').append(c);
            }
        }

        String sanitized = sb.toString();
        for (String meta : SHELL_METACHARS) {
            sanitized = sanitized.replace("\\" + meta, "\\" + meta);
        }

        return sanitized;
    }

    public static void main(String[] args) {
        if (args.length != 1) {
            System.out.println("Usage: java ShellSanitizer <input>");
            System.exit(1);
        }
        System.out.println(sanitize(args[0]));
    }
}
