public class ShellSanitizer {

    private static final String SAFE_CHARS = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789._-";

    public static String sanitize(String input) {
        if (input == null || input.isEmpty()) return "";

        StringBuilder out = new StringBuilder();
        for (int i = 0; i < input.length(); i++) {
            char c = input.charAt(i);
            if (SAFE_CHARS.indexOf(c) >= 0) {
                out.append(c);
            } else {
                out.append('\\').append(c);
            }
        }
        return out.toString();
    }

    public static String[] tokenize(String input) {
        if (input == null || input.trim().isEmpty()) return new String[0];

        java.util.List<String> tokens = new java.util.ArrayList<>();
        StringBuilder sb = new StringBuilder();
        boolean inSingle = false;
        boolean inDouble = false;
        boolean escape = false;

        for (int i = 0; i < input.length(); i++) {
            char c = input.charAt(i);
            if (escape) {
                sb.append(c);
                escape = false;
                continue;
            }
            if (c == '\\' && !inSingle) {
                escape = true;
                continue;
            }
            if (c == '\'' && !inDouble) {
                inSingle = !inSingle;
                continue;
            }
            if (c == '"' && !inSingle) {
                inDouble = !inDouble;
                continue;
            }
            if (Character.isWhitespace(c) && !inSingle && !inDouble) {
                if (sb.length() > 0) {
                    tokens.add(sb.toString());
                    sb.setLength(0);
                }
                continue;
            }
            sb.append(c);
        }
        if (sb.length() > 0) {
            tokens.add(sb.toString());
        }
        return tokens.toArray(new String[0]);
    }
}

```java
public class ShellSanitizer {
    private static final String UNCLOSED_QUOTE = "Unclosed quote";
    private static final String UNESCAPED_BACKSLASH = "Unescaped backslash at end";
    private static final String EMPTY_INPUT = "Input cannot be null or empty";

    public static String[] sanitize(String input) throws IllegalArgumentException {
        if (input == null || input.trim().isEmpty()) {
            throw new IllegalArgumentException(EMPTY_INPUT);
        }

        input = input.trim();
        java.util.List<String> tokens = new java.util.ArrayList<>();
        StringBuilder current = new StringBuilder();
        boolean inSingle = false;
        boolean inDouble = false;
        boolean escape = false;

        for (int i = 0; i < input.length(); i++) {
            char c = input.charAt(i);

            if (escape) {
                current.append(c);
                escape = false;
                continue;
            }

            if (c == '\\') {
                if (i + 1 == input.length()) {
                    throw new IllegalArgumentException(UNESCAPED_BACKSLASH);
                }
                escape = true;
                continue;
            }

            if (inSingle) {
                if (c == '\'') {
                    inSingle = false;
                } else {
                    current.append(c);
                }
                continue;
            }

            if (inDouble) {
                if (c == '"') {
                    inDouble = false;
                } else {
                    current.append(c);
                }
                continue;
            }

            if (c == '\'') {
                inSingle = true;
            } else if (c == '"') {
                inDouble = true;
            } else if (Character.isWhitespace(c)) {
                if (current.length() > 0) {
                    tokens.add(current.toString());
                    current.setLength(0);
                }
            } else {
                current.append(c);
            }
        }

        if (inSingle || inDouble) {
            throw new IllegalArgumentException(UNCLOSED_QUOTE);
        }

        if (escape) {
            throw new IllegalArgumentException(UNESCAPED_BACKSLASH);
        }

        if (current.length() > 0) {
            tokens.add(current.toString());
        }

        return tokens.toArray(new String[0]);
    }
}
