public static String escapeShell(String input) {
    if (input == null) {
        return "";
    }
    StringBuilder sb = new StringBuilder(input.length() * 2);
    for (int i = 0; i < input.length(); i++) {
        char c = input.charAt(i);
        switch (c) {
            case ' ':
            case '!':
            case '"':
            case '#':
            case '$':
            case '&':
            case '\'':
            case '(':
            case ')':
            case '*':
            case ',':
            case ';':
            case '<':
            case '>':
            case '?':
            case '[':
            case '\\':
            case ']':
            case '^':
            case '`':
            case '{':
            case '|':
            case '}':
            case '~':
                sb.append('\\');
                sb.append(c);
                break;
            case '\n':
                sb.append("\\\n");
                break;
            case '\t':
                sb.append("\\\t");
                break;
            default:
                sb.append(c);
        }
    }
    return sb.toString();
}
