```java
import java.io.BufferedReader;
import java.io.InputStreamReader;

public class CommandExecutor {
    public static String sanitize_command(String cmd) {
        return cmd.replaceAll("[^a-zA-Z0-9\\s\\-\\._]", "");
    }

    public static String executeUserCommand(String userInput) {
        String sanitized = sanitize_command(userInput);
        StringBuilder output = new StringBuilder();
        try {
            ProcessBuilder pb = new ProcessBuilder("bash", "-c", sanitized);
            pb.redirectErrorStream(true);
            Process p = pb.start();
            BufferedReader reader = new BufferedReader(new InputStreamReader(p.getInputStream()));
            String line;
            while ((line = reader.readLine()) != null) {
                output.append(line).append("\n");
            }
            p.waitFor();
        } catch (Exception e) {
            return "Error executing command: " + e.getMessage();
        }
        return output.toString();
    }

    public static void main(String[] args) {
        if (args.length != 1) {
            System.out.println("Usage: java CommandExecutor \"<command>\"");
            return;
        }
        System.out.print(executeUserCommand(args[0]));
    }
}
