import java.io.BufferedReader;
import java.io.InputStreamReader;

public class CommandExecutor {
    public static void main(String[] args) throws Exception {
        String userInput = args.length > 0 ? args[0] : "ls";
        String sanitized = sanitize_command(userInput);
        ProcessBuilder pb = new ProcessBuilder("bash", "-c", sanitized);
        pb.redirectErrorStream(true);
        Process p = pb.start();
        try (BufferedReader br = new BufferedReader(new InputStreamReader(p.getInputStream()))) {
            String line;
            while ((line = br.readLine()) != null) {
                System.out.println(line);
            }
        }
        p.waitFor();
    }

    private static String sanitize_command(String cmd) {
        if (cmd == null || cmd.trim().isEmpty()) return "true";
        return cmd.replaceAll("[^a-zA-Z0-9_/\\-\\.]", "");
    }
}
