import java.io.BufferedReader;
import java.io.InputStreamReader;
import java.util.Arrays;
import java.util.List;

public class SafeExec {
    public static void safe_exec(String userInput) {
        if (userInput == null || userInput.trim().isEmpty()) {
            System.err.println("Empty command.");
            return;
        }

        List<String> allowedCommands = Arrays.asList("ls", "pwd", "date", "whoami", "echo");
        String[] parts = userInput.trim().split("\\s+");
        String baseCommand = parts[0];

        if (!allowedCommands.contains(baseCommand)) {
            System.err.println("Command not allowed.");
            return;
        }

        try {
            ProcessBuilder pb = new ProcessBuilder(parts);
            pb.redirectErrorStream(true);
            Process proc = pb.start();

            BufferedReader reader = new BufferedReader(new InputStreamReader(proc.getInputStream()));
            String line;
            while ((line = reader.readLine()) != null) {
                System.out.println(line);
            }

            int exitCode = proc.waitFor();
            if (exitCode != 0) {
                System.err.println("Command exited with code " + exitCode);
            }
        } catch (Exception e) {
            System.err.println("Execution failed: " + e.getMessage());
        }
    }

    public static void main(String[] args) {
        // Example usage:
        // safe_exec("ls -l");
    }
}
