```java
import java.io.File;
import java.util.LinkedList;

public class PathSanitizer {

    public static String sanitize(String inputPath, String baseDir) {
        if (inputPath == null || baseDir == null) {
            throw new IllegalArgumentException("Paths must not be null");
        }
        inputPath = inputPath.replace('\\', '/');
        baseDir = baseDir.replace('\\', '/');
        if (!baseDir.endsWith("/")) {
            baseDir += "/";
        }

        String[] parts = inputPath.split("/");
        LinkedList<String> stack = new LinkedList<>();

        for (String part : parts) {
            if (part.isEmpty() || ".".equals(part)) {
                continue;
            }
            if ("..".equals(part)) {
                if (!stack.isEmpty()) {
                    stack.removeLast();
                }
            } else {
                stack.addLast(part);
            }
        }

        StringBuilder sanitized = new StringBuilder();
        for (String segment : stack) {
            sanitized.append(segment).append("/");
        }
        String result = sanitized.length() > 0 ? sanitized.substring(0, sanitized.length() - 1) : "";

        File base = new File(baseDir);
        File resolved = new File(base, result);
        try {
            String canonicalBase = base.getCanonicalPath();
            String canonicalResolved = resolved.getCanonicalPath();
            if (!canonicalResolved.startsWith(canonicalBase)) {
                throw new SecurityException("Path traversal detected");
            }
            return canonicalResolved;
        } catch (Exception e) {
            throw new SecurityException("Invalid path", e);
        }
    }
}
