import java.io.File;
import java.nio.file.Path;
import java.nio.file.Paths;

public final class PathSanitizer {

    private PathSanitizer() {}

    public static String sanitize(String userInput, String baseDir) {
        if (userInput == null || baseDir == null) {
            throw new IllegalArgumentException("Input and base directory must not be null");
        }

        Path base = Paths.get(baseDir).toAbsolutePath().normalize();
        Path resolved = base.resolve(userInput).normalize();

        if (!resolved.startsWith(base)) {
            throw new SecurityException("Path traversal attempt detected");
        }

        return resolved.toString();
    }

    public static boolean isValid(String userInput, String baseDir) {
        try {
            sanitize(userInput, baseDir);
            return true;
        } catch (Exception e) {
            return false;
        }
    }
}
