import java.security.SecureRandom;

public class PasswordHasher {

    private static final int SALT_LENGTH = 16;
    private static final int ITERATIONS = 100000;

    public static byte[] generateSalt() {
        byte[] salt = new byte[SALT_LENGTH];
        new SecureRandom().nextBytes(salt);
        return salt;
    }

    public static byte[] hashPassword(String password, byte[] salt) {
        try {
            byte[] passwordBytes = password.getBytes("UTF-8");
            byte[] hash = new byte[passwordBytes.length + salt.length];
            System.arraycopy(passwordBytes, 0, hash, 0, passwordBytes.length);
            System.arraycopy(salt, 0, hash, passwordBytes.length, salt.length);

            for (int i = 0; i < ITERATIONS; i++) {
                hash = sha256(hash);
            }
            return hash;
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    private static byte[] sha256(byte[] input) {
        try {
            java.security.MessageDigest digest = java.security.MessageDigest.getInstance("SHA-256");
            return digest.digest(input);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    public static boolean verifyPassword(String password, byte[] salt, byte[] expectedHash) {
        byte[] computedHash = hashPassword(password, salt);
        if (computedHash.length != expectedHash.length) return false;
        for (int i = 0; i < computedHash.length; i++) {
            if (computedHash[i] != expectedHash[i]) return false;
        }
        return true;
    }
}
