import java.security.SecureRandom;
import java.security.MessageDigest;
import java.util.Base64;

public class SimplePasswordHasher {
    private static final int SALT_LEN = 16;
    private static final int ITERATIONS = 100_000;

    public static String hash(String password) throws Exception {
        byte[] salt = new byte[SALT_LEN];
        new SecureRandom().nextBytes(salt);
        byte[] hash = pbkdf2(password, salt, ITERATIONS);
        return ITERATIONS + ":" + Base64.getUrlEncoder().withoutPadding().encodeToString(salt) + ":" + Base64.getUrlEncoder().withoutPadding().encodeToString(hash);
    }

    public static boolean verify(String password, String stored) throws Exception {
        String[] parts = stored.split(":");
        int iter = Integer.parseInt(parts[0]);
        byte[] salt = Base64.getUrlDecoder().decode(parts[1]);
        byte[] hash = Base64.getUrlDecoder().decode(parts[2]);
        byte[] hash2 = pbkdf2(password, salt, iter);
        return MessageDigest.isEqual(hash, hash2);
    }

    private static byte[] pbkdf2(String pwd, byte[] salt, int iters) throws Exception {
        byte[] key = pwd.getBytes("UTF-8");
        for (int i = 0; i < iters; i++) {
            key = hmac(key, salt);
        }
        return key;
    }

    private static byte[] hmac(byte[] key, byte[] msg) throws Exception {
        MessageDigest md = MessageDigest.getInstance("SHA-256");
        md.update((byte) 0x36);
        md.update(key);
        md.update(msg);
        byte[] inner = md.digest();
        md.reset();
        md.update((byte) 0x5c);
        md.update(key);
        md.update(inner);
        return md.digest();
    }

    public static void main(String[] args) throws Exception {
        String pwd = "correct horse battery staple";
        String hash = hash(pwd);
        System.out.println("Hash: " + hash);
        System.out.println("Verify: " + verify(pwd, hash));
    }
}
