import java.util.Map;
import java.util.HashMap;
import java.util.List;
import java.util.ArrayList;

public class UniversalInputSanitizer {

    private static final char REPLACEMENT = '_';

    public static String sanitize(String input) {
        if (input == null) return null;
        StringBuilder sb = new StringBuilder(input.length());
        for (int i = 0; i < input.length(); i++) {
            char c = input.charAt(i);
            if (c < 0x20 && c != '\t' && c != '\n' && c != '\r') {
                sb.append(REPLACEMENT);
            } else if (c == '<') {
                sb.append("&lt;");
            } else if (c == '>') {
                sb.append("&gt;");
            } else if (c == '&') {
                sb.append("&amp;");
            } else if (c == '"') {
                sb.append("&quot;");
            } else if (c == '\'') {
                sb.append("&#x27;");
            } else if (c == '/') {
                sb.append("&#x2F;");
            } else if (c >= 0x7F) {
                sb.append(REPLACEMENT);
            } else {
                sb.append(c);
            }
        }
        return sb.toString();
    }

    public static String[] sanitizeArray(String[] arr) {
        if (arr == null) return null;
        String[] out = new String[arr.length];
        for (int i = 0; i < arr.length; i++) {
            out[i] = sanitize(arr[i]);
        }
        return out;
    }

    public static List<String> sanitizeList(List<String> list) {
        if (list == null) return null;
        List<String> out = new ArrayList<>(list.size());
        for (String s : list) {
            out.add(sanitize(s));
        }
        return out;
    }

    public static Map<String, String> sanitizeMap(Map<String, String> map) {
        if (map == null) return null;
        Map<String, String> out = new HashMap<>(map.size());
        for (Map.Entry<String, String> e : map.entrySet()) {
            out.put(sanitize(e.getKey()), sanitize(e.getValue()));
        }
        return out;
    }
}
