import java.util.regex.Pattern;

public class Sanitizer {
    private static final Pattern SCRIPT_PATTERN = Pattern.compile("<script>.*?</script>", Pattern.CASE_INSENSITIVE | Pattern.DOTALL);
    private static final Pattern TAG_PATTERN = Pattern.compile("<[^>]*>");
    private static final Pattern SQL_PATTERN = Pattern.compile("('.+--)|(--)|(\\|)|(\\^)|(\\*)|(\\;)|(\\%)|(\\\")", Pattern.CASE_INSENSITIVE);

    public static String sanitize_input(String input) {
        if (input == null) return null;
        input = SCRIPT_PATTERN.matcher(input).replaceAll("");
        input = TAG_PATTERN.matcher(input).replaceAll("");
        input = SQL_PATTERN.matcher(input).replaceAll("");
        return input.trim();
    }
}
