```java
import java.util.regex.Pattern;

public class DataSanitizer {

    public static String clean_data(String input) {
        if (input == null || input.trim().isEmpty()) {
            return "";
        }

        // Remove script tags and their contents
        String cleaned = input.replaceAll("(?i)<script[^>]*>.*?</script>", "");

        // Remove event handlers (e.g., onclick, onerror, etc.)
        cleaned = cleaned.replaceAll("(?i)\\s*on\\w+\\s*=\\s*[\"']?[^\"'>]*[\"']?", "");

        // Remove javascript: protocol in href/src
        cleaned = cleaned.replaceAll("(?i)\\b(javascript:|vbscript:|data:text/html)", "");

        // Remove dangerous HTML tags and attributes
        cleaned = cleaned.replaceAll("(?i)<(iframe|object|embed|form|input|meta|link|style|script).*?>", "");

        // Escape special characters to prevent XSS
        cleaned = cleaned.replace("&", "&amp;")
                         .replace("<", "&lt;")
                         .replace(">", "&gt;")
                         .replace("\"", "&quot;")
                         .replace("'", "&#x27;");

        return cleaned.trim();
    }
}
