public static byte[] encrypt_data(byte[] data, byte[] key) {
    if (data == null || key == null || key.length == 0) return null;
    byte[] out = new byte[data.length];
    int klen = key.length;
    for (int i = 0; i < data.length; i++) {
        out[i] = (byte)(data[i] ^ key[i % klen]);
    }
    return out;
}

