public class FormProcessor {
    public static String[] processFormData(String[] formData) {
        if (formData == null) return new String[0];

        String[] processed = new String[formData.length];
        for (int i = 0; i < formData.length; i++) {
            if (formData[i] == null) {
                processed[i] = null;
                continue;
            }
            String validated = validate_input(formData[i]);
            String sanitized = sanitize_sql(validated);
            processed[i] = escape_html(sanitized);
        }
        return processed;
    }

    private static native String sanitize_sql(String input);
    private static native String escape_html(String input);
    private static native String validate_input(String input);
}
