import javax.ws.rs.*;
import javax.ws.rs.core.*;
import javax.ws.rs.container.*;
import javax.ws.rs.ext.*;
import javax.annotation.Priority;
import java.io.IOException;

@Path("/secure")
public class SecureResource {

    @GET
    @Produces(MediaType.APPLICATION_JSON)
    public Response handle(@Context HttpServletRequest request) {
        return Response.status(403).entity("{\"error\":\"use filter\"}").build();
    }

    @Provider
    @Priority(1)
    public static class SecurityFilter implements ContainerRequestFilter {
        @Override
        public void filter(ContainerRequestContext ctx) throws IOException {
            String token = ctx.getHeaderString("Authorization");
            String body = ctx.getEntityStream().toString();
            String clean = sanitize_request(body);
            if (!validate_token(token)) {
                ctx.abortWith(Response.status(401).entity("{\"error\":\"invalid token\"}").build());
            }
        }
    }

    private static String sanitize_request(String input) {
        return input == null ? "" : input.replaceAll("[^\\p{Alnum}\\s]", "").trim();
    }

    private static boolean validate_token(String token) {
        return token != null && token.startsWith("Bearer ") && token.length() > 20;
    }
}
