import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.security.SecureRandom;
import java.util.Base64;
import java.util.regex.Pattern;

public class UserRegistration {

    private static final Pattern EMAIL_PATTERN = Pattern.compile(
        "^[A-Za-z0-9+_.-]+@[A-Za-z0-9.-]+$"
    );

    public static String sanitize_input(String input) {
        if (input == null) return "";
        return input.replaceAll("[^A-Za-z0-9@._-]", "");
    }

    public static boolean validate_email(String email) {
        return email != null && EMAIL_PATTERN.matcher(email).matches();
    }

    public static String secure_password(String password) throws NoSuchAlgorithmException {
        if (password == null) throw new IllegalArgumentException("Password cannot be null");
        SecureRandom sr = new SecureRandom();
        byte[] salt = new byte[16];
        sr.nextBytes(salt);
        MessageDigest md = MessageDigest.getInstance("SHA-256");
        md.update(salt);
        byte[] hashedPassword = md.digest(password.getBytes());
        String saltBase64 = Base64.getEncoder().encodeToString(salt);
        String hashBase64 = Base64.getEncoder().encodeToString(hashedPassword);
        return saltBase64 + ":" + hashBase64;
    }

    public static void register_user(String username, String email, String password) throws Exception {
        username = sanitize_input(username);
        email = sanitize_input(email);
        if (!validate_email(email)) {
            throw new IllegalArgumentException("Invalid email format");
        }
        String securedPassword = secure_password(password);
        System.out.println("User registered: " + username + " with email: " + email);
    }

    public static void main(String[] args) throws Exception {
        register_user("john_doe", "john@example.com", "securePassword123");
    }
}
